var psa_ch_7_Verses = [
  {num:1,words:[["Ieova e,", "O LORD my God,"], ["lo'u Atua,", "in thee do I put my trust:"], ["ou te faatuatua lava ia te oe; ia e faaola mai ia te au i e tuliloa mai ia te au uma lava,", "save me from all them that persecute me,"], ["ma ia e laveaiina a'u.", "and deliver me:"]]},
  {num:2,words:[["Ne'i saeia a'u e ia e pei o se leona,", "Lest he tear my soul like a lion,"], ["ne'i faamomomoina a'u ,", "rending it in pieces,"], ["a e leai se laveai mai.", "while there is none to deliver."]]},
  {num:3,words:[["Ieova e,", "O LORD my God,"], ["lo'u Atua, afai ua a'u faia lena mea;", "if I have done this;"], ["pe afai o i o'u lima se amio leaga;", "if there be iniquity in my hands;"]]},
  {num:4,words:[["afai ua ou agaleaga atu i le na ma nofo lelei ma ia;", "If I have rewarded evil unto him that was at peace with me; (yea,"], ["afai ua ou vetea mea a le ua ita fua mai ia te au;", "I have delivered him that without cause is mine enemy: )"]]},
  {num:5,words:[["ia tuliloaina a'u e le ua ita mai,", "Let the enemy persecute my soul,"], ["ma ia maua mai a'u e ia;", "and take it;"], ["ia solia foi e ia lo'u ola i le eleele,", "yea, let him tread down my life upon the earth,"], ["ma ia faataatia lo'u mamalu i le efuefu.", "and lay mine honour in the dust."], ["Selā.", "Selah."]]},
  {num:6,words:[["Ieova e,", "Arise,"], ["ia e tulai mai i lou toasa,", "O LORD,"], ["ia faasilisili oe ona o le ita o e saua mai ia te au;", "in thine anger, lift up thyself because of the rage of mine enemies:"], ["ma ia e maleifua mai ona o a'u i le faamasinoga ua e fetalai mai ai.", "and awake for me to the judgment that thou hast commanded."]]},
  {num:7,words:[["Ona siosiomia ai lea o oe e le faapotopotoga o nuu;", "So shall the congregation of the people compass thee about:"], ["ia e foi mai i o latou luga i le mea maualuga.", "for their sakes therefore return thou on high."]]},
  {num:8,words:[["E faatonuina nuu e Ieova;", "The LORD shall judge the people:"], ["Ieova e,", "judge me,"], ["ia e faamasino ia te au e tusa ma la'u amiotonu,", "O LORD, according to my righteousness,"], ["e tusa foi ma la'u amio sao.", "and according to mine integrity that is in me."]]},
  {num:9,words:[["Ia faaumatia le leaga o e amio leaga;", "Oh let the wickedness of the wicked come to an end;"], ["a ia e faatumauina le ua amiotonu;", "but establish the just:"], ["auā e suesue loto ma manatu e le Atua amiotonu.", "for the righteous God trieth the hearts and reins."]]},
  {num:10,words:[["O le Atua o lo'u talita ia,", "My defence is of God,"], ["o le faaola o ia o e ua tonu o latou loto.", "which saveth the upright in heart."]]},
  {num:11,words:[["O le Atua, o le faamasino amiotonu o ia;", "God judgeth the righteous,"], ["ua toasa foi le Atua i aso uma lava i le ua amio leaga .", "and God is angry with the wicked every day."]]},
  {num:12,words:[["Afai e le foi mai o ia,", "If he turn not,"], ["ona faamaai ai lea e ia o lana pelu;", "he will whet his sword;"], ["ua ia lolou i lana aufana,", "he hath bent his bow,"], ["ma sauni i ai.", "and made it ready."]]},
  {num:13,words:[["Ua ia sauni atu foi ia te ia le auupega e oti ai;", "He hath also prepared for him the instruments of death;"], ["na te faia foi ana u fanafana mu.", "he ordaineth his arrows against the persecutors."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["ua faatiga o ia i le agasala;", "he travaileth with iniquity,"], ["ua to foi i le amio leaga,", "and hath conceived mischief,"], ["ma na fanauina le pepelo.", "and brought forth falsehood."]]},
  {num:15,words:[["Ua faia e ia le lua,", "He made a pit,"], ["ua elia lava;", "and digged it,"], ["a e paū lava o ia i le lua na ia faia.", "and is fallen into the ditch which he made."]]},
  {num:16,words:[["E toe iu atu lona leaga i lona lava ulu,", "His mischief shall return upon his own head,"], ["e paū foi lana sauaga i luga o lona tumuai.", "and his violent dealing shall come down upon his own pate."]]},
  {num:17,words:[["Ou te vivii atu ia Ieova ona o lana amiotonu;", "I will praise the LORD according to his righteousness:"], ["ou te pese atu foi i le suafa o Ieova lē Silisili ese.", "and will sing praise to the name of the LORD most high."]]},
];
