var psa_ch_8_Verses = [
  {num:1,words:[["Ieova e, lo matou Alii,", "O LORD our Lord,"], ["e silisili lava lou suafa i le lalolagi uma lava; o oe lava ua e faasilisili lou viiga i le lagi.", "how excellent is thy name in all the earth! who hast set thy glory above the heavens."]]},
  {num:2,words:[["Ua e faatumauina le viiga i gutu o tama meamea ma tama fesusui, ona o e faasaua ia te oe,", "Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies,"], ["ina ia faanofosaoina le ua ita ma le ua taui ma sui.", "that thou mightest still the enemy and the avenger."]]},
  {num:3,words:[["A ou vaai atu i lou lagi,", "When I consider thy heavens,"], ["o le galuega a ou tamatamai lima,", "the work of thy fingers, the moon and the stars,"], ["o le masina atoa ma fetu na e faia;", "which thou hast ordained;"]]},
  {num:4,words:[["se a ea le tagata e te manatu mai ai ia te ia;", "What is man, that thou art mindful of him? and the son of man,"], ["ma le atalii o le tagata e te asiasi mai ai ia te ia?", "that thou visitest him?"]]},
  {num:5,words:[["Auā ua e faamaulalo ane teisi o ia i agelu;", "For thou hast made him a little lower than the angels,"], ["ua e faapaleina foi o ia i le mamalu ma le matagofie.", "and hast crowned him with glory and honour."]]},
  {num:6,words:[["Ua e foaiina ia te ia le pule i galuega a ou aao;", "Thou madest him to have dominion over the works of thy hands;"], ["ua e tuuina mea uma i lalo o ona vae;", "thou hast put all things under his feet:"]]},
  {num:7,words:[["o lafu mamoe ma povi uma lava,", "All sheep and oxen, yea,"], ["atoa ma manu vaefa o le vao;", "and the beasts of the field;"]]},
  {num:8,words:[["o manu felelei,", "The fowl of the air,"], ["ma i'a o le sami,", "and the fish of the sea,"], ["ua tataa i ala o le sami.", "and whatsoever passeth through the paths of the seas."]]},
  {num:9,words:[["Ieova e, lo matou Alii,", "O LORD our Lord,"], ["e silisili lava lou suafa i le lalolagi uma lava.", "how excellent is thy name in all the earth!"]]},
];
renderVerseSet(psa_ch_8_Verses, 'psa-ch8-verses');

var psa_ch_9_Verses = [
  {num:1,words:[["Ou te vivii atu ia te oe Ieova ma lo'u loto atoa;", "I will praise thee, O LORD,"], ["ou te ta'uta'u atu foi ou vavega uma.", "with my whole heart; I will shew forth all thy marvellous works."]]},
  {num:2,words:[["Ou te fiafia ma ou olioli ia te oe;", "I will be glad and rejoice in thee:"], ["ou te pese lava i lou suafa,", "I will sing praise to thy name,"], ["lē Silisili ese.", "O thou most High."]]},
  {num:3,words:[["Na liutuaina o e ua ita mai ia te au; ona tausuai ai lea o i latou,", "When mine enemies are turned back,"], ["ma fano lava ai ou luma.", "they shall fall and perish at thy presence."]]},
  {num:4,words:[["Auā ua e faia lo'u faamasinoga ma la'u finauga;", "For thou hast maintained my right and my cause;"], ["ua e tietie i le nofoālii e faamasino tonu ai.", "thou satest in the throne judging right."]]},
  {num:5,words:[["Ua e aoai atu i nuu ese;", "Thou hast rebuked the heathen,"], ["ua faaumatia e oe o e amio leaga,", "thou hast destroyed the wicked,"], ["ua e sōloiesea o latou igoa e oo i le faavavau faavavau lava.", "thou hast put out their name for ever and ever."]]},
  {num:6,words:[["O e ita mai,", "O thou enemy,"], ["ua faaumatia e faavavau o latou faatafunaga;", "destructions are come to a perpetual end:"], ["ua e olopalaina aai;", "and thou hast destroyed cities;"], ["ua gālo lava le faamanatuina o i latou.", "their memorial is perished with them."]]},
  {num:7,words:[["A o Ieova, e tietie lava ia e faavavau;", "But the LORD shall endure for ever:"], ["ua saunia e ia lona nofoālii e faamasino ai.", "he hath prepared his throne for judgment."]]},
  {num:8,words:[["O ia lava na te faamasinoina le atulaulau ma le tonu;", "And he shall judge the world in righteousness,"], ["na te faatonuina ma le sa'o finauga a nuu.", "he shall minister judgment to the people in uprightness."]]},
  {num:9,words:[["O Ieova e fai ma 'olo maualuga mo le ua faasauaina,", "The LORD also will be a refuge for the oppressed,"], ["o le 'olo maualuga i ona po e i ai le puapuaga.", "a refuge in times of trouble."]]},
  {num:10,words:[["E faatuatua ia te oe o e ua iloa lou suafa;", "And they that know thy name will put their trust in thee:"], ["auā,", "for thou,"], ["Ieova e,", "LORD,"], ["e te le tuuna i latou o e saili ia te oe.", "hast not forsaken them that seek thee."]]},
  {num:11,words:[["Ina pepese atu ia outou ia Ieova,", "Sing praises to the LORD,"], ["o loo afio i Siona;", "which dwelleth in Zion:"], ["ina faaali atu ia i nuu ana mea na fai.", "declare among the people his doings."]]},
  {num:12,words:[["Auā o lē taui i le toto na te manatua i latou;", "When he maketh inquisition for blood, he remembereth them:"], ["na te le faagalogaloina le tagi o e ua puapuagatia.", "he forgetteth not the cry of the humble."]]},
  {num:13,words:[["Ieova e,", "Have mercy upon me,"], ["ia e alofa mai ia te au,", "O LORD;"], ["ia e silasila mai i lo'u puapuaga na tupu mai i e ua 'ino'ino mai ia te au,", "consider my trouble which I suffer of them that hate me,"], ["o oe na o le ua aveina ae a'u ai faitotoa o le oti;", "thou that liftest me up from the gates of death:"]]},
  {num:14,words:[["ina ia ou ta'uta'u atu ou viiga uma i faitotoa o le tama fafine a Siona;", "That I may shew forth all thy praise in the gates of the daughter of Zion:"], ["ou te fiafia i lau faaolataga.", "I will rejoice in thy salvation."]]},
  {num:15,words:[["Ua gogoto nuu ese i le lua na latou faia;", "The heathen are sunk down in the pit that they made:"], ["o lea lava upega na natia e i latou ua lāvea ai o latou vae.", "in the net which they hid is their own foot taken."]]},
  {num:16,words:[["E iloa Ieova i le faamasinoga ua na faia;", "The LORD is known by the judgment which he executeth:"], ["ua maileia le fai amio leaga i le galuega a ona lava lima. Ikaiona. Selā.", "the wicked is snared in the work of his own hands. Higgaion. Selah."]]},
  {num:17,words:[["E tulia i seoli o e fai amio leaga,", "The wicked shall be turned into hell,"], ["o nuu uma lava o e faagalogalo i le Atua.", "and all the nations that forget God."]]},
  {num:18,words:[["Auā e le faagalogaloina e faavavau o e matitiva;", "For the needy shall not alway be forgotten:"], ["o le faamoemoega foi o e ua puapuagatia e le fano lea a le tu a le tu lava.", "the expectation of the poor shall not perish for ever."]]},
  {num:19,words:[["Ieova e,", "Arise,"], ["ina tulai mai ia,", "O LORD;"], ["aua ne'i manumalo tagata;", "let not man prevail:"], ["ia faamasinoina nuu ese i ou luma.", "let the heathen be judged in thy sight."]]},
  {num:20,words:[["Ieova e,", "Put them in fear,"], ["ia e faamatatau ia te i latou;", "O LORD:"], ["ia iloa e nuu ese o tagata lava i latou. Selā.", "that the nations may know themselves to be but men. Selah."]]},
];
renderVerseSet(psa_ch_9_Verses, 'psa-ch9-verses');

var psa_ch_10_Verses = [
  {num:1,words:[["Ieova e, se a le mea e te tūtūmamao ai,", "Why standest thou afar off,"], ["ma e liliu ese ai i ona po e i ai le puapuaga?", "O LORD? why hidest thou thyself in times of trouble?"]]},
  {num:2,words:[["O le faamaualuga o le tagata amio leaga ua ia matuā faasaua ai i e ua puapuagatia;", "The wicked in his pride doth persecute the poor:"], ["ua maua i latou i ia lava togafiti na latou manatua.", "let them be taken in the devices that they have imagined."]]},
  {num:3,words:[["Auā ua mitamita lē amio leaga i tu'inanau o lona loto;", "For the wicked boasteth of his heart's desire,"], ["o le ua matapeapea foi, ua faaamuia o ia e ia ,", "and blesseth the covetous,"], ["ua 'ino'ino ia Ieova.", "whom the LORD abhorreth."]]},
  {num:4,words:[["O le faasiasia o mata o le ua amio leaga e le saili ai o ia;", "The wicked,"], ["o ona mafaufau uma,", "through the pride of his countenance, will not seek after God:"], ["E leai se Atua.", "God is not in all his thoughts."]]},
  {num:5,words:[["Ua manuia ona ala e le aunoa;", "His ways are always grievous;"], ["ua mamao i luga ia te ia au faamasinoga;", "thy judgments are far above out of his sight: as for all his enemies,"], ["ua na ulafia i e ita ia te ia uma lava.", "he puffeth at them."]]},
  {num:6,words:[["Ua fai ifo ia i lona loto,", "He hath said in his heart,"], ["E le faagaeetia a'u;", "I shall not be moved:"], ["e le oo mai se mea leaga ia te au e faavavau.", "for I shall never be in adversity."]]},
  {num:7,words:[["Ua tumu lona gutu i le fetuu, ma le tau'ole'ole,", "His mouth is full of cursing and deceit and fraud:"], ["ma le saua; o loo i lalo o lona laulaufaiva le faatiga ma le amio leaga.", "under his tongue is mischief and vanity."]]},
  {num:8,words:[["Ua nofo ia i mea e lamalama ai i faoa aai,", "He sitteth in the lurking places of the villages:"], ["na te fasioti i mea lilo i e le sala;", "in the secret places doth he murder the innocent:"], ["ua lamalama ona mata i le ua tigaina.", "his eyes are privily set against the poor."]]},
  {num:9,words:[["Ua lamalama ia i le mea lilo,", "He lieth in wait secretly as a lion in his den:"], ["e pei o le leona i le mea e fale ai;", "he lieth in wait to catch the poor:"], ["ua lamalama ia ina ia puea e ia le ua puapuagaina; ua puea e ia o le ua puapuagaina,", "he doth catch the poor,"], ["i lona toso mai ia te ia i lana upega.", "when he draweth him into his net."]]},
  {num:10,words:[["Ua lafotuina ona ua momomo ua pauu foi e ua tigaina i lana 'au malosi.", "He croucheth, and humbleth himself, that the poor may fall by his strong ones."]]},
  {num:11,words:[["Ua fai ifo o ia i lona loto,", "He hath said in his heart,"], ["Ua galo i le Atua;", "God hath forgotten:"], ["ua 'alo ese ona fofoga;", "he hideth his face;"], ["na te le silafia e faavavau.", "he will never see it."]]},
  {num:12,words:[["Ieova e,", "Arise,"], ["ia e tulai mai;", "O LORD;"], ["le Atua e,", "O God,"], ["ina sii ia lou aao;", "lift up thine hand:"], ["aua ne'i galo ia te oe e ua puapuagaina.", "forget not the humble."]]},
  {num:13,words:[["Se a le mea ua 'ino'ino ai i le Atua le ua amio leaga? Ua fai ifo i lona loto,", "Wherefore doth the wicked contemn God? he hath said in his heart,"], ["E te le suesuea.", "Thou wilt not require it."]]},
  {num:14,words:[["Ua e silafia lava,", "Thou hast seen it;"], ["auā o oe lava,", "for thou beholdest mischief and spite,"], ["e te silasila i le tiga ma le ita, ina ia tuu atu ai i lou aao;", "to requite it with thy hand:"], ["o le ua tigaina e tuuina o ia e ia ia te oe;", "the poor committeth himself unto thee;"], ["o oe lava o le fesoasoani o le ua mātuaoti.", "thou art the helper of the fatherless."]]},
  {num:15,words:[["Ia e gagau le lima o lē fai amio leaga; o lē agaleaga foi,", "Break thou the arm of the wicked and the evil man:"], ["ia e suesue i lana amio leaga seia e le toe silafia.", "seek out his wickedness till thou find none."]]},
  {num:16,words:[["O Ieova o le Tupu ia e faavavau faavavau lava;", "The LORD is King for ever and ever:"], ["ua fano nuu ese nai lona laueleele.", "the heathen are perished out of his land."]]},
  {num:17,words:[["Ieova e,", "LORD,"], ["ua e faafofogaina le manao o e ua puapuagatia;", "thou hast heard the desire of the humble:"], ["e faamauina e oe o latou loto,", "thou wilt prepare their heart,"], ["ua liliu mai i ai ou fofoga;", "thou wilt cause thine ear to hear:"]]},
  {num:18,words:[["ina ia faamasino i le ua mātuaoti ma le ua faasauaina;", "To judge the fatherless and the oppressed,"], ["ina ia le toe faamatau mai le tagata ua tupu mai le eleele.", "that the man of the earth may no more oppress."]]},
];
renderVerseSet(psa_ch_10_Verses, 'psa-ch10-verses');

var psa_ch_11_Verses = [
  {num:1,words:[["Ou te faalagolago ia Ieova;", "In the LORD put I my trust:"], ["se a le mea tou te fai mai ai ia te au,", "how say ye to my soul,"], ["Ina sola ia e pei o le manulele i lo outou mauga?", "Flee as a bird to your mountain?"]]},
  {num:2,words:[["Auā,", "For,"], ["faauta,", "lo,"], ["o e fai amio leaga ua latou lolou le aufana,", "the wicked bend their bow,"], ["ua latou tuu le u i le fu'a,", "they make ready their arrow upon the string,"], ["e fana faalilolilo ai i e ua tonu o latou loto.", "that they may privily shoot at the upright in heart."]]},
  {num:3,words:[["Auā ua fulisia faavae;", "If the foundations be destroyed,"], ["se a se mea e mafai ai le tagata amiotonu ona fai?", "what can the righteous do?"]]},
  {num:4,words:[["O Ieova o i lona malumalu paia o ia;", "The LORD is in his holy temple,"], ["o Ieova o loo i le lagi lona nofoālii;", "the LORD'S throne is in heaven:"], ["e silasila mai ona fofoga,", "his eyes behold, his eyelids try,"], ["e tofotofo le fanau a tagata e ona laufofoga.", "the children of men."]]},
  {num:5,words:[["E tofotofo e Ieova i le ua amiotonu; a ua inosia e lona finagalo lē fai amio leaga,", "The LORD trieth the righteous:"], ["ma lē fiafia i le faasaua.", "but the wicked and him that loveth violence his soul hateth."]]},
  {num:6,words:[["E faatotō faaua mai e ia i luga o e fai amio leaga o mailei,", "Upon the wicked he shall rain snares,"], ["o le afi ma le teio,", "fire and brimstone,"], ["o le matagi foi e manunu ai;", "and an horrible tempest:"], ["o le tofi lea o la latou ipu.", "this shall be the portion of their cup."]]},
  {num:7,words:[["Auā o Ieova lē amiotonu e fiafia o ia i le amiotonu;", "For the righteous LORD loveth righteousness;"], ["e silasila ona fofoga i le ua amio sa'o.", "his countenance doth behold the upright."]]},
];
renderVerseSet(psa_ch_11_Verses, 'psa-ch11-verses');

var psa_ch_12_Verses = [
  {num:1,words:[["Ieova e,", "Help,"], ["ia e faaola mai;", "LORD;"], ["auā ua uma tagata amio Atua;", "for the godly man ceaseth;"], ["auā ua mavae e ua faamaoni nai le fanau a tagata.", "for the faithful fail from among the children of men."]]},
  {num:2,words:[["O loo tautalatala le tagata i le la te tuaoi i mea pepelo;", "They speak vanity every one with his neighbour:"], ["o loo o latou tautalatala i laugutu molemole ma le faalotolotolua.", "with flattering lips and with a double heart do they speak."]]},
  {num:3,words:[["E vavae ese e Ieova o laugutu molemole uma lava,", "The LORD shall cut off all flattering lips,"], ["ma le laulaufaiva e tautala i mea faasausili;", "and the tongue that speaketh proud things:"]]},
  {num:4,words:[["o e ua fai mai,", "Who have said,"], ["O tatou laulaufaiva tatou te manumalo ai,", "With our tongue will we prevail;"], ["o tatou laugutu o tatou lava ia;", "our lips are our own:"], ["o ai ea so tatou alii?", "who is lord over us?"]]},
  {num:5,words:[["Ona o le fasauaina o e ua puapuagatia,", "For the oppression of the poor,"], ["ma le feoi o e ua matitiva,", "for the sighing of the needy,"], ["ua fetalai mai ai Ieova,", "now will I arise,"], ["ou te tulai atu ai nei,", "saith the LORD;"], ["ou te faasaogalemuina i latou i e ua ulafia atu ia te i latou.", "I will set him in safety from him that puffeth at him."]]},
  {num:6,words:[["O afioga a Ieova o afioga mamā ia;", "The words of the LORD are pure words:"], ["ua se ario ua faate'a ese ai le eleele i le umu,", "as silver tried in a furnace of earth,"], ["e faafitu ona faamamāina.", "purified seven times."]]},
  {num:7,words:[["Ieova e,", "Thou shalt keep them,"], ["o oe lava e te tausi ia te i latou;", "O LORD,"], ["e te leoleo ia te ia mai lenei lava tupulaga e oo i le faavavau.", "thou shalt preserve them from this generation for ever."]]},
  {num:8,words:[["Ua feoai i lea itu ma lea itu o e fai amio leaga,", "The wicked walk on every side,"], ["ina ua faaeaina o le ua sili lona ulavale i le fanau a tagata.", "when the vilest men are exalted."]]},
];
renderVerseSet(psa_ch_12_Verses, 'psa-ch12-verses');

var psa_ch_13_Verses = [
  {num:1,words:[["Ieova e,", "How long wilt thou forget me,"], ["e te faagalogalo pea lava ia te au seia afea? E te 'alo ou fofoga ia te au seia afea?", "O LORD? for ever? how long wilt thou hide thy face from me?"]]},
  {num:2,words:[["Ou te filifili a'u ma le faanoanoa i lo'u loto i aso uma seia afea? E faamaualugaina e sili ia te au le ua ita mai ia te au seia afea?", "How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?"]]},
  {num:3,words:[["Ieova e lo'u Atua,", "Consider and hear me,"], ["ia e silasila mai ma tali mai ia te au;", "O LORD my God:"], ["ia e faamalamalamaina o'u mata,", "lighten mine eyes,"], ["ne'i ou moe i le oti;", "lest I sleep the sleep of death;"]]},
  {num:4,words:[["ne'i fai ane le ua ita mai ia te au,", "Lest mine enemy say,"], ["Ua ou manumalo ia te ia; ne'i mitamita e ua saua mai ia te au,", "I have prevailed against him;"], ["pe a faagaeetia o a'u.", "and those that trouble me rejoice when I am moved."]]},
  {num:5,words:[["A o a'u ne'i, ou te faatuatua i lou alofa,", "But I have trusted in thy mercy;"], ["e fiafia lo'u loto i lau faaolataga.", "my heart shall rejoice in thy salvation."]]},
  {num:6,words:[["Ou te pese atu ia Ieova,", "I will sing unto the LORD,"], ["auā ua agalelei mai o ia ia te au.", "because he hath dealt bountifully with me."]]},
];
renderVerseSet(psa_ch_13_Verses, 'psa-ch13-verses');

var psa_ch_14_Verses = [
  {num:1,words:[["Ua fai ifo le tagata valea i lona loto,", "The fool hath said in his heart,"], ["E leai se Atua. Ua leaga lava i latou;", "There is no God. They are corrupt,"], ["ua inosia a latou amioga;", "they have done abominable works,"], ["e leai se tasi ua amio lelei.", "there is none that doeth good."]]},
  {num:2,words:[["O loo silasila mai Ieova mai le lagi i le fanau a tagata,", "The LORD looked down from heaven upon the children of men,"], ["ina ia silafia pe i ai se tasi ua poto,", "to see if there were any that did understand,"], ["se ua saili i le Atua.", "and seek God."]]},
  {num:3,words:[["Ua latou 'alo'alo ese uma lava,", "They are all gone aside,"], ["ua leaga faatasi i latou;", "they are all together become filthy:"], ["e leai se tasi ua amio lelei,", "there is none that doeth good, no,"], ["e leai lava se tasi.", "not one."]]},
  {num:4,words:[["E le o iloa ea e i latou uma lava o e fai amio leaga? O loo 'aina e i latou lo'u nuu, e pei ona latou aai i mea e 'ai;", "Have all the workers of iniquity no knowledge? who eat up my people as they eat bread,"], ["ua latou le valaau ia Ieova.", "and call not upon the LORD."]]},
  {num:5,words:[["Ua matatau tele i latou i lea mea;", "There were they in great fear:"], ["auā o i le tupulaga o e amiotonu le Atua.", "for God is in the generation of the righteous."]]},
  {num:6,words:[["Ua outou faamaina le filifiliga a le ua puapuagaina;", "Ye have shamed the counsel of the poor,"], ["auā o lona malu o Ieova lea.", "because the LORD is his refuge."]]},
  {num:7,words:[["E! Fia iloa se na te aumaia mai Siona le faaolataga o Isaraelu. Pe a faafoisia mai e Ieova le tafeaga a lona nuu,", "Oh that the salvation of Israel were come out of Zion! when the LORD bringeth back the captivity of his people,"], ["ona olioli ai lea o Iakopo,", "Jacob shall rejoice,"], ["e fiafia ai Isaraelu.", "and Israel shall be glad."]]},
];
renderVerseSet(psa_ch_14_Verses, 'psa-ch14-verses');

var psa_ch_15_Verses = [
  {num:1,words:[["Ieova e,", "LORD,"], ["o ai ea e nofo i lou fale fetafai? O ai ea e mau i lou mauga paia?", "who shall abide in thy tabernacle? who shall dwell in thy holy hill?"]]},
  {num:2,words:[["O le savali ma le amio sao,", "He that walketh uprightly,"], ["ma ua fai le amiotonu,", "and worketh righteousness,"], ["ma tautala ma le faamaoni i lona loto.", "and speaketh the truth in his heart."]]},
  {num:3,words:[["O le ua le tuua'i fua i lona laulaufaiva,", "He that backbiteth not with his tongue,"], ["ua le agaleaga i le la te tuaoi,", "nor doeth evil to his neighbour,"], ["e le faatupu foi se mea e faalumaina ai le ua lata mai ia te ia.", "nor taketh up a reproach against his neighbour."]]},
  {num:4,words:[["O loo inosia e ia le ua leaga,", "In whose eyes a vile person is contemned;"], ["a e viia e ia o e matatau ia Ieova; e tauto ia i le mea e tiga ai o ia,", "but he honoureth them that fear the LORD. He that sweareth to his own hurt,"], ["a e le 'alo ai.", "and changeth not."]]},
  {num:5,words:[["Ua le avane e ia ana tupe e fai ai taui faasili;", "He that putteth not out his money to usury,"], ["e le talia e ia se meaalofa e faasala ai le ua le sala. O le ua faia ia mea e le faagaeetia lava ia e faavavau.", "nor taketh reward against the innocent. He that doeth these things shall never be moved."]]},
];
renderVerseSet(psa_ch_15_Verses, 'psa-ch15-verses');

var psa_ch_16_Verses = [
  {num:1,words:[["Le Atua e,", "Preserve me,"], ["ia e leoleo mai ia te au;", "O God:"], ["auā ou te faatuatua ia te oe.", "for in thee do I put my trust."]]},
  {num:2,words:[["Lo'u agaga e ,", "O my soul,"], ["ua e fai atu ia Ieova,", "thou hast said unto the LORD,"], ["O oe lava o lo'u Alii;", "Thou art my Lord:"], ["o lo'u manuia e le aunoa lea ma oe;", "my goodness extendeth not to thee;"]]},
  {num:3,words:[["o tagata paia,", "But to the saints that are in the earth,"], ["o i latou lava o i le lalolagi, ma e ua sili ona lelei,", "and to the excellent,"], ["o loo ia te i latou lo'u fiafia uma.", "in whom is all my delight."]]},
  {num:4,words:[["E faateleina o latou tiga o e vave o atu i se tasi;", "Their sorrows shall be multiplied that hasten after another god:"], ["o a latou taulaga i mea e inu ua faia i le toto ou te le sasaaina,", "their drink offerings of blood will I not offer,"], ["ma o latou igoa ou te le ta'ua i o'u laugutu.", "nor take up their names into my lips."]]},
  {num:5,words:[["O Ieova o lo'u tofi lava ia ma la'u ipu;", "The LORD is the portion of mine inheritance and of my cup:"], ["o oe lava e faamauina lo'u tofi.", "thou maintainest my lot."]]},
  {num:6,words:[["Ua fuafuaina mo'u le fanua i mea valevalenoa;", "The lines are fallen unto me in pleasant places;"], ["e moni,", "yea,"], ["ua ia te au le tofi matagofie.", "I have a goodly heritage."]]},
  {num:7,words:[["Ou te faamanū atu ia Ieova,", "I will bless the LORD,"], ["o lē faatonu mai ia te au;", "who hath given me counsel:"], ["o le po foi e a'oa'o mai ai ia te au o lo'u mafaufau.", "my reins also instruct me in the night seasons."]]},
  {num:8,words:[["Ou te tuu Ieova i o'u luma e le aunoa;", "I have set the LORD always before me:"], ["auā o i lo'u itu taumatau o ia,", "because he is at my right hand,"], ["e le faagaeetia ai lava a'u.", "I shall not be moved."]]},
  {num:9,words:[["O le mea lea e fiafia ai lo'u loto,", "Therefore my heart is glad,"], ["ma olioli ai lo'u mamalu;", "and my glory rejoiceth:"], ["e malolo foi lo'u tino ma le saogalemu.", "my flesh also shall rest in hope."]]},
  {num:10,words:[["Auā e te le tuua a'u i le tuugamau;", "For thou wilt not leave my soul in hell;"], ["e te le tuu atu lou tagata paia ia oo i ai le pala.", "neither wilt thou suffer thine Holy One to see corruption."]]},
  {num:11,words:[["E te faailoa mai ia te au le ala o le ola;", "Thou wilt shew me the path of life:"], ["o i ou luma le fiafia e mālie ai;", "in thy presence is fulness of joy;"], ["o i lou itu taumatau le olioli e faavavau.", "at thy right hand there are pleasures for evermore."]]},
];
renderVerseSet(psa_ch_16_Verses, 'psa-ch16-verses');

var psa_ch_17_Verses = [
  {num:1,words:[["Ieova e,", "Hear the right,"], ["ia e faafofoga mai i le amiotonu,", "O LORD,"], ["ia e liliu mai i la'u alaga;", "attend unto my cry, give ear unto my prayer,"], ["ia e faafofoga mai i la'u tatalo e le faia i laugutu 'ole'ole.", "that goeth not out of feigned lips."]]},
  {num:2,words:[["Ia oo mai lo'u faamasinoga mai ou luma;", "Let my sentence come forth from thy presence;"], ["ia silasila mai ou fofoga i le amio sa'o.", "let thine eyes behold the things that are equal."]]},
  {num:3,words:[["Ua uma ona e tofotofoina lo'u loto;", "Thou hast proved mine heart;"], ["ua e asiasia mai i le po;", "thou hast visited me in the night;"], ["ua uma ona e suesue mai ia te au,", "thou hast tried me,"], ["a ua leai se mea na e maua;", "and shalt find nothing;"], ["o lo'u manatu e le agasala lo'u gutu.", "I am purposed that my mouth shall not transgress."]]},
  {num:4,words:[["A o mea e faia e tagata,", "Concerning the works of men,"], ["o afioga mai lou fofoga na ou tausia ai a'u ne'i ui i ala o le ua saua.", "by the word of thy lips I have kept me from the paths of the destroyer."]]},
  {num:5,words:[["Ia e taofi ae lo'u savali i ou ala,", "Hold up my goings in thy paths,"], ["ina ne'i le mau o'u vae.", "that my footsteps slip not."]]},
  {num:6,words:[["Le Atua e,", "I have called upon thee,"], ["ou te valaau atu ia te oe;", "for thou wilt hear me,"], ["auā e te faafofoga mai ia te au;", "O God:"], ["ia e liliu mai ou fofoga ia te au,", "incline thine ear unto me,"], ["ia e faafofoga mai i a'u upu.", "and hear my speech."]]},
  {num:7,words:[["Ia iloga mai lou alofa,", "Shew thy marvellous lovingkindness,"], ["o oe le faaola o e faatuatua ia te oe i e tautetee i lou aao taumatau.", "O thou that savest by thy right hand them which put their trust in thee from those that rise up against them."]]},
  {num:8,words:[["Ia e leoleo mai ia te au e pei o le tamatamai mata;", "Keep me as the apple of the eye,"], ["ia e natia a'u i le paolo o ou apaau,", "hide me under the shadow of thy wings,"]]},
  {num:9,words:[["i luma o e amio leaga,", "From the wicked that oppress me,"], ["o e faasaua mai ia te au, o e ita mai ia te au,", "from my deadly enemies,"], ["o e siosio ia te au ia a'u oti.", "who compass me about."]]},
  {num:10,words:[["Ua puputa lava o latou tino;", "They are inclosed in their own fat:"], ["o loo tautalatala faasausili o latou gutu.", "with their mouth they speak proudly."]]},
  {num:11,words:[["O lenei, ua latou siosiomia i matou o matou o savavali;", "They have now compassed us in our steps:"], ["ua vaai o latou mata ua punou ifo i le eleele.", "they have set their eyes bowing down to the earth;"]]},
  {num:12,words:[["E tusa ma le leona ua naunau i le fia saei o manu ,", "Like as a lion that is greedy of his prey,"], ["po ua faapei o le leona taanoa ua nofo i mea lilo.", "and as it were a young lion lurking in secret places."]]},
  {num:13,words:[["Ieova e,", "Arise,"], ["ia e tulai mai;", "O LORD,"], ["ia e muamua atu ia te ia,", "disappoint him, cast him down:"], ["ia e lafo ia te ia i lalo;", "deliver my soul from the wicked,"], ["ia e laveai mai ia te au i lau pelu ai tagata amio leaga;", "which is thy sword:"]]},
  {num:14,words:[["Ieova e ia e laveai mai ia te au i lou aao ai tagata o tagata o le lalolagi,", "From men which are thy hand,"], ["ua i le ola nei lo latou tofi,", "O LORD, from men of the world,"], ["ua e faamaoonaina i latou i au mea lelei;", "which have their portion in this life,"], ["ua malilie i latou i fanau;", "and whose belly thou fillest with thy hid treasure: they are full of children,"], ["o a latou mea foi o totoe ua tuu lava ia mā o latou tama iti.", "and leave the rest of their substance to their babes."]]},
  {num:15,words:[["A o a'u,", "As for me, I will behold thy face in righteousness:"], ["ou te vaavaai i ou fofoga i le amiotonu;", "I shall be satisfied,"], ["ou te mălie pe a a'u ala ua foliga ia te oe.", "when I awake, with thy likeness."]]},
];
renderVerseSet(psa_ch_17_Verses, 'psa-ch17-verses');

var psa_ch_18_Verses = [
  {num:1,words:[["Ieova e,", "I will love thee,"], ["lo'u malosi,", "O LORD,"], ["ou te alofa lava ia te oe.", "my strength."]]},
  {num:2,words:[["O Ieova o lo'u papa ia,", "The LORD is my rock,"], ["ma lo'u 'olo,", "and my fortress,"], ["ma lo'u faaola;", "and my deliverer;"], ["o lo'u Atua,", "my God,"], ["o lo'u papa,", "my strength,"], ["ou te faatuatua ia te ia;", "in whom I will trust;"], ["o lo'u talita,", "my buckler,"], ["ma le nifo o lo'u olataga,", "and the horn of my salvation,"], ["o lo'u 'olo maualuga.", "and my high tower."]]},
  {num:3,words:[["Ou te valaau ia Ieova,", "I will call upon the LORD,"], ["e tatau ona viia o ia;", "who is worthy to be praised:"], ["o lea e faaolaina ai a'u i e ua ita mai ia te au.", "so shall I be saved from mine enemies."]]},
  {num:4,words:[["Na siosiomia a'u i mailei e oti ai,", "The sorrows of death compassed me,"], ["na faamatautia foi a'u i tafega a e ulavavale.", "and the floods of ungodly men made me afraid."]]},
  {num:5,words:[["Na siomia a'u i mailei a seoli;", "The sorrows of hell compassed me about:"], ["na ou lumanai o matāsele a le oti.", "the snares of death prevented me."]]},
  {num:6,words:[["Ona ou valaau atu ai lea ia Ieova i lo'u puapuaga,", "In my distress I called upon the LORD,"], ["ma ou alaga atu i lo'u Atua;", "and cried unto my God:"], ["na faafofoga mai o ia i lona malumalu i lo'u leo,", "he heard my voice out of his temple, and my cry came before him,"], ["na oo atu ia te ia la'u alaga i ona lava fofoga.", "even into his ears."]]},
  {num:7,words:[["Ona luluina ai lea ma mafuie le lalolagi;", "Then the earth shook and trembled;"], ["ua gatete foi faavae o mauga, ua luluina i latou,", "the foundations also of the hills moved and were shaken,"], ["auā na toasa lava o ia.", "because he was wroth."]]},
  {num:8,words:[["Ua alu ae le asu i on pogaiisu;", "There went up a smoke out of his nostrils,"], ["o le afi mai lona fofoga ua maamaai lea;", "and fire out of his mouth devoured:"], ["ua mu ai malala ola.", "coals were kindled by it."]]},
  {num:9,words:[["Na lolou ifo e ia lagi ma afio ifo;", "He bowed the heavens also, and came down:"], ["o le pogisa foi sa i lalo o ona aao.", "and darkness was under his feet."]]},
  {num:10,words:[["Na tietie ia i le kerupi,", "And he rode upon a cherub,"], ["ma ua lele;", "and did fly: yea,"], ["na lele ia i apaau o le matagi.", "he did fly upon the wings of the wind."]]},
  {num:11,words:[["Na faia e ia o le pouliuli ma mea e lilo ai o ia; o lona apitaga ua siomia ai o ia,", "He made darkness his secret place;"], ["o le vai pouliuli, o ao uliuli o le lagi.", "his pavilion round about him were dark waters and thick clouds of the skies."]]},
  {num:12,words:[["Na mavae ese atu o ana ao ona o le pupula na i ona luma;", "At the brightness that was before him his thick clouds passed,"], ["o uato'a ma malala ola o le afi.", "hail stones and coals of fire."]]},
  {num:13,words:[["Na faititili foi Ieova mai le lagi,", "The LORD also thundered in the heavens,"], ["na tŭlei ifo e le Silisili ese o lona siufofoga;", "and the Highest gave his voice;"], ["o uato'a ma malala ola o le afi.", "hail stones and coals of fire."]]},
  {num:14,words:[["Na fana atu e ia ana u fanafana,", "Yea,"], ["ma faataapeape ia te i latou;", "he sent out his arrows,"], ["ma ana uila e tele,", "and scattered them; and he shot out lightnings,"], ["ua tuli ai ia te i latou.", "and discomfited them."]]},
  {num:15,words:[["Ona iloa atu ai lea o iliti vai,", "Then the channels of waters were seen,"], ["ua aliali mai o faavae o le lalolagi i lau aoaiga,", "and the foundations of the world were discovered at thy rebuke,"], ["Ieova e,", "O LORD,"], ["o le mapugatamai o ou fofoga.", "at the blast of the breath of thy nostrils."]]},
  {num:16,words:[["Ua ia aapa mai lona aao mai luga,", "He sent from above,"], ["ma tago ia te ua,", "he took me,"], ["ua ia faaea ia te au ai vai e tele.", "he drew me out of many waters."]]},
  {num:17,words:[["Ua ia laveai mai ia te au ai le tagata malosi na ita mai,", "He delivered me from my strong enemy,"], ["ma e na 'ino'ino ia te au;", "and from them which hated me:"], ["auā na sili lo latou malosi i lo'u.", "for they were too strong for me."]]},
  {num:18,words:[["Na latou lumanai a'u i le aso o lo'u malaia; a o Ieova,", "They prevented me in the day of my calamity:"], ["o ia na ou faalagolago i ai.", "but the LORD was my stay."]]},
  {num:19,words:[["Ua ia aumaia a'u i le mea lautele;", "He brought me forth also into a large place;"], ["ua ia laveai ia te au,", "he delivered me,"], ["auā ua finagalo alofa mai o ia ia te au.", "because he delighted in me."]]},
  {num:20,words:[["Ua tauia mai a'u e Ieova e tusa ma la'u amiotonu;", "The LORD rewarded me according to my righteousness;"], ["ua taui mai e ia ia te au e tusa ma o'u lima mamā.", "according to the cleanness of my hands hath he recompensed me."]]},
  {num:21,words:[["Auā ua ou tausia ala o Ieova,", "For I have kept the ways of the LORD,"], ["ma a'u le lafoai faalematau i lo'u Atua.", "and have not wickedly departed from my God."]]},
  {num:22,words:[["Auā ua ou lumanai pea ana faamasinoga uma;", "For all his judgments were before me,"], ["na ou le tuueseina foi ana tulafono ia te au.", "and I did not put away his statutes from me."]]},
  {num:23,words:[["Na ou amiotonu i ona luma,", "I was also upright before him,"], ["na ou taofia a'u ina ne'i o'u agasala.", "and I kept myself from mine iniquity."]]},
  {num:24,words:[["O lenei, ua tauia a'u e Ieova e tusa ma la'u amiotonu,", "Therefore hath the LORD recompensed me according to my righteousness,"], ["e tusa ma o'u lima mamā i ona luma.", "according to the cleanness of my hands in his eyesight."]]},
  {num:25,words:[["E te amio alofa oe i le ua alofa;", "With the merciful thou wilt shew thyself merciful;"], ["e te amiotonu oe i le tagata amiotonu.", "with an upright man thou wilt shew thyself upright;"]]},
  {num:26,words:[["E te amio mamā oe i le ua amio mamā;", "With the pure thou wilt shew thyself pure;"], ["e te faapiopio foi oe i le ua faapiopio.", "and with the froward thou wilt shew thyself froward."]]},
  {num:27,words:[["Auā o oe lava, e te faaolaina le nuu ua tigaina;", "For thou wilt save the afflicted people;"], ["a o e ua mata faasiasia, e te faamaualaloina i latou.", "but wilt bring down high looks."]]},
  {num:28,words:[["Auā foi e te tutu mai la'u lamepa;", "For thou wilt light my candle:"], ["e faamalamalamaina lo'u pouliuli e Ieova lo'u Atua.", "the LORD my God will enlighten my darkness."]]},
  {num:29,words:[["Auā o oe na ou sofai ai le 'au;", "For by thee I have run through a troop;"], ["o lo'u Atua na ou osopuna ai i le pa.", "and by my God have I leaped over a wall."]]},
  {num:30,words:[["O le Atua,", "As for God,"], ["e sao lava lona ala;", "his way is perfect:"], ["ua se ario ua te'a ma le otaota afioga a Ieova;", "the word of the LORD is tried:"], ["o ia lava o le talta o i latou uma o e faatuatua ia te ia.", "he is a buckler to all those that trust in him."]]},
  {num:31,words:[["Auā o ai ea le Atua, ua na o Ieova? O ai ea le papa, ua na o lo tatou Atua?", "For who is God save the LORD? or who is a rock save our God?"]]},
  {num:32,words:[["O le Atua lea o loo fusia a'u i le malosi,", "It is God that girdeth me with strength,"], ["ua ia faalaulelei foi i lo'u ala.", "and maketh my way perfect."]]},
  {num:33,words:[["Ua na faia o'u vae ia pei o vae o aila;", "He maketh my feet like hinds' feet,"], ["ua ia faatuina lava a'u i a'u mea maualuga.", "and setteth me upon my high places."]]},
  {num:34,words:[["Ua ia a'oa'o i o'u lima e tau ai le taua;", "He teacheth my hands to war,"], ["ua lolou ai e o'u lima le aufana 'apa memea.", "so that a bow of steel is broken by mine arms."]]},
  {num:35,words:[["Ua e foaiina foi ia te au le talita o le olataga mai ia te oe;", "Thou hast also given me the shield of thy salvation:"], ["ua faatumauina a'u e lou aao taumatau;", "and thy right hand hath holden me up,"], ["o lou agamalu ua faasilisiliina ai a'u.", "and thy gentleness hath made me great."]]},
  {num:36,words:[["Ua faalauteleina e oe le mea ou te savali ai,", "Thou hast enlarged my steps under me,"], ["ne'i mapeva o'u vae.", "that my feet did not slip."]]},
  {num:37,words:[["Na ou tuliloa i e na fai a'u mo latou fili,", "I have pursued mine enemies,"], ["ma ou maua; na ou faaumatia i latou,", "and overtaken them:"], ["ona ou faatoa foi mai lea.", "neither did I turn again till they were consumed."]]},
  {num:38,words:[["Na ou fāsia i latou, ua latou le mafaia ona tutū i luga;", "I have wounded them that they were not able to rise:"], ["na pauu i latou i lalo o o'u vae.", "they are fallen under my feet."]]},
  {num:39,words:[["Ua e fusia a'u i le malosi mo le taua;", "For thou hast girded me with strength unto the battle:"], ["ua e faatoilalo i e na laga mai ia te au.", "thou hast subdued under me those that rose up against me."]]},
  {num:40,words:[["O oe ua liutuaina mai ai ia te au o e ua fai a'u mo latou fili;", "Thou hast also given me the necks of mine enemies;"], ["ua fano foi ia te au o e na 'ino'ino mai ia te au.", "that I might destroy them that hate me."]]},
  {num:41,words:[["Na alalaga i latou,", "They cried,"], ["a ua leai se faaola;", "but there was none to save them:"], ["na alalaga i latou ia Ieova,", "even unto the LORD,"], ["a ua na le tali atu ia te i latou.", "but he answered them not."]]},
  {num:42,words:[["Ona ou nutininii lea ia te i latou, e pei o le efuefu ona lelea i le matagi;", "Then did I beat them small as the dust before the wind:"], ["na ou sasaaina atu i latou e pei o le palapala i le ala.", "I did cast them out as the dirt in the streets."]]},
  {num:43,words:[["Na e laveai ia te au ai fefinauaiga ma le nuu;", "Thou hast delivered me from the strivings of the people;"], ["ua e tofia a'u ia ou pule i nuu ese;", "and thou hast made me the head of the heathen:"], ["e anauna mai ia te au le nuu na ou le iloa.", "a people whom I have not known shall serve me."]]},
  {num:44,words:[["A latou lagona,", "As soon as they hear of me,"], ["ona latou faalogo ai lea ia te au;", "they shall obey me:"], ["e faatagā vivii mai ia te au tagata ese.", "the strangers shall submit themselves unto me."]]},
  {num:45,words:[["E mavae atu tagata ese;", "The strangers shall fade away,"], ["e tetemu i latou i mea ua latou puipuia mo i latou.", "and be afraid out of their close places."]]},
  {num:46,words:[["O loo soifua Ieova,", "The LORD liveth;"], ["ia faafetaia foi lo'u papa;", "and blessed be my rock;"], ["ma ia viia le Atua o lo'u faaolataga.", "and let the God of my salvation be exalted."]]},
  {num:47,words:[["O le Atua lea o loo faia le taui ma sui mo a'u;", "It is God that avengeth me,"], ["o le ua faatoilaloina foi le nuu ia te au.", "and subdueth the people under me."]]},
  {num:48,words:[["O le ua laveaiina a'u i e ua ita mai ia te au;", "He delivereth me from mine enemies:"], ["ua e faasilisiliina foi a'u i e na laga mai ia te au;", "yea, thou liftest me up above those that rise up against me:"], ["ua e laveaiina a'u i le tagata faasaua.", "thou hast delivered me from the violent man."]]},
  {num:49,words:[["O le mea lava lea,", "Therefore will I give thanks unto thee,"], ["Ieova e,", "O LORD,"], ["ou te vivii atu ai ia te oe i luma o nuu ese;", "among the heathen,"], ["ou te pese atu foi i lou suafa.", "and sing praises unto thy name."]]},
  {num:50,words:[["O le ua faia o le olataga tele i lana tupu;", "Great deliverance giveth he to his king;"], ["e agalelei foi o ia i le na ia faauuina,", "and sheweth mercy to his anointed,"], ["o Tavita lava lea,", "to David,"], ["atoa ma lana fanau e oo i le faavavau.", "and to his seed for evermore."]]},
];
renderVerseSet(psa_ch_18_Verses, 'psa-ch18-verses');

var psa_ch_19_Verses = [
  {num:1,words:[["Ua tala mai e le lagi le mamalu o le Atua;", "The heavens declare the glory of God;"], ["ua faaalia foi e le va nimonimo le galuega a ona aao.", "and the firmament sheweth his handywork."]]},
  {num:2,words:[["O loo ta'u atu le upu e le tasi aso i le tasi aso,", "Day unto day uttereth speech,"], ["o loo faailoa foi le poto e le tasi po i le tasi po.", "and night unto night sheweth knowledge."]]},
  {num:3,words:[["E leai se gagana, e leai foi ni upu,", "There is no speech nor language,"], ["e le lagona o latou leo.", "where their voice is not heard."]]},
  {num:4,words:[["Ua oo atu lo latou leo i le lalolagi uma lava,", "Their line is gone out through all the earth,"], ["ma a latou upu i tuluiga o le atu laulau. Ua na tuu i ai le fale ie mo le la;", "and their words to the end of the world. In them hath he set a tabernacle for the sun,"]]},
  {num:5,words:[["o ia foi, e faapei o se faatoafaiavā ua sau mai lona afeafe;", "Which is as a bridegroom coming out of his chamber,"], ["e fiafia o ia e pei o se tagata fitafita e tamo'e i le ala.", "and rejoiceth as a strong man to run a race."]]},
  {num:6,words:[["O lona alu atu,", "His going forth is from the end of the heaven,"], ["mai le tasi tuluiga o le lagi lea, ua oo foi lana faataamilosaga i le tasi ona tuluiga;", "and his circuit unto the ends of it:"], ["e leai foi se mea e lilo i lona vevela.", "and there is nothing hid from the heat thereof."]]},
  {num:7,words:[["E sao le tulafono a Ieova,", "The law of the LORD is perfect,"], ["e faafoisia mai ai le agaga;", "converting the soul:"], ["e faamaoni poloaiga a Ieova,", "the testimony of the LORD is sure,"], ["e faapotoina ai le ua faigofie.", "making wise the simple."]]},
  {num:8,words:[["E tonu feau a Ieova,", "The statutes of the LORD are right,"], ["e faafiafia ai le loto;", "rejoicing the heart:"], ["e mamā poloaiga a Ieova,", "the commandment of the LORD is pure,"], ["e malamalama ai mata.", "enlightening the eyes."]]},
  {num:9,words:[["E mamā le mata'u ia Ieova,", "The fear of the LORD is clean,"], ["e tumau e faavavau;", "enduring for ever:"], ["o faamasinoga foi a Ieova e moni ia ma tonu uma lava.", "the judgments of the LORD are true and righteous altogether."]]},
  {num:10,words:[["E silisili ona lelei i le auro,", "More to be desired are they than gold,"], ["o le auro e sili ona lelei e tele;", "yea,"], ["e sili foi ona suamalie i lo le meli,", "than much fine gold:"], ["o le meli ua sisina ifo.", "sweeter also than honey and the honeycomb."]]},
  {num:11,words:[["Ua apoapoaiina mai ai foi lau auauna;", "Moreover by them is thy servant warned:"], ["e tele foi le taui pe a tausi i ai.", "and in keeping of them there is great reward."]]},
  {num:12,words:[["O ai ea na te iloa amio sese? Ia e faamagalo ia te au i agasala lilo.", "Who can understand his errors? cleanse thou me from secret faults."]]},
  {num:13,words:[["Ia e taofi foi i lau auauna i agasala faamaualuga;", "Keep back thy servant also from presumptuous sins;"], ["aua ne'i pule ia ia te au ona sao ai lea o la'u amio,", "let them not have dominion over me: then shall I be upright,"], ["ou te le nofo sala foi i le leaga sili.", "and I shall be innocent from the great transgression."]]},
  {num:14,words:[["Ia mālie foi ia te oe upu a lo'u gutu,", "Let the words of my mouth, and the meditation of my heart,"], ["ma mafaufauga o lo'u loto,", "be acceptable in thy sight,"], ["Ieova e,", "O LORD,"], ["lo'u papa ma le na te togiolaina a'u.", "my strength, and my redeemer."]]},
];
renderVerseSet(psa_ch_19_Verses, 'psa-ch19-verses');

var psa_ch_20_Verses = [
  {num:1,words:[["Ia faafofoga mai Ieova ia te oe i le aso o le puapuaga,", "The LORD hear thee in the day of trouble;"], ["ia faamamaluina oe i le suafa o le Atua o Iakopo.", "the name of the God of Jacob defend thee;"]]},
  {num:2,words:[["Ia tuuina atu e ia ia te oe o le fesoasoani mai le malumalu,", "Send thee help from the sanctuary,"], ["ma ia lagolagoina oe e ia mai Siona.", "and strengthen thee out of Zion;"]]},
  {num:3,words:[["Ia manatua e ia au taulaga uma i mea e 'ai,", "Remember all thy offerings, and accept thy burnt sacrifice;"], ["ia talia foi au taulaga mu. Selā.", "Selah."]]},
  {num:4,words:[["Ia foaiina e ia ia te oe e tusa ma lou lava loto,", "Grant thee according to thine own heart,"], ["ma ia faataunuuina lau pule uma lava.", "and fulfil all thy counsel."]]},
  {num:5,words:[["Matou te fiafia i lau faaolataga;", "We will rejoice in thy salvation,"], ["o le suafa foi o lo tatou Atua tatou te sii ai i luga o tatou tagavai;", "and in the name of our God we will set up our banners:"], ["ia faataunuuina e Ieova au tatalo uma lava.", "the LORD fulfil all thy petitions."]]},
  {num:6,words:[["O lenei, ua ou iloa e faaolaina e Ieova o le na ia faauuina;", "Now know I that the LORD saveth his anointed;"], ["e tali mai o ia ia te ia ai lona lagi paia i le malosi o lona aao taumatau e ola ai.", "he will hear him from his holy heaven with the saving strength of his right hand."]]},
  {num:7,words:[["O loo ta'uta'u nisi i kariota,", "Some trust in chariots,"], ["ma nisi i solofanua;", "and some in horses:"], ["a o i tatou ua tatou ta'uta'u le suafa o Ieova lo tatou Atua.", "but we will remember the name of the LORD our God."]]},
  {num:8,words:[["E punonou i latou,", "They are brought down and fallen:"], ["ma latou pauu; a o i tatou,", "but we are risen,"], ["tatou te tutū i luga ma tutumau.", "and stand upright."]]},
  {num:9,words:[["Ieova e,", "Save,"], ["ia e faaola mai;", "LORD:"], ["ia faafofoga mai le Tupu ia te i matou i le aso matou te valaau atu ai.", "let the king hear us when we call."]]},
];
renderVerseSet(psa_ch_20_Verses, 'psa-ch20-verses');

var psa_ch_21_Verses = [
  {num:1,words:[["Ieova e,", "The king shall joy in thy strength,"], ["e olioli le tupu i lou malosi;", "O LORD;"], ["e matuā fiafia lava ia i lau faaolataga.", "and in thy salvation how greatly shall he rejoice!"]]},
  {num:2,words:[["Ua e foaiina ia te ia le manao o lona loto;", "Thou hast given him his heart's desire,"], ["ua e le faafiti foi ia te ia le mea na ole atu ai ona laugutu. Selā.", "and hast not withholden the request of his lips. Selah."]]},
  {num:3,words:[["Auā ua tomua mai ia te ia le manuia silisili mai ia te oe;", "For thou preventest him with the blessings of goodness:"], ["ua e faaee i lona ao le palealii auro lelei.", "thou settest a crown of pure gold on his head."]]},
  {num:4,words:[["Na ia faatogaina atu ia te oe ina ia ola,", "He asked life of thee, and thou gavest it him,"], ["ona e foaiina mai ai lea ia te ia o le ola tulu'i faavavau faavavau lava.", "even length of days for ever and ever."]]},
  {num:5,words:[["Ua tele lava lona mamalu i lau faaolataga;", "His glory is great in thy salvation:"], ["ua e faaeetia i ona luga le viiga ma le matagofie.", "honour and majesty hast thou laid upon him."]]},
  {num:6,words:[["Auā ua e tuuina ia te ia le manuia e oo i le faavavau;", "For thou hast made him most blessed for ever:"], ["ua e faaolioliina o ia i le fiafia i ou luma.", "thou hast made him exceeding glad with thy countenance."]]},
  {num:7,words:[["Auā ua faatuatua le tupu ia Ieova;", "For the king trusteth in the LORD,"], ["ona o le alofa o lē Silisili ese e le faagaeetia ai o ia.", "and through the mercy of the most High he shall not be moved."]]},
  {num:8,words:[["E maua e lou aao o i latou uma o e ita ia te oe;", "Thine hand shall find out all thine enemies:"], ["e maua lava e lou aao taumatau o e 'ino'ino ia te oe.", "thy right hand shall find out those that hate thee."]]},
  {num:9,words:[["E te faia i latou e pei o le umu aasa i ona po o lou toasa;", "Thou shalt make them as a fiery oven in the time of thine anger:"], ["e faaumatia i latou e Ieova i lona toasa,", "the LORD shall swallow them up in his wrath,"], ["e faaumatia i latou i le afi.", "and the fire shall devour them."]]},
  {num:10,words:[["E fano lava ia te oe o latou gafa ai le lalolagi,", "Their fruit shalt thou destroy from the earth,"], ["ma a latou fanau e fano ia nai le fanau a tagata.", "and their seed from among the children of men."]]},
  {num:11,words:[["Auā na latou manatu i se mea leaga ia oo ia te oe;", "For they intended evil against thee:"], ["na latou mafaufau i se togafiti leaga,", "they imagined a mischievous device,"], ["a e latou te le mafaia.", "which they are not able to perform."]]},
  {num:12,words:[["Auā e te faaliutuaina mai i latou,", "Therefore shalt thou make them turn their back,"], ["e te saunia au fu'a e fana atu ai ia te i latou.", "when thou shalt make ready thine arrows upon thy strings against the face of them."]]},
  {num:13,words:[["Ieova e,", "Be thou exalted,"], ["ia faasilisiliina oe i lou malosi;", "LORD, in thine own strength:"], ["matou te pepese ma fai pesega i lou mana.", "so will we sing and praise thy power."]]},
];
renderVerseSet(psa_ch_21_Verses, 'psa-ch21-verses');

var psa_ch_22_Verses = [
  {num:1,words:[["Lo'u Atua e,", "My God,"], ["lo'u Atua e,", "my God,"], ["se a ea le mea ua e tuulafoai mai ai ia te 'au, e taumamao ma lo'u faaolataga,", "why hast thou forsaken me? why art thou so far from helping me,"], ["o upu foi o lo'u faataio?", "and from the words of my roaring?"]]},
  {num:2,words:[["Lo'u Atua e,", "O my God,"], ["ou te valaau ia te oe i le ao,", "I cry in the daytime,"], ["a e te le faafofogaina mai;", "but thou hearest not;"], ["atoa foi ma le po,", "and in the night season,"], ["ua ou le mapu lava.", "and am not silent."]]},
  {num:3,words:[["A o oe, e paia oe;", "But thou art holy,"], ["o loo e tietie i viiga a Isaraelu.", "O thou that inhabitest the praises of Israel."]]},
  {num:4,words:[["Na faatuatua ia te oe o matou tamā;", "Our fathers trusted in thee:"], ["na latou faatuatua,", "they trusted,"], ["ua e laveai foi ia te i latou.", "and thou didst deliver them."]]},
  {num:5,words:[["Na latou alalaga atu ia te oe,", "They cried unto thee,"], ["ona laveaiina ai lea o i latou;", "and were delivered:"], ["na latou faatuatua ia te oe,", "they trusted in thee,"], ["ona le faamaina lea o i latou.", "and were not confounded."]]},
  {num:6,words:[["A o a'u,", "But I am a worm,"], ["o le tuga lava a'u,", "and no man;"], ["a e le se tagata; ua faalumaina a'u e tagata,", "a reproach of men,"], ["ma inosia a'u e le nuu.", "and despised of the people."]]},
  {num:7,words:[["Ua faatauemu mai ia te au o i latou uma ua vaai mai;", "All they that see me laugh me to scorn:"], ["ua faamamaga o latou gutu,", "they shoot out the lip,"], ["ua lialiai o latou ulu,", "they shake the head,"], ["ua faapea mai ,", "saying,"]]},
  {num:8,words:[["Na ia faalagolago ia Ieova;", "He trusted on the LORD that he would deliver him:"], ["ia na faaola ia te ia; ia laveai o ia ia te ia,", "let him deliver him,"], ["auā ua na fiafia ia te ia.", "seeing he delighted in him."]]},
  {num:9,words:[["A o oe, na e aumaia a'u mai le manava;", "But thou art he that took me out of the womb:"], ["o oe na saogalemu ai a'u ina ou susu i lo'u tinā.", "thou didst make me hope when I was upon my mother's breasts."]]},
  {num:10,words:[["Na tuuina atu a'u ia te oe talu lo'u fanau mai;", "I was cast upon thee from the womb:"], ["o oe lava lo'u Atua talu ina ou i le manava o lo'u tinā.", "thou art my God from my mother's belly."]]},
  {num:11,words:[["Aua ne'i e taumamao ia te au,", "Be not far from me;"], ["auā ua latalata mai le puapuaga;", "for trouble is near;"], ["auā e leai sē fesoasoani mai.", "for there is none to help."]]},
  {num:12,words:[["Ua siosiomia a'u e povi poa e tele;", "Many bulls have compassed me:"], ["o e malolosi i Vasana ua vagavagai mai ia te au.", "strong bulls of Bashan have beset me round."]]},
  {num:13,words:[["Ua faamamaga o latou gutu ia te au, e pei o le leona ua saei manu,", "They gaped upon me with their mouths,"], ["ma ua tagi.", "as a ravening and a roaring lion."]]},
  {num:14,words:[["Ua sasaaina a'u e pei o le suāvai,", "I am poured out like water,"], ["ua see o'u ivi uma;", "and all my bones are out of joint:"], ["o lo'u loto ua pei o le pulu,", "my heart is like wax;"], ["ua liu suāvai i totonu o lo'u manava.", "it is melted in the midst of my bowels."]]},
  {num:15,words:[["Ua mago lo'u malosi,", "My strength is dried up like a potsherd;"], ["e pei o le ta'egāipu, ma ua pipii lo'u laulaufaiva i lo'u gutu;", "and my tongue cleaveth to my jaws;"], ["ua e tuuina a'u i le eleele o le oti.", "and thou hast brought me into the dust of death."]]},
  {num:16,words:[["Auā ua siosiomia a'u e ulī;", "For dogs have compassed me:"], ["ua punitia a'u e le vao tagata amio leaga;", "the assembly of the wicked have inclosed me:"], ["ua tu'ia e i latou o'u lima ma o'u vae.", "they pierced my hands and my feet."]]},
  {num:17,words:[["Ou te mafaia ona faitau o'u ivi uma; o i latou,", "I may tell all my bones:"], ["ua latou vaavaai mai, ua matamata mai ia te au.", "they look and stare upon me."]]},
  {num:18,words:[["Ua latou tufatufa o'u ofu mo i latou,", "They part my garments among them,"], ["ma latou fai le vili i lo'u ofu tino.", "and cast lots upon my vesture."]]},
  {num:19,words:[["A o oe,", "But be not thou far from me,"], ["Ieova e,", "O LORD:"], ["aua ne'i e taumamao; lo'u malosi e,", "O my strength,"], ["ia e vave mai e fesoasoani mai ia te au.", "haste thee to help me."]]},
  {num:20,words:[["Ia e laveai ia te au ai le pelu,", "Deliver my soul from the sword;"], ["ia laveaiina a'u ua toatasi mai le lima o le ulī.", "my darling from the power of the dog."]]},
  {num:21,words:[["Ia faaola mai ia te au ai le gutu o le leona;", "Save me from the lion's mouth:"], ["ua e faafofoga mai ia te au mai nifo o rema.", "for thou hast heard me from the horns of the unicorns."]]},
  {num:22,words:[["Ou te ta'u atu lou suafa i o'u uso;", "I will declare thy name unto my brethren:"], ["ou te vivii atu ia te oe i totonu o le faapotopotoga.", "in the midst of the congregation will I praise thee."]]},
  {num:23,words:[["O outou o e matatau ia Ieova,", "Ye that fear the LORD,"], ["ina vivii atu ia ia te ia;", "praise him;"], ["o outou o le fanauga uma a Iakopo,", "all ye the seed of Jacob,"], ["ina vivii atu ia ia te ia;", "glorify him;"], ["o outou o le fanauga uma a Isaraelu,", "and fear him,"], ["ia outou fefefe ia te ia.", "all ye the seed of Israel."]]},
  {num:24,words:[["Auā e le ta'ufaatauvaa o ia,", "For he hath not despised nor abhorred the affliction of the afflicted;"], ["e le 'ino'ino foi o ia i le puapuaga o le ua puapuagaina;", "neither hath he hid his face from him;"], ["e le liliu ese foi e ia ona fofoga ia te ia; na tagi atu o ia ia te ia,", "but when he cried unto him,"], ["ona faafofoga mai ai lea o ia.", "he heard."]]},
  {num:25,words:[["Ou te vivii lava ia te oe i totonu o le faapotopotoga tele;", "My praise shall be of thee in the great congregation:"], ["ou te avatua foi ia te ia i luma o e matatau ia te ia o mea na ou tauto ai.", "I will pay my vows before them that fear him."]]},
  {num:26,words:[["E aai o e matitiva,", "The meek shall eat and be satisfied:"], ["ma latou maoona ai; e vivii atu ia Ieova e ua sailiili ia te ia;", "they shall praise the LORD that seek him:"], ["e faalototeleina outou e faavavau.", "your heart shall live for ever."]]},
  {num:27,words:[["E manatunatu ifo ma liliu mai ia Ieova o tulu'iga uma lava o le lalolagi;", "All the ends of the world shall remember and turn unto the LORD:"], ["e ifo atu foi i ou luma aiga uma o nuu ese.", "and all the kindreds of the nations shall worship before thee."]]},
  {num:28,words:[["Auā o loo ia Ieova le malo;", "For the kingdom is the LORD'S:"], ["o loo pule o ia i nuu ese.", "and he is the governor among the nations."]]},
  {num:29,words:[["E aai ma ifo ia te ia atoa uma o e puputa i le lalolagi;", "All they that be fat upon earth shall eat and worship:"], ["e punonou i ona luma atoa uma o e ō ifo i le eleele,", "all they that go down to the dust shall bow before him:"], ["atoa ma le ua le faaola o ia ia te ia.", "and none can keep alive his own soul."]]},
  {num:30,words:[["E auauna ia te ia le fanau;", "A seed shall serve him;"], ["e ta'ua i latou e fai ma tupulaga mo le Alii.", "it shall be accounted to the Lord for a generation."]]},
  {num:31,words:[["E o mai i latou,", "They shall come,"], ["ma latou faaali lana amiotonu i le nuu o le a fanau mai,", "and shall declare his righteousness unto a people that shall be born,"], ["na faia lava e ia.", "that he hath done this."]]},
];
renderVerseSet(psa_ch_22_Verses, 'psa-ch22-verses');

var psa_ch_23_Verses = [
  {num:1,words:[["O Ieova, o lo'u leoleo mamoe o ia;", "The LORD is my shepherd;"], ["e leai se mea ou te mativa ai.", "I shall not want."]]},
  {num:2,words:[["Na te ave a'u i le mea e i ai le vao mu'a ou te taoto ai;", "He maketh me to lie down in green pastures:"], ["na te ta'ita'i ia te au i tafatafa o vai e tafe lemu.", "he leadeth me beside the still waters."]]},
  {num:3,words:[["Na te faafoisia mai lo'u agaga;", "He restoreth my soul:"], ["na te ta'ita'i ia te au i ala o le amiotonu ona o lona suafa.", "he leadeth me in the paths of righteousness for his name's sake."]]},
  {num:4,words:[["E ui lava ina ou savali i le vanu o le ata o le oti,", "Yea,"], ["ou te le fefe lava i se mea leaga;", "though I walk through the valley of the shadow of death,"], ["auā o oe ta te faatasi ma a'u;", "I will fear no evil: for thou art with me;"], ["o lau laau ma lou tootoo e faamafanafanaina ai a'u.", "thy rod and thy staff they comfort me."]]},
  {num:5,words:[["E te laulau mai mea i le laoai ma a'u i luma o e ita mai ia te au;", "Thou preparest a table before me in the presence of mine enemies:"], ["ua e faauuina lo'u ulu i le suāuu;", "thou anointest my head with oil;"], ["ua taumasuasua la'u ipu.", "my cup runneth over."]]},
  {num:6,words:[["E moni e mulimuli mai ia te au le agalelei ma le alofa i aso uma o lo'u ola;", "Surely goodness and mercy shall follow me all the days of my life:"], ["ou te nofo foi i le fale o Ieova i aso e tele lava.", "and I will dwell in the house of the LORD for ever."]]},
];
renderVerseSet(psa_ch_23_Verses, 'psa-ch23-verses');

var psa_ch_24_Verses = [
  {num:1,words:[["O le lalolagi ma mea ua tumu ai o a Ieova ia;", "The earth is the LORD'S, and the fulness thereof;"], ["o le atu laulau ma e o nonofo ai.", "the world, and they that dwell therein."]]},
  {num:2,words:[["Auā o ia lava na faavaeina ai i luga o le sami,", "For he hath founded it upon the seas,"], ["ma faamau ai i luga o vaitafe.", "and established it upon the floods."]]},
  {num:3,words:[["O ai ea se alu ae i le mauga o Ieova? O ai se tumau i lona afioaga paia?", "Who shall ascend into the hill of the LORD? or who shall stand in his holy place?"]]},
  {num:4,words:[["O le ua i ai lima mamā,", "He that hath clean hands,"], ["ma le loto mamā;", "and a pure heart;"], ["o le ua le naunau lona loto i le mea faatauvaa,", "who hath not lifted up his soul unto vanity,"], ["ma ua le tauto faa'ole'ole.", "nor sworn deceitfully."]]},
  {num:5,words:[["Na te maua le manuia mai ia Ieova,", "He shall receive the blessing from the LORD,"], ["ma le amiotonu mai le Atua o lona faaolataga.", "and righteousness from the God of his salvation."]]},
  {num:6,words:[["O le tupulaga lena e sailiili ia te ia,", "This is the generation of them that seek him,"], ["o e saili ia te oe,", "that seek thy face,"], ["o Iakopo ia . Selā.", "O Jacob. Selah."]]},
  {num:7,words:[["Ina faaea ia i luga o outou ulu,", "Lift up your heads,"], ["outou faitotoa e;", "O ye gates;"], ["ia faaeaina i luga o outou puipui o le faavavau e,", "and be ye lift up, ye everlasting doors;"], ["se'i ulu atu ai le Tupu mamalu.", "and the King of glory shall come in."]]},
  {num:8,words:[["O ai ea lenei Tupu mamalu? O Ieova, le malosi ma le fitafita,", "Who is this King of glory? The LORD strong and mighty,"], ["o Ieova le fitafita i le taua.", "the LORD mighty in battle."]]},
  {num:9,words:[["Ina faaea ia i luga o outou ulu,", "Lift up your heads,"], ["outou,", "O ye gates;"], ["faitotoa e;", "even lift them up,"], ["ia faaeaina i luga o outou puipui o le faavavau e,", "ye everlasting doors;"], ["se'i ulu atu ai le Tupu mamalu.", "and the King of glory shall come in."]]},
  {num:10,words:[["O ai ea lenei Tupu mamalu? O Ieova o 'au,", "Who is this King of glory? The LORD of hosts,"], ["o ia lava le tupu mamalu. Selā.", "he is the King of glory. Selah."]]},
];
renderVerseSet(psa_ch_24_Verses, 'psa-ch24-verses');

var psa_ch_25_Verses = [
  {num:1,words:[["Ieova e,", "Unto thee, O LORD,"], ["ou te faanaunau atu ia te oe ma lo'u loto.", "do I lift up my soul."]]},
  {num:2,words:[["Lo'u Atua e,", "O my God,"], ["ou te faatuatua ia te oe;", "I trust in thee:"], ["aua ne'i faamaina a'u;", "let me not be ashamed,"], ["aua ne'i mitamita mai ia te au o e ita mai ia te au.", "let not mine enemies triumph over me."]]},
  {num:3,words:[["O i latou uma foi o e faatalitali ia te oe,", "Yea,"], ["aua ne'i faamaina i latou;", "let none that wait on thee be ashamed:"], ["e faamaina o e fai fua a latou amio pepelo.", "let them be ashamed which transgress without cause."]]},
  {num:4,words:[["Ieova e,", "Shew me thy ways,"], ["ia e faailoa mai ia te au ou ala;", "O LORD;"], ["ia e a'oa'o mai ia te au i ou magāala.", "teach me thy paths."]]},
  {num:5,words:[["Ia e ta'ita'i mai ia te au i le mea moni mai ia te oe,", "Lead me in thy truth,"], ["ma a'oa'o mai ia te au,", "and teach me:"], ["auā o oe o le Atua o lo'u olataga;", "for thou art the God of my salvation;"], ["ou te faatalitali ia te oe i le aso atoa.", "on thee do I wait all the day."]]},
  {num:6,words:[["Ieova e,", "Remember,"], ["ia e manatua lou alofa mutimuti vale ma lou agalelei;", "O LORD, thy tender mercies and thy lovingkindnesses;"], ["auā talu mai le vavau lava ia.", "for they have been ever of old."]]},
  {num:7,words:[["Aua e te manatua a'u agasala ina o ou taulealea,", "Remember not the sins of my youth,"], ["ma o'u solitulafono;", "nor my transgressions:"], ["a e tusa ma lou alofa ia e manatua mai a'u, Ieova e,", "according to thy mercy remember thou me for thy goodness' sake,"], ["ona o lou agalelei.", "O LORD."]]},
  {num:8,words:[["O Ieova, e agalelei ma amiotonu ia,", "Good and upright is the LORD:"], ["o le mea lea na te faasinoina atu ai le ala i tagata agasala.", "therefore will he teach sinners in the way."]]},
  {num:9,words:[["E ta'ita'iina e ia o e agamalu i le faamasinoga;", "The meek will he guide in judgment:"], ["na te a'oa'o mai foi i e agamalu i lona ala.", "and the meek will he teach his way."]]},
  {num:10,words:[["O ala uma lava o Ieova, o le alofa ia ma le faamaoni i e ua tausi i lana feagaiga ma ana tulafono.", "All the paths of the LORD are mercy and truth unto such as keep his covenant and his testimonies."]]},
  {num:11,words:[["Ieova e,", "For thy name's sake,"], ["ona o lou suafa,", "O LORD,"], ["ia e faamagalo mai ai la'u agasala,", "pardon mine iniquity;"], ["auā ua tele lava ia.", "for it is great."]]},
  {num:12,words:[["O ai ea le tagata o lē mata'u ia Ieova? E faasinoina atu i ai e ia le ala na te filifilia.", "What man is he that feareth the LORD? him shall he teach in the way that he shall choose."]]},
  {num:13,words:[["E mau o ia i le manuia;", "His soul shall dwell at ease;"], ["o lana fanau foi e fai mo latou le nuu.", "and his seed shall inherit the earth."]]},
  {num:14,words:[["O loo faaali e Ieova lona finagalo i e matatau ia te ia;", "The secret of the LORD is with them that fear him;"], ["na te faailoa atu foi lana feagaiga ia te i latou.", "and he will shew them his covenant."]]},
  {num:15,words:[["O loo faasaga pea lava o'u mata ia Ieova;", "Mine eyes are ever toward the LORD;"], ["auā o ia lava e tatalaina o'u vae ai le upega.", "for he shall pluck my feet out of the net."]]},
  {num:16,words:[["Ia e liuliu alo mai ia te au,", "Turn thee unto me,"], ["ma alofa mai ia te au;", "and have mercy upon me;"], ["auā o a'u ou te toatasi ma puapuagaina.", "for I am desolate and afflicted."]]},
  {num:17,words:[["Ua faateleina puapuaga o lo'u loto;", "The troubles of my heart are enlarged:"], ["ia e aveeseina a'u i mea ou te tiga ai.", "O bring thou me out of my distresses."]]},
  {num:18,words:[["Ia e silasila mai i lo'u puapuaga ma lo'u tiga;", "Look upon mine affliction and my pain;"], ["ma ia e faamagaloina a'u agasala uma lava.", "and forgive all my sins."]]},
  {num:19,words:[["Ia e silasila i e o ita mai ia te au,", "Consider mine enemies;"], ["auā e toatele i latou;", "for they are many;"], ["ua latou 'ino'ino foi ia te au i le 'ino'ino faasaua.", "and they hate me with cruel hatred."]]},
  {num:20,words:[["Ia e leoleo ia te au,", "O keep my soul,"], ["ma laveai mai ia te au;", "and deliver me:"], ["aua ne'i ou mā,", "let me not be ashamed;"], ["auā ou te faatuatua ia te oe.", "for I put my trust in thee."]]},
  {num:21,words:[["Ia tausia a'u e le amio sao ma le amiotonu;", "Let integrity and uprightness preserve me;"], ["auā ou te faatalitali ia te oe.", "for I wait on thee."]]},
  {num:22,words:[["Le Atua e,", "Redeem Israel, O God,"], ["ia e laveai ia Isaraelu i ona puapuaga uma lava.", "out of all his troubles."]]},
];
renderVerseSet(psa_ch_25_Verses, 'psa-ch25-verses');

var psa_ch_26_Verses = [
  {num:1,words:[["Ieova e,", "Judge me,"], ["ia e faamasino ia te au;", "O LORD;"], ["auā o a'u nei ua ou savali ma la'u amio sao;", "for I have walked in mine integrity:"], ["ou te faatuatua foi ia Ieova;", "I have trusted also in the LORD;"], ["e le mapeva o'u vae .", "therefore I shall not slide."]]},
  {num:2,words:[["Ieova e,", "Examine me,"], ["ia e suesue ia te au,", "O LORD,"], ["ma tofotofo ia te au;", "and prove me;"], ["ia e faamamā i o'u manatu ma lo'u loto.", "try my reins and my heart."]]},
  {num:3,words:[["Auā o loo i o'u luma lou alofa;", "For thy lovingkindness is before mine eyes:"], ["ua ou savali foi i le mea moni mai ia te oe.", "and I have walked in thy truth."]]},
  {num:4,words:[["Ou te lei nofo faatasi ma tagata ulavavale;", "I have not sat with vain persons,"], ["ou te lei alu faatasi ma tagata pepelo.", "neither will I go in with dissemblers."]]},
  {num:5,words:[["Ua ou 'ino'ino i le faapotopotoga o e fai mea leaga;", "I have hated the congregation of evil doers;"], ["ou te le nofo foi faatasi ma tagata amio leaga.", "and will not sit with the wicked."]]},
  {num:6,words:[["Ou te fafano o'u lima e fai ma faailoga ua ou le sala;", "I will wash mine hands in innocency:"], ["ona ou faataamilomilo ai lea i lou fata faitaulaga,", "so will I compass thine altar,"], ["Ieova e;", "O LORD:"]]},
  {num:7,words:[["ina ia lagona atu le leo o le viiga,", "That I may publish with the voice of thanksgiving,"], ["ma ia ta'uta'u atu ou vavega uma lava.", "and tell of all thy wondrous works."]]},
  {num:8,words:[["Ieova e,", "LORD,"], ["ou te fiafia i le mea e tu ai lou maota,", "I have loved the habitation of thy house,"], ["o le mea foi e afio ai lou mamalu.", "and the place where thine honour dwelleth."]]},
  {num:9,words:[["Aua ne'i e faatasia a'u ma tagata agasala,", "Gather not my soul with sinners,"], ["ma lo'u ola ne'i faatasia ma tagata ua totolima.", "nor my life with bloody men:"]]},
  {num:10,words:[["O loo i o latou lima amio leaga,", "In whose hands is mischief,"], ["ua tutumu foi o latou lima taumatau i mea alofa.", "and their right hand is full of bribes."]]},
  {num:11,words:[["A e peitai a'u nei,", "But as for me,"], ["ou te savali ma la'u amio sao;", "I will walk in mine integrity:"], ["ia e laveai ia te au,", "redeem me,"], ["ma ia e alofa mai ia te au.", "and be merciful unto me."]]},
  {num:12,words:[["Ua tu o'u vae i le mea laugatasi;", "My foot standeth in an even place:"], ["ou te faamanū atu ia Ieova i totonu o faapotopotoga.", "in the congregations will I bless the LORD."]]},
];
