var psa_ch_27_Verses = [
  {num:1,words:[["O Ieova, o lo'u malamalama ia,", "The LORD is my light and my salvation;"], ["ma lo'u olataga: o ai ea se ou te fefe ai? O Ieova,", "whom shall I fear? the LORD is the strength of my life;"], ["o le malosi ia o lo'u ola; ou te mata'u ea ia te ai?", "of whom shall I be afraid?"]]},
  {num:2,words:[["Na sii taua mai ia te au tagata amio leaga,", "When the wicked,"], ["ina ia 'ai lo'u tino o e saua mai ma e ita mai ia te au;", "even mine enemies and my foes,"], ["ona tausuai lea o i latou,", "came upon me to eat up my flesh,"], ["ma latou pauu.", "they stumbled and fell."]]},
  {num:3,words:[["E ui lava ina to lauapi se itu taua e tau ma a'u,", "Though an host should encamp against me,"], ["e le fefe ai lo'u loto;", "my heart shall not fear:"], ["e ui ina siitia se taua ia te au,", "though war should rise against me,"], ["ou te loto tele lava i lea mea.", "in this will I be confident."]]},
  {num:4,words:[["E tasi le mea ua ou ole atu ai ia Ieova,", "One thing have I desired of the LORD,"], ["o le mea lava lea ou te saili atu ai;", "that will I seek after;"], ["ia ou nofo i le fale o Ieova i aso uma o lo'u ola,", "that I may dwell in the house of the LORD all the days of my life,"], ["ina ia ou iloa atu ai le matagofie o Ieova,", "to behold the beauty of the LORD,"], ["ma ou saili i lona malumalu.", "and to enquire in his temple."]]},
  {num:5,words:[["Auā na te faalilo ia te au i lona fale apitaga i le aso vale;", "For in the time of trouble he shall hide me in his pavilion:"], ["na te natia a'u i le mea lilo i lona fale fetafai;", "in the secret of his tabernacle shall he hide me;"], ["na te faaeetia a'u i le papa.", "he shall set me up upon a rock."]]},
  {num:6,words:[["O lenei,", "And now shall mine head be lifted up above mine enemies round about me:"], ["e faaeaina lo'u ulu i luga o e ua ita mai ia te au,", "therefore will I offer in his tabernacle sacrifices of joy;"], ["o e siosio ia te au;", "I will sing,"], ["ou te osia ai taulaga i lona fale fetafai ma le alaga fiafia;", "yea,"], ["ou te pese ma ou fai pesega ia Ieova.", "I will sing praises unto the LORD."]]},
  {num:7,words:[["Ieova e,", "Hear,"], ["ia e faafofoga mai i lo'u leo,", "O LORD,"], ["ou te valaau;", "when I cry with my voice:"], ["ia e alofa mai,", "have mercy also upon me,"], ["ma ia e tali mai ia te au.", "and answer me."]]},
  {num:8,words:[["Na fai atu lo'u loto ia te oe i lau na e fetalai mai ,", "When thou saidst, Seek ye my face;"], ["Ia outou sailiili mai ia te au;", "my heart said unto thee,"], ["Ieova e,", "Thy face,"], ["ou te sailiili atu i lau afio.", "LORD, will I seek."]]},
  {num:9,words:[["Aua e te liliu ese ou fofoga ia te au;", "Hide not thy face far from me;"], ["aua e te tuli i lau auauna i lou toatamai;", "put not thy servant away in anger:"], ["na fai oe mo'u fesoasoani; aua le tuulafoaiina a'u,", "thou hast been my help;"], ["aua foi e te tuua a'u,", "leave me not,"], ["le Atua e,", "neither forsake me,"], ["lo'u faaolataga.", "O God of my salvation."]]},
  {num:10,words:[["E ui lava ina tuua a'u e lo'u tamā ma lo'u tinā,", "When my father and my mother forsake me,"], ["a e talia a'u e Ieova.", "then the LORD will take me up."]]},
  {num:11,words:[["Ieova e,", "Teach me thy way,"], ["ia e a'oa'o mai ia te au i lou ala,", "O LORD,"], ["ma ta'ita'i ia te au i le ala laulelei,", "and lead me in a plain path,"], ["ona o e ita mai ia te au.", "because of mine enemies."]]},
  {num:12,words:[["Aua e te tuuina a'u i le manao o e saua mai ia te au;", "Deliver me not over unto the will of mine enemies:"], ["auā ua laga mai ia te au o e molimau pepelo,", "for false witnesses are risen up against me,"], ["ma latou tautalatala i le faasaua.", "and such as breathe out cruelty."]]},
  {num:13,words:[["Ana ou le faatuatua ou te iloa le agalelei o Ieova i le nuu o tagata ola,", "I had fainted,"], ["po ua ou faavaivai lava .", "unless I had believed to see the goodness of the LORD in the land of the living."]]},
  {num:14,words:[["Ina faatalitali atu ia ia Ieova,", "Wait on the LORD: be of good courage,"], ["ina loto tele ia,", "and he shall strengthen thine heart:"], ["e faamalosia foi e ia lou loto;", "wait,"], ["ina faatalitali lava ia ia Ieova.", "I say, on the LORD."]]},
];
