var psa_ch_31_Verses = [
  {num:1,words:[["Ieova e,", "In thee,"], ["ou te faatuatua lava ia te oe;", "O LORD,"], ["aua ne'i faamaina a'u e oo i le faavavau;", "do I put my trust; let me never be ashamed:"], ["ia e laveai mai ia te au i lau amiotonu.", "deliver me in thy righteousness."]]},
  {num:2,words:[["Ia e liliu mai ou fofoga ia te au;", "Bow down thine ear to me;"], ["ia e vave laveai ia te au;", "deliver me speedily:"], ["ia fai oe mo'u papa malosi,", "be thou my strong rock,"], ["o le 'olo mauga ou te ola ai.", "for an house of defence to save me."]]},
  {num:3,words:[["Auā o oe lava lo'u papa,", "For thou art my rock and my fortress;"], ["ma lo'u 'olo;", "therefore for thy name's sake lead me,"], ["ia e ta'ita'i mai ma tausi ia te au ona o lou suafa.", "and guide me."]]},
  {num:4,words:[["Ia e ave ese ia te au i lea lava upega na latou natia ia maua ai a'u;", "Pull me out of the net that they have laid privily for me:"], ["auā o oe lava lo'u malosi.", "for thou art my strength."]]},
  {num:5,words:[["Ou te tuuina atu lo'u agaga i lou aao;", "Into thine hand I commit my spirit:"], ["Ieova e, le Atua faamaoni,", "thou hast redeemed me,"], ["ua e togiolaina a'u.", "O LORD God of truth."]]},
  {num:6,words:[["Ou te 'ino'ino i e ua anaana i mea faatauvaa ma le pepelo;", "I have hated them that regard lying vanities:"], ["a e ou te faatuatua lava ia Ieova.", "but I trust in the LORD."]]},
  {num:7,words:[["Ou te fiafia ma ou olioli i lou alofa mai;", "I will be glad and rejoice in thy mercy:"], ["auā ua e silasila i lo'u tiga;", "for thou hast considered my trouble;"], ["ua e silafia a'u ina o puapuagatia.", "thou hast known my soul in adversities;"]]},
  {num:8,words:[["Ua e le tuuina foi a'u i le pule a e ita mai ia te au;", "And hast not shut me up into the hand of the enemy:"], ["ua e faatuina o'u vae i le mea lautele.", "thou hast set my feet in a large room."]]},
  {num:9,words:[["Ieova e,", "Have mercy upon me,"], ["ia e alofa mai ia te au,", "O LORD,"], ["auā ua ou puapuaga; ua fole o'u mata,", "for I am in trouble:"], ["atoa ma lo'u agaga,", "mine eye is consumed with grief,"], ["ma lo'u manava,", "yea,"], ["i le tiga.", "my soul and my belly."]]},
  {num:10,words:[["Auā ua faauma lo'u ola i le faanoanoa,", "For my life is spent with grief,"], ["ma ou tausaga i le mapuitiga;", "and my years with sighing:"], ["ua faavaivaiina lo'u malosi i a'u agasala,", "my strength faileth because of mine iniquity,"], ["ua gagase foi o'u ivi.", "and my bones are consumed."]]},
  {num:11,words:[["Ua faalumaina a'u e i latou uma o e ita mai ia te au,", "I was a reproach among all mine enemies,"], ["a e sili lava i latou matou te tuaoi;", "but especially among my neighbours,"], ["ua avea a'u ma faamatau i e sa matou masani;", "and a fear to mine acquaintance:"], ["ua sosola ese ia te au o e iloa mai a'u i fafo.", "they that did see me without fled from me."]]},
  {num:12,words:[["Ua faagalogaloina a'u e pei o le ua oti, ua le manatua lava;", "I am forgotten as a dead man out of mind:"], ["peiseai a'u se ipu ua nutililii.", "I am like a broken vessel."]]},
  {num:13,words:[["Auā ua ou faalogo i le faaleaga mai e le toatele;", "For I have heard the slander of many:"], ["ua siosiomia a'u e le mata'u,", "fear was on every side:"], ["ona ua latou taupulepule faatasi ia te au,", "while they took counsel together against me,"], ["ua latou manatu i se togafiti ou te oti ai.", "they devised to take away my life."]]},
  {num:14,words:[["A e peitai a'u nei,", "But I trusted in thee,"], ["ou te faalagolago ia te oe Ieova e,", "O LORD:"], ["ou te faapea atu,", "I said,"], ["O oe lava lo'u Atua.", "Thou art my God."]]},
  {num:15,words:[["O loo i ou aao o'u aso;", "My times are in thy hand:"], ["ia e laveai mai ia te au ai lima o e ita mai,", "deliver me from the hand of mine enemies,"], ["ma e ua tuliloa mai ia te au.", "and from them that persecute me."]]},
  {num:16,words:[["Ia malamalama mai ou fofoga i lau auauna;", "Make thy face to shine upon thy servant:"], ["ia e faaola mai ia te au ona o lou alofa.", "save me for thy mercies' sake."]]},
  {num:17,words:[["Ieova e,", "Let me not be ashamed,"], ["aua ne'i famaina lava a'u,", "O LORD;"], ["auā ou te valaau ia te oe;", "for I have called upon thee:"], ["ia faamaina o e fai amio leaga,", "let the wicked be ashamed,"], ["ia faalologo i latou i seoli.", "and let them be silent in the grave."]]},
  {num:18,words:[["Ia faalologo laugutu pepelo; o e tautala faasiasia,", "Let the lying lips be put to silence;"], ["ma le faamaualuga, ma le 'ino'ino i le tagata amiotonu.", "which speak grievous things proudly and contemptuously against the righteous."]]},
  {num:19,words:[["Ua tele lava lou agalelei ua teua e oe mo e ua matatau ia te oe,", "Oh how great is thy goodness, which thou hast laid up for them that fear thee;"], ["ua e faia i luma o le fanau a tagata mo e faatuatua ia te oe.", "which thou hast wrought for them that trust in thee before the sons of men!"]]},
  {num:20,words:[["E natia i latou e oe i le mea lilo i ou luma, ia le oo ia te i latou taupulepulega a tagata;", "Thou shalt hide them in the secret of thy presence from the pride of man:"], ["e te faalilo ia te i latou i lou fale apitaga, ina ia le oo ai le finauga a laulaufaiva.", "thou shalt keep them secretly in a pavilion from the strife of tongues."]]},
  {num:21,words:[["Faafetai ia Ieova,", "Blessed be the LORD:"], ["auā na ia faasilisili lona alofa ia te au i le aai nofo 'olo.", "for he hath shewed me his marvellous kindness in a strong city."]]},
  {num:22,words:[["O a'u foi na ou fai atu i lo'u polepole vale,", "For I said in my haste,"], ["Ua faateaina a'u ai ou luma;", "I am cut off from before thine eyes:"], ["a e peitai ua e faafofoga mai i le leo o la'u aioi atu i lo'u alaga atu ia te oe.", "nevertheless thou heardest the voice of my supplications when I cried unto thee."]]},
  {num:23,words:[["O outou na uma lava o ona tagata amio Atua,", "O love the LORD,"], ["ia outou alolofa atu ia Ieova;", "all ye his saints:"], ["e leoleoina e Ieova o e faamaoni,", "for the LORD preserveth the faithful,"], ["a e matuā tauia e ia o e amio faamaualuga.", "and plentifully rewardeth the proud doer."]]},
  {num:24,words:[["O outou na uma lava,", "Be of good courage,"], ["o e faamoemoe ia Ieova, ina faalototetele ia;", "and he shall strengthen your heart,"], ["e faamalolosia foi e ia o outou loto.", "all ye that hope in the LORD."]]},
];
