var psa_ch_32_Verses = [
  {num:1,words:[["Amuia le tagata ua faamagaloina lona solitulafono,", "Blessed is he whose transgression is forgiven,"], ["ma ua ufitia lana agasala.", "whose sin is covered."]]},
  {num:2,words:[["Amuia le tagata e le ta'usalaina e Ieova,", "Blessed is the man unto whom the LORD imputeth not iniquity,"], ["e leai foi se 'ole'olega i lona loto.", "and in whose spirit there is no guile."]]},
  {num:3,words:[["Na ou faalologo,", "When I kept silence,"], ["ona palagia ai lea o o'u ivi i lo'u faataio i le aso atoa;", "my bones waxed old through my roaring all the day long."]]},
  {num:4,words:[["auā sa mamafa lou aao i luga ia te au i le ao atoa foi ma le po;", "For day and night thy hand was heavy upon me:"], ["ua liua lava lo'u malosi i le vevela o le tausaga vevela. Selā.", "my moisture is turned into the drought of summer. Selah."]]},
  {num:5,words:[["Ona ou faailoa atu ai lea ia te oe o la'u agasala,", "I acknowledged my sin unto thee,"], ["na ou le ufitia foi la'u amioletonu;", "and mine iniquity have I not hid. I said,"], ["sa ou faapea, Ou te faaali atu ia Ieova o'u solitulafono;", "I will confess my transgressions unto the LORD;"], ["ona e aveesea ai lea o le leaga o la'u agasala. Selā.", "and thou forgavest the iniquity of my sin. Selah."]]},
  {num:6,words:[["O le mea lea e tatalo atu ai ia te oe o e amio Atua uma lava, i ona po e maua ai oe;", "For this shall every one that is godly pray unto thee in a time when thou mayest be found:"], ["e moni, e le oo ia te i latou tafega o vai e tele.", "surely in the floods of great waters they shall not come nigh unto him."]]},
  {num:7,words:[["O oe lava lo'u lafitaga,", "Thou art my hiding place;"], ["e te leoleoina a'u i le puapuaga,", "thou shalt preserve me from trouble;"], ["e te siosiomia a'u i siva o le olataga. Selā.", "thou shalt compass me about with songs of deliverance. Selah."]]},
  {num:8,words:[["Ou te a'oa'o ia te oe, ma faasino ia te oe i lea lava ala e te savali ai;", "I will instruct thee and teach thee in the way which thou shalt go:"], ["ou te faatonu ia te oe, ma ou vaai ia te oe.", "I will guide thee with mine eye."]]},
  {num:9,words:[["Aua e te faapei o le solofanua,", "Be ye not as the horse,"], ["po o le falata,", "or as the mule,"], ["e le o i ai se mafaufau,", "which have no understanding:"], ["o latou teuga o le faagutu ma le taofi e taofi ai,", "whose mouth must be held in with bit and bridle,"], ["auā ua latou le faalatalata mai ia te oe.", "lest they come near unto thee."]]},
  {num:10,words:[["E tele mea tiga e oo i e amio leaga;", "Many sorrows shall be to the wicked: but he that trusteth in the LORD,"], ["a o lē faatuatua ia Ieova e siomia o ia i le alofa.", "mercy shall compass him about."]]},
  {num:11,words:[["Ina fiafia ia ia Ieova,", "Be glad in the LORD, and rejoice,"], ["ma olioli o outou o e amiotonu;", "ye righteous:"], ["ina alalaga ia ma le fiafia o outou uma o e ua faamaoni o outou loto.", "and shout for joy, all ye that are upright in heart."]]},
];
renderVerseSet(psa_ch_32_Verses, 'psa-ch32-verses');

var psa_ch_33_Verses = [
  {num:1,words:[["Ina pepese ia ia Ieova o outou o e amiotonu;", "Rejoice in the LORD, O ye righteous:"], ["e ono lava i e ua amio sa'o ona vivii atu.", "for praise is comely for the upright."]]},
  {num:2,words:[["Ina vivii atu ia ia Ieova i le kitara;", "Praise the LORD with harp:"], ["ia fai pesega ia te ia i le napeli e sefulu ona manoa.", "sing unto him with the psaltery and an instrument of ten strings."]]},
  {num:3,words:[["Ina pepese atu ia ia te ia i le pese fou;", "Sing unto him a new song;"], ["ia outou ta malie ma le leo fiafia.", "play skilfully with a loud noise."]]},
  {num:4,words:[["Auā e sa'o lava le afioga a Ieova;", "For the word of the LORD is right;"], ["ua faia foi e ia ana galuega uma i le faamaoni.", "and all his works are done in truth."]]},
  {num:5,words:[["E fiafia o ia i le amiotonu ma le faamasinoga;", "He loveth righteousness and judgment:"], ["ua tumu le lalolagi i le alofa o Ieova.", "the earth is full of the goodness of the LORD."]]},
  {num:6,words:[["O le afioga a Ieova na faia ai le lagi; ma 'au uma o i ai,", "By the word of the LORD were the heavens made;"], ["na faia i le mānava a lona fofoga.", "and all the host of them by the breath of his mouth."]]},
  {num:7,words:[["Ua faapotopotoina e ia o suāsami e pei se mea maupuepue;", "He gathereth the waters of the sea together as an heap:"], ["ua tuuina atu e ia o le moana i fale oloa.", "he layeth up the depth in storehouses."]]},
  {num:8,words:[["Ia matatau ia Ieova atoa uma le lalolagi;", "Let all the earth fear the LORD:"], ["ia fefefe lava ia te ia o outou uma o e nonofo i le atu laulau.", "let all the inhabitants of the world stand in awe of him."]]},
  {num:9,words:[["Auā o ia lava na fetalai ane,", "For he spake,"], ["ona i ai lava lea;", "and it was done;"], ["o ia na tŭlei mai lana afioga,", "he commanded,"], ["ona tu mai lava lea.", "and it stood fast."]]},
  {num:10,words:[["E faaleaogaina e Ieova o taupulepulega o nuu ese;", "The LORD bringeth the counsel of the heathen to nought:"], ["e faaiuvaleina e ia o mafaufauga a tagata.", "he maketh the devices of the people of none effect."]]},
  {num:11,words:[["E tu le pule a Ieova e oo i le faavavau;", "The counsel of the LORD standeth for ever,"], ["o mafaufauga a lona finagalo e a le tu a le tu lava.", "the thoughts of his heart to all generations."]]},
  {num:12,words:[["Amuia le nuu ua Atua ia Ieova,", "Blessed is the nation whose God is the LORD;"], ["o le nuu ua filifilia e ia e fai mona lava tofi.", "and the people whom he hath chosen for his own inheritance."]]},
  {num:13,words:[["O loo silasila mai Ieova mai le lagi;", "The LORD looketh from heaven;"], ["e silafia e ia le fanau uma a tagata.", "he beholdeth all the sons of men."]]},
  {num:14,words:[["O loo matuā silasila mai o ia mai le mea o loo afio ai o ia ia i latou uma o e nonofo i le lalolagi.", "From the place of his habitation he looketh upon all the inhabitants of the earth."]]},
  {num:15,words:[["E faia lava e ia o latou loto uma lava;", "He fashioneth their hearts alike;"], ["o loo matuā silafia e ia a latou galuega uma.", "he considereth all their works."]]},
  {num:16,words:[["E le faaolaina se tupu i le toatele o ana 'au;", "There is no king saved by the multitude of an host:"], ["e le laveaiina le tagata fitafita i lona malosi tele.", "a mighty man is not delivered by much strength."]]},
  {num:17,words:[["E le aoga le faaola a le solofanua;", "An horse is a vain thing for safety:"], ["e leai foi sē laveaiina e ia i lona malosi tele.", "neither shall he deliver any by his great strength."]]},
  {num:18,words:[["Faauta,", "Behold,"], ["o loo silasila Ieova i e matatau ia te ia,", "the eye of the LORD is upon them that fear him,"], ["o e faamoemoe i lona alofa;", "upon them that hope in his mercy;"]]},
  {num:19,words:[["ina ia laveai ia te i latou ai le oti,", "To deliver their soul from death,"], ["ina ia ola foi i latou i le oge.", "and to keep them alive in famine."]]},
  {num:20,words:[["O loo faatalitali o tatou loto ia Ieova;", "Our soul waiteth for the LORD:"], ["o ia lava lo tatou fesoasoani ma lo tatou talita.", "he is our help and our shield."]]},
  {num:21,words:[["Auā o loo fiafia ia te ia o tatou loto;", "For our heart shall rejoice in him,"], ["auā ua tatou faatuatua i lona suafa paia.", "because we have trusted in his holy name."]]},
  {num:22,words:[["Ieova e,", "Let thy mercy,"], ["ia i luga ia te i matou lou alofa,", "O LORD, be upon us,"], ["e pei ona matou faamoemoe ia te oe.", "according as we hope in thee."]]},
];
renderVerseSet(psa_ch_33_Verses, 'psa-ch33-verses');

var psa_ch_34_Verses = [
  {num:1,words:[["Ou te faafetai ia Ieova i aso uma lava;", "I will bless the LORD at all times:"], ["e le aunoa ōna viiga i lo'u gutu.", "his praise shall continually be in my mouth."]]},
  {num:2,words:[["E mitamita lo'u agaga ia Ieova;", "My soul shall make her boast in the LORD:"], ["e faalogologo i ai e ua puapuagaina,", "the humble shall hear thereof,"], ["ona latou fiafia ai lea.", "and be glad."]]},
  {num:3,words:[["Ia outou faaneenee atu ia Ieova faatasi ma a'u;", "O magnify the LORD with me,"], ["ma ia tatou vivii faatasi i lona suafa.", "and let us exalt his name together."]]},
  {num:4,words:[["Na ou saili atu ia Ieova,", "I sought the LORD,"], ["ona tali mai ai lea o ia ia te au,", "and he heard me,"], ["ma na laveaiina a'u ai mea uma na ou fefe ai.", "and delivered me from all my fears."]]},
  {num:5,words:[["Na latou vaavaai atu ia te ia,", "They looked unto him,"], ["ona faaolioliina lea o i latou;", "and were lightened:"], ["e le mā foi o latou mata.", "and their faces were not ashamed."]]},
  {num:6,words:[["Na valaau atu lenei tagata ua tigaina,", "This poor man cried,"], ["ona faafofoga mai ai lea o Ieova,", "and the LORD heard him,"], ["ma na faaola ia te ia i ona puapuaga uma lava.", "and saved him out of all his troubles."]]},
  {num:7,words:[["E to lauapi le agelu a Ieova e siosiomia ai e o matatau ia te ia,", "The angel of the LORD encampeth round about them that fear him,"], ["e laveai foi o ia ia te i latou.", "and delivereth them."]]},
  {num:8,words:[["Ina tofotofo ia outou, ma ia outou iloa e lelei Ieova;", "O taste and see that the LORD is good:"], ["amuia lava le tagata o lē faatuatua ia te ia.", "blessed is the man that trusteth in him."]]},
  {num:9,words:[["O outou na o ona tagata paia,", "O fear the LORD,"], ["ia outou matatau ia Ieova,", "ye his saints:"], ["auā e leai se mea e mativa ai e ua matatau ia te ia.", "for there is no want to them that fear him."]]},
  {num:10,words:[["E oge mea leona taanoa,", "The young lions do lack,"], ["ma latou fia aai;", "and suffer hunger:"], ["a e e leai se mea lelei e mativa ai i latou o e saili ia Ieova.", "but they that seek the LORD shall not want any good thing."]]},
  {num:11,words:[["Le fanau e,", "Come,"], ["ina o mai ia,", "ye children,"], ["ina faalogologo mai ia ia te au;", "hearken unto me:"], ["ou te a'oa'o atu ia te outou ia matatau ia Ieova.", "I will teach you the fear of the LORD."]]},
  {num:12,words:[["O ai ea le tagata ua manao i le ola,", "What man is he that desireth life,"], ["ma ua loto ia tele ona aso,", "and loveth many days,"], ["ia iloa ai e ia mea lelei?", "that he may see good?"]]},
  {num:13,words:[["Aua ne'i tautala lou laulaufaiva i upu leaga,", "Keep thy tongue from evil,"], ["ma ou laugutu ne'i tautala faa'ole'ole.", "and thy lips from speaking guile."]]},
  {num:14,words:[["Ina 'alo ese ia i mea leaga,", "Depart from evil,"], ["a ia fai mea lelei;", "and do good;"], ["ina sailiili atu ia i le filemu,", "seek peace,"], ["ma tausisi i ai.", "and pursue it."]]},
  {num:15,words:[["O fofoga o Ieova o loo faasaga i e amiotonu,", "The eyes of the LORD are upon the righteous,"], ["e liliu mai foi ona taliga i a latou alaga.", "and his ears are open unto their cry."]]},
  {num:16,words:[["A o fofoga o Ieova, o loo faasaga i e fai amio leaga,", "The face of the LORD is against them that do evil,"], ["ina ia tineia le faamanatuina o i latou ai le lalolagi.", "to cut off the remembrance of them from the earth."]]},
  {num:17,words:[["Ua alalaga e ua amiotonu ,", "The righteous cry,"], ["ona faafofoga mai ai lea o Ieova;", "and the LORD heareth,"], ["ua ia laveai mai foi ia te i latou ai o latou puapuaga uma.", "and delivereth them out of all their troubles."]]},
  {num:18,words:[["Ua latalata mai Ieova i e ua loto momomo;", "The LORD is nigh unto them that are of a broken heart;"], ["ua ia faaola foi i e ua loto nutimomoia.", "and saveth such as be of a contrite spirit."]]},
  {num:19,words:[["E tele lava mea leaga e oo i le ua amiotonu;", "Many are the afflictions of the righteous:"], ["a e laveaiina o ia e Ieova ai ia mea uma.", "but the LORD delivereth him out of them all."]]},
  {num:20,words:[["E leoleoina e ia o ona ivi uma;", "He keepeth all his bones:"], ["e le gau lava se tasi.", "not one of them is broken."]]},
  {num:21,words:[["E fasiotia e le malaia le ua amio leaga;", "Evil shall slay the wicked:"], ["o i latou foi e ua 'ino'ino i le ua amiotonu e faasalaina i latou.", "and they that hate the righteous shall be desolate."]]},
  {num:22,words:[["E laveaiina e Ieova o agaga o ana auauna;", "The LORD redeemeth the soul of his servants:"], ["e le faasalaina foi so latou o e faatuatua ia te ia.", "and none of them that trust in him shall be desolate."]]},
];
renderVerseSet(psa_ch_34_Verses, 'psa-ch34-verses');

var psa_ch_35_Verses = [
  {num:1,words:[["Ieova e,", "Plead my cause,"], ["ia e finau ma i latou o e finau mai ia te au,", "O LORD, with them that strive with me:"], ["ia e tau ma i latou o e faasaga tau mai ia te au.", "fight against them that fight against me."]]},
  {num:2,words:[["Ia e tago i le talita ma le talipupuni,", "Take hold of shield and buckler,"], ["ma ia e tulai mai e fesoasoani mai ia te au.", "and stand up for mine help."]]},
  {num:3,words:[["Ia e to ae le tao,", "Draw out also the spear,"], ["ma e pupuni atu i e tuliloa mai ia te au;", "and stop the way against them that persecute me:"], ["ia e fetalai mai i lo'u agaga,", "say unto my soul,"], ["O lou faaola o a'u lava lea.", "I am thy salvation."]]},
  {num:4,words:[["Ia faamaina ma ia masiasi o e saili ia oti a'u;", "Let them be confounded and put to shame that seek after my soul:"], ["ia liutuaina ma ia taufaimamā i latou o e manatunatu i se mea e leaga ai a'u.", "let them be turned back and brought to confusion that devise my hurt."]]},
  {num:5,words:[["Ia avea i latou ia faapei o aputi o saito ona lelea i le matagi;", "Let them be as chaff before the wind:"], ["ia tuleia i latou e le agelu a Ieova.", "and let the angel of the LORD chase them."]]},
  {num:6,words:[["Ia pouliuli ma ia maseesee lo latou ala;", "Let their way be dark and slippery:"], ["ma ia tuliloaina i latou e le agelu a Ieova.", "and let the angel of the LORD persecute them."]]},
  {num:7,words:[["Auā na latou natia fua lo latou upega ia maua ai a'u i le lua,", "For without cause have they hid for me their net in a pit,"], ["na latou elia fua lava ia ou oti ai.", "which without cause they have digged for my soul."]]},
  {num:8,words:[["Ia oo ia te ia le malaia ua na le iloa;", "Let destruction come upon him at unawares;"], ["ia maua lava o ia i lona upega na ia natia;", "and let his net that he hath hid catch himself:"], ["ia paū lava o ia i lea lava malaia.", "into that very destruction let him fall."]]},
  {num:9,words:[["Ona fiafia lea o lo'u loto ia Ieova;", "And my soul shall be joyful in the LORD:"], ["e olioli lava i lana faaolataga.", "it shall rejoice in his salvation."]]},
  {num:10,words:[["E fai atu o'u ivi uma lava,", "All my bones shall say,"], ["Ieova e,", "LORD,"], ["o ai ea se tusa ma oe,", "who is like unto thee,"], ["o le ua laveai le tagata ua puapuagaina,", "which deliverest the poor from him that is too strong for him,"], ["mai ia te ia ua i ai le malosi e sili i lona;", "yea,"], ["e laveaiina foi le ua puapuagaina ma le mativa i le ua faoa ana mea?", "the poor and the needy from him that spoileth him?"]]},
  {num:11,words:[["Ua tutū mai ia te au o molimau faasaua,", "False witnesses did rise up;"], ["ua latou suesue ia te au i mea ou te lei iloa.", "they laid to my charge things that I knew not."]]},
  {num:12,words:[["Ua latou taui mai lo'u lelei i le leaga, e ausage ai lo'u agaga.", "They rewarded me evil for good to the spoiling of my soul."]]},
  {num:13,words:[["A e peitai o a'u nei,", "But as for me,"], ["na ou ofu i ie talatala ina o latou mama'i;", "when they were sick,"], ["na ou faatigaina a'u e a'u i le anapogi;", "my clothing was sackcloth: I humbled my soul with fasting;"], ["ma ua foi mai la'u tatalo i lo'u fatafata.", "and my prayer returned into mine own bosom."]]},
  {num:14,words:[["Na ou fealuai e peiseai o la'u uo o ia po o lo'u uso;", "I behaved myself as though he had been my friend or brother:"], ["na ou punou eleelea,", "I bowed down heavily,"], ["e pei o le ua faanoanoa i lona tinā.", "as one that mourneth for his mother."]]},
  {num:15,words:[["A ua latou fiafia ina ua ou setusetu;", "But in mine adversity they rejoiced,"], ["ma ua latou faapotopoto mai;", "and gathered themselves together:"], ["ua faapotopoto o e agatele e faatiga ia te au,", "yea, the abjects gathered themselves together against me,"], ["a ua ou le iloa;", "and I knew it not;"], ["na latou fesaeiai ia te au,", "they did tear me,"], ["ua le mapu lava.", "and ceased not:"]]},
  {num:16,words:[["Ua lilivau o latou nifo ia te au faatasi ma tagata faalematau,", "With hypocritical mockers in feasts,"], ["o e faianaga ia maua ai se potoi areto.", "they gnashed upon me with their teeth."]]},
  {num:17,words:[["Le Alii e,", "Lord,"], ["e te silasila i ai seia afea? Ia e faafoisia mai lo'u agaga mai a latou faatafunaga,", "how long wilt thou look on? rescue my soul from their destructions,"], ["ia laveaiina a'u ua toatasi mai leona.", "my darling from the lions."]]},
  {num:18,words:[["Ou te vivii atu ia te oe i le faapotopotoga tele,", "I will give thee thanks in the great congregation:"], ["ma pese atu ia te oe i luma o le nuu e toatele.", "I will praise thee among much people."]]},
  {num:19,words:[["Aua ne'i mitamita ia te au o e ita fua mai ia te au;", "Let not them that are mine enemies wrongfully rejoice over me:"], ["aua ne'i fegenoai mata o e 'ino'ino fua mai ia te au.", "neither let them wink with the eye that hate me without a cause."]]},
  {num:20,words:[["Auā e le tautala i le filemu i latou,", "For they speak not peace:"], ["a ua latou manatunatu i upu pepelo i e ua nofo fifilemu i le nuu.", "but they devise deceitful matters against them that are quiet in the land."]]},
  {num:21,words:[["Ua faamamaga foi o latou gutu ia te au,", "Yea, they opened their mouth wide against me,"], ["ua fai mai,", "and said, Aha,"], ["Ue! ue! ua vaai lava i ai o tatou mata.", "aha, our eye hath seen it."]]},
  {num:22,words:[["Ieova e,", "This thou hast seen,"], ["ua e silasila i ai;", "O LORD:"], ["aua ne'i e le tali mai;", "keep not silence:"], ["le Alii e,", "O Lord,"], ["aua e te vavamamao ma a'u.", "be not far from me."]]},
  {num:23,words:[["Lo'u Atua e,", "Stir up thyself,"], ["lo'u Alii e,", "and awake to my judgment,"], ["ia e tulai mai, ma e maleifua mai i lo'u faamasinoga,", "even unto my cause,"], ["ma la'u nei finauga.", "my God and my Lord."]]},
  {num:24,words:[["Ieova e,", "Judge me,"], ["lo'u Atua ia e faamasino mai ia te au e tusa ma lau amiotonu;", "O LORD my God, according to thy righteousness;"], ["aua ne'i latou mitamita mai ia te au.", "and let them not rejoice over me."]]},
  {num:25,words:[["Aua ne'i latou fai ifo i o latou loto,", "Let them not say in their hearts,"], ["Ue! o lo tatou lava manao lena;", "Ah,"], ["aua ne'i latou fai ane,", "so would we have it: let them not say,"], ["Ua foloina o ia e i tatou.", "We have swallowed him up."]]},
  {num:26,words:[["Ia taufaimamā ma ia masiasi faatasi i latou o e ua mitamita i lo'u tiga;", "Let them be ashamed and brought to confusion together that rejoice at mine hurt:"], ["ia faaofuina i latou i le mā ma le masiasi o e faasausili ia te au.", "let them be clothed with shame and dishonour that magnify themselves against me."]]},
  {num:27,words:[["Ia pepese ma taufaiolioli o e loto i la'u amiotonu;", "Let them shout for joy, and be glad,"], ["ia fai ane pea lava i latou,", "that favour my righteous cause: yea,"], ["Ia viia Ieova,", "let them say continually,"], ["o le ua finagalo ia manuia lana auauna.", "Let the LORD be magnified, which hath pleasure in the prosperity of his servant."]]},
  {num:28,words:[["E ta'uta'u atu foi lo'u laulaufaiva i lau amiotonu, ma vivii atu ai ia te oe i le aso atoa.", "And my tongue shall speak of thy righteousness and of thy praise all the day long."]]},
];
renderVerseSet(psa_ch_35_Verses, 'psa-ch35-verses');

var psa_ch_36_Verses = [
  {num:1,words:[["O le upu a le solitulafono ua i le tagata amio leaga, o loo i totonu o lo'u loto lea;", "The transgression of the wicked saith within my heart,"], ["e leai lava sona mata'u i le Atua.", "that there is no fear of God before his eyes."]]},
  {num:2,words:[["Auā o loo faaoleole o ia ia te ia lava,", "For he flattereth himself in his own eyes,"], ["ina ia iloa ana agasala ia inosia ai.", "until his iniquity be found to be hateful."]]},
  {num:3,words:[["O ana upu o le agasala ia ma le faa'ole'ole;", "The words of his mouth are iniquity and deceit: he hath left off to be wise,"], ["ua tuua e ia le faautauta ma le amio lelei.", "and to do good."]]},
  {num:4,words:[["O loo mafaufau o ia i le amio leaga i luga o lona moega;", "He deviseth mischief upon his bed;"], ["ua ia tumau i le ala e le lelei;", "he setteth himself in a way that is not good;"], ["na te le 'ino'ino i le leaga.", "he abhorreth not evil."]]},
  {num:5,words:[["Ieova e,", "Thy mercy,"], ["o i le lagi lou alofa;", "O LORD, is in the heavens;"], ["ua oo lava i ao lou faamaoni.", "and thy faithfulness reacheth unto the clouds."]]},
  {num:6,words:[["E pei o le atu mauga o le Atua lau amiotonu;", "Thy righteousness is like the great mountains;"], ["o le moana sausau au faamasino;", "thy judgments are a great deep:"], ["Ieova e,", "O LORD,"], ["ua ola ia te oe tagata atoa ma manu.", "thou preservest man and beast."]]},
  {num:7,words:[["Le Atua e, e maeu lava lou alofa,", "How excellent is thy lovingkindness,"], ["o le mea lea ua faatuatua ai tagata i le paolo o ou apaau.", "O God! therefore the children of men put their trust under the shadow of thy wings."]]},
  {num:8,words:[["E malilie i latou i mea lololo ua i lou fale;", "They shall be abundantly satisfied with the fatness of thy house;"], ["e te faainumia foi i latou i le vaitafe o au mea faafiafia.", "and thou shalt make them drink of the river of thy pleasures."]]},
  {num:9,words:[["Auā o loo ia te oe le puna o le ola;", "For with thee is the fountain of life:"], ["o lou malamalama matou te iloa ai le malamalama.", "in thy light shall we see light."]]},
  {num:10,words:[["Ia e faafualoa lou alofa i e ua iloa oe,", "O continue thy lovingkindness unto them that know thee;"], ["ma lau amiotonu i e ua faamaoni o latou loto.", "and thy righteousness to the upright in heart."]]},
  {num:11,words:[["Aua ne'i oo ia te au le vae o lē faamaualuga;", "Let not the foot of pride come against me,"], ["aua foi ne'i tulieseina a'u e lima o e ua amio leaga.", "and let not the hand of the wicked remove me."]]},
  {num:12,words:[["Ua pauu e ua fai amio leaga i lea lava mea;", "There are the workers of iniquity fallen:"], ["ua tuleia lava i latou,", "they are cast down,"], ["ua le toe mafai ai ona tutū i luga.", "and shall not be able to rise."]]},
];
renderVerseSet(psa_ch_36_Verses, 'psa-ch36-verses');

var psa_ch_37_Verses = [
  {num:1,words:[["Aau e te faameo ona o e amio leaga;", "Fret not thyself because of evildoers,"], ["aua foi e te losilosi ona o e fai mea leaga.", "neither be thou envious against the workers of iniquity."]]},
  {num:2,words:[["Auā e le pine ona seleeseina i latou e pei o le mutia;", "For they shall soon be cut down like the grass,"], ["e mamae i latou e pei o le vao mu'a lauolaola.", "and wither as the green herb."]]},
  {num:3,words:[["Ia e faatuatua ia Ieova,", "Trust in the LORD,"], ["ma e faia amio lelei;", "and do good;"], ["ia e nofo i le nuu,", "so shalt thou dwell in the land,"], ["ma tausisi i le faamaoni.", "and verily thou shalt be fed."]]},
  {num:4,words:[["Ia e fiafia lava oe ia Ieova,", "Delight thyself also in the LORD;"], ["ona foaiina lea e ia ia te oe o mea e manao i ai lou loto.", "and he shall give thee the desires of thine heart."]]},
  {num:5,words:[["Ia e tuuina atu lou ala ia Ieova,", "Commit thy way unto the LORD;"], ["ma faatuatua ia te ia,", "trust also in him;"], ["ona faia lava lea e ia.", "and he shall bring it to pass."]]},
  {num:6,words:[["E faaalia e ia lau amiotonu e pei o le malamalama,", "And he shall bring forth thy righteousness as the light,"], ["ma lou faamasinoga e pei o le aoauli.", "and thy judgment as the noonday."]]},
  {num:7,words:[["Ia e faalologo i luma o Ieova,", "Rest in the LORD,"], ["ma faamoemoe ia te ia;", "and wait patiently for him:"], ["aua e te faameo ona o le ua manuia lona ala,", "fret not thyself because of him who prospereth in his way,"], ["o le tagata ua faia togafiti leaga.", "because of the man who bringeth wicked devices to pass."]]},
  {num:8,words:[["Ina soia e te ita,", "Cease from anger,"], ["ma ia tuu lou tiga; aua e te faameo,", "and forsake wrath:"], ["ne'i e faia se mea leaga.", "fret not thyself in any wise to do evil."]]},
  {num:9,words:[["Auā e faaumatia o e fai amio leaga;", "For evildoers shall be cut off:"], ["a o e faatalitali ia Ieova,", "but those that wait upon the LORD,"], ["o i latou lava ia e fai mo latou le nuu.", "they shall inherit the earth."]]},
  {num:10,words:[["E toe itiiti,", "For yet a little while,"], ["ona leai lea o le tagata amio leaga;", "and the wicked shall not be:"], ["e te mafaufau foi i le mea sa i ai o ia,", "yea, thou shalt diligently consider his place,"], ["a e leai lava.", "and it shall not be."]]},
  {num:11,words:[["A o e agamalu, e fai mo latou le nuu;", "But the meek shall inherit the earth;"], ["e faafiafia foi i latou ia te i latou ona o le manuia e tele.", "and shall delight themselves in the abundance of peace."]]},
  {num:12,words:[["Ua manatunatu le tagata amio leaga i se mea e leaga ai le tagata amiotonu;", "The wicked plotteth against the just,"], ["ua lilivau foi ona nifo ia te ia.", "and gnasheth upon him with his teeth."]]},
  {num:13,words:[["E soisoi le Alii ia te ia;", "The Lord shall laugh at him:"], ["auā ua na silafia o le a sau lona aso.", "for he seeth that his day is coming."]]},
  {num:14,words:[["Ua fese'i ae e tagata amio leaga a latou pelu,", "The wicked have drawn out the sword,"], ["ua lolou a latou aufana,", "and have bent their bow,"], ["ia oti ai e ua puapuagaina ma e matitiva,", "to cast down the poor and needy,"], ["ina ia fasioti i e ua sa'o a latou amio.", "and to slay such as be of upright conversation."]]},
  {num:15,words:[["E oo a latou pelu i o latou lava fatu,", "Their sword shall enter into their own heart,"], ["e gauia foi a latou aufana.", "and their bows shall be broken."]]},
  {num:16,words:[["O le mea itiiti ua i le tagata amiotonu, e sili ona lelei lea i oloa e tele o e amio leaga e toatele.", "A little that a righteous man hath is better than the riches of many wicked."]]},
  {num:17,words:[["Auā e gauia lima o e amio leaga;", "For the arms of the wicked shall be broken:"], ["a e taofiina ae e Ieova o e amiotonu.", "but the LORD upholdeth the righteous."]]},
  {num:18,words:[["O loo silafia e Ieova aso o e ua sao a latou amio;", "The LORD knoweth the days of the upright:"], ["e faavavau lava lo latou tofi.", "and their inheritance shall be for ever."]]},
  {num:19,words:[["E le mamā i latou i le aso vale;", "They shall not be ashamed in the evil time:"], ["e maoona foi i latou i ona po e i ai le oge.", "and in the days of famine they shall be satisfied."]]},
  {num:20,words:[["Auā e fano lava o e amio leaga;", "But the wicked shall perish,"], ["o e ita foi ia Ieova,", "and the enemies of the LORD shall be as the fat of lambs:"], ["e pei o le mea sili o i tamai mamoe i latou; e mavae atu i latou,", "they shall consume;"], ["e mavae atu e pei o le asu.", "into smoke shall they consume away."]]},
  {num:21,words:[["Ua no mea le tagata amio leaga,", "The wicked borroweth,"], ["a e le toe taui atu ai;", "and payeth not again:"], ["a o le tagata amiotonu, ua amio alofa ia,", "but the righteous sheweth mercy,"], ["ma foai fua ana mea .", "and giveth."]]},
  {num:22,words:[["Auā o e ua faamanuia e ia, e fai mo latou le nuu;", "For such as be blessed of him shall inherit the earth;"], ["a o e ua faafanoina e ia, e faaumatia i latou.", "and they that be cursed of him shall be cut off."]]},
  {num:23,words:[["E mau ia Ieova le savali o le tagata;", "The steps of a good man are ordered by the LORD:"], ["e fiafia foi o ia i lona ala.", "and he delighteth in his way."]]},
  {num:24,words:[["Afai e paū ia,", "Though he fall,"], ["e le taatia pea ia i lalo;", "he shall not be utterly cast down:"], ["auā e taofia lona lima e Ieova.", "for the LORD upholdeth him with his hand."]]},
  {num:25,words:[["Ua ou toeaina a'u nei,", "I have been young,"], ["sa a'u taulealea;", "and now am old;"], ["a ou te lei iloa se tagata amiotonu na lafoaiina,", "yet have I not seen the righteous forsaken,"], ["po o ana fanau ua 'aiisi i latou.", "nor his seed begging bread."]]},
  {num:26,words:[["Ua amio alofa ia i aso uma lava;", "He is ever merciful,"], ["ua avatu e ia ana mea i e nono mai;", "and lendeth;"], ["ua manuia foi ana fanau.", "and his seed is blessed."]]},
  {num:27,words:[["Ia e 'alo ese i mea leaga,", "Depart from evil,"], ["ma e faia mea lelei;", "and do good;"], ["e te mau ai e faavavau.", "and dwell for evermore."]]},
  {num:28,words:[["Auā e fiafia Ieova i le faamasinoga,", "For the LORD loveth judgment,"], ["na te le tuua foi ona tagata amio Atua;", "and forsaketh not his saints;"], ["e leoleoina i latou e faavavau;", "they are preserved for ever:"], ["a e faaumatia fanau a e amio leaga.", "but the seed of the wicked shall be cut off."]]},
  {num:29,words:[["E fai lava le nuu mo tagata amiotonu,", "The righteous shall inherit the land,"], ["e nonofo ai pea i latou.", "and dwell therein for ever."]]},
  {num:30,words:[["O le gutu o le tagata amiotonu e tautala lea i le poto,", "The mouth of the righteous speaketh wisdom,"], ["e tautala foi lona laulaufaiva i le faamasinoga.", "and his tongue talketh of judgment."]]},
  {num:31,words:[["O loo i lona loto le tulafono a lona Atua,", "The law of his God is in his heart;"], ["e le mapeva foi ona vae.", "none of his steps shall slide."]]},
  {num:32,words:[["Ua lamalama le tagata amio leaga i le tagata amiotonu,", "The wicked watcheth the righteous,"], ["ua ia sailiili foi e fasioti ia te ia.", "and seeketh to slay him."]]},
  {num:33,words:[["E le tuuna o ia e Ieova i lona lima;", "The LORD will not leave him in his hand,"], ["na te le faasala foi ia te ia pe a faamasinoina o ia.", "nor condemn him when he is judged."]]},
  {num:34,words:[["Ia e faatalitali ia Ieova,", "Wait on the LORD,"], ["ma e tausi i lona ala;", "and keep his way,"], ["ona faaeaina lea o oe e ia ina ia fai mou le nuu;", "and he shall exalt thee to inherit the land: when the wicked are cut off,"], ["e te iloa atu le fanoga o e amio leaga.", "thou shalt see it."]]},
  {num:35,words:[["Na ou iloa atu le tagata amio leaga ua faasaua, ua faateleina foi o ia e pei o le laau ua tupu i lona lava eleele,", "I have seen the wicked in great power,"], ["ma tauluulu ola.", "and spreading himself like a green bay tree."]]},
  {num:36,words:[["A ua mavae ese o ia,", "Yet he passed away,"], ["faauta foi,", "and, lo,"], ["ua leai;", "he was not:"], ["na ou sailiili foi ia te ia,", "yea, I sought him,"], ["a ua le iloa lava.", "but he could not be found."]]},
  {num:37,words:[["Ina mafaufau ia i le ua sao lana amio,", "Mark the perfect man,"], ["ma vaavaai i le ua amiotonu;", "and behold the upright:"], ["auā o le iuga o lea tagata o le manuia lava lea.", "for the end of that man is peace."]]},
  {num:38,words:[["A e fano faatasi o e solitulafono;", "But the transgressors shall be destroyed together:"], ["o le iuga o e amio leaga o le malaia lava lea.", "the end of the wicked shall be cut off."]]},
  {num:39,words:[["O loo mai ia Ieova le faaolataga o e amiotonu;", "But the salvation of the righteous is of the LORD:"], ["o ia lava lo latou malosi i ona po o le puapuaga.", "he is their strength in the time of trouble."]]},
  {num:40,words:[["E fesoasoani foi Ieova ia te i latou,", "And the LORD shall help them,"], ["ma laveai ia te i latou;", "and deliver them:"], ["e laveaiina lava i latou e ia ai tagata amio leaga,", "he shall deliver them from the wicked,"], ["na te faaolaina foi i latou,", "and save them,"], ["auā ua latou faatuatua ia te ia.", "because they trust in him."]]},
];
renderVerseSet(psa_ch_37_Verses, 'psa-ch37-verses');

var psa_ch_38_Verses = [
  {num:1,words:[["Ieova e,", "O LORD,"], ["aua e te aoai mai ia te au i lou toasa;", "rebuke me not in thy wrath:"], ["aua foi e te sasa ia te au i lou toasa tele.", "neither chasten me in thy hot displeasure."]]},
  {num:2,words:[["Auā ua o au u fanafana i totonu ia te au,", "For thine arrows stick fast in me,"], ["ua mamafa foi lou aao i luga ia te au.", "and thy hand presseth me sore."]]},
  {num:3,words:[["E leai se itu o lo'u tino ua sao ona o lo'u toatamai;", "There is no soundness in my flesh because of thine anger;"], ["e leai se filemu i o'u ivi ona o a'u agasala.", "neither is there any rest in my bones because of my sin."]]},
  {num:4,words:[["Auā ua oo lava a'u agasala i luga o lo'u ulu; e pei o se avega mamafa,", "For mine iniquities are gone over mine head:"], ["ua mafatia ai lava a'u.", "as an heavy burden they are too heavy for me."]]},
  {num:5,words:[["Ua elosia o'u manua; ua alu ae le alou ona o lo'u valea.", "My wounds stink and are corrupt because of my foolishness."]]},
  {num:6,words:[["Ua faano'uno'uina a'u;", "I am troubled;"], ["ua ou matuā punou lava i lalo;", "I am bowed down greatly;"], ["ou te fealuai ma le eleelea i le aso atoa.", "I go mourning all the day long."]]},
  {num:7,words:[["Auā ua tigaina lo'u manava i le ma'i vevela;", "For my loins are filled with a loathsome disease:"], ["e leai se itu o lo'u tino ua sao.", "and there is no soundness in my flesh."]]},
  {num:8,words:[["Ua ou matuā vaivai, ua ou momomo lava;", "I am feeble and sore broken:"], ["ou te faataio ona o le oi o lo'u loto.", "I have roared by reason of the disquietness of my heart."]]},
  {num:9,words:[["Le Alii e,", "Lord,"], ["o loo i ou luma lo'u manao uma;", "all my desire is before thee;"], ["e le lilo foi ia te oe lo'u mapuitiga.", "and my groaning is not hid from thee."]]},
  {num:10,words:[["Ua sapotuvale lo'u fatu manava,", "My heart panteth,"], ["ua te'a lo'u malosi;", "my strength faileth me:"], ["o le malamalama foi sa i o'u mata,", "as for the light of mine eyes,"], ["ua le ia te au lea.", "it also is gone from me."]]},
  {num:11,words:[["Ua tutū mamao a'u uo ma a'u aumea mamae i lo'u malaia;", "My lovers and my friends stand aloof from my sore;"], ["ua tutū mamao foi o i latou matou te tuaoi.", "and my kinsmen stand afar off."]]},
  {num:12,words:[["Ua fai mailei o e saili ia ou oti;", "They also that seek after my life lay snares for me:"], ["o i latou foi o e sailiili ia leaga ai a'u o loo tautala i mea leaga,", "and they that seek my hurt speak mischievous things,"], ["ma mafaufau i mea faa'ole'ole i le aso atoa.", "and imagine deceits all the day long."]]},
  {num:13,words:[["Peitai a'u nei,", "But I,"], ["ua faapei o se tagata tutuli,", "as a deaf man,"], ["ua ou le lagona; po o sē gūgū,", "heard not;"], ["ua le tautala lona gutu.", "and I was as a dumb man that openeth not his mouth."]]},
  {num:14,words:[["O a'u foi e pei se tagata ua le lagona,", "Thus I was as a man that heareth not,"], ["e leai foi se upu finau i lona gutu.", "and in whose mouth are no reproofs."]]},
  {num:15,words:[["Auā Ieova e,", "For in thee,"], ["ou te faamoemoe ia te oe;", "O LORD,"], ["o oe le Alii e,", "do I hope:"], ["lo'u Atua,", "thou wilt hear,"], ["e te tali mai ai.", "O Lord my God."]]},
  {num:16,words:[["Auā na ou faapea,", "For I said, Hear me,"], ["ne'i latou mitamita mai ia te au;", "lest otherwise they should rejoice over me:"], ["pe a mapeva lo'u vae latou te faasausili mai ia te au.", "when my foot slippeth, they magnify themselves against me."]]},
  {num:17,words:[["Auā o a'u nei, e toe ina ou paū;", "For I am ready to halt,"], ["ua lumanai pea ia te au lo'u tiga.", "and my sorrow is continually before me."]]},
  {num:18,words:[["Auā ou te ta'uta'uina atu la'u amio leaga;", "For I will declare mine iniquity;"], ["ou te atuatuvale ona o la'u agasala.", "I will be sorry for my sin."]]},
  {num:19,words:[["A ua tagata ola i latou o e ita mai ia te au,", "But mine enemies are lively,"], ["ua malolosi i latou;", "and they are strong:"], ["ua faatoateleina o e 'ino'ino fua mai ia te au.", "and they that hate me wrongfully are multiplied."]]},
  {num:20,words:[["O i latou foi o e taui atu le lelei i le leaga, ua latou fai a'u mo latou fili,", "They also that render evil for good are mine adversaries;"], ["auā ou te tausisi i mea lelei.", "because I follow the thing that good is."]]},
  {num:21,words:[["Ieova e,", "Forsake me not,"], ["aua ne'i e tuuna mai a'u;", "O LORD:"], ["lo'u Atua e,", "O my God,"], ["aua e te vavamamao ma a'u.", "be not far from me."]]},
  {num:22,words:[["Le Alii e, lo'u faaolataga,", "Make haste to help me,"], ["ia e faataalise mai e fesoasoani mai ia te au.", "O Lord my salvation."]]},
];
renderVerseSet(psa_ch_38_Verses, 'psa-ch38-verses');

var psa_ch_39_Verses = [
  {num:1,words:[["Na ou faapea,", "I said,"], ["Ou te faaeteete i o'u ala,", "I will take heed to my ways,"], ["ina ne'i ou agasala i lo'u laulaufaiva;", "that I sin not with my tongue:"], ["ou te faaeteete i lo'u gutu,", "I will keep my mouth with a bridle,"], ["ou te taofiofi a o i o'u luma tagata amio leaga.", "while the wicked is before me."]]},
  {num:2,words:[["Na ou faalologo,", "I was dumb with silence,"], ["ua ou le gagana;", "I held my peace,"], ["na ou le tautala lava i mea lelei;", "even from good;"], ["ona faagaeetia ai lea o lo'u tiga.", "and my sorrow was stirred."]]},
  {num:3,words:[["Sa vevela lava lo'u loto i totonu ia te au;", "My heart was hot within me,"], ["o lo'u mafaufau foi ua mu ai le afi;", "while I was musing the fire burned:"], ["ona tautala ai lea o lo'u laulaufaiva.", "then spake I with my tongue,"]]},
  {num:4,words:[["Ieova e,", "LORD,"], ["ia e faailoa mai ia te au lo'u iuga,", "make me to know mine end,"], ["pe se a foi le fua o o'u aso;", "and the measure of my days, what it is;"], ["ina ia ou iloa pe fia ni aso ua toe ia te au.", "that I may know how frail I am."]]},
  {num:5,words:[["Faauta, ua e faia o'u aso e pei o le lautele o le alofilima;", "Behold,"], ["o lo'u olaga foi, ua peiseai ua leai i ou luma;", "thou hast made my days as an handbreadth;"], ["e moni,", "and mine age is as nothing before thee:"], ["o tagata uma a o malolosi e matuā faatauvaa lava i latou, Selā.", "verily every man at his best state is altogether vanity. Selah."]]},
  {num:6,words:[["E moni, o loo savavali tagata e peiseai o se ata;", "Surely every man walketh in a vain shew:"], ["e moni,", "surely they are disquieted in vain:"], ["ua faaatuatuvaleina fua lava i latou;", "he heapeth up riches,"], ["ua faafaulai e ia le oloa , a e le iloa e ia po o ai e faapotopotoina ai.", "and knoweth not who shall gather them."]]},
  {num:7,words:[["O lenei,", "And now,"], ["le Alii e,", "Lord,"], ["se a ea se mea ou te faatalitali i ai? O loo ia te oe lo'u lava faamoemoe.", "what wait I for? my hope is in thee."]]},
  {num:8,words:[["Ia e laveai mai ia te au ai o'u solitulafono uma;", "Deliver me from all my transgressions:"], ["aua ne'i faalumaina a'u e le vale.", "make me not the reproach of the foolish."]]},
  {num:9,words:[["Ou te faalologo lava a'u,", "I was dumb,"], ["ou te le gagana;", "I opened not my mouth;"], ["auā o oe lava na e faia.", "because thou didst it."]]},
  {num:10,words:[["Ia e taofia lau ta ia te au;", "Remove thy stroke away from me:"], ["ua faaumatia a'u nei i le sasa mai o lou aao.", "I am consumed by the blow of thine hand."]]},
  {num:11,words:[["A e sasa i le tagata i aoaiga ona o le agasala, ona e faaumatia ai lea o lona lelei,", "When thou with rebukes dost correct man for iniquity,"], ["e pei o le mogamoga ona atia o le ofu;", "thou makest his beauty to consume away like a moth:"], ["e moni, o tagata uma e faatauvaa lava i latou.", "surely every man is vanity."], ["Selā.", "Selah."]]},
  {num:12,words:[["Ieova e,", "Hear my prayer,"], ["ia e faafofoga mai i la'u tatalo,", "O LORD,"], ["ma liliu mai ou fofoga i la'u alaga;", "and give ear unto my cry; hold not thy peace at my tears:"], ["aua ne'i e le tali mai i la'u tagi;", "for I am a stranger with thee,"], ["auā ou te se tagata ese a'u i ou luma ma le āumau,", "and a sojourner,"], ["e pei o o'u tamā uma lava.", "as all my fathers were."]]},
  {num:13,words:[["Ia 'alo ese ou fofoga ia te au,", "O spare me,"], ["seia ou malolo ane manū ou te lei alu ese,", "that I may recover strength, before I go hence,"], ["ma ua leai o a'u.", "and be no more."]]},
];
renderVerseSet(psa_ch_39_Verses, 'psa-ch39-verses');

var psa_ch_40_Verses = [
  {num:1,words:[["Na ou matuā faatalitali lava ia Ieova;", "I waited patiently for the LORD;"], ["ona faasaga mai ai lea o ia ia te au,", "and he inclined unto me,"], ["ua faafofoga mai foi o ia i la'u alaga.", "and heard my cry."]]},
  {num:2,words:[["Na ia aveina ae a'u ai le lua e malaia ai,", "He brought me up also out of an horrible pit,"], ["ma le mea matuā palapalā;", "out of the miry clay,"], ["na faatuina foi o'u vae i luga o le papa,", "and set my feet upon a rock,"], ["ua faamautuina ai o'u savali.", "and established my goings."]]},
  {num:3,words:[["Ua tuuina mai e ia le pese fou i lo'u gutu,", "And he hath put a new song in my mouth,"], ["o le viiga i lo tatou Atua;", "even praise unto our God:"], ["e iloa ai e le toatele,", "many shall see it,"], ["e matatau foi i latou,", "and fear,"], ["ma latou faatuatua ia Ieova.", "and shall trust in the LORD."]]},
  {num:4,words:[["Amuia le tagata o lē faatuatua ia Ieova,", "Blessed is that man that maketh the LORD his trust,"], ["a e le faasaga i e faamaualuluga,", "and respecteth not the proud,"], ["ma e ua liliu ane i mea pepelo.", "nor such as turn aside to lies."]]},
  {num:5,words:[["Ieova e,", "Many,"], ["lo'u Atua,", "O LORD my God,"], ["e tele lava mea ua e faia,", "are thy wonderful works which thou hast done,"], ["o ou vavega ma ou manatu ia te i matou,", "and thy thoughts which are to us-ward:"], ["e le mafai ona laulauina atu ai ia te oe;", "they cannot be reckoned up in order unto thee:"], ["ou te fia faailoa ma tautala i ai,", "if I would declare and speak of them,"], ["a e le mafaitaulia lava.", "they are more than can be numbered."]]},
  {num:6,words:[["E te le finagalo i le taulaga ma le taulaga i mea e 'ai;", "Sacrifice and offering thou didst not desire;"], ["ua elia e oe o'u taliga;", "mine ears hast thou opened:"], ["o le taulaga mu ma le taulaga mo le agasala e te lei fetalai mai ai.", "burnt offering and sin offering hast thou not required."]]},
  {num:7,words:[["Ona ou fai ane ai lea,", "Then said I,"], ["Faauta,", "Lo, I come:"], ["ou te alu atu;", "in the volume of the book it is written of me,"]]},
  {num:8,words:[["ua tusia a'u i le tusi taai,", "I delight to do thy will,"], ["Lo'u Atua e,", "O my God:"], ["ou te fiafia e fai lou finagalo;", "yea,"], ["o loo i totonu lava ia te au lau tulafono.", "thy law is within my heart."]]},
  {num:9,words:[["Ua ou tala'i le amiotonu i le faapotopotoga tele;", "I have preached righteousness in the great congregation:"], ["faauta,", "lo,"], ["ou te lei taofia lava o'u laugutu,", "I have not refrained my lips,"], ["Ieova e,", "O LORD,"], ["ua e silafia lava.", "thou knowest."]]},
  {num:10,words:[["Ou te lei natia lava i lo'u loto lau amiotonu;", "I have not hid thy righteousness within my heart;"], ["ua ou ta'uina atu lou faamaoni ma lau faaolataga;", "I have declared thy faithfulness and thy salvation:"], ["ou te lei faalilolilo lou alofa ma le mea moni mai ia te oe i le faapotopotoga tele.", "I have not concealed thy lovingkindness and thy truth from the great congregation."]]},
  {num:11,words:[["Ieova e,", "Withhold not thou thy tender mercies from me,"], ["aua e te taofi e oe lou alofa mutimuti vale ia te au;", "O LORD:"], ["ia leoleoina pea lava a'u e lou alofa ma lou faamaoni.", "let thy lovingkindness and thy truth continually preserve me."]]},
  {num:12,words:[["Auā ua siosiomia a'u i mea leaga e le mafaitaulia;", "For innumerable evils have compassed me about:"], ["ua maua mai a'u e a'u agasala,", "mine iniquities have taken hold upon me,"], ["o lea ou te le mafaia ai ona vaai;", "so that I am not able to look up;"], ["ua sili ia ona tele i o'u lauulu;", "they are more than the hairs of mine head:"], ["ua matuā faavaivai ai lo'u loto.", "therefore my heart faileth me."]]},
  {num:13,words:[["Ieova e,", "Be pleased,"], ["ia e finagalo e laveai mai ia te au;", "O LORD,"], ["Ieova e,", "to deliver me: O LORD,"], ["ia vave ona e fesoasoani mai ia te au.", "make haste to help me."]]},
  {num:14,words:[["Ia taufaimamā ma ia masiasi faatasi e ua fia fasioti ia te au;", "Let them be ashamed and confounded together that seek after my soul to destroy it;"], ["ia liutuaina ma faamaina e ua mananao i se mea ia leaga ai a'u.", "let them be driven backward and put to shame that wish me evil."]]},
  {num:15,words:[["Ia fememeai ona o lo latou mā o e fai mai ia te au,", "Let them be desolate for a reward of their shame that say unto me, Aha,"], ["Ue! Ue!", "aha."]]},
  {num:16,words:[["Ia olioli ma fiafia ia te oe o i latou uma o e sailiili ia te oe;", "Let all those that seek thee rejoice and be glad in thee:"], ["ia fai ane pea i latou o e fiafia i lau faaolataga,", "let such as love thy salvation say continually,"], ["Ia viia Ieova.", "The LORD be magnified."]]},
  {num:17,words:[["A o a'u nei,", "But I am poor and needy;"], ["ua ou puapuagatia ma ou mativa;", "yet the Lord thinketh upon me:"], ["e manatua mai a'u e le Alii; o oe lava lo'u fesoasoani ma lo'u faaola;", "thou art my help and my deliverer;"], ["lo'u Atua e,", "make no tarrying,"], ["aua lava e te tuai mai.", "O my God."]]},
];
renderVerseSet(psa_ch_40_Verses, 'psa-ch40-verses');

var psa_ch_41_Verses = [
  {num:1,words:[["Amuia le tagata ua manatua le ua mativa;", "Blessed is he that considereth the poor:"], ["e faasaoina o ia e Ieova i le aso vale.", "the LORD will deliver him in time of trouble."]]},
  {num:2,words:[["E tausia o ia e Ieova ma faaolaina;", "The LORD will preserve him,"], ["e manuia foi o ia i le nuu;", "and keep him alive; and he shall be blessed upon the earth:"], ["e te le tuua foi o ia i le manao o e ita ia te ia.", "and thou wilt not deliver him unto the will of his enemies."]]},
  {num:3,words:[["E lagolago ane Ieova ia te ia i le taotoga o lona ma'i;", "The LORD will strengthen him upon the bed of languishing:"], ["e te liua lona moega uma lava i lona ma'i.", "thou wilt make all his bed in his sickness."]]},
  {num:4,words:[["Na ou fai atu,", "I said,"], ["Ieova e,", "LORD,"], ["ia e alofa mai ia te au;", "be merciful unto me:"], ["ia e faamalolo i lo'u agaga;", "heal my soul;"], ["auā ua ou agasala atu ia te oe.", "for I have sinned against thee."]]},
  {num:5,words:[["O e ita mai ia te au, ua latou tautala i se mea e leaga ai au,", "Mine enemies speak evil of me,"], ["ua faapea ane ,", "When shall he die,"], ["Po o afea e oti ai o ia, ma galo ai lona igoa?", "and his name perish?"]]},
  {num:6,words:[["Afai foi e sau o ia e asiasi mai ia te au ,", "And if he come to see me,"], ["ua tautala i le pepelo,", "he speaketh vanity:"], ["ua faaputuina e lona loto o mea leaga mo ia;", "his heart gathereth iniquity to itself; when he goeth abroad,"], ["ona alu ai lea o ia i fafo ua tautala a'i.", "he telleth it."]]},
  {num:7,words:[["Ua musumusu faatasi o i latou uma o e 'ino'ino mai ia te au i se mea e oo ia te au;", "All that hate me whisper together against me:"], ["ma latou manatunatu i se mea e leaga ai a'u.", "against me do they devise my hurt."]]},
  {num:8,words:[["Ua faapea i latou ,", "An evil disease,"], ["Ua oo lava le mea matuā leaga ia te ia;", "say they,"], ["ua taoto ia,", "cleaveth fast unto him:"], ["e le toe tu i luga.", "and now that he lieth he shall rise up no more."]]},
  {num:9,words:[["O le tagata foi o la'u uo,", "Yea,"], ["o le na ou faatuatua i ai,", "mine own familiar friend,"], ["na 'ai la'u areto,", "in whom I trusted, which did eat of my bread,"], ["ua aa mai o ia ia te au i lona mulivae.", "hath lifted up his heel against me."]]},
  {num:10,words:[["A o oe,", "But thou,"], ["Ieova e,", "O LORD,"], ["ia e alofa mai ia te au,", "be merciful unto me,"], ["ma faatu ia te au,", "and raise me up,"], ["ina ia a'u taui atu ia te i latou.", "that I may requite them."]]},
  {num:11,words:[["O le mea lea ua ou iloa ai e te finagalo mălie mai ia te au,", "By this I know that thou favourest me,"], ["ina ua le mitamita mai ia te au o lē ita mai ia te au.", "because mine enemy doth not triumph over me."]]},
  {num:12,words:[["A o a'u nei,", "And as for me,"], ["e te taofia a'u i luga i la'u amio sao;", "thou upholdest me in mine integrity,"], ["e te faatuina foi a'u i ou luma e faavavau.", "and settest me before thy face for ever."]]},
  {num:13,words:[["Ia faafetaia Ieova,", "Blessed be the LORD God of Israel from everlasting,"], ["le Atua o Isaraelu,", "and to everlasting. Amen,"], ["mai le vavau e oo lava i le faavavau. Amene ma Amene.", "and Amen."]]},
];
renderVerseSet(psa_ch_41_Verses, 'psa-ch41-verses');

var psa_ch_42_Verses = [
  {num:1,words:[["Le Atua e,", "As the hart panteth after the water brooks,"], ["e faapei ona naunau o le aila i vaitafe,", "so panteth my soul after thee,"], ["o loo faapea ona naunau o lo'u agaga ia te oe.", "O God."]]},
  {num:2,words:[["Ua fia inu lo'u agaga i le Atua,", "My soul thirsteth for God,"], ["o le Atua soifua;", "for the living God:"], ["o afea ea ou te alu atu ai ia iloa ai a'u i luma o le Atua?", "when shall I come and appear before God?"]]},
  {num:3,words:[["Ua faia o'u loimata ma'u mea e 'ai i ao ma po,", "My tears have been my meat day and night,"], ["a o fai mai pea i latou,", "while they continually say unto me,"], ["O ifea ea lou Atua?", "Where is thy God?"]]},
  {num:4,words:[["Ou te manatunatu i ia mea,", "When I remember these things,"], ["ona faavaivai ai lea o lo'u loto i totonu ia te au;", "I pour out my soul in me:"], ["auā sa matou o faatasi ma le toatele,", "for I had gone with the multitude, I went with them to the house of God,"], ["ma matou savavali i le fale o le Atua ma le leo fiafia ma le viiga,", "with the voice of joy and praise,"], ["o le toatele o e fai le tausamiga.", "with a multitude that kept holyday."]]},
  {num:5,words:[["Lo'u agaga e,", "Why art thou cast down,"], ["se a ea le mea ua e faanoanoa ai, ma ē atuatuvale ai i totonu ia te au? Ia e faamoemoe i le Atua,", "O my soul? and why art thou disquieted in me? hope thou in God:"], ["auā ou te toe vivii ia te ia ona o le faaolataga mai ona luma.", "for I shall yet praise him for the help of his countenance."]]},
  {num:6,words:[["Lo'u Atua e,", "O my God,"], ["ua faanoanoa lo'u agaga i totonu ia te au;", "my soul is cast down within me:"], ["o le mea lea ou te manatunatu ai ia te oe i le nuu o Ioritana,", "therefore will I remember thee from the land of Jordan,"], ["ma le atu Heremoni,", "and of the Hermonites,"], ["ma le mauga itiiti.", "from the hill Mizar."]]},
  {num:7,words:[["O loo fevalaauai lea moana ma lea moana i le vāgana mai o ou afu;", "Deep calleth unto deep at the noise of thy waterspouts:"], ["ua felaaiai mai i luga ia te au ou galu ma ou peau uma lava.", "all thy waves and thy billows are gone over me."]]},
  {num:8,words:[["E pule mai Ieova lona alofa ia te au i le ao,", "Yet the LORD will command his lovingkindness in the daytime,"], ["e ia te au foi le pese ia te ia i le po,", "and in the night his song shall be with me,"], ["o le tatalo i le Atua o lo'u ola.", "and my prayer unto the God of my life."]]},
  {num:9,words:[["Ou te fai atu i le Atua lo'u papa, Se a le mea ua e faagalogalo ai ia te au? Se a le mea ou te fealuai ai ma le eleelea,", "I will say unto God my rock,"], ["ona o le saua mai o le ita mai?", "Why hast thou forgotten me? why go I mourning because of the oppression of the enemy?"]]},
  {num:10,words:[["Ua momomo o'u ivi i le faalumaina o a'u e i latou o e ita mai ia te au,", "As with a sword in my bones,"], ["i lo latou fai mai pea,", "mine enemies reproach me; while they say daily unto me,"], ["O ifea ea lou Atua?", "Where is thy God?"]]},
  {num:11,words:[["Lo'u agaga e,", "Why art thou cast down,"], ["se a ea le mea ua e faanoanoa ai? Ua atuatuvale foi oe i totonu ia te au i se a? Ia e faamoemoe i le Atua,", "O my soul? and why art thou disquieted within me? hope thou in God:"], ["auā ou te toe vivii ia te ia,", "for I shall yet praise him, who is the health of my countenance,"], ["o lo'u faaolataga ia ma lo'u Atua.", "and my God."]]},
];
renderVerseSet(psa_ch_42_Verses, 'psa-ch42-verses');

var psa_ch_43_Verses = [
  {num:1,words:[["Le Atua e,", "Judge me,"], ["ia e faamasino ia te au,", "O God,"], ["ma ia e faia la'u finauga i le nuu faalealofa;", "and plead my cause against an ungodly nation:"], ["ia e laveai mai ia te au ai le tagata faa'ole'ole ma le amio leaga.", "O deliver me from the deceitful and unjust man."]]},
  {num:2,words:[["Auā o oe o le Atua ou te malosi ai; se a le mea ua e lafoai mai ai ia te au? Se a le mea ou te fealuai ai ma le eleelea,", "For thou art the God of my strength:"], ["ona o le saua o le ua ita mai?", "why dost thou cast me off? why go I mourning because of the oppression of the enemy?"]]},
  {num:3,words:[["Ia e aauina lou malamalama ma lau upu moni,", "O send out thy light and thy truth:"], ["ia la ta'ita'i mai ia te au,", "let them lead me; let them bring me unto thy holy hill,"], ["ia la faaoo ia te au i lou mauga paia ma lou malumalu.", "and to thy tabernacles."]]},
  {num:4,words:[["Ona ou alu atu ai lea i le fata faitaulaga o le Atua,", "Then will I go unto the altar of God,"], ["o le Atua ou te matuā fiafia i ai;", "unto God my exceeding joy:"], ["le Atua e,", "yea, upon the harp will I praise thee,"], ["lo'u Atua ou te vivii atu ia te oe i le kitara.", "O God my God."]]},
  {num:5,words:[["Lo'u agaga e,", "Why art thou cast down,"], ["se a ea le mea ua e faanoanoa ai? Ua atuatuvale foi oe i totonu ia te au i se a? Ia e faamoemoe i le Atua,", "O my soul? and why art thou disquieted within me? hope in God:"], ["auā ou te toe vivii ia te ia,", "for I shall yet praise him, who is the health of my countenance,"], ["o lo'u faaolataga ia ma lo'u Atua.", "and my God."]]},
];
renderVerseSet(psa_ch_43_Verses, 'psa-ch43-verses');

var psa_ch_44_Verses = [
  {num:1,words:[["Le Atua e,", "We have heard with our ears, O God,"], ["ua faalogo o matou taliga,", "our fathers have told us,"], ["ua talatalaina e o matou tamā ia te i matou le galuega na e faia i ona po sa i ai latou i aso anamua.", "what work thou didst in their days, in the times of old."]]},
  {num:2,words:[["O oe lava na e tulia i lou aao o nuu ese,", "How thou didst drive out the heathen with thy hand,"], ["a e totōina ai i latou;", "and plantedst them;"], ["ua e faatigaina foi ia nuu,", "how thou didst afflict the people,"], ["a ua e faatuputeleina i latou.", "and cast them out."]]},
  {num:3,words:[["Auā e lei maua e i latou le fanua i a latou pelu,", "For they got not the land in possession by their own sword,"], ["e lei faaolaina foi i latou i o latou lima;", "neither did their own arm save them:"], ["a o lou aao taumatau,", "but thy right hand,"], ["o lou aao lava,", "and thine arm,"], ["ma le malamalama o ou fofoga,", "and the light of thy countenance,"], ["auā na e fiafia ia te i latou.", "because thou hadst a favour unto them."]]},
  {num:4,words:[["Le Atua e,", "Thou art my King,"], ["o oe lava lo'u Tupu;", "O God:"], ["ia e fetalai ia faaolaina Iakopo.", "command deliverances for Jacob."]]},
  {num:5,words:[["O oe lava matou te tulei ai i e ita mai ia te i matou;", "Through thee will we push down our enemies:"], ["o lou suafa foi matou te soli ai i e laga mai ia te i matou.", "through thy name will we tread them under that rise up against us."]]},
  {num:6,words:[["Auā ou te le faatuatua i la'u aufana,", "For I will not trust in my bow,"], ["e le faaolaina foi a'u i la'u pelu.", "neither shall my sword save me."]]},
  {num:7,words:[["Auā ua e faaola lava ia te i matou i e ita mai ia te i matou;", "But thou hast saved us from our enemies,"], ["ua e faamasiasi foi i e 'ino'ino mai ia te i matou.", "and hast put them to shame that hated us."]]},
  {num:8,words:[["Matou te vivii atu pea lava i le Atua,", "In God we boast all the day long,"], ["matou te faaneenee foi e faavavau i lou suafa. Selā.", "and praise thy name for ever. Selah."]]},
  {num:9,words:[["A e peitai ua e lafoaiina ma faamaina i matou;", "But thou hast cast off, and put us to shame;"], ["ua e le 'au faatasi foi ma la matou itu taua.", "and goest not forth with our armies."]]},
  {num:10,words:[["Ua e faaliutuaina i matou i luma o e ita mai;", "Thou makest us to turn back from the enemy:"], ["ua vetea foi a matou mea e i latou o e 'ino'ino mai ia te i matou.", "and they which hate us spoil for themselves."]]},
  {num:11,words:[["Ua e tuuina atu i matou e pei o mamoe a 'aina;", "Thou hast given us like sheep appointed for meat;"], ["ua e faataapeapeina i matou i nuu ese.", "and hast scattered us among the heathen."]]},
  {num:12,words:[["Ua e faatau atu i lou nuu a e leai se oloa ua maua;", "Thou sellest thy people for nought,"], ["e lei faateleina foi au oloa i le tau na faatau ai i latou.", "and dost not increase thy wealth by their price."]]},
  {num:13,words:[["Ua e faia i matou ma gao a ē matou te tuaoi,", "Thou makest us a reproach to our neighbours,"], ["o ulaga ma tauemuga a ē vagavagai mai ia te i matou.", "a scorn and a derision to them that are round about us."]]},
  {num:14,words:[["Ua e faia i matou ma upu faatusa i nuu ese;", "Thou makest us a byword among the heathen,"], ["ua lialiai ai ulu o tagata.", "a shaking of the head among the people."]]},
  {num:15,words:[["Ua ou lumanai pea le mea ou te masiasi ai;", "My confusion is continually before me,"], ["ua ufitia foi a'u i le mea e mā ai o'u mata,", "and the shame of my face hath covered me,"]]},
  {num:16,words:[["ona o le leo o le ua gaogao mai ma faifai mai; ona o lē ita mai,", "For the voice of him that reproacheth and blasphemeth;"], ["atoa ma le ua taui ma sui.", "by reason of the enemy and avenger."]]},
  {num:17,words:[["Ua oo mai ia te i matou ia mea uma;", "All this is come upon us;"], ["a e peitai matou te lei faagalogalo ia te oe,", "yet have we not forgotten thee,"], ["matou te lei pepelo foi i lau feagaiga.", "neither have we dealt falsely in thy covenant."]]},
  {num:18,words:[["E lei tuumuli o matou loto;", "Our heart is not turned back,"], ["e lei liliu ese foi o matou vae i lou ala;", "neither have our steps declined from thy way;"]]},
  {num:19,words:[["ina ua e tu'imomomoina i matou i le mea o i ai tanimo,", "Though thou hast sore broken us in the place of dragons,"], ["ma ua e ufitia i matou i le ata o le oti.", "and covered us with the shadow of death."]]},
  {num:20,words:[["Pe afai ua matou faagalogalo i le suafa o lo matou Atua,", "If we have forgotten the name of our God,"], ["afai foi ua faaloaloa ane o matou lima i se atua ese;", "or stretched out our hands to a strange god;"]]},
  {num:21,words:[["e le suesue ea lenei mea e le Atua? Auā o ia lava na te silafia mea lilo o i le loto.", "Shall not God search this out? for he knoweth the secrets of the heart."]]},
  {num:22,words:[["Ona o oe lava ua fasiotia i matou i aso uma;", "Yea, for thy sake are we killed all the day long;"], ["ua faatatauina i matou e pei o mamoe a fāsia.", "we are counted as sheep for the slaughter."]]},
  {num:23,words:[["Le Alii e,", "Awake,"], ["ia e tulai mai,", "why sleepest thou,"], ["se a le mea ua e tofa ai? Ia e maleifua mai,", "O Lord? arise,"], ["aua e te lafoai ia te i matou e faavavau.", "cast us not off for ever."]]},
  {num:24,words:[["Se a le mea ua e 'alo ai ou fofoga,", "Wherefore hidest thou thy face,"], ["ma faagalogalo i lo matou tiga ma lo matou sauaina?", "and forgettest our affliction and our oppression?"]]},
  {num:25,words:[["Auā ua faano'uno'u ifo i matou i le efuefu;", "For our soul is bowed down to the dust:"], ["ua pipii o matou manava i le eleele.", "our belly cleaveth unto the earth."]]},
  {num:26,words:[["Ina tulai mai ia e fai ma fesoasoani ia te i matou;", "Arise for our help,"], ["ma ia e laveai ia te i matou ona o lou alofa.", "and redeem us for thy mercies' sake."]]},
];
renderVerseSet(psa_ch_44_Verses, 'psa-ch44-verses');

var psa_ch_45_Verses = [
  {num:1,words:[["Ua puna mai lo'u loto i upu lelei;", "My heart is inditing a good matter:"], ["ou te tautala atu i mea ua ou faia i le Tupu;", "I speak of the things which I have made touching the king:"], ["o lo'u laulaufaiva o le peni lea a le tusiupu lima vave.", "my tongue is the pen of a ready writer."]]},
  {num:2,words:[["Ua sili lava lou aulelei i atalii o tagata;", "Thou art fairer than the children of men:"], ["ua masaa ifo i ou laufofoga upu alofa;", "grace is poured into thy lips:"], ["o le mea lea e faamanuia ai oe e le Atua e faavavau.", "therefore God hath blessed thee for ever."]]},
  {num:3,words:[["Ina fusi ia lau pelu i lou vae,", "Gird thy sword upon thy thigh,"], ["o oe na le toa,", "O most mighty,"], ["o lou viiga ma lou mamalu.", "with thy glory and thy majesty."]]},
  {num:4,words:[["O lou mamalu foi ia e tietie ai i le manu ma le manuia, ona o le upu moni,", "And in thy majesty ride prosperously because of truth and meekness and righteousness;"], ["ma le agamalu, ma le amiotonu; ia a'oa'oina foi oe e lou aao taumatau i mea e matautia ai.", "and thy right hand shall teach thee terrible things."]]},
  {num:5,words:[["E maamaai au u fanafana; e pauu ai tagata ia te oe;", "Thine arrows are sharp in the heart of the king's enemies;"], ["e tuia ai loto o e faia le Tupu mo latou fili.", "whereby the people fall under thee."]]},
  {num:6,words:[["Le Atua e,", "Thy throne,"], ["o lou nofoālii e faavavau faavavau lava lea;", "O God,"], ["o le tootoo o lou malo,", "is for ever and ever:"], ["o le tootoo o le amiotonu lea.", "the sceptre of thy kingdom is a right sceptre."]]},
  {num:7,words:[["Ua e finagalo i le amiotonu,", "Thou lovest righteousness,"], ["ma e 'ino'ino i le amio leaga;", "and hatest wickedness:"], ["o le mea lea ua faauuina ai oe e le Atua, o lou Atua lava,", "therefore God,"], ["i le suāuu o le fiafia,", "thy God,"], ["e sili lava i e tou te faatasi.", "hath anointed thee with the oil of gladness above thy fellows."]]},
  {num:8,words:[["Ou ofu uma lava ua ni muro,", "All thy garments smell of myrrh,"], ["ma aloe,", "and aloes,"], ["ma kesia,", "and cassia, out of the ivory palaces,"], ["mai maota nifo o elefane ua latou faafiafia ai ia te oe.", "whereby they have made thee glad."]]},
  {num:9,words:[["O loo faatasi o alo fafine o tupu ma e ua faapelepeleina e oe;", "Kings' daughters were among thy honourable women:"], ["ua tu mai le masiofo i lou itu taumatau ua ofu ia i le auro lelei mai Ofeira.", "upon thy right hand did stand the queen in gold of Ophir."]]},
  {num:10,words:[["Ina faafogafoga mai ia,", "Hearken,"], ["le alo fafine e,", "O daughter,"], ["ma silasila,", "and consider,"], ["ma liliu mai ou fofoga;", "and incline thine ear;"], ["ia e faagalogalo foi i lou nuu,", "forget also thine own people,"], ["ma le aiga o lou tamā.", "and thy father's house;"]]},
  {num:11,words:[["Ona naunau ai lea o le Tupu i lou lalelei;", "So shall the king greatly desire thy beauty:"], ["auā o ia lava lou Alii,", "for he is thy Lord;"], ["ia e ifo ia te ia.", "and worship thou him."]]},
  {num:12,words:[["E sau le tama fafine a Turo ma le mea alofa;", "And the daughter of Tyre shall be there with a gift;"], ["e ole atu ia te oe o e tamaoaiga i le nuu.", "even the rich among the people shall intreat thy favour."]]},
  {num:13,words:[["Ua matuā matagofie le alo fafine o le Tupu i totonu;", "The king's daughter is all glorious within:"], ["ua teuteua lona ofu i le auro.", "her clothing is of wrought gold."]]},
  {num:14,words:[["E ta'ita'iina o ia i le Tupu ma ona ofu lanu eseese; o ana uo,", "She shall be brought unto the king in raiment of needlework:"], ["o taupou o e mulimuli atu ia te ia, e aumaia i latou ia te oe.", "the virgins her companions that follow her shall be brought unto thee."]]},
  {num:15,words:[["E ta'ita'iina i latou ma le fiafia ma le olioli;", "With gladness and rejoicing shall they be brought:"], ["e ulufale atu i latou i le maota o le Tupu.", "they shall enter into the king's palace."]]},
  {num:16,words:[["E suia ou tamā i ou alo;", "Instead of thy fathers shall be thy children,"], ["e te tofia i latou e fai ma alii sili i le lalolagi uma.", "whom thou mayest make princes in all the earth."]]},
  {num:17,words:[["Ou te ta'uta'u atu lou suafa i augātupulaga uma lava;", "I will make thy name to be remembered in all generations:"], ["o le mea lea e vivii atu ai tagata ia te oe e faavavau faavavau lava.", "therefore shall the people praise thee for ever and ever."]]},
];
renderVerseSet(psa_ch_45_Verses, 'psa-ch45-verses');

var psa_ch_46_Verses = [
  {num:1,words:[["O le Atua, o lo tatou malu ia ma lo tatou malosi;", "God is our refuge and strength,"], ["e fai o ia ma fesoasoani silisili i puapuaga.", "a very present help in trouble."]]},
  {num:2,words:[["O le mea lea tatou te le fefefe ai,", "Therefore will not we fear,"], ["pe a faaliliuina le lalolagi,", "though the earth be removed,"], ["ma luluina mauga i totonu o le sami;", "and though the mountains be carried into the midst of the sea;"]]},
  {num:3,words:[["pe a taalili ma sousou ona suāsami,", "Though the waters thereof roar and be troubled,"], ["ma faagateteina ai mauga i lona maualuga. Selā.", "though the mountains shake with the swelling thereof. Selah."]]},
  {num:4,words:[["O le vaitafe,", "There is a river,"], ["e faafiafia ona magāvai i le aai a le Atua, o le mea paia,", "the streams whereof shall make glad the city of God,"], ["o i ai afioaga o lē Silisili ese.", "the holy place of the tabernacles of the most High."]]},
  {num:5,words:[["O loo i totonu ia te ia le Atua,", "God is in the midst of her;"], ["e le faagaeetia lava ia,", "she shall not be moved: God shall help her,"], ["e fesoasoani le Atua ia te ia i le vaveao.", "and that right early."]]},
  {num:6,words:[["Ua vāvāō nuu ese,", "The heathen raged,"], ["ua faagaeetia malo;", "the kingdoms were moved:"], ["ua tŭlei mai lona siufofoga,", "he uttered his voice,"], ["ona liu suāvai lea o le lalolagi.", "the earth melted."]]},
  {num:7,words:[["Ua ia te i tatou Ieova o 'au;", "The LORD of hosts is with us;"], ["o le Atua o Iakopo o lo tatou 'olo maualuga ia. Selā.", "the God of Jacob is our refuge. Selah."]]},
  {num:8,words:[["Ina o mai ia,", "Come,"], ["ina vaavaai i galuega a Ieova,", "behold the works of the LORD,"], ["o le ua faia faatafunaga i le lalolagi.", "what desolations he hath made in the earth."]]},
  {num:9,words:[["Ua faaiua e ia o taua e oo lava i tulu'iga o le lalolagi;", "He maketh wars to cease unto the end of the earth;"], ["ua gagau e ia le aufana,", "he breaketh the bow,"], ["ma vavae le tao;", "and cutteth the spear in sunder;"], ["ua susunuina foi e ia kariota i le afi.", "he burneth the chariot in the fire."]]},
  {num:10,words:[["Ina soia,", "Be still,"], ["ma ia outou iloa o a'u lava o le Atua;", "and know that I am God:"], ["e viia a'u i nuu ese,", "I will be exalted among the heathen,"], ["e viia a'u i le lalolagi.", "I will be exalted in the earth."]]},
  {num:11,words:[["Ua ia te i tatou Ieova o 'au, o le Atua o Iakopo,", "The LORD of hosts is with us;"], ["o lo tatou 'olo maualuga ia.", "the God of Jacob is our refuge."], ["Selā.", "Selah."]]},
];
renderVerseSet(psa_ch_46_Verses, 'psa-ch46-verses');

var psa_ch_47_Verses = [
  {num:1,words:[["Ina patipati ia o outou lima,", "O clap your hands,"], ["o outou nuu uma lava;", "all ye people;"], ["ina alalaga atu ia i le Atua ma le leo fiafia.", "shout unto God with the voice of triumph."]]},
  {num:2,words:[["Auā e matautia Ieova lē Silisili ese;", "For the LORD most high is terrible;"], ["o le Tupu silisili ia i le lalolagi atoa.", "he is a great King over all the earth."]]},
  {num:3,words:[["E faatoilaloina e ia o nuu ia te i tatou,", "He shall subdue the people under us,"], ["ma nuu ese i lalo o tatou vae.", "and the nations under our feet."]]},
  {num:4,words:[["E filifilia e ia le tofi mo i tatou, o le mea e mitamita ai Iakopo,", "He shall choose our inheritance for us,"], ["na ia alofa i ai.", "the excellency of Jacob whom he loved."], ["Selā.", "Selah."]]},
  {num:5,words:[["O loo afio ae le Atua ma le alaga fiafia,", "God is gone up with a shout,"], ["o loo afio ae Ieova ma le leo o le pu.", "the LORD with the sound of a trumpet."]]},
  {num:6,words:[["Ina pepese atu ia i le Atua,", "Sing praises to God,"], ["ina pepese ia;", "sing praises:"], ["ina pepese atu ia i lo tatou Tupu,", "sing praises unto our King,"], ["ina pepese ia.", "sing praises."]]},
  {num:7,words:[["Auā o le Atua, o le Tupu ia o le lalolagi atoa;", "For God is the King of all the earth:"], ["ina pepese atu ia ma le atamai.", "sing ye praises with understanding."]]},
  {num:8,words:[["Ua fai ma tupu le Atua i nuu ese;", "God reigneth over the heathen:"], ["o loo tietie le Atua i lona nofoālii paia.", "God sitteth upon the throne of his holiness."]]},
  {num:9,words:[["Ua faatasia alii o nuu i le nuu o le Atua o Aperaamo;", "The princes of the people are gathered together,"], ["auā e ō le Atua talita o le lalolagi;", "even the people of the God of Abraham: for the shields of the earth belong unto God:"], ["e matuā silisili ese lava o ia.", "he is greatly exalted."]]},
];
renderVerseSet(psa_ch_47_Verses, 'psa-ch47-verses');

var psa_ch_48_Verses = [
  {num:1,words:[["E sili lava Ieova,", "Great is the LORD,"], ["e tatau foi ona matuā viia o ia i le aai a lo tatou Atua,", "and greatly to be praised in the city of our God,"], ["o lona mauga paia.", "in the mountain of his holiness."]]},
  {num:2,words:[["E matagofie le maualuga o le mauga o Siona,", "Beautiful for situation,"], ["e fiafia ai le lalolagi uma,", "the joy of the whole earth,"], ["o i le itu i matu,", "is mount Zion, on the sides of the north,"], ["le aai a le Tupu silisili.", "the city of the great King."]]},
  {num:3,words:[["E iloa lava le Atua i ona maota, e fai o ia ma 'olo maualuga.", "God is known in her palaces for a refuge."]]},
  {num:4,words:[["Auā faauta,", "For,"], ["na faapotopoto mai tupu;", "lo, the kings were assembled,"], ["ua latou o atu faatasi.", "they passed by together."]]},
  {num:5,words:[["Na latou vaavaai mai,", "They saw it,"], ["ona fememeai ai lea;", "and so they marvelled;"], ["ua atuatuvale i latou,", "they were troubled,"], ["ona latou vave sosola ese ai lea.", "and hasted away."]]},
  {num:6,words:[["Na maua lava i latou i lea mea i le gatete,", "Fear took hold upon them there, and pain,"], ["o le tiga pei o le fafine a fanau mai.", "as of a woman in travail."]]},
  {num:7,words:[["Ua e lepetia vaa Tasesa i le matagi mai sasae.", "Thou breakest the ships of Tarshish with an east wind."]]},
  {num:8,words:[["E pei ona tatou faalogo atu ai,", "As we have heard,"], ["e faapea ona tatou iloa i le aai a Ieova o 'au,", "so have we seen in the city of the LORD of hosts,"], ["o le aai a lo tatou Atua;", "in the city of our God:"], ["e faatumauina ia e le Atua e oo i le favavau. Selā.", "God will establish it for ever. Selah."]]},
  {num:9,words:[["Le Atua e,", "We have thought of thy lovingkindness, O God,"], ["ua matou mafaufau i lou alofa i totonu o lou malumalu.", "in the midst of thy temple."]]},
  {num:10,words:[["Le Atua e,", "According to thy name,"], ["e pei o lou suafa,", "O God,"], ["e faapea lou viiga ona oo i tulu'iga o le lalolagi;", "so is thy praise unto the ends of the earth:"], ["ua tumu lou aao taumatau i le amiotonu.", "thy right hand is full of righteousness."]]},
  {num:11,words:[["Ia fiafia le mauga o Siona,", "Let mount Zion rejoice,"], ["ia olioli tamafafine a Iuta,", "let the daughters of Judah be glad,"], ["ona o au faamasinoga.", "because of thy judgments."]]},
  {num:12,words:[["Ina faataamilo ia i Siona,", "Walk about Zion,"], ["ma ia soo ai,", "and go round about her:"], ["ina faitau ia i ona 'olo.", "tell the towers thereof."]]},
  {num:13,words:[["Matuā mafaufau ia i lona aupa,", "Mark ye well her bulwarks,"], ["ma mātau mai ona maota;", "consider her palaces;"], ["ina ia outou talatala atu ai i le tupulaga atali.", "that ye may tell it to the generation following."]]},
  {num:14,words:[["Auā o lenei Atua, o lo tatou Atua lava ia e faavavau faavavau lava;", "For this God is our God for ever and ever:"], ["o ia lava na te ta'ita'iina i tatou e oo lava i le oti.", "he will be our guide even unto death."]]},
];
renderVerseSet(psa_ch_48_Verses, 'psa-ch48-verses');

var psa_ch_49_Verses = [
  {num:1,words:[["Ina faalogologo mai ia i lenei mea o outou nuu uma;", "Hear this, all ye people;"], ["ina uai mai ia o outou taliga o outou uma o e nonofo i le lalolagi;", "give ear, all ye inhabitants of the world:"]]},
  {num:2,words:[["o tagatānuu atoa ma alii;", "Both low and high, rich and poor,"], ["o e tamaoaiga faatasi ma e matitiva.", "together."]]},
  {num:3,words:[["E tautala lo'u gutu i le poto;", "My mouth shall speak of wisdom;"], ["e atamamai foi mafaufauga o lo'u loto.", "and the meditation of my heart shall be of understanding."]]},
  {num:4,words:[["Ou te uai atu o'u taliga i le faataoto,", "I will incline mine ear to a parable:"], ["ou te faamatala a'u upu lilo i le kitara.", "I will open my dark saying upon the harp."]]},
  {num:5,words:[["Se a le mea ou te fefe ai i aso vale,", "Wherefore should I fear in the days of evil,"], ["pe a vagavagaia mai a'u e le agasala a e lamalama ia te au?", "when the iniquity of my heels shall compass me about?"]]},
  {num:6,words:[["O i latou o e faatuatua i o latou oa,", "They that trust in their wealth,"], ["ma mitamita i latou ona o le tele o a latou oloa;", "and boast themselves in the multitude of their riches;"]]},
  {num:7,words:[["e le mafaia lava e so latou ona faatau i lona uso,", "None of them can by any means redeem his brother,"], ["pe avatu i le Atua se togiola mo ia,", "nor give to God a ransom for him:"]]},
  {num:8,words:[["(auā e matuā faigata le togiola o latou agaga,", "(For the redemption of their soul is precious,"], ["e le mafaia lava ia e faavavau;", "and it ceaseth for ever:"], [")", ")"]]},
  {num:9,words:[["ina ia ola pea ia e faavavau;", "That he should still live for ever,"], ["ia le iloa e ia le tuugamau.", "and not see corruption."]]},
  {num:10,words:[["Auā ua iloa e ia e oti tagata popoto,", "For he seeth that wise men die,"], ["e fano foi le tagata valea atoa ma le vale;", "likewise the fool and the brutish person perish,"], ["ona tuua lea e i latou a latou oa mā nisi.", "and leave their wealth to others."]]},
  {num:11,words:[["O lo latou taofi,", "Their inward thought is,"], ["e faavavau o latou fale,", "that their houses shall continue for ever,"], ["ma mea e mau ai i latou e augātupulaga ia;", "and their dwelling places to all generations;"], ["ua faaigoa e i latou o latou fanua i o latou lava igoa.", "they call their lands after their own names."]]},
  {num:12,words:[["A e le tumau le tagata i lona lelei;", "Nevertheless man being in honour abideth not:"], ["e tusa i latou ma manu ona fano.", "he is like the beasts that perish."]]},
  {num:13,words:[["O lo latou ala lenei, o lo latou lea valea;", "This their way is their folly:"], ["a ua fiafia e ua mulimuli ia te i latou i a latou upu.", "yet their posterity approve their sayings."], ["Selā", "Selah."]]},
  {num:14,words:[["Ua tuuina atu i latou e pei o mamoe i le tuugamau;", "Like sheep they are laid in the grave;"], ["e 'aina i latou e le oti;", "death shall feed on them;"], ["e pule e ua amiotonu ia te i latou i le taeao; e mavae lo latou matagofie i le tuugamau,", "and the upright shall have dominion over them in the morning;"], ["mai le mea latou te mau ai.", "and their beauty shall consume in the grave from their dwelling."]]},
  {num:15,words:[["A e peitai e faaola e le Atua lo'u agaga ai le pule a le tuugamau;", "But God will redeem my soul from the power of the grave:"], ["auā na te talia mai a'u. Selā.", "for he shall receive me. Selah."]]},
  {num:16,words:[["Aua e te fefe pe a faatamaoaigaina se tasi,", "Be not thou afraid when one is made rich,"], ["pe a faateleina le mamalu o lona aiga;", "when the glory of his house is increased;"]]},
  {num:17,words:[["auā e leai se mea na te avea pe a oti o ia;", "For when he dieth he shall carry nothing away:"], ["e le mulimuli ifo ia te ia lona mamalu.", "his glory shall not descend after him."]]},
  {num:18,words:[["E ui ina faaamuia atu o ia i lona agaga ina o ola o ia;", "Though while he lived he blessed his soul: and men will praise thee,"], ["e viia foi oe pe a e agalelei oe ia te oe;", "when thou doest well to thyself."]]},
  {num:19,words:[["E oo lava ia i le tupulaga o ona tamā;", "He shall go to the generation of his fathers;"], ["e le iloa e i latou le malamalama e oo i le faavavau.", "they shall never see light."]]},
  {num:20,words:[["O tagata o loo i le lelei,", "Man that is in honour,"], ["a e le mafaufau,", "and understandeth not,"], ["e tusa i latou ma manu ona fano.", "is like the beasts that perish."]]},
];
renderVerseSet(psa_ch_49_Verses, 'psa-ch49-verses');

var psa_ch_50_Verses = [
  {num:1,words:[["O le Atua o atua,", "The mighty God,"], ["o Ieova,", "even the LORD,"], ["ua fetalai mai o ia,", "hath spoken,"], ["ma ua valaau i le lalolagi ai le mea e alu ae ai le la e oo lava i le mea e alu ifo ai.", "and called the earth from the rising of the sun unto the going down thereof."]]},
  {num:2,words:[["O loo pupula mai le Atua mai Siona,", "Out of Zion, the perfection of beauty,"], ["o le mea e silisili ese ona matagofie.", "God hath shined."]]},
  {num:3,words:[["O loo afio mai lo tatou Atua,", "Our God shall come,"], ["ua le tuua lona siufofoga;", "and shall not keep silence:"], ["ua maamaai le afi i ona luma;", "a fire shall devour before him,"], ["o loo siosiomia foi o ia i le afā tele lava.", "and it shall be very tempestuous round about him."]]},
  {num:4,words:[["E valaau ia i le lagi i luga,", "He shall call to the heavens from above,"], ["atoa foi ma le lalolagi,", "and to the earth,"], ["i le faamasinoina o lona nuu.", "that he may judge his people."]]},
  {num:5,words:[["Ina faapotopoto mai ia ia te au o'u tagata amio Atua,", "Gather my saints together unto me;"], ["o e ua osia le feagaiga ma a'u i le taulaga.", "those that have made a covenant with me by sacrifice."]]},
  {num:6,words:[["E ta'ua foi e le lagi lana amiotonu;", "And the heavens shall declare his righteousness:"], ["auā o le Atua o ia lava le faamasino. Selā.", "for God is judge himself. Selah."]]},
  {num:7,words:[["Ina faalogologo mai ia lo'u nuu e,", "Hear,"], ["se'i ou fai atu;", "O my people,"], ["Isaraelu e,", "and I will speak; O Israel,"], ["se'i ou ta'utino atu foi i te oe;", "and I will testify against thee:"], ["o 'au lava o le Atua,", "I am God,"], ["o lou Atua lava.", "even thy God."]]},
  {num:8,words:[["E le ona o au taulaga ou te aoai atu ai nei ia te oe, po o au taulaga mu,", "I will not reprove thee for thy sacrifices or thy burnt offerings,"], ["ua i ai i o'u luma e le aunoa.", "to have been continually before me."]]},
  {num:9,words:[["Ou te le avea se povi poa ai lou fale,", "I will take no bullock out of thy house,"], ["po o se 'oti poa ai ou lotoā.", "nor he goats out of thy folds."]]},
  {num:10,words:[["Auā o ia te au manu uma i le vao matua,", "For every beast of the forest is mine,"], ["o manu e tataa i mauga e afe.", "and the cattle upon a thousand hills."]]},
  {num:11,words:[["Ua ou iloa manu felelei uma lava o i atu mauga; o manu tataa foi,", "I know all the fowls of the mountains:"], ["o ia te au lava ia.", "and the wild beasts of the field are mine."]]},
  {num:12,words:[["Ana ou fia 'ai,", "If I were hungry,"], ["ou te le ta'u atu ia te oe;", "I would not tell thee: for the world is mine,"], ["auā o ia te au le lalolagi ma mea ua tumu ai.", "and the fulness thereof."]]},
  {num:13,words:[["Ou te 'ai ea i tino o povi poa,", "Will I eat the flesh of bulls,"], ["pe inu i le toto o 'oti?", "or drink the blood of goats?"]]},
  {num:14,words:[["O le viiga, ia e faia lea ma taulaga i le Atua;", "Offer unto God thanksgiving;"], ["ia e avatu foi i lē Silisili ese mea na e tauto ai.", "and pay thy vows unto the most High:"]]},
  {num:15,words:[["Ia e valaau foi ia te au i le aso e i ai le puapuaga;", "And call upon me in the day of trouble:"], ["ou te laveaiina ai oe,", "I will deliver thee,"], ["ona e vivii mai ai lea ia te au.", "and thou shalt glorify me."]]},
  {num:16,words:[["A ua fetalai ane le Atua i le tagata amio leaga,", "But unto the wicked God saith,"], ["Se a ea le mea ua e tautala ai i a'u tulafono,", "What hast thou to do to declare my statutes,"], ["ma e ta'u la'u feagaiga i lou gutu?", "or that thou shouldest take my covenant in thy mouth?"]]},
  {num:17,words:[["O oe foi, ua e 'ino'ino i le aoaiga,", "Seeing thou hatest instruction,"], ["ma ua e lafoaiina a'u upu i ou tua.", "and castest my words behind thee."]]},
  {num:18,words:[["Ua e iloa atu se gaoi,", "When thou sawest a thief,"], ["ona e loto gatasi ai lea ma ia;", "then thou consentedst with him,"], ["ua fai foi lou tofi faatasi ma e mulilulua.", "and hast been partaker with adulterers."]]},
  {num:19,words:[["Ua e lafo upu leaga i lou gutu,", "Thou givest thy mouth to evil,"], ["ua e fatu foi upu faa'ole'ole i lou laulaufaiva.", "and thy tongue frameth deceit."]]},
  {num:20,words:[["Ua e nofo ma fai upu i lou uso;", "Thou sittest and speakest against thy brother;"], ["ua e fatu fua ni tala i le tama a lou tinā.", "thou slanderest thine own mother's son."]]},
  {num:21,words:[["Ua e faia ia mea,", "These things hast thou done,"], ["a ua ou faalologo lava a'u;", "and I kept silence;"], ["fa te oe ua tutusa lava a'u ma oe;", "thou thoughtest that I was altogether such an one as thyself:"], ["ou te aoai atu ia te oe,", "but I will reprove thee,"], ["ma laulau atu ia mea i ou luma.", "and set them in order before thine eyes."]]},
  {num:22,words:[["Ina mafaufau ia i lenei mea,", "Now consider this,"], ["o outou o e faagalogalo i le atua,", "ye that forget God,"], ["ina ne'i ou saeia outou ,", "lest I tear you in pieces,"], ["a e leai se na te laveai.", "and there be none to deliver."]]},
  {num:23,words:[["O lē faia le viiga ma taulaga, o lē ava lea ia te au;", "Whoso offereth praise glorifieth me:"], ["ma le ua mafaufau i lona ala, ou te faailoa atu ia te ia le faaolataga mai le Atua.", "and to him that ordereth his conversation aright will I shew the salvation of God."]]},
];
renderVerseSet(psa_ch_50_Verses, 'psa-ch50-verses');

var psa_ch_51_Verses = [
  {num:1,words:[["Le Atua e,", "Have mercy upon me,"], ["ia e alofa mai ia te au,", "O God,"], ["e tusa ma lou lava alofa; e tusa ma le tele o lou alofa mutimutivale,", "according to thy lovingkindness:"], ["ia e sōloiesea o'u solitulafono.", "according unto the multitude of thy tender mercies blot out my transgressions."]]},
  {num:2,words:[["Ia e matuā fufulu mai ia te au i la'u amio leaga,", "Wash me throughly from mine iniquity,"], ["ma ia e faamamā mai ia te au i la'u agasala.", "and cleanse me from my sin."]]},
  {num:3,words:[["Auā ua ou iloa e 'au lo'u solitulafono;", "For I acknowledge my transgressions:"], ["e le aunoa foi ona i ai i o'u luma o la'u agasala.", "and my sin is ever before me."]]},
  {num:4,words:[["Ua ou agasala atu ia te oe,", "Against thee,"], ["na o oe lava;", "thee only,"], ["ua ou faia foi lenei mea leaga i ou luma;", "have I sinned, and done this evil in thy sight:"], ["e tonu ai oe i lau fetalaiga,", "that thou mightest be justified when thou speakest,"], ["e sao foi oe pe a e faamasino.", "and be clear when thou judgest."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["na fanaua a'u ma le amio leaga;", "I was shapen in iniquity;"], ["na ou i ai foi i le manava o lo'u tinā ma le agasala.", "and in sin did my mother conceive me."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ua e finagalo i le faamaoni o le loto;", "thou desirest truth in the inward parts:"], ["ma e faailoa mai ia te au le poto i le mea lilo.", "and in the hidden part thou shalt make me to know wisdom."]]},
  {num:7,words:[["Ia e faamamā ia te au i le isopo,", "Purge me with hyssop,"], ["ona mamā ai lea o a'u;", "and I shall be clean:"], ["ia e fufulu mai ia te au,", "wash me,"], ["ona sinasina ai lea o a'u e sili i lo le kiona.", "and I shall be whiter than snow."]]},
  {num:8,words:[["Ia ou faalogo mai ia te oe i le olioli ma le fiafia;", "Make me to hear joy and gladness;"], ["ina ia fiafia ivi ua e faamomomoina.", "that the bones which thou hast broken may rejoice."]]},
  {num:9,words:[["Ia 'alo ou fofoga i a'u agasala,", "Hide thy face from my sins,"], ["ma ia e sōloi ese a'u amio leaga uma.", "and blot out all mine iniquities."]]},
  {num:10,words:[["Le Atua e,", "Create in me a clean heart,"], ["ia e faia se loto mamā mo a'u;", "O God;"], ["ma ia e faafouina se loto mau i totonu ia te au.", "and renew a right spirit within me."]]},
  {num:11,words:[["Aua e te lafoaiina a'u i ou luma;", "Cast me not away from thy presence;"], ["aua foi e te aveeseina lou Agaga Paia ia te au.", "and take not thy holy spirit from me."]]},
  {num:12,words:[["Ia e faafoisia mai ia te au le olioli o le olataga mai ia te oe;", "Restore unto me the joy of thy salvation;"], ["ia e taofimauina foi o a'u ma le loto fiafia.", "and uphold me with thy free spirit."]]},
  {num:13,words:[["Ou te a'oa'o atu ai ou ala i e ua solitulafono;", "Then will I teach transgressors thy ways;"], ["ona faaliliuina atu ai lea ia te oe o e ua agasala.", "and sinners shall be converted unto thee."]]},
  {num:14,words:[["Le Atua e,", "Deliver me from bloodguiltiness,"], ["le Atua o lo'u olataga,", "O God,"], ["ia e laveai mai ia te au ai le sala o le toto;", "thou God of my salvation:"], ["ona pese fiafia ai lea o lo'u laulaufaiva i le amiotonu mai ia te oe.", "and my tongue shall sing aloud of thy righteousness."]]},
  {num:15,words:[["Le Alii e,", "O Lord,"], ["ia e faamatala mai o'u laugutu;", "open thou my lips;"], ["ona ta'uta'u atu lea e lo'u gutu lou viiga.", "and my mouth shall shew forth thy praise."]]},
  {num:16,words:[["Auā ua e le finagalo i se taulaga;", "For thou desirest not sacrifice;"], ["ana e finagalo i ai po ua ou avatu lava;", "else would I give it:"], ["ua e le fiafia i se taulaga mu.", "thou delightest not in burnt offering."]]},
  {num:17,words:[["O taulaga i le Atua,", "The sacrifices of God are a broken spirit:"], ["o le loto momomo lea;", "a broken and a contrite heart,"], ["le Atua e,", "O God,"], ["e te le inosia le loto momomo ma le nutimomoia.", "thou wilt not despise."]]},
  {num:18,words:[["Ia e faamanuia mai i Siona i lou finagalo alofa;", "Do good in thy good pleasure unto Zion:"], ["ia e ati ae pa o Ieusalema.", "build thou the walls of Jerusalem."]]},
  {num:19,words:[["Ona e finagalo ai lea i taulga tonu,", "Then shalt thou be pleased with the sacrifices of righteousness,"], ["o le taulaga mu, ma le taulaga mu uma;", "with burnt offering and whole burnt offering:"], ["ona latou faaee ai lea o povi poa i lau fata faitaulaga.", "then shall they offer bullocks upon thine altar."]]},
];
renderVerseSet(psa_ch_51_Verses, 'psa-ch51-verses');

var psa_ch_52_Verses = [
  {num:1,words:[["O oe na le toa,", "Why boastest thou thyself in mischief,"], ["se a le mea e te mitamita ai i le leaga? O loo agalelei le Atua i aso uma lava.", "O mighty man? the goodness of God endureth continually."]]},
  {num:2,words:[["Ua mafaufau lou laulaufaiva i mea leaga;", "Thy tongue deviseth mischiefs; like a sharp razor,"], ["e fai le pepelo e pei o se tafi maai.", "working deceitfully."]]},
  {num:3,words:[["Ua sili lou manao i le leaga, a e itiiti i le lelei;", "Thou lovest evil more than good;"], ["ua sili lou manao i le tala pepelo, a e itiiti i le upu tonu.", "and lying rather than to speak righteousness."], ["Selā.", "Selah."]]},
  {num:4,words:[["Le laulaufaiva faa'ole'ole e,", "Thou lovest all devouring words,"], ["ua e manao i upu uma e fano ai.", "O thou deceitful tongue."]]},
  {num:5,words:[["O lea e faaumatia ai oe e faavavau e le Atua;", "God shall likewise destroy thee for ever,"], ["na te aveeseina ma liaiina oe ai le fale ie;", "he shall take thee away, and pluck thee out of thy dwelling place,"], ["na te liaiina foi oe ai le nuu o e ola.", "and root thee out of the land of the living."], ["Selā.", "Selah."]]},
  {num:6,words:[["E iloa atu ai foi e ua amiotonu,", "The righteous also shall see,"], ["ma latou matatau ai, latou te featani ai ia te ia;", "and fear,"], ["e faapea atu ,", "and shall laugh at him:"]]},
  {num:7,words:[["Faauta,", "Lo,"], ["o le tagata lea na na le faia le Atua mona malosi,", "this is the man that made not God his strength;"], ["a ua faatuatua ia i le tele o lona oloa;", "but trusted in the abundance of his riches,"], ["na ia faamalosi i lona leaga.", "and strengthened himself in his wickedness."]]},
  {num:8,words:[["A o a'u, ou te pei o se olive ona tāuluulu ola i le fale o le Atua;", "But I am like a green olive tree in the house of God:"], ["ou te faatuatua i le alofa o le Atua e faavavau faavavau lava.", "I trust in the mercy of God for ever and ever."]]},
  {num:9,words:[["Ou te vivii atu ia te oe e faavavau lava,", "I will praise thee for ever,"], ["auā na e faia lena mea;", "because thou hast done it:"], ["ou te faatalitali foi i lou suafa,", "and I will wait on thy name;"], ["auā e lelei i luma o ou tagata amio Atua.", "for it is good before thy saints."]]},
];
renderVerseSet(psa_ch_52_Verses, 'psa-ch52-verses');

var psa_ch_53_Verses = [
  {num:1,words:[["Ua fai ifo le tagata valea i lona loto,", "The fool hath said in his heart,"], ["E leai se Atua. Ua leaga lava i latou,", "There is no God. Corrupt are they,"], ["ua inosia a latou amioga;", "and have done abominable iniquity:"], ["e leai lava se tasi ua amio lelei.", "there is none that doeth good."]]},
  {num:2,words:[["Na silasila mai le Atua mai le lagi i le fanau a tagata,", "God looked down from heaven upon the children of men,"], ["ina ia silafia pe ai se tasi ua poto,", "to see if there were any that did understand,"], ["o se na te sailia le Atua.", "that did seek God."]]},
  {num:3,words:[["Ua latou taitasi ma foi i tua,", "Every one of them is gone back:"], ["ua leaga faatasi lava i latou;", "they are altogether become filthy;"], ["e leai se tasi ua amio lelei,", "there is none that doeth good, no,"], ["e leai lava se tasi.", "not one."]]},
  {num:4,words:[["E le o iloa ea o e fai amioleaga? Ua latou aai i lo'u nuu, e pei ona latou aai i le mea e 'ai;", "Have the workers of iniquity no knowledge? who eat up my people as they eat bread:"], ["ua latou le valaau i le Atua.", "they have not called upon God."]]},
  {num:5,words:[["Ua latou matuā matatau i lea mea sa leai se mea e matatau ai;", "There were they in great fear,"], ["auā na faataapeapeina e le Atua o ivi o le na to lauapi mai ia te oe;", "where no fear was:"], ["na faamaina i latou ,", "for God hath scattered the bones of him that encampeth against thee: thou hast put them to shame,"], ["auā ua ino'ino le Atua ia te i latou.", "because God hath despised them."]]},
  {num:6,words:[["E! Fia iloa se na te aumaia le olataga o Isaraelu mai Siona. Pe a faafoisia mai e le Atua le tafeaga o lona nuu,", "Oh that the salvation of Israel were come out of Zion! When God bringeth back the captivity of his people,"], ["ona olioli ai lea o Iakopo,", "Jacob shall rejoice,"], ["e fiafia ai Isaraelu.", "and Israel shall be glad."]]},
];
renderVerseSet(psa_ch_53_Verses, 'psa-ch53-verses');

var psa_ch_54_Verses = [
  {num:1,words:[["Le Atua e,", "Save me,"], ["ia e faaola mai ia te au ona o lou suafa;", "O God, by thy name,"], ["ia e faia le finauga mo a'u i lo'u malosi.", "and judge me by thy strength."]]},
  {num:2,words:[["Le Atua e,", "Hear my prayer,"], ["ia e faafofoga mai i la'u tatalo;", "O God;"], ["ia liliu mai ou fofoga i upu a lo'u gutu.", "give ear to the words of my mouth."]]},
  {num:3,words:[["Auā ua laga mai ia te au tagata ese;", "For strangers are risen up against me,"], ["o e saua foi ua sailiili e fasioti ia te au;", "and oppressors seek after my soul:"], ["latou te le manatua le Atua. Selā.", "they have not set God before them. Selah."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["o le Atua o lo'u lea fesoasoani;", "God is mine helper:"], ["o loo i ai le Alii i e ua faamalosi mai ia te au.", "the Lord is with them that uphold my soul."]]},
  {num:5,words:[["Na te faafoi atu le leaga i e ua ita mai ia te au;", "He shall reward evil unto mine enemies:"], ["ia e faaumatia i latou i lou faamaoni.", "cut them off in thy truth."]]},
  {num:6,words:[["Ou te avatu taulaga ia te oe e fai fua i lo'u loto;", "I will freely sacrifice unto thee:"], ["Ieova e,", "I will praise thy name,"], ["ou te vivii atu i lou suafa,", "O LORD;"], ["auā e lelei.", "for it is good."]]},
  {num:7,words:[["Auā na ia laveaiina mai a'u i puapuaga uma;", "For he hath delivered me out of all trouble:"], ["ua iloa foi e o'u mata le taui o e ita mai ia te au.", "and mine eye hath seen his desire upon mine enemies."]]},
];
renderVerseSet(psa_ch_54_Verses, 'psa-ch54-verses');

var psa_ch_55_Verses = [
  {num:1,words:[["Le Atua e,", "Give ear to my prayer,"], ["ia e faafofoga mai i la'u tatalo,", "O God;"], ["aua foi e te liliu ese i la'u aioi atu.", "and hide not thyself from my supplication."]]},
  {num:2,words:[["Ia faafofoga mai ia te au,", "Attend unto me,"], ["ma tali mai ia te au;", "and hear me:"], ["ua ou faanoanoa i lo'u mafaufau,", "I mourn in my complaint,"], ["ma ou uio;", "and make a noise;"]]},
  {num:3,words:[["ona o le leo o le ua ita mai,", "Because of the voice of the enemy,"], ["ona o le saua o lē amio leaga;", "because of the oppression of the wicked:"], ["auā ua latou faaoo mai ia te au le amio leaga,", "for they cast iniquity upon me,"], ["o le ita lava ua latou faasaua mai ai ia te au.", "and in wrath they hate me."]]},
  {num:4,words:[["Ua sapotuvale lo'u lava loto i totonu ia te au;", "My heart is sore pained within me:"], ["ua oo mai foi ia te au le mata'u i le oti.", "and the terrors of death are fallen upon me."]]},
  {num:5,words:[["Ua oo mai lava ia te au le mata'u ma le gatete;", "Fearfulness and trembling are come upon me,"], ["ua matuā faagateteina a'u.", "and horror hath overwhelmed me."]]},
  {num:6,words:[["Ona ou faapea lea,", "And I said,"], ["E! Ta fia maua apaau e pei o le lupe, ou te lele ese ai lava,", "Oh that I had wings like a dove! for then would I fly away,"], ["i le ou nofo mau ai.", "and be at rest."]]},
  {num:7,words:[["Faauta,", "Lo,"], ["ou te sola mamao atu lava;", "then would I wander far off,"], ["i le ou nofo ai i le vao. Selā.", "and remain in the wilderness. Selah."]]},
  {num:8,words:[["Ou te faataalise ona sola o a'u, ona o le matagi tetele ma le afā.", "I would hasten my escape from the windy storm and tempest."]]},
  {num:9,words:[["Le Alii e,", "Destroy,"], ["ia e faaumatia i latou ,", "O Lord,"], ["ia e vaeluaina a latou taupulepulega;", "and divide their tongues:"], ["auā ua ou iloa le saua ma le misa i le aai.", "for I have seen violence and strife in the city."]]},
  {num:10,words:[["Ua la siomia o ia i ona pa i le ao ma le po;", "Day and night they go about it upon the walls thereof:"], ["ua i totonu lava ia te ia le amio leaga ma le malaia;", "mischief also and sorrow are in the midst of it."]]},
  {num:11,words:[["ua i totonu lava ia te ia le amio paaā;", "Wickedness is in the midst thereof:"], ["e le alu ese lava i lona malae le saua ma le amio pepelo.", "deceit and guile depart not from her streets."]]},
  {num:12,words:[["Auā e le o se fai a'u mona fili na upuleagaina a'u; ana se ita mai ,", "For it was not an enemy that reproached me;"], ["po ua ou oono ai;", "then I could have borne it:"], ["e le o lē ita mai ia te au ua faasausili mai ia te au;", "neither was it he that hated me that did magnify himself against me;"], ["ana se ita mai , po ua ou lafi ia te ia;", "then I would have hid myself from him:"]]},
  {num:13,words:[["a o oe lava,", "But it was thou,"], ["o le tagata ta te tutusa ma a'u;", "a man mine equal,"], ["o la'u uo lava,", "my guide,"], ["o le ua ta masani;", "and mine acquaintance."]]},
  {num:14,words:[["sa fefaamalieai lava a tā tautalaga,", "We took sweet counsel together,"], ["sa tā o gatasi ma le vao tagata i le fale o le Atua.", "and walked unto the house of God in company."]]},
  {num:15,words:[["Ia faafuasei atu lava le oti ia te i latou;", "Let death seize upon them,"], ["ia latou o ifo o ola i seoli;", "and let them go down quick into hell:"], ["auā ua i ai mea leaga i mea o latou nonofo ai,", "for wickedness is in their dwellings,"], ["o i totonu ia i latou lava.", "and among them."]]},
  {num:16,words:[["O a'u nei,", "As for me,"], ["ou te valaau atu i le Atua;", "I will call upon God;"], ["o Ieova lava na te faaolaina mai a'u.", "and the LORD shall save me."]]},
  {num:17,words:[["O le afiafi,", "Evening,"], ["ma le taeao,", "and morning,"], ["ma le tutonu o le la,", "and at noon,"], ["ou te tagi ai,", "will I pray,"], ["ma ou uio;", "and cry aloud:"], ["ona faafofoga mai ai lea o ia i lo'u leo.", "and he shall hear my voice."]]},
  {num:18,words:[["Na ia laveai mai ia te au, ia ou filemu ai i le taua sa ia te au;", "He hath delivered my soul in peace from the battle that was against me:"], ["auā e toatele i latou sa ia te au.", "for there were many with me."]]},
  {num:19,words:[["E faafofoga mai le Atua,", "God shall hear,"], ["na te faatigaina foi i latou;", "and afflict them,"], ["o ia lava lea o loo tietie talu mai le vavau lava. Selā. Auā latou te le āu liliu lava,", "even he that abideth of old. Selah. Because they have no changes,"], ["ma ua latou le matatau i le Atua.", "therefore they fear not God."]]},
  {num:20,words:[["Ua ia faaoo atu ona lima i e ua nofo lelei ma ia;", "He hath put forth his hands against such as be at peace with him:"], ["ua tuumavaega ai o ia.", "he hath broken his covenant."]]},
  {num:21,words:[["O lona gutu ua se suāsusu ua to'a e molemole,", "The words of his mouth were smoother than butter,"], ["a o i lona loto le taua;", "but war was in his heart:"], ["e sili le malulu o ana upu i le suāuu,", "his words were softer than oil,"], ["a o pelu ua seia lava ia.", "yet were they drawn swords."]]},
  {num:22,words:[["Ia e tuuina atu ia Ieova o mea e te popole vale ai;", "Cast thy burden upon the LORD,"], ["o ia lava na te tausia oe;", "and he shall sustain thee:"], ["na te le tuuna e faavavau le amiotonu ia faagaeetia.", "he shall never suffer the righteous to be moved."]]},
  {num:23,words:[["A o oe,", "But thou,"], ["le Atua e, e te lafoina i lalo i latou i le to e fano ai;", "O God,"], ["o tagata ua totolima ma e pepelo,", "shalt bring them down into the pit of destruction:"], ["latou te le oo i le tautuluaga o latou aso; a o a'u,", "bloody and deceitful men shall not live out half their days;"], ["ou te faatuatua lava ia te oe.", "but I will trust in thee."]]},
];
renderVerseSet(psa_ch_55_Verses, 'psa-ch55-verses');

var psa_ch_56_Verses = [
  {num:1,words:[["Le Atua e,", "Be merciful unto me,"], ["ia e alofa mai ia te au;", "O God:"], ["auā ua naunau tagata i le fia maua o a'u;", "for man would swallow me up;"], ["ua faasaua mai ia te au i lona fai taua mai i aso uma lava.", "he fighting daily oppresseth me."]]},
  {num:2,words:[["Ua naunau mai i aso fai soo o e ua ita mai ia te au;", "Mine enemies would daily swallow me up: for they be many that fight against me,"], ["auā e toatele o e fai taua ia te au ma le faasausili mai.", "O thou most High."]]},
  {num:3,words:[["O le aso ou te mata'u ai,", "What time I am afraid,"], ["ou te faatuatua ai ia te oe.", "I will trust in thee."]]},
  {num:4,words:[["Ou te mitamita i le Atua ona o lana afioga;", "In God I will praise his word,"], ["ou te faatuatua i le Atua;", "in God I have put my trust;"], ["ou te le fefe i se mea e faia e tagata ia te au.", "I will not fear what flesh can do unto me."]]},
  {num:5,words:[["Ua latou faauigaese i a'u upu i aso uma lava;", "Every day they wrest my words:"], ["ua faasaga mai ia te au o latou mafaufau uma lava ia a'u leaga ai.", "all their thoughts are against me for evil."]]},
  {num:6,words:[["Ua latou faapotopoto,", "They gather themselves together,"], ["ua latou lalafi,", "they hide themselves,"], ["ua latou vaavaai i o'u tulagāvae;", "they mark my steps,"], ["auā ua latou lamalama ia ou oti.", "when they wait for my soul."]]},
  {num:7,words:[["Latou te sao ea ona o le amio leaga? Le Atua e,", "Shall they escape by iniquity? in thine anger cast down the people,"], ["ia e lafoina i lalo le nuu i lou toasa.", "O God."]]},
  {num:8,words:[["Ua e faitauina lava lo'u fesolasolatai;", "Thou tellest my wanderings:"], ["ia e utu o'u loimata i lau fagu;", "put thou my tears into thy bottle:"], ["e le o i ai ea i lau tusi?", "are they not in thy book?"]]},
  {num:9,words:[["O le aso ou te valaau atu ai ia te oe ,", "When I cry unto thee,"], ["ona liutuaina ai lea o e ua ita mai ia te au;", "then shall mine enemies turn back:"], ["ua ou iloa lenei mea,", "this I know;"], ["ua ia te au le Atua.", "for God is for me."]]},
  {num:10,words:[["OU te vivii atu i le Atua ona o lana afioga;", "In God will I praise his word:"], ["ou te vivii atu ia Ieova ona o lana afioga.", "in the LORD will I praise his word."]]},
  {num:11,words:[["Ua ou faatuatua i le Atua;", "In God have I put my trust:"], ["ou te le fefe i se mea e faia e tagata ia te au.", "I will not be afraid what man can do unto me."]]},
  {num:12,words:[["Le Atua e,", "Thy vows are upon me,"], ["o ia te au mea na ou tauto e avatu ai ia te oe;", "O God:"], ["ou te avatu taulaga faafetai ia te oe.", "I will render praises unto thee."]]},
  {num:13,words:[["Auā ua e laveaiina a'u nai le oti;", "For thou hast delivered my soul from death:"], ["e te le faamalosia ea o'u vae ne'i tuleia,", "wilt not thou deliver my feet from falling,"], ["ina ia ou savali i luma o le Atua i le malamalama o e ola.", "that I may walk before God in the light of the living?"]]},
];
renderVerseSet(psa_ch_56_Verses, 'psa-ch56-verses');

var psa_ch_57_Verses = [
  {num:1,words:[["Le Atua e,", "Be merciful unto me,"], ["ia e alofa mai ia te au,", "O God,"], ["ia e alofa mai ia te au;", "be merciful unto me: for my soul trusteth in thee:"], ["auā ua ou faatuatua lava ia te oe;", "yea,"], ["ou te faatuatua foi i le paolo o ou apaau,", "in the shadow of thy wings will I make my refuge,"], ["seia mavae atu nei mea leaga.", "until these calamities be overpast."]]},
  {num:2,words:[["Ou te valaau atu i le Atua silisili ese;", "I will cry unto God most high;"], ["o le Atua lava na te faataunuuina mea uma mo a'u.", "unto God that performeth all things for me."]]},
  {num:3,words:[["E auina mai e ia mai le lagi, ma faaola mai ia te au,", "He shall send from heaven,"], ["a o upu leaga mai le ua naunau i le fia maua o a'u.", "and save me from the reproach of him that would swallow me up."], ["Selā.", "Selah."], ["E auina mai e le Atua o lona alofa ma lona faamaoni.", "God shall send forth his mercy and his truth."]]},
  {num:4,words:[["Ua i le va o le ona lava a'u;", "My soul is among lions:"], ["e taoto lava a'u i le va o e o mumū mai o latou ita ,", "and I lie even among them that are set on fire,"], ["o le fanau a tagata i latou,", "even the sons of men,"], ["o latou nifo o tao ma u fanafana ia,", "whose teeth are spears and arrows,"], ["o pelu maai foi o latou laulaufaiva.", "and their tongue a sharp sword."]]},
  {num:5,words:[["Le Atua e,", "Be thou exalted,"], ["ia faasilisiliina oe i le lagi;", "O God, above the heavens;"], ["ia i ai i le lalolagi uma lou mamalu.", "let thy glory be above all the earth."]]},
  {num:6,words:[["Ua latou saunia se upega i le mea ou te ui ai;", "They have prepared a net for my steps;"], ["ua faavaivai ai lo'u loto;", "my soul is bowed down:"], ["ua latou elia se lua o'u lumanai,", "they have digged a pit before me,"], ["ua pauu i ai i latou. Selā.", "into the midst whereof they are fallen themselves. Selah."]]},
  {num:7,words:[["Le Atua e,", "My heart is fixed,"], ["ua mau lo'u loto,", "O God,"], ["ua mau lava lo'u loto; ou te pese lava,", "my heart is fixed:"], ["ma ou fai pesega.", "I will sing and give praise."]]},
  {num:8,words:[["Ala mai ia lo'u mamalu,", "Awake up, my glory;"], ["ala mai ia le napeli ma le kitara;", "awake,"], ["ou te ala i le taeao lava.", "psaltery and harp: I myself will awake early."]]},
  {num:9,words:[["Le Alii e,", "I will praise thee,"], ["ou te vivii atu ia te oe i luma o le nuu;", "O Lord, among the people:"], ["ou te fai pesega ia te oe i luma o tagata.", "I will sing unto thee among the nations."]]},
  {num:10,words:[["Auā e tele lou alofa ua oo i le lagi,", "For thy mercy is great unto the heavens,"], ["e tele foi lou faamaoni ua oo i ao.", "and thy truth unto the clouds."]]},
  {num:11,words:[["Le Atua e,", "Be thou exalted,"], ["ia faasilisiliina oe i le lagi;", "O God, above the heavens:"], ["ia i ai i le lalolagi uma lou mamalu.", "let thy glory be above all the earth."]]},
];
renderVerseSet(psa_ch_57_Verses, 'psa-ch57-verses');

var psa_ch_58_Verses = [
  {num:1,words:[["E moni ea ua le tautala le amiotonu? Ina tautala mai ia outou. Outou le fanau a tagata,", "Do ye indeed speak righteousness, O congregation? do ye judge uprightly,"], ["ia outou faamasino ma le sa'o.", "O ye sons of men?"]]},
  {num:2,words:[["E moni,", "Yea,"], ["ua outou galulue ma le loto i mea leaga;", "in heart ye work wickedness;"], ["ua outou fuatia atu le sauaga a o outou lima i le nuu.", "ye weigh the violence of your hands in the earth."]]},
  {num:3,words:[["Ua liliu ese o e amio leaga talu ina fanau mai;", "The wicked are estranged from the womb:"], ["talu ina fanau mai ua sese i latou,", "they go astray as soon as they be born,"], ["ua tala pepelo.", "speaking lies."]]},
  {num:4,words:[["O ia te i latou mea oona e tusa ma le mea oona i le gata;", "Their poison is like the poison of a serpent:"], ["e pei o le asipi tutuli ua ia punitia ona taliga;", "they are like the deaf adder that stoppeth her ear;"]]},
  {num:5,words:[["o le na te le faalogoina atu le leo o e taufaaoleole gata ,", "Which will not hearken to the voice of charmers,"], ["o loo faaoleole i le taufaaoleolega poto.", "charming never so wisely."]]},
  {num:6,words:[["Le Atua e,", "Break their teeth,"], ["ia e gauia o latou nifo i o latou gutu;", "O God,"], ["Ieova e,", "in their mouth: break out the great teeth of the young lions,"], ["ia e tu'imomomoina gao o leona taanoa.", "O LORD."]]},
  {num:7,words:[["Ia liu suāvai i latou,", "Let them melt away as waters which run continually:"], ["ia pei o le vai ona mavae atu; a lolou le aufana e fana atu i ana u,", "when he bendeth his bow to shoot his arrows,"], ["ia peiseai ua vavaeeseina ia.", "let them be as cut in pieces."]]},
  {num:8,words:[["E pei o le sisi vao ona liu suāvai ia mavae atu o ia;", "As a snail which melteth,"], ["e pei o le fanau le āu a le fafine,", "let every one of them pass away: like the untimely birth of a woman,"], ["aua ne'i latou iloa le la.", "that they may not see the sun."]]},
  {num:9,words:[["A o lei lagona a outou ulo le afi laau tuitui,", "Before your pots can feel the thorns,"], ["pe mata pe mu,", "he shall take them away as with a whirlwind, both living,"], ["na te faaleleaeseina i latou i le afā.", "and in his wrath."]]},
  {num:10,words:[["E fiafia le ua amaiotonu pe a iloa e ia le taui;", "The righteous shall rejoice when he seeth the vengeance:"], ["e mulumulu ona vae i le toto o le ua amio leaga.", "he shall wash his feet in the blood of the wicked."]]},
  {num:11,words:[["Ona faapea ane ai lea o tagata, E moni,", "So that a man shall say,"], ["ua fai le taui mo le ua amiotonu;", "Verily there is a reward for the righteous:"], ["e moni, o le Atua o le faamasino o ia i le lalolagi.", "verily he is a God that judgeth in the earth."]]},
];
renderVerseSet(psa_ch_58_Verses, 'psa-ch58-verses');

var psa_ch_59_Verses = [
  {num:1,words:[["Lo'u Atua e,", "Deliver me from mine enemies,"], ["ia e laveai mai ia te au i e ua ita mai ia te au;", "O my God:"], ["ia e faamamalu mai ia te au i e ua laga mai ia te au.", "defend me from them that rise up against me."]]},
  {num:2,words:[["Ia e laveai mai ia te au i e ua fai amio leaga;", "Deliver me from the workers of iniquity,"], ["ia e faaola mai ia te au i tagata ua totolima.", "and save me from bloody men."]]},
  {num:3,words:[["Auā faauta mai,", "For,"], ["ua latou lamalama e fasioti ia te au;", "lo,"], ["ua faapotopoto ē malolosi ia agaleaga mai ia te au;", "they lie in wait for my soul: the mighty are gathered against me;"], ["Ieova e,", "not for my transgression,"], ["e le ona o lo'u solitulafono,", "nor for my sin,"], ["po o sa'u agasala.", "O LORD."]]},
  {num:4,words:[["Ua leai sa'u pagota,", "They run and prepare themselves without my fault:"], ["a ua latou taufetuli mai, ma latou sauniuni. Ia e tulai mai e faafetaiai mai ia te au,", "awake to help me,"], ["ma e silasila mai.", "and behold."]]},
  {num:5,words:[["O oe foi,", "Thou therefore,"], ["Ieova e, le Atua o 'au,", "O LORD God of hosts,"], ["le Atua o Isaraelu,", "the God of Israel,"], ["ia e maleifua mai, ma e asiasi ai i nuu ese uma lava;", "awake to visit all the heathen:"], ["aua ne'i e alofa atu i se tasi o e amio leaga ma le pepelo.", "be not merciful to any wicked transgressors."], ["Selā.", "Selah."]]},
  {num:6,words:[["Ua latou foi mai i le afiafi,", "They return at evening:"], ["ua latou fetagisi e pei o le ulī,", "they make a noise like a dog,"], ["ma latou faataamilo ane i le aai.", "and go round about the city."]]},
  {num:7,words:[["Faauta,", "Behold, they belch out with their mouth:"], ["ua luai mai upu leaga i o latou gutu;", "swords are in their lips:"], ["ua i ai pelu i o latou laugutu;", "for who,"], ["auā o ai se faalogo ane?", "say they, doth hear?"]]},
  {num:8,words:[["A o oe,", "But thou,"], ["Ieova e,", "O LORD,"], ["e te soisoi ia te i latou;", "shalt laugh at them;"], ["e te tauemu i nuu ese uma lava.", "thou shalt have all the heathen in derision."]]},
  {num:9,words:[["Ou te naunau atu lava ia te oe ona o lona malosi;", "Because of his strength will I wait upon thee:"], ["auā o le Atua o lo'u 'olo maualuga ia.", "for God is my defence."]]},
  {num:10,words:[["O loo ou lumanai lo'u Atua alofa;", "The God of my mercy shall prevent me:"], ["e faaali mai ia te au e le Atua le taui o e ita mai ia te au.", "God shall let me see my desire upon mine enemies."]]},
  {num:11,words:[["Aua e te fasiotia i latou,", "Slay them not,"], ["ne'i galo i lo'u nuu;", "lest my people forget:"], ["ia e faafeoai solo ia te i latou i lou lava malosi; ma e lafoina i lalo i latou,", "scatter them by thy power;"], ["le Alii e,", "and bring them down,"], ["lo matou talita.", "O Lord our shield."]]},
  {num:12,words:[["O le agasala a o latou gutu, o le upu lea ai o latou laugutu,", "For the sin of their mouth and the words of their lips let them even be taken in their pride:"], ["ia maileia lava i latou i lo latou lava faamaualuga; ona o a latou fetuu foi ma a latou tala pepelo ua latou tautala ai.", "and for cursing and lying which they speak."]]},
  {num:13,words:[["Ia e faaumatia i latou i le toasa,", "Consume them in wrath,"], ["ia e faaumatia lava,", "consume them,"], ["ina ia leai so latou e toe; ia latou iloa o loo pule le Atua ia Iakopo,", "that they may not be:"], ["ia oo lava i tulu'iga o le lalolagi.", "and let them know that God ruleth in Jacob unto the ends of the earth."], ["Selā.", "Selah."]]},
  {num:14,words:[["Latou te foi mai i le afiafi,", "And at evening let them return;"], ["latou te fetagisi e pei o le ulī;", "and let them make a noise like a dog,"], ["ma latou faataamilo ane i le aai.", "and go round about the city."]]},
  {num:15,words:[["Latou te feoai i le fia aai; ae le maoona,", "Let them wander up and down for meat,"], ["ona latou nonofo ai lea i le po.", "and grudge if they be not satisfied."]]},
  {num:16,words:[["A o a'u ou te pese atu i lou malosi;", "But I will sing of thy power;"], ["ou te alaga fiafia i le taeao i lou alofa mai;", "yea,"], ["auā na fai oe mo'u 'olo maualuga,", "I will sing aloud of thy mercy in the morning:"], ["ma o'u malu i le aso na puapuagaina ai a'u.", "for thou hast been my defence and refuge in the day of my trouble."]]},
  {num:17,words:[["Lo'u malosi e,", "Unto thee,"], ["ou te fai pesega lava ia te oe;", "O my strength,"], ["auā o le Atua o lo'u 'olo maualuga lea,", "will I sing: for God is my defence,"], ["o le Atua ua alofa mai ia te au.", "and the God of my mercy."]]},
];
renderVerseSet(psa_ch_59_Verses, 'psa-ch59-verses');

var psa_ch_60_Verses = [
  {num:1,words:[["Le Atua e,", "O God,"], ["na e lafoaiina i matou,", "thou hast cast us off,"], ["na e faataapeapeina i matou,", "thou hast scattered us,"], ["na e toatamai;", "thou hast been displeased;"], ["ia e toe liliu mai ia te i matou.", "O turn thyself to us again."]]},
  {num:2,words:[["Na e luluina le eleele,", "Thou hast made the earth to tremble;"], ["na e faamāvaevaeina;", "thou hast broken it:"], ["ia e fofoina ona gaugau;", "heal the breaches thereof;"], ["auā o loo lulu ia.", "for it shaketh."]]},
  {num:3,words:[["Na e faailoa mai mea faigata i lou nuu;", "Thou hast shewed thy people hard things:"], ["na e faainumia i matou i le uaina e tautevateva a'i.", "thou hast made us to drink the wine of astonishment."]]},
  {num:4,words:[["Na e foaiina atu le tagavai mo e matatau ia te oe,", "Thou hast given a banner to them that fear thee,"], ["e siitia i luga ona o le upu moni. Selā.", "that it may be displayed because of the truth. Selah."]]},
  {num:5,words:[["Ina ia laveaiina au pele;", "That thy beloved may be delivered;"], ["ia e faaola mai i lou aao taumatau,", "save with thy right hand,"], ["ma ia e tali mai ia te au.", "and hear me."]]},
  {num:6,words:[["Ua fetalai le Atua i lona malumalu;", "God hath spoken in his holiness;"], ["ou te fiafia lava a'u,", "I will rejoice,"], ["ou te tofitofia Sekema,", "I will divide Shechem,"], ["o le vanu o Sukota ou te fuafuatia lea.", "and mete out the valley of Succoth."]]},
  {num:7,words:[["O loo ia te au Kiliata,", "Gilead is mine,"], ["o loo ia te au foi Manase;", "and Manasseh is mine; Ephraim also is the strength of mine head;"], ["e fai foi Efaraima ma malosi o lo'u ulu;", "Judah is my lawgiver;"]]},
  {num:8,words:[["o la'u faipule o Iuta lea;", "Moab is my washpot;"], ["o Moapi o le ipu lea ou te mulumulu ai;", "over Edom will I cast out my shoe:"], ["ou te lafoina lo'u seevae i Etoma; Filisitia e,", "Philistia,"], ["ina alaga ia i lou manumalo ia te au.", "triumph thou because of me."]]},
  {num:9,words:[["O ai se na te avea a'u i le aai nofo 'olo? O ai se na te ta'ita'iina a'u i Etoma?", "Who will bring me into the strong city? who will lead me into Edom?"]]},
  {num:10,words:[["E le o oe ea,", "Wilt not thou,"], ["le Atua e,", "O God,"], ["sa e lafoaiina mai i matou, ma ua e le afio atu,", "which hadst cast us off? and thou,"], ["le Atua e,", "O God,"], ["faatasi ma la matou itu taua?", "which didst not go out with our armies?"]]},
  {num:11,words:[["Ia e fesoasoani mai ia te i matou i le puapuaga;", "Give us help from trouble:"], ["auā e le aoga lava le olataga mai tagata.", "for vain is the help of man."]]},
  {num:12,words:[["O le Atua lava e fai ai i matou ma toa;", "Through God we shall do valiantly:"], ["auā o ia na te solia e ua ita mai ia te i matou.", "for he it is that shall tread down our enemies."]]},
];
renderVerseSet(psa_ch_60_Verses, 'psa-ch60-verses');

var psa_ch_61_Verses = [
  {num:1,words:[["Le Atua e,", "Hear my cry,"], ["ia e faafofoga mai i la'u alaga;", "O God;"], ["ia e liliu mai i la'u tatalo.", "attend unto my prayer."]]},
  {num:2,words:[["Ou te valaau atu ia te oe ai le gataaga o le nuu,", "From the end of the earth will I cry unto thee,"], ["pe a faavaivai lo'u loto;", "when my heart is overwhelmed:"], ["ia e ta'ita'iina a'u i le papa e sili ona maualuga ia te au.", "lead me to the rock that is higher than I."]]},
  {num:3,words:[["Auā ua fai oe mo'u malu,", "For thou hast been a shelter for me,"], ["o le 'olo malosi ai le ua ita mai.", "and a strong tower from the enemy."]]},
  {num:4,words:[["Ou te nofo e faavavau lava i lou fale fetafai;", "I will abide in thy tabernacle for ever:"], ["ou te faatuatua i le paolo o ou apaau. Selā.", "I will trust in the covert of thy wings. Selah."]]},
  {num:5,words:[["Auā o oe,", "For thou,"], ["le Atua e,", "O God,"], ["ua e faafofoga mai i a'u tautoga;", "hast heard my vows:"], ["na e foaiina mai le tofi o e matatau i lou suafa.", "thou hast given me the heritage of those that fear thy name."]]},
  {num:6,words:[["E te faaualoaina le soifua o le tupu;", "Thou wilt prolong the king's life:"], ["ia avea ona tausaga ia autupulaga.", "and his years as many generations."]]},
  {num:7,words:[["E tietie o ia e faavavau i luma o le Atua;", "He shall abide before God for ever: O prepare mercy and truth,"], ["ia e saunia le alofa ma le faamaoni la te leoleoina ai o ia.", "which may preserve him."]]},
  {num:8,words:[["Ona ou fai pesega ai lea i lou suafa e faavavau,", "So will I sing praise unto thy name for ever,"], ["ina ia ou avatua i lea aso ma lea aso o mea na ou tauto ai.", "that I may daily perform my vows."]]},
];
renderVerseSet(psa_ch_61_Verses, 'psa-ch61-verses');

var psa_ch_62_Verses = [
  {num:1,words:[["E moni lava, e faalologo lo'u agaga i luma o le Atua;", "Truly my soul waiteth upon God:"], ["mai ia te ia lo'u faaolataga.", "from him cometh my salvation."]]},
  {num:2,words:[["E moni lava, o ia lo'u papa,", "He only is my rock and my salvation;"], ["ma lo'u faaolataga,", "he is my defence;"], ["o lo'u 'olo maualuga; e le faagaeeteleina a'u.", "I shall not be greatly moved."]]},
  {num:3,words:[["Tou te feosofi ea i le tagata seia afea? E fasiotia outou uma lava;", "How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be,"], ["e pei o le pa ua tulolo o le āi ua tuleia.", "and as a tottering fence."]]},
  {num:4,words:[["E moni,", "They only consult to cast him down from his excellency:"], ["ua latou filifilia ina ia tuleia o ia ai lona mamalu;", "they delight in lies:"], ["ua naunau i latou i le pepelo; ua latou faamanuia i o latou gutu,", "they bless with their mouth,"], ["a ua fetuu i o latou loto.", "but they curse inwardly."], ["Selā.", "Selah."]]},
  {num:5,words:[["E moni lo'u agaga e,", "My soul,"], ["e te faalologo lava i luma o le Atua;", "wait thou only upon God;"], ["auā mai ia te ia lava lo'u faamoemoe.", "for my expectation is from him."]]},
  {num:6,words:[["E moni lava, o ia lo'u papa,", "He only is my rock and my salvation:"], ["ma lo'u faaolataga,", "he is my defence;"], ["o lo'u 'olo maualuga; e le faagaeeina a'u.", "I shall not be moved."]]},
  {num:7,words:[["O loo i le Atua lo'u olataga ma lo'u mamalu;", "In God is my salvation and my glory: the rock of my strength,"], ["o lo'u papa malosi ma lo'u malu o loo i le Atua ia.", "and my refuge, is in God."]]},
  {num:8,words:[["Le nuu e,", "Trust in him at all times;"], ["ia outou faatuatua ia te ia i aso uma;", "ye people,"], ["ia outou momoli atu o outou loto i ona luma;", "pour out your heart before him:"], ["o lo tatou malu o le Atua lea. Selā.", "God is a refuge for us. Selah."]]},
  {num:9,words:[["E moni,", "Surely men of low degree are vanity,"], ["e faatauvaa lava tagata lautele,", "and men of high degree are a lie:"], ["e pepelo foi alii; e siitia i latou i le fua faatautau,", "to be laid in the balance,"], ["o i latou faatasi e sili ona mamasagia i le mea faatauvaa.", "they are altogether lighter than vanity."]]},
  {num:10,words:[["Aua tou te faatuatua i le faasaua,", "Trust not in oppression,"], ["aua foi ne'i outou mitamita vale i mea ua faoa;", "and become not vain in robbery:"], ["a faateleina le oloa,", "if riches increase,"], ["aua ne'i uai o outou loto i ai.", "set not your heart upon them."]]},
  {num:11,words:[["Na fetalai faatasi mai le Atua;", "God hath spoken once;"], ["ua ou faalogo faalua i lenei mea,", "twice have I heard this;"], ["o i le Atua le malosi.", "that power belongeth unto God."]]},
  {num:12,words:[["Le Alii e,", "Also unto thee,"], ["o loo ia te oe foi le alofa;", "O Lord, belongeth mercy:"], ["auā o oe e te taui taitasi atu i tagata e tusa ma a latou galuega.", "for thou renderest to every man according to his work."]]},
];
renderVerseSet(psa_ch_62_Verses, 'psa-ch62-verses');

var psa_ch_63_Verses = [
  {num:1,words:[["Le Atua e,", "O God,"], ["o lo'u Atua lava oe;", "thou art my God;"], ["ou te ala saili ia te oe; ua fia inu lo'u agaga ia te oe,", "early will I seek thee:"], ["ua ou matuā naunau atu ia te oe i le nuu naumati,", "my soul thirsteth for thee,"], ["e lailoa ai,", "my flesh longeth for thee in a dry and thirsty land,"], ["e leai ni vai;", "where no water is;"]]},
  {num:2,words:[["ia ou iloa lou malosi ma lou mamalu,", "To see thy power and thy glory,"], ["e pei ona ou iloa oe i le malumalu.", "so as I have seen thee in the sanctuary."]]},
  {num:3,words:[["Auā o lou alofa e sili ona lelei lea i le ola;", "Because thy lovingkindness is better than life,"], ["ou te vivii atu lava ia te oe i o'u laugutu.", "my lips shall praise thee."]]},
  {num:4,words:[["O lea ou te faamanū atu ai ia te oe a o ou ola;", "Thus will I bless thee while I live:"], ["ou te sii o'u lima i lou suafa.", "I will lift up my hands in thy name."]]},
  {num:5,words:[["E peiseai o le ga'o ma le mea lololo, ou te ma'ona ai lava a'u;", "My soul shall be satisfied as with marrow and fatness;"], ["e vivii atu foi ia te oe o lo'u gutu ma o'u laugutu e alaga fiafia.", "and my mouth shall praise thee with joyful lips:"]]},
  {num:6,words:[["A ou manatua oe i lo'u moega,", "When I remember thee upon my bed,"], ["ou te mafaufau ia te oe i leoleoga i itu po.", "and meditate on thee in the night watches."]]},
  {num:7,words:[["Auā na fai oe ma fesoasoani ia te au;", "Because thou hast been my help,"], ["ou te olioli foi i le paolo o ou apaau.", "therefore in the shadow of thy wings will I rejoice."]]},
  {num:8,words:[["Ua pipii atu lava lo'u loto ia te oe;", "My soul followeth hard after thee:"], ["o lou aao taumatau ua taofiina ai a'u.", "thy right hand upholdeth me."]]},
  {num:9,words:[["A o i latou o e saili e fasioti ia te au ia ou fano,", "But those that seek my soul, to destroy it,"], ["latou te oo i mea loloto i le eleele.", "shall go into the lower parts of the earth."]]},
  {num:10,words:[["E tuuina atu i latou i le pelu e oti ai;", "They shall fall by the sword:"], ["e avea i latou ma tufaaga a alope.", "they shall be a portion for foxes."]]},
  {num:11,words:[["A o le tupu,", "But the king shall rejoice in God;"], ["e fiafia lava ia i le Atua; e taitasi ma mitamita o e tauto ia te ia;", "every one that sweareth by him shall glory:"], ["auā e punitia gutu o e tala pepelo.", "but the mouth of them that speak lies shall be stopped."]]},
];
renderVerseSet(psa_ch_63_Verses, 'psa-ch63-verses');

var psa_ch_64_Verses = [
  {num:1,words:[["Le Atua e,", "Hear my voice,"], ["ia e faafofoga mai i la'u tatalo;", "O God, in my prayer:"], ["ia e leoleo mai i lo'u ola ia le mata'u i le ua ita mai.", "preserve my life from fear of the enemy."]]},
  {num:2,words:[["Ia e natia a'u ai le taupulepulega a e amio leaga,", "Hide me from the secret counsel of the wicked;"], ["ma le faanunununu o e fai amioletonu.", "from the insurrection of the workers of iniquity:"]]},
  {num:3,words:[["Ua latou faamataina o latou laulaufaiva e pei o se pelu;", "Who whet their tongue like a sword,"], ["ua latou lolou i aufana e fana mai a latou u,", "and bend their bows to shoot their arrows,"], ["o upu ogo lava ia;", "even bitter words:"]]},
  {num:4,words:[["ina ia latou fana lafitai i le ua amio sao;", "That they may shoot in secret at the perfect:"], ["e faafuasei ona latou fana ia te ia,", "suddenly do they shoot at him,"], ["latou te le matatau lava.", "and fear not."]]},
  {num:5,words:[["Ua latou fefaamalosiai i le mea leaga;", "They encourage themselves in an evil matter:"], ["ua latou filifili e natia ni matāsele;", "they commune of laying snares privily;"], ["ua latou faapea ane,", "they say,"], ["O ai se na te iloa i latou?", "Who shall see them?"]]},
  {num:6,words:[["Ua latou saili mea leaga;", "They search out iniquities;"], ["ua faapea ane ,", "they accomplish a diligent search:"], ["Ua uma ona tatou matuā sailiili lava;", "both the inward thought of every one of them, and the heart,"], ["o latou mafaufau taitasi ma le loto ua suegata lava.", "is deep."]]},
  {num:7,words:[["A o le Atua, na te fanaina atu le u ia te i latou e faafuasei;", "But God shall shoot at them with an arrow;"], ["e manunua ai i latou.", "suddenly shall they be wounded."]]},
  {num:8,words:[["E leaga i latou i o latou lava laulaufaiva;", "So they shall make their own tongue to fall upon themselves:"], ["e taitasi ma sola ese lava o e vaavaai ia te i latou.", "all that see them shall flee away."]]},
  {num:9,words:[["E matatau tagata uma,", "And all men shall fear,"], ["latou te faaaliina atu foi le mea ua faia e le Atua;", "and shall declare the work of God;"], ["latou te mafaufau foi i lana galuega.", "for they shall wisely consider of his doing."]]},
  {num:10,words:[["E fiafia lē amiotonu ia Ieova,", "The righteous shall be glad in the LORD,"], ["ma faalagolago ia te ia;", "and shall trust in him;"], ["ona mitamita ai lea o i latou uma ua loto sa'o.", "and all the upright in heart shall glory."]]},
];
renderVerseSet(psa_ch_64_Verses, 'psa-ch64-verses');

var psa_ch_65_Verses = [
  {num:1,words:[["Le Atua e,", "Praise waiteth for thee,"], ["ua ia te oe le viiga e faia ma le faalologo i Siona;", "O God, in Sion:"], ["e avatua lava ia te oe le mea na tauto ai.", "and unto thee shall the vow be performed."]]},
  {num:2,words:[["Le faafofoga tatalo e,", "O thou that hearest prayer,"], ["e o atu ia te oe tagata uma lava.", "unto thee shall all flesh come."]]},
  {num:3,words:[["Ua manumalo mai ia te au o amio leaga;", "Iniquities prevail against me: as for our transgressions,"], ["o a matou solitulafono e te togiolaina lava e oe.", "thou shalt purge them away."]]},
  {num:4,words:[["Amuia le ua e filifilia,", "Blessed is the man whom thou choosest,"], ["ma e faalatalataina o ia ia te oe ,", "and causest to approach unto thee,"], ["e nofo o ia i ou lotoā;", "that he may dwell in thy courts:"], ["e maoona i matou i mea lelei o i lou fale,", "we shall be satisfied with the goodness of thy house,"], ["o lou lava malumalu paia.", "even of thy holy temple."]]},
  {num:5,words:[["Le Atua o lo matou olataga e,", "By terrible things in righteousness wilt thou answer us,"], ["e te tali mai ia te i matou ma le tonu i mea matautia;", "O God of our salvation;"], ["o oe le faatuatuaga o tulu'iga uma lava o le lalolagi,", "who art the confidence of all the ends of the earth,"], ["atoa ma e o mamao i le vasa.", "and of them that are afar off upon the sea:"]]},
  {num:6,words:[["O loo faatumauina mauga i lona lava malosi;", "Which by his strength setteth fast the mountains;"], ["o loo fusia o ia i le mana;", "being girded with power:"]]},
  {num:7,words:[["o le taalili o le sami ua faalologo ia te ia,", "Which stilleth the noise of the seas,"], ["o le taalili foi o ona peau,", "the noise of their waves,"], ["ma le vāvāō o nuu.", "and the tumult of the people."]]},
  {num:8,words:[["Ua matatau foi i ou faailoga o e nonofo i mea mamao; o mea e aliali i le taeao ma le afiafi,", "They also that dwell in the uttermost parts are afraid at thy tokens:"], ["o oe ua alalaga fiafia ai ia mea .", "thou makest the outgoings of the morning and evening to rejoice."]]},
  {num:9,words:[["Ua e asiasi i le laueleele,", "Thou visitest the earth,"], ["ma e faasūsūina lava;", "and waterest it:"], ["ua e faalafulemuteleina ai;", "thou greatly enrichest it with the river of God, which is full of water:"], ["o le vaitafe o le Atua ua tumu i le vai;", "thou preparest them corn,"], ["ua e saunia a latou saito ina ua faapea ona e sauni i ai.", "when thou hast so provided for it."]]},
  {num:10,words:[["Ua e faasūsūteleina ona atu pue;", "Thou waterest the ridges thereof abundantly:"], ["e faatafe ifo le ua i ona utu;", "thou settlest the furrows thereof:"], ["ua e faamalulu ai i le uaga;", "thou makest it soft with showers:"], ["e te faaolaolaina foi ona moemoe.", "thou blessest the springing thereof."]]},
  {num:11,words:[["Ua e faaee i le tausaga le palealii o lou agalelei;", "Thou crownest the year with thy goodness;"], ["o ou ala na tautulu ai mea lololo.", "and thy paths drop fatness."]]},
  {num:12,words:[["Ua tautulu ai i le vao i mea e tataa ai manu;", "They drop upon the pastures of the wilderness:"], ["o mauga foi ua fusia ia i le fusi i le fiafia.", "and the little hills rejoice on every side."]]},
  {num:13,words:[["O mea e tataa ai manu ua liloia i lafu mamoe;", "The pastures are clothed with flocks;"], ["ua ufitia foi vanu i le saito;", "the valleys also are covered over with corn;"], ["ua latou alalaga fiafia,", "they shout for joy,"], ["ua pepese lava.", "they also sing."]]},
];
renderVerseSet(psa_ch_65_Verses, 'psa-ch65-verses');

var psa_ch_66_Verses = [
  {num:1,words:[["Le lalolagi uma e,", "Make a joyful noise unto God,"], ["ia outou alalaga atu i le Atua.", "all ye lands:"]]},
  {num:2,words:[["Ia outou pepese atu i lona suafa mamalu;", "Sing forth the honour of his name:"], ["ia mamalu ia te outou lona viiga.", "make his praise glorious."]]},
  {num:3,words:[["Ia outou fai atu i le Atua,", "Say unto God,"], ["E matuā matautia oe i au galuega. O lou malosi tele e faatagā vivii atu ai ia te oe o e ua ita ia te oe.", "How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee."]]},
  {num:4,words:[["E ifo atu lava ia te oe le lalolagi uma;", "All the earth shall worship thee,"], ["latou te fai pesega ia te oe,", "and shall sing unto thee;"], ["latou te fai pesega i lou suafa. Selā.", "they shall sing to thy name. Selah."]]},
  {num:5,words:[["O mai ia, ia outou matamata i galuega a le Atua;", "Come and see the works of God:"], ["e matautia ia i mea na na faia i le fanau a tagata.", "he is terrible in his doing toward the children of men."]]},
  {num:6,words:[["Na ia liua le sami ma laueleele matutu;", "He turned the sea into dry land:"], ["na latou sopoia atu le vaitafe i o latou vae;", "they went through the flood on foot:"], ["na tatou fiafia ia te ia i lea mea.", "there did we rejoice in him."]]},
  {num:7,words:[["E pule ia e faavavau i lona lava malosi;", "He ruleth by his power for ever;"], ["ua matuā silasila atu ona fofoga i nuu ese; o e fouvale,", "his eyes behold the nations:"], ["aua ne'i faamaualuga i latou.", "let not the rebellious exalt themselves."], ["Selā.", "Selah."]]},
  {num:8,words:[["Le nuu e,", "O bless our God,"], ["ia outou faafetai atu i lo tatou Atua;", "ye people,"], ["ia lagona mai le leo o lona viiga.", "and make the voice of his praise to be heard:"]]},
  {num:9,words:[["O le na tuuina mai le ola i totonu ia i tatou,", "Which holdeth our soul in life,"], ["na te le tuuna i tatou ia mapepeva ai o tatou vae.", "and suffereth not our feet to be moved."]]},
  {num:10,words:[["Auā na e suesueina i matou,", "For thou,"], ["le Atua e;", "O God,"], ["na e tofotofoina i matou,", "hast proved us: thou hast tried us,"], ["e pei o le ario ona tofotofoina.", "as silver is tried."]]},
  {num:11,words:[["Na e aumaia i matou i le upega;", "Thou broughtest us into the net;"], ["na e tuuina mai mea mamafa i o matou tua.", "thou laidst affliction upon our loins."]]},
  {num:12,words:[["Na e faatietie tagata i o matou ulu;", "Thou hast caused men to ride over our heads;"], ["na matou savavali i le afi ma le vai;", "we went through fire and through water:"], ["a ua e ta'ita'iina mai i matou i le nuu lafulemu.", "but thou broughtest us out into a wealthy place."]]},
  {num:13,words:[["Ou te alu atu i lou fale ma taulaga mu;", "I will go into thy house with burnt offerings:"], ["ou te avatua ia te oe mea na ou tauto ai.", "I will pay thee my vows,"]]},
  {num:14,words:[["O mea ia na ou fai atu ai i o'u laugutu,", "Which my lips have uttered, and my mouth hath spoken,"], ["na ou tautala atu ai i lo'u gutu i lo'u puapuaga.", "when I was in trouble."]]},
  {num:15,words:[["Ou te avatua ia te oe taulaga mu i mea pepeti, atoa ma mea manogi;", "I will offer unto thee burnt sacrifices of fatlings,"], ["ou te saunia mamoe poa,", "with the incense of rams;"], ["o povi poa, atoa ma 'oti poa.", "I will offer bullocks with goats."], ["Selā.", "Selah."]]},
  {num:16,words:[["Outou uma o e matatau i le Atua,", "Come and hear,"], ["o mai ia, ina faalogologo mai,", "all ye that fear God,"], ["ona ou ta'u atu ai lea o mea na na faia mo lo'u agaga.", "and I will declare what he hath done for my soul."]]},
  {num:17,words:[["Na ou alaga atu ia te ia i lo'u gutu,", "I cried unto him with my mouth,"], ["ua viia foi o ia e lo'u laulaufaiva.", "and he was extolled with my tongue."]]},
  {num:18,words:[["Ana ou manatu i se amio leaga i lo'u loto,", "If I regard iniquity in my heart,"], ["po ua le faafofoga mai le Alii ia te au;", "the Lord will not hear me:"]]},
  {num:19,words:[["a e peitai ua faafofogaina mai a'u e le Atua;", "But verily God hath heard me;"], ["ua ia liliu mai i le leo o la'u tatalo.", "he hath attended to the voice of my prayer."]]},
  {num:20,words:[["Ia faafetaia le Atua,", "Blessed be God,"], ["ua na le liliueseina la'u tatalo,", "which hath not turned away my prayer,"], ["po o lona alofa ia te au.", "nor his mercy from me."]]},
];
renderVerseSet(psa_ch_66_Verses, 'psa-ch66-verses');

var psa_ch_67_Verses = [
  {num:1,words:[["Ia alofa mai le Atua ia i matou,", "God be merciful unto us,"], ["ma ia faamanuia mai i matou;", "and bless us; and cause his face to shine upon us;"], ["ia malamalama mai ia te i matou ona fofoga. Selā.", "Selah."]]},
  {num:2,words:[["Ina ia iloa lou ala i le lalolagi,", "That thy way may be known upon earth,"], ["o le olataga mai ia te oe i nuu ese uma lava.", "thy saving health among all nations."]]},
  {num:3,words:[["Le Atua e,", "Let the people praise thee,"], ["ia viia oe e le nuu; ia viia lava oe e le nuu,", "O God;"], ["o i latou uma lava.", "let all the people praise thee."]]},
  {num:4,words:[["Ia fiafia nuu,", "O let the nations be glad and sing for joy:"], ["ia latou alalaga fiafia; auā e te faamasino tonu mai i tagata,", "for thou shalt judge the people righteously,"], ["e te ta'ita'i foi i nuu o i le lalolagi.", "and govern the nations upon earth."], ["Selā.", "Selah."]]},
  {num:5,words:[["Le Atua e,", "Let the people praise thee,"], ["ia viia oe e le nuu; ia viia lava oe e le nuu,", "O God;"], ["o i latou uma lava.", "let all the people praise thee."]]},
  {num:6,words:[["Ua fua mai e le laueleele ona lava fua;", "Then shall the earth yield her increase;"], ["o le Atua,", "and God, even our own God,"], ["o lo matou Atua lava na te faamanuia mai i matou.", "shall bless us."]]},
  {num:7,words:[["O le Atua na te faamanuia mai i matou;", "God shall bless us;"], ["ona matatau ai lea ia te ia o tulu'iga uma o le lalolagi.", "and all the ends of the earth shall fear him."]]},
];
renderVerseSet(psa_ch_67_Verses, 'psa-ch67-verses');

var psa_ch_68_Verses = [
  {num:1,words:[["Ia tulai mai le Atua,", "Let God arise,"], ["ia faataapeapeina e ua ita ia te ia;", "let his enemies be scattered:"], ["ia sosola ese foi i ona luma o e ua 'ino'ino ia te ia.", "let them also that hate him flee before him."]]},
  {num:2,words:[["E pei ona lelea o le asu,", "As smoke is driven away,"], ["ia faapea ona e faaleleaina i latou;", "so drive them away:"], ["e pei ona liu suāvai o le pulu i le afi,", "as wax melteth before the fire,"], ["ia faapea ona fano i luma o le Atua o e amio leaga.", "so let the wicked perish at the presence of God."]]},
  {num:3,words:[["A ia fiafia o e amiotonu;", "But let the righteous be glad;"], ["ia latou olioli lava i luma o le Atua;", "let them rejoice before God: yea,"], ["ia matuā fiafia lava i latou.", "let them exceedingly rejoice."]]},
  {num:4,words:[["Ia outou pepese atu i le Atua,", "Sing unto God,"], ["ia fai pesega i lona suafa;", "sing praises to his name:"], ["ia outou faalaulelei le ala mo lē tietie ma afio atu i le vao; o Ioa o lona suafa lea,", "extol him that rideth upon the heavens by his name JAH,"], ["ma ia outou olioli i ona luma.", "and rejoice before him."]]},
  {num:5,words:[["O le Tamā ia o e ua mātuaoti,", "A father of the fatherless,"], ["le na te faamasinoina mo fafine ua oti a latou tane,", "and a judge of the widows,"], ["o le Atua lea o loo i lona afioaga paia.", "is God in his holy habitation."]]},
  {num:6,words:[["O le Atua na te faatagatāina e ua ausage;", "God setteth the solitary in families:"], ["na te aumaia e ua noanoatia i le mea e manuia ai; a o e fouvale,", "he bringeth out those which are bound with chains:"], ["latou te nonofo i le nuu naumati.", "but the rebellious dwell in a dry land."]]},
  {num:7,words:[["Le Atua e,", "O God,"], ["na e muamua atu i lou nuu,", "when thou wentest forth before thy people, when thou didst march through the wilderness;"], ["na e afio atu i le vao. Selā.", "Selah:"]]},
  {num:8,words:[["Ona gatete ai lea o le lalolagi,", "The earth shook,"], ["ole lagi foi na tautulu ifo i luma o le Atua;", "the heavens also dropped at the presence of God:"], ["o Sinai lava na gatete ia i luma o le Atua,", "even Sinai itself was moved at the presence of God,"], ["o le Atua o Isaraelu.", "the God of Israel."]]},
  {num:9,words:[["Le Atua e,", "Thou,"], ["na e faatotoina ifo le ua tele,", "O God,"], ["o lou tofi sa lailoa,", "didst send a plentiful rain, whereby thou didst confirm thine inheritance,"], ["o oe lava na e faamalosia.", "when it was weary."]]},
  {num:10,words:[["Sa nofo i ai lau faapotopotoga;", "Thy congregation hath dwelt therein:"], ["le Atua e,", "thou, O God,"], ["o lou alofa na e sauni ai mo le ua puapuagatia.", "hast prepared of thy goodness for the poor."]]},
  {num:11,words:[["Na tŭlei mai le afioga a le Alii;", "The Lord gave the word:"], ["e tele 'au o e na tala'iina.", "great was the company of those that published it."]]},
  {num:12,words:[["Na sosola tupu o 'au, na latou sosola lava;", "Kings of armies did flee apace:"], ["o le fafine foi na faamuli na ia tufatufaina le vete.", "and she that tarried at home divided the spoil."]]},
  {num:13,words:[["E ui lava ina taooto outou i le va o ulo,", "Though ye have lien among the pots,"], ["e avea outou e pei o apaau o le lupe e liloia i ario,", "yet shall ye be as the wings of a dove covered with silver,"], ["ma ona fulu e liloia i le auro samasama.", "and her feathers with yellow gold."]]},
  {num:14,words:[["Na faataapeapeina ai tupu e Le e ona le malosi uma lava,", "When the Almighty scattered kings in it,"], ["ona sinasina ai lea e pei o le kiona i Salemoni.", "it was white as snow in Salmon."]]},
  {num:15,words:[["O le mauga o Vasana, o le mauga o le Atua lea;", "The hill of God is as the hill of Bashan;"], ["o le mauga o Vasana, o le atu mauga lava lea.", "an high hill as the hill of Bashan."]]},
  {num:16,words:[["Le atumauga e,", "Why leap ye,"], ["se a le mea tou te lamalama mai ai? O le mauga nei ua finagalo le Atua e afio ai;", "ye high hills? this is the hill which God desireth to dwell in; yea,"], ["e mau ai lava Ieova e faavavau.", "the LORD will dwell in it for ever."]]},
  {num:17,words:[["O kariota o le Atua e lua sefulu o afe,", "The chariots of God are twenty thousand,"], ["e manomano lava;", "even thousands of angels:"], ["o loo ia te i latou le Alii,", "the Lord is among them, as in Sinai,"], ["e pei ona i ai Sinai i le mea paia.", "in the holy place."]]},
  {num:18,words:[["Na e afio ae i le mea maualuga,", "Thou hast ascended on high,"], ["na e ta'ita'i faatagataotaua i le tafeaga;", "thou hast led captivity captive:"], ["na e maua meaalofa mo tagata,", "thou hast received gifts for men; yea,"], ["o e fouvale lava,", "for the rebellious also,"], ["ina ia nofo ai Ioa le Atua.", "that the LORD God might dwell among them."]]},
  {num:19,words:[["Ia faafetaia le Alii i lea aso ma lea aso;", "Blessed be the Lord,"], ["ua faaee avega ia te i tatou,", "who daily loadeth us with benefits,"], ["o le Atua o lo tatou olataga ia. Selā.", "even the God of our salvation. Selah."]]},
  {num:20,words:[["O lo tatou Atua, o le Atua o le olataga lea;", "He that is our God is the God of salvation;"], ["o Ieova le Alii e ana e faasaoina i le oti.", "and unto GOD the Lord belong the issues from death."]]},
  {num:21,words:[["E moni, o le Atua na te foaina ulu o e ita ia te ia,", "But God shall wound the head of his enemies,"], ["o le tumuai lauulua o le ua finau i ana agasala.", "and the hairy scalp of such an one as goeth on still in his trespasses."]]},
  {num:22,words:[["Ua fetalai mai le Alii,", "The Lord said,"], ["Ou te faafoisia mai mai Vasana,", "I will bring again from Bashan,"], ["ou te faafoisia mai mai le loloto o le sami;", "I will bring my people again from the depths of the sea:"]]},
  {num:23,words:[["ina ia feseuai lou vae i le toto;", "That thy foot may be dipped in the blood of thine enemies,"], ["ia etoeto foi laulaufaiva o āu ulī le toto o e ita ia te oe taitasi uma lava.", "and the tongue of thy dogs in the same."]]},
  {num:24,words:[["Le Atua e,", "They have seen thy goings,"], ["na latou iloa lou afio atu;", "O God;"], ["o le afio atu o lo'u Atua,", "even the goings of my God, my King,"], ["ma lo'u Tupu i le malumalu.", "in the sanctuary."]]},
  {num:25,words:[["Ua muamua o e pepese,", "The singers went before,"], ["ua mulimuli o e ta laaupese;", "the players on instruments followed after;"], ["ua i le va taupou ta topa.", "among them were the damsels playing with timbrels."]]},
  {num:26,words:[["Ia faafetaia le Atua i faapotopotoga,", "Bless ye God in the congregations,"], ["o le Alii lava,", "even the Lord,"], ["outou na ua puna mai ia Isaraelu.", "from the fountain of Israel."]]},
  {num:27,words:[["O i ai Peniamina le uii,", "There is little Benjamin with their ruler,"], ["o le pule ia i latou;", "the princes of Judah and their council,"], ["o alii o Iuta ma o latou faipule;", "the princes of Zebulun,"], ["o alii o Sepulona atoa ma alii o Nafatali.", "and the princes of Naphtali."]]},
  {num:28,words:[["Ua pule mai e lou Atua lou malosi;", "Thy God hath commanded thy strength:"], ["le Atua e,", "strengthen, O God,"], ["ia malosi oe i le mea ua e faia mo i matou.", "that which thou hast wrought for us."]]},
  {num:29,words:[["O tupu latou te avatu mea alofa ia te oe, ona o lou malumalu i Ierusalema.", "Because of thy temple at Jerusalem shall kings bring presents unto thee."]]},
  {num:30,words:[["Ia e aoai i manu feai o i mea ūa,", "Rebuke the company of spearmen,"], ["atoa ma le vao povi malolosi ma tamai povi a le nuu,", "the multitude of the bulls,"], ["seia ifo mai ia ma fāsi ario;", "with the calves of the people, till every one submit himself with pieces of silver:"], ["ia e faataapeapeina le nuu ua naunau i taua.", "scatter thou the people that delight in war."]]},
  {num:31,words:[["E o mai alii sili mai Aikupito;", "Princes shall come out of Egypt;"], ["e vave ona faaloaloa atu e Aitiope ona lima i le Atua.", "Ethiopia shall soon stretch out her hands unto God."]]},
  {num:32,words:[["O outou malo o le lalolagi ina pepese atu ia i le Atua;", "Sing unto God,"], ["ia outou fai pesega i le Alii;", "ye kingdoms of the earth; O sing praises unto the Lord;"], ["Selā;", "Selah:"]]},
  {num:33,words:[["o lē tietie atu i lagi o lagi o le vavau;", "To him that rideth upon the heavens of heavens, which were of old;"], ["faauta,", "lo,"], ["ua ia tŭlei mai lona siufofoga o le siufofoga malosi.", "he doth send out his voice, and that a mighty voice."]]},
  {num:34,words:[["Ia outou tuu atu le malosi i le Atua;", "Ascribe ye strength unto God:"], ["o loo i luga o Isaraelu lona silisili ese,", "his excellency is over Israel,"], ["o loo i ao foi lona malosi.", "and his strength is in the clouds."]]},
  {num:35,words:[["Le Atua e,", "O God,"], ["ua matautia oe ai ou afioaga paia; o le Atua o Isaraelu,", "thou art terrible out of thy holy places:"], ["o ia lea na te tuuina atu le malosi ma le fitafita i lona nuu.", "the God of Israel is he that giveth strength and power unto his people."], ["Ia faafetaia lava le Atua.", "Blessed be God."]]},
];
renderVerseSet(psa_ch_68_Verses, 'psa-ch68-verses');

var psa_ch_69_Verses = [
  {num:1,words:[["Le Atua e,", "Save me,"], ["ia e faaola mai ia te au; auā o a'u nei,", "O God;"], ["a malemo lava a'u i le vai.", "for the waters are come in unto my soul."]]},
  {num:2,words:[["O le a a'u goto i le palapala loloto,", "I sink in deep mire,"], ["e le o i ai se mea e tu ai;", "where there is no standing:"], ["ua oo lava a'u i mea loloto o le vai,", "I am come into deep waters,"], ["ua lofia foi a'u i le vaitafe.", "where the floods overflow me."]]},
  {num:3,words:[["Ua lailoa lava a'u i lo'u valaau;", "I am weary of my crying:"], ["ua fa lo'u leo; ua mole lava o'u mata,", "my throat is dried:"], ["a o faatalitali atu a'u i lo'u Atua.", "mine eyes fail while I wait for my God."]]},
  {num:4,words:[["O e ua 'ino'ino fua mai ia te au,", "They that hate me without a cause are more than the hairs of mine head:"], ["e toatele i latou i o'u lauulu;", "they that would destroy me,"], ["e malolosi lava o e fia fasiotia mai a'u,", "being mine enemies wrongfully,"], ["o e ita fua mai ia te au;", "are mighty:"], ["o mea na ou le faoa ua ou toe avatua lava.", "then I restored that which I took not away."]]},
  {num:5,words:[["Le Atua e,", "O God,"], ["o oe lava ua e silafia mai lo'u valea;", "thou knowest my foolishness;"], ["e le lilo foi a'u agasala ia te oe.", "and my sins are not hid from thee."]]},
  {num:6,words:[["Le Alii e,", "Let not them that wait on thee,"], ["Ieova o 'au,", "O Lord GOD of hosts,"], ["aua ne'i faamaina ona o a'u o e faatalitali atu ia te oe;", "be ashamed for my sake:"], ["le Atua o Isaraelu e,", "let not those that seek thee be confounded for my sake,"], ["aua ne'i masiasi ona o a'u o e sailiili ia te oe.", "O God of Israel."]]},
  {num:7,words:[["Auā ua faalumaina lava a'u ona o oe;", "Because for thy sake I have borne reproach;"], ["ua ufitia o'u mata i le ma.", "shame hath covered my face."]]},
  {num:8,words:[["Ua fai a'u ma tagata āumau i o'u uso,", "I am become a stranger unto my brethren,"], ["ma tagata ese i le fanau a lo'u tinā.", "and an alien unto my mother's children."]]},
  {num:9,words:[["Auā ua 'aina lava a'u i le manao tele i lou fale;", "For the zeal of thine house hath eaten me up;"], ["ua oo mai foi ia te au faifaiga a e na faifaia oe.", "and the reproaches of them that reproached thee are fallen upon me."]]},
  {num:10,words:[["Ua ou tagi,", "When I wept,"], ["ma ou anapogi,", "and chastened my soul with fasting,"], ["ua fai lea ma luma ia te au.", "that was to my reproach."]]},
  {num:11,words:[["Na ou ofu i le ie talatala;", "I made sackcloth also my garment;"], ["ona faia lea o a'u ma upu faatusa a i latou.", "and I became a proverb to them."]]},
  {num:12,words:[["Ua upuia a'u e i latou o e nonofo i le faitotoa,", "They that sit in the gate speak against me;"], ["ua fai foi ma pese a e inu 'ava.", "and I was the song of the drunkards."]]},
  {num:13,words:[["A o a'u,", "But as for me,"], ["ou te tatalo ia te oe,", "my prayer is unto thee,"], ["Ieova e,", "O LORD,"], ["i ona po o le alofa;", "in an acceptable time:"], ["le Atua e,", "O God,"], ["ona o le tele o lou alofa,", "in the multitude of thy mercy hear me,"], ["ia e tali mai ia te au i le faamaoni o le olataga mai ia te oe.", "in the truth of thy salvation."]]},
  {num:14,words:[["Ia e laveai mai ia te au ai le palapala,", "Deliver me out of the mire,"], ["aua ne'i ou goto ai;", "and let me not sink:"], ["ia laveaiina a'u i e ua 'ino'ino mai ia te au,", "let me be delivered from them that hate me,"], ["atoa ma vai loloto.", "and out of the deep waters."]]},
  {num:15,words:[["Aua ne'i lofia a'u i le vaitafe,", "Let not the waterflood overflow me,"], ["aua foi ne'i tofatumoanaina a'u i le mea loloto,", "neither let the deep swallow me up,"], ["aua foi ne'i punitia le gutu o le lua i luga o a'u.", "and let not the pit shut her mouth upon me."]]},
  {num:16,words:[["Ieova e,", "Hear me,"], ["ia e tali mai ia te au,", "O LORD;"], ["auā e lelei lou alofa mai; ia e liuliu alo mai ia te au,", "for thy lovingkindness is good:"], ["e pei ona tele o lou alofa mutimuti vale.", "turn unto me according to the multitude of thy tender mercies."]]},
  {num:17,words:[["Aua ne'i 'alo ou fofoga i lau auauna;", "And hide not thy face from thy servant;"], ["auā ua ou puapuagaina;", "for I am in trouble:"], ["ia vave ona e tali mai ia te au.", "hear me speedily."]]},
  {num:18,words:[["Ia e faalatalata mai i lo'u agaga e faaola mai ai;", "Draw nigh unto my soul, and redeem it:"], ["ia e laveai mai ia te au auā o e ita mai ia te au.", "deliver me because of mine enemies."]]},
  {num:19,words:[["O oe,", "Thou hast known my reproach,"], ["ua e silafia le faalumaina o a'u,", "and my shame,"], ["ma le faamaina o a'u, ma lo'u faamasiasiga;", "and my dishonour:"], ["ua i ou luma o i latou uma o e ita mai ia te au.", "mine adversaries are all before thee."]]},
  {num:20,words:[["O le luma ua momomo ai lo'u loto,", "Reproach hath broken my heart;"], ["ua ma'i lava a'u;", "and I am full of heaviness:"], ["ua ou faatalitali foi i se na te faamatalaloto mai,", "and I looked for some to take pity,"], ["a e leai lava se tasi,", "but there was none;"], ["ma ni e faamafanafana mai,", "and for comforters,"], ["a e leai se isi na ou maua.", "but I found none."]]},
  {num:21,words:[["Na latou avane le mea oona e fai ma'u mea e 'ai; ua ou fia inu,", "They gave me also gall for my meat;"], ["ona latou avane ai lea o le vineta ou te inu ai.", "and in my thirst they gave me vinegar to drink."]]},
  {num:22,words:[["O latou laoai i o latou luma,", "Let their table become a snare before them:"], ["ia avea lea ma matāsele; o latou filemu foi,", "and that which should have been for their welfare,"], ["ia fai ma mailei.", "let it become a trap."]]},
  {num:23,words:[["Ia faapouliuligia lava o latou mata,", "Let their eyes be darkened,"], ["ia latou le mavaavaai ai;", "that they see not;"], ["ia tetemu o latou sulugatiti e le aunoa.", "and make their loins continually to shake."]]},
  {num:24,words:[["Ia sasaaina atu lou toasa ia i latou;", "Pour out thine indignation upon them,"], ["ia oo atu lava ia te i latou lou toatamai e matuā tele.", "and let thy wrathful anger take hold of them."]]},
  {num:25,words:[["Ia faatafunaina le mea latou te nonofo ai;", "Let their habitation be desolate;"], ["aua foi ne'i i ai sē inofo i o latou fale ie.", "and let none dwell in their tents."]]},
  {num:26,words:[["Auā ua latou tuliloa i le na taia lava e oe;", "For they persecute him whom thou hast smitten;"], ["ua latou ta'uta'u atu le tiga o e ua manunua ia te oe.", "and they talk to the grief of those whom thou hast wounded."]]},
  {num:27,words:[["Ia e faaopoopoina atu le agasala i la latou agasala;", "Add iniquity unto their iniquity:"], ["aua foi ne'i oo i latou i le amiotonu mai ia te oe.", "and let them not come into thy righteousness."]]},
  {num:28,words:[["Ia sōloia i latou ai le tusi o le ola;", "Let them be blotted out of the book of the living,"], ["aua foi ne'i tusia i latou faatasi ma e ua amiotonu.", "and not be written with the righteous."]]},
  {num:29,words:[["O a'u foi ua puapuagatia a'u,", "But I am poor and sorrowful:"], ["ma ua tiga lava;", "let thy salvation,"], ["le Atua e,", "O God,"], ["ia mamalu lava a'u i le olataga mai ia te oe.", "set me up on high."]]},
  {num:30,words:[["Ou te vivii atu i le suafa o le Atua i le pese;", "I will praise the name of God with a song,"], ["ou te faaneenee atu foi ia te ia i le viiga.", "and will magnify him with thanksgiving."]]},
  {num:31,words:[["E sili ona lelei lea ia Ieova i le povi, o le povi taanoa o i ai nifo ma atigivae.", "This also shall please the LORD better than an ox or bullock that hath horns and hoofs."]]},
  {num:32,words:[["E iloa e ua tigaina,", "The humble shall see this,"], ["ona latou olioli ai lea; ona fiafia ai lea o outou loto,", "and be glad:"], ["o outou ua saili i le Atua.", "and your heart shall live that seek God."]]},
  {num:33,words:[["Auā o loo faafofoga Ieova i e matitiva,", "For the LORD heareth the poor,"], ["e le 'ino'ino foi o ia i ona tagata ua noanoatia.", "and despiseth not his prisoners."]]},
  {num:34,words:[["Ia vivii atu ia te ia le lagi atoa ma le lalolagi;", "Let the heaven and earth praise him, the seas,"], ["o le sami atoa ma mea uma e tataa ai.", "and every thing that moveth therein."]]},
  {num:35,words:[["Auā o le Atua na te faaolaina Siona,", "For God will save Zion,"], ["na te faatuina foi aai o Iuta;", "and will build the cities of Judah:"], ["latou te nonofo ai,", "that they may dwell there,"], ["e fai foi mo i latou.", "and have it in possession."]]},
  {num:36,words:[["E fai foi ma tofi o le fanau a ana auauna;", "The seed also of his servants shall inherit it:"], ["o e alolofa atu i lona suafa e mau ai i latou.", "and they that love his name shall dwell therein."]]},
];
renderVerseSet(psa_ch_69_Verses, 'psa-ch69-verses');

var psa_ch_70_Verses = [
  {num:1,words:[["Le Atua e,", "Make haste,"], ["ia vave ona e laveai mai ia te au;", "O God,"], ["Ieova e,", "to deliver me; make haste to help me,"], ["ia vave ona e fesoasoani mai ia te au.", "O LORD."]]},
  {num:2,words:[["Ia mamā ma ia masiasi e ua sailiili ia ou oti;", "Let them be ashamed and confounded that seek after my soul: let them be turned backward,"], ["ia liutuaina ma ia faamaina e ua mananao i se mea e leaga ai a'u.", "and put to confusion, that desire my hurt."]]},
  {num:3,words:[["Ia faaliliuina i latou ona o lo latou mā,", "Let them be turned back for a reward of their shame that say,"], ["o e faapea ane,", "Aha,"], ["Ue! Ue!", "aha."]]},
  {num:4,words:[["Ia olioli ma fiafia ia te oe i latou uma o e sailiili ia te oe;", "Let all those that seek thee rejoice and be glad in thee:"], ["ia fai ane pea i latou o e fiafia i lau faaolataga,", "and let such as love thy salvation say continually,"], ["Ia viia le Atua.", "Let God be magnified."]]},
  {num:5,words:[["A o a'u, ua ou puapuagatia a'u,", "But I am poor and needy:"], ["ma le mativa;", "make haste unto me,"], ["le Atua e,", "O God:"], ["ia e vave mai ia te au; o lo'u fesoasoani ma lo'u faaola,", "thou art my help and my deliverer;"], ["o oe lava lea; Ieova e,", "O LORD,"], ["aua lava e te tuai mai.", "make no tarrying."]]},
];
renderVerseSet(psa_ch_70_Verses, 'psa-ch70-verses');

var psa_ch_71_Verses = [
  {num:1,words:[["Ieova e,", "In thee,"], ["ou te faatuatua ia te oe;", "O LORD, do I put my trust:"], ["aua ne'i faamaina a'u e oo i le faavavau.", "let me never be put to confusion."]]},
  {num:2,words:[["Ia e laveai mai ia te au i lau amiotonu,", "Deliver me in thy righteousness,"], ["ma ia e faaola mai ia te au;", "and cause me to escape:"], ["ia e faafofoga mai ia te au,", "incline thine ear unto me,"], ["ma ia e faaola mai ia te au.", "and save me."]]},
  {num:3,words:[["Ia fai oe ma papa ou te mau ai,", "Be thou my strong habitation,"], ["ia ou alu atu pea i ai;", "whereunto I may continually resort:"], ["ua e pule e faaola mai ia te au;", "thou hast given commandment to save me;"], ["auā o lo'u papa ma lo'u 'olo o oe lava lea.", "for thou art my rock and my fortress."]]},
  {num:4,words:[["Lo'u Atua e,", "Deliver me,"], ["ia e faaola mai ia te au ai le lima o lē amio leaga,", "O my God, out of the hand of the wicked,"], ["o le lima o lē amio paaa ma le saua.", "out of the hand of the unrighteous and cruel man."]]},
  {num:5,words:[["Auā o oe lava o lo'u faamoemoega,", "For thou art my hope,"], ["le Alii e Ieova,", "O Lord GOD:"], ["o lo'u faatuatuaga oe talu ina ou tama itiiti.", "thou art my trust from my youth."]]},
  {num:6,words:[["O oe ua lagolago mai ia te a'u talu ina fanaua o a'u;", "By thee have I been holden up from the womb:"], ["na e aumaia a'u mai le manava o lo'u tinā;", "thou art he that took me out of my mother's bowels:"], ["e le aunoa ona ou vivii atu ia te oe.", "my praise shall be continually of thee."]]},
  {num:7,words:[["Sa fai a'u e peiseai se mea e ofo ai le toatele;", "I am as a wonder unto many;"], ["a o oe o lo'u malu malosi oe.", "but thou art my strong refuge."]]},
  {num:8,words:[["E tumu lava lo'u gutu i lou viiga, ma lou faaneeneega i aso uma lava.", "Let my mouth be filled with thy praise and with thy honour all the day."]]},
  {num:9,words:[["Aua e te lafoai ia te au i ona po ou te toeaina ai;", "Cast me not off in the time of old age;"], ["aua e te tuulafoai mai ia te au pe a mavae atu lo'u malosi.", "forsake me not when my strength faileth."]]},
  {num:10,words:[["Auā ua upuia a'u e i latou ua ita mai ia te au;", "For mine enemies speak against me;"], ["ua taupulepule faatasi e ua lamalama ia oti a'u.", "and they that lay wait for my soul take counsel together,"]]},
  {num:11,words:[["Ua faapea ane,", "Saying,"], ["Ua tuulafoaiina o ia e le Atua;", "God hath forsaken him:"], ["ia outou tuliloa ma pue ia te ia,", "persecute and take him;"], ["auā e leai se na te laveaiina o ia .", "for there is none to deliver him."]]},
  {num:12,words:[["Le Atua e,", "O God,"], ["aua e te mamao ia te au;", "be not far from me:"], ["lo'u Atua e,", "O my God,"], ["ia vave ona e fesoasoani mai ia te au.", "make haste for my help."]]},
  {num:13,words:[["Ia mamā, ia faaumatia i latou o e fai a'u mo latou fili,", "Let them be confounded and consumed that are adversaries to my soul;"], ["ia liloia i le luma ma le masiasi o e sailiili ia leaga ai a'u.", "let them be covered with reproach and dishonour that seek my hurt."]]},
  {num:14,words:[["A o a'u, ou te faamoemoe e le aunoa,", "But I will hope continually,"], ["ma a'u toe faaopoopoina atu i ou viiga uma lava.", "and will yet praise thee more and more."]]},
  {num:15,words:[["E ta'uta'u atu i lo'u gutu le amiotonu mai ia te oe, e ta'uta'u foi le olataga mai ia te oe i aso uma lava;", "My mouth shall shew forth thy righteousness and thy salvation all the day;"], ["auā ua le masino ia te au lona faitau aofai.", "for I know not the numbers thereof."]]},
  {num:16,words:[["Ou te alu atu i le malosi o le Alii o Ieova;", "I will go in the strength of the Lord GOD:"], ["ou te ta'uta'u i lau amiotonu,", "I will make mention of thy righteousness,"], ["na o lau lava.", "even of thine only."]]},
  {num:17,words:[["Le Atua e,", "O God,"], ["na e a'oa'o mai ia te au talu ina ou tama itiiti;", "thou hast taught me from my youth:"], ["ua oo mai foi i nei ona po ua ou faaali atu ou vavega.", "and hitherto have I declared thy wondrous works."]]},
  {num:18,words:[["Le Atua e,", "Now also when I am old and grayheaded,"], ["aua e te tuulafoai mai ia te au e oo ina toeaina ma ulusinā;", "O God,"], ["seia ou faaali atu lou aao i leneiit tupulaga,", "forsake me not; until I have shewed thy strength unto this generation,"], ["ma lou malosi i e amuli uma lava.", "and thy power to every one that is to come."]]},
  {num:19,words:[["Le Atua e,", "Thy righteousness also,"], ["e silisili lava lau amiotonu,", "O God,"], ["o mea ua e faia o mea mamana ia;", "is very high, who hast done great things:"], ["le Atua e,", "O God,"], ["o ai ea se tusa ma oe?", "who is like unto thee!"]]},
  {num:20,words:[["O le ua faailoa mai ia te au o puapuaga e tele ma le leaga,", "Thou,"], ["e te toe faaola mai ia te au,", "which hast shewed me great and sore troubles, shalt quicken me again,"], ["e te toe avae ia te au nai le mea loloto i le eleele.", "and shalt bring me up again from the depths of the earth."]]},
  {num:21,words:[["E te faateleina lo'u mamalu;", "Thou shalt increase my greatness,"], ["e te liliu mai ma faamafanafana mai ia te au.", "and comfort me on every side."]]},
  {num:22,words:[["O a'u foi,", "I will also praise thee with the psaltery,"], ["ou te vivii atu ia te oe i le napeli,", "even thy truth,"], ["o lou faamaoni lava, lo'u Atua e;", "O my God:"], ["ou te fai pesega ia te oe i le kitara,", "unto thee will I sing with the harp,"], ["o oe le Paia o Isaraelu.", "O thou Holy One of Israel."]]},
  {num:23,words:[["E alaga fiafia o'u laugutu pe a a'u fai pesega ia te oe,", "My lips shall greatly rejoice when I sing unto thee; and my soul,"], ["atoa foi ma lo'u agaga ua e faaolaina.", "which thou hast redeemed."]]},
  {num:24,words:[["E ta'uta'u atu foi lo'u laulaufaiva i lau amiotonu i aso uma lava;", "My tongue also shall talk of thy righteousness all the day long: for they are confounded,"], ["auā ua faamaina ma ua masiasi i latou o e sailiili ia leaga ai a'u.", "for they are brought unto shame, that seek my hurt."]]},
];
renderVerseSet(psa_ch_71_Verses, 'psa-ch71-verses');

var psa_ch_72_Verses = [
  {num:1,words:[["Le Atua e,", "Give the king thy judgments,"], ["ia e avatua au faamasinoga i le Tupu,", "O God,"], ["ma lau amiotonu i le alo o le Tupu.", "and thy righteousness unto the king's son."]]},
  {num:2,words:[["E faamasino e ia lou nuu i le amiotonu,", "He shall judge thy people with righteousness,"], ["e faamasino foi ma le tonu ou tagata ua puapuagatia.", "and thy poor with judgment."]]},
  {num:3,words:[["E fua mai mauga le manuia mo le nuu,", "The mountains shall bring peace to the people, and the little hills,"], ["ma mauga iti e fua mai i le amiotonu.", "by righteousness."]]},
  {num:4,words:[["E faamasino e ia o e puapuaga o le nuu;", "He shall judge the poor of the people,"], ["e faaolaina foi e ia le fanau a e ua matitiva,", "he shall save the children of the needy,"], ["a e faamomomoina e ia o le ua faasaua.", "and shall break in pieces the oppressor."]]},
  {num:5,words:[["E matatau lava tagata ia te oe a o tumau le la ma le masina,", "They shall fear thee as long as the sun and moon endure,"], ["i lea tupulaga ma lea tupulaga.", "throughout all generations."]]},
  {num:6,words:[["E alu ifo ia e pei o le ua i le mutia ua seleseleina,", "He shall come down like rain upon the mown grass:"], ["e pei o timuga e sūsū ai le eleele.", "as showers that water the earth."]]},
  {num:7,words:[["O lana nofoaiga e tupu olaola mai ai le ua amiotonu; e manuia tele ai,", "In his days shall the righteous flourish;"], ["seia leai se masina.", "and abundance of peace so long as the moon endureth."]]},
  {num:8,words:[["E pule foi o ia e pau mai i le tasi sami e oo atu i le tasi sami;", "He shall have dominion also from sea to sea,"], ["e pau mai le vaitafe e oo atu i tulu'iga o le lalolagi.", "and from the river unto the ends of the earth."]]},
  {num:9,words:[["E ifo foi i ona luma o e nonofo i le nuu naumati,", "They that dwell in the wilderness shall bow before him;"], ["e etoeto i le eleele o e ita ia te ia.", "and his enemies shall lick the dust."]]},
  {num:10,words:[["O tupu o Tasesa, ma nuu tu matafaga latou te avane meaalofa;", "The kings of Tarshish and of the isles shall bring presents:"], ["o tupu o Seepa ma Sepa latou te avane mea foai fua.", "the kings of Sheba and Seba shall offer gifts."]]},
  {num:11,words:[["E ifo lava ia te ia o tupu uma lava;", "Yea, all kings shall fall down before him:"], ["e auauna ia te ia o nuu uma.", "all nations shall serve him."]]},
  {num:12,words:[["Auā e laveai e ia o le mativa i lona alaga mai;", "For he shall deliver the needy when he crieth;"], ["atoa ma le ua puapuagatia,", "the poor also,"], ["ma le ua leai sona fesoasoani.", "and him that hath no helper."]]},
  {num:13,words:[["E alofa atu ia i le ua vaivai ma le ua mativa;", "He shall spare the poor and needy,"], ["e faaola lava e ia e ua matitiva.", "and shall save the souls of the needy."]]},
  {num:14,words:[["E laveai o ia ia i latou ai le saua ma le faamalo;", "He shall redeem their soul from deceit and violence:"], ["e silisili foi o latou toto i lona manatu.", "and precious shall their blood be in his sight."]]},
  {num:15,words:[["E soifua lava ia,", "And he shall live,"], ["e avatua foi ia te ia ni auro mai Seepa;", "and to him shall be given of the gold of Sheba:"], ["e le aunoa ona talosia o ia;", "prayer also shall be made for him continually;"], ["e faafetaia o ia i aso uma lava.", "and daily shall he be praised."]]},
  {num:16,words:[["E taumafa o saito i le nuu i tumutumu lava o mauga;", "There shall be an handful of corn in the earth upon the top of the mountains;"], ["e gasē ona fua e pei o Lepanona;", "the fruit thereof shall shake like Lebanon:"], ["e fuga mai foi tagata o le aai e pei o le vao i le laueleele.", "and they of the city shall flourish like grass of the earth."]]},
  {num:17,words:[["E faavavau lava lona suafa;", "His name shall endure for ever:"], ["e tumau pea lona suafa a o i ai le la;", "his name shall be continued as long as the sun:"], ["latou te faaamuia i latou ona o ia;", "and men shall be blessed in him:"], ["e faaamuia o ia e nuu uma lava.", "all nations shall call him blessed."]]},
  {num:18,words:[["Ia faafetaia Ieova le Atua,", "Blessed be the LORD God,"], ["o le Atua o Isaraelu,", "the God of Israel,"], ["na o ia lava na te faia vavega.", "who only doeth wondrous things."]]},
  {num:19,words:[["Ia viia lava lona suafa mamalu e faavavau lava;", "And blessed be his glorious name for ever:"], ["ia tumu foi le lalolagi uma i lona mamalu;", "and let the whole earth be filled with his glory; Amen,"], ["Amene ma Amene.", "and Amen."]]},
  {num:20,words:[["Ua faaiuina tatalo a Tavita le atalii o Iese.", "The prayers of David the son of Jesse are ended."]]},
];
renderVerseSet(psa_ch_72_Verses, 'psa-ch72-verses');

var psa_ch_73_Verses = [
  {num:1,words:[["E moni lava, e agalelei mai le Atua ia Isaraelu,", "Truly God is good to Israel,"], ["o e ua mamā o latou loto.", "even to such as are of a clean heart."]]},
  {num:2,words:[["A o a'u nei,", "But as for me,"], ["o toe ina mapeva o'u vae;", "my feet were almost gone;"], ["e toetoe lava ina see o'u vae;", "my steps had well nigh slipped."]]},
  {num:3,words:[["auā na ou mataua i e vālea;", "For I was envious at the foolish,"], ["na ou vaai i le manuia o e ua amio leaga.", "when I saw the prosperity of the wicked."]]},
  {num:4,words:[["Auā e leai ni o latou puapuaga e oo i le oti;", "For there are no bands in their death:"], ["a ua puputa pea o latou tino.", "but their strength is firm."]]},
  {num:5,words:[["E le oo ia te i latou puapuaga faatagata ola,", "They are not in trouble as other men;"], ["e le pesia foi i latou faatasi ma isi tagata.", "neither are they plagued like other men."]]},
  {num:6,words:[["O le mea lea ua asoa ai i latou i le faamaualuga;", "Therefore pride compasseth them about as a chain;"], ["o le saua ua fai ma ofu latou te oofu ai.", "violence covereth them as a garment."]]},
  {num:7,words:[["Ua lululu o latou mata;", "Their eyes stand out with fatness:"], ["latou te faasilisili i manatu o le loto.", "they have more than heart could wish."]]},
  {num:8,words:[["Ua latou tauemu,", "They are corrupt,"], ["ma ua tautala leaga i le saua;", "and speak wickedly concerning oppression:"], ["ua latou tautala faamaualuga.", "they speak loftily."]]},
  {num:9,words:[["Ua upu vale o latou gutu i le lagi;", "They set their mouth against the heavens,"], ["ua feoai foi o latou laulaufaiva i le lalolagi.", "and their tongue walketh through the earth."]]},
  {num:10,words:[["O le mea lea e foi mai ai lona nuu iinei;", "Therefore his people return hither:"], ["e faainumia foi i latou i le vai e tele.", "and waters of a full cup are wrung out to them."]]},
  {num:11,words:[["E faapea a latou,", "And they say,"], ["Pe faapefea ona silafia e le Atua? Pe silafia ea e lē Silisili ese?", "How doth God know? and is there knowledge in the most High?"]]},
  {num:12,words:[["Faauta,", "Behold,"], ["o i latou nei o e amio leaga,", "these are the ungodly,"], ["e ua manuia i le olaga nei;", "who prosper in the world;"], ["e faateleina o latou oloa.", "they increase in riches."]]},
  {num:13,words:[["E moni lava, ua ou faamamāfuaina lo'u loto,", "Verily I have cleansed my heart in vain,"], ["ma a'u fafano o'u lima ina ua ou le sala, a e fai fua lava .", "and washed my hands in innocency."]]},
  {num:14,words:[["Ua taia lava a'u i aso fai soo,", "For all the day long have I been plagued,"], ["ua aoaiina foi a'u i taeao uma lava.", "and chastened every morning."]]},
  {num:15,words:[["Afai ou te faapea ane,", "If I say,"], ["Ou te ta'uta'u atu faapena;", "I will speak thus;"], ["faauta,", "behold,"], ["ona ou faa'ole'ole lea i le tupulaga o lau fanau.", "I should offend against the generation of thy children."]]},
  {num:16,words:[["Na ou mafaufau lava ia a'u iloa lenei mea;", "When I thought to know this,"], ["o le mea faatiga lava lea i lo'u manatu;", "it was too painful for me;"]]},
  {num:17,words:[["ua oo i le aso na ou alu atu ai i le malumalu o le Atua;", "Until I went into the sanctuary of God;"], ["ona ou iloa ai lea o lo latou iuga.", "then understood I their end."]]},
  {num:18,words:[["E moni lava, na e tuuina atu i latou i mea maseesee;", "Surely thou didst set them in slippery places:"], ["na e faapaūina atu i latou i mea faatafunaina.", "thou castedst them down into destruction."]]},
  {num:19,words:[["Aue! Ua faafuasei ona faatafunaina o i latou; ua fano i latou,", "How are they brought into desolation,"], ["ua faaumatia lava ona o mea matautia.", "as in a moment! they are utterly consumed with terrors."]]},
  {num:20,words:[["E pei o le miti ina o tulai se tasi,", "As a dream when one awaketh; so,"], ["e faapea foi oe le Alii i lou maleifua,", "O Lord,"], ["e te ta'ufaatauvaaina lo Iatou ata.", "when thou awakest, thou shalt despise their image."]]},
  {num:21,words:[["Auā na tigaina ai lo'u loto;", "Thus my heart was grieved,"], ["na tuia ai foi lo'u manatu.", "and I was pricked in my reins."]]},
  {num:22,words:[["O a'u foi,", "So foolish was I,"], ["na fai ai a'u ma vale, ma le le iloa;", "and ignorant:"], ["ua avea a'u i ou luma e tusa ma le manu vaefa.", "I was as a beast before thee."]]},
  {num:23,words:[["A o a'u, e le aunoa ona ta faatasi ma oe;", "Nevertheless I am continually with thee:"], ["na e taofiina lo'u lima taumatau.", "thou hast holden me by my right hand."]]},
  {num:24,words:[["E te ta'ita'i ia te au i lau pule,", "Thou shalt guide me with thy counsel,"], ["a e mulimuli ane e te talia mai a'u i le manuia.", "and afterward receive me to glory."]]},
  {num:25,words:[["O ai ea se ua ia te au i le lagi? E leai foi se tasi i le lalolagi ou te fiafia i ai, na o oe.", "Whom have I in heaven but thee? and there is none upon earth that I desire beside thee."]]},
  {num:26,words:[["E vaivai lo'u tino ma lo'u loto,", "My flesh and my heart faileth:"], ["a o le Atua,", "but God is the strength of my heart,"], ["o le papa ia o lo'u loto ma lo'u tofi e faavavau.", "and my portion for ever."]]},
  {num:27,words:[["Auā faauta,", "For,"], ["e fano lava o e faamamao ma oe;", "lo, they that are far from thee shall perish:"], ["e te faaumatia i latou uma lava o e o ese ia te oe e faitaaga ai.", "thou hast destroyed all them that go a whoring from thee."]]},
  {num:28,words:[["A o a'u nei,", "But it is good for me to draw near to God:"], ["ou te faalatalata atu i le Atua ou te lelei ai; ua ou faia le Alii o Ieova ma ou malu,", "I have put my trust in the Lord GOD,"], ["ina ia ou ta'uina atu o au galuega uma.", "that I may declare all thy works."]]},
];
renderVerseSet(psa_ch_73_Verses, 'psa-ch73-verses');

var psa_ch_74_Verses = [
  {num:1,words:[["Le Atua e,", "O God,"], ["se a le mea ua e lafoaiina mai ai i matou e faavavau? Se a foi le mea e pusa mai ai lou toasa i le lafu mamoe o loo e fagaina?", "why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?"]]},
  {num:2,words:[["Ia e manatua mai lau faapotopotoga na e faatauina anamua;", "Remember thy congregation, which thou hast purchased of old;"], ["o le aiga o lou tofi na e faaolaina;", "the rod of thine inheritance, which thou hast redeemed;"], ["o lenei mauga o Siona na e afio ai.", "this mount Zion, wherein thou hast dwelt."]]},
  {num:3,words:[["Ia e afio ae i mea ua faatafunaina e faavavau;", "Lift up thy feet unto the perpetual desolations;"], ["o e ua ita mai ua faataumaoi mea uma i le malumalu.", "even all that the enemy hath done wickedly in the sanctuary."]]},
  {num:4,words:[["Ua pisapisao o e ita ia te oe i totonu o au faapotopotoga;", "Thine enemies roar in the midst of thy congregations;"], ["ua latou faatuina o latou faailoga e fai ma faailoga.", "they set up their ensigns for signs."]]},
  {num:5,words:[["Ua iloa i latou, e pei o tagata ona sii ae o mătau i le vao filifili e tuu a'i .", "A man was famous according as he had lifted up axes upon the thick trees."]]},
  {num:6,words:[["O lenei, ua uma ai ana mea togitogi, ua lepetia e i latou i mătau ma samala.", "But now they break down the carved work thereof at once with axes and hammers."]]},
  {num:7,words:[["Ua latou susunuina lou malumalu i le afi, ua latou solia le malumalu o i ai lou suafa,", "They have cast fire into thy sanctuary,"], ["ua oo i le eleele.", "they have defiled by casting down the dwelling place of thy name to the ground."]]},
  {num:8,words:[["Ua latou faapea ifo i o latou loto,", "They said in their hearts,"], ["Ia tatou faataumaoi faatasi i latou;", "Let us destroy them together:"], ["ua latou susunuina mea uma i le nuu sa fai ai potopotoga i le Atua.", "they have burned up all the synagogues of God in the land."]]},
  {num:9,words:[["Ua tatou le iloa o tatou faailoga;", "We see not our signs:"], ["e leai foi se toe perofeta;", "there is no more any prophet:"], ["e leai foi so tatou na te iloa pe iu afea nei mea .", "neither is there among us any that knoweth how long."]]},
  {num:10,words:[["Le Atua e,", "O God,"], ["e faifai le ua ita mai seia afea? Pe faavavau ea ona 'ino'ino i lou suafa le ua ita?", "how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?"]]},
  {num:11,words:[["Se a le mea ua e toe faafoi atu ai lou aao, o lou aao taumatau lava? Ia e to mai ai nai lou fatafata,", "Why withdrawest thou thy hand,"], ["ia e faaumatia i latou.", "even thy right hand? pluck it out of thy bosom."]]},
  {num:12,words:[["A o le Atua, o lo'u lea Tupu talu anamua;", "For God is my King of old,"], ["o loo galue e faaola ai i luma o le lalolagi.", "working salvation in the midst of the earth."]]},
  {num:13,words:[["Na e vaeluaina le sami i lou mana;", "Thou didst divide the sea by thy strength:"], ["na e tu'imomomoina ulu o tanimo o le sami.", "thou brakest the heads of the dragons in the waters."]]},
  {num:14,words:[["O ulu o leviatana na e nutininii ai lava;", "Thou brakest the heads of leviathan in pieces,"], ["na e tuuina atu ai e 'aina e i latou ua nonofo i nuu naumati.", "and gavest him to be meat to the people inhabiting the wilderness."]]},
  {num:15,words:[["O oe lava, na e foaina le vaipuna ma le alia;", "Thou didst cleave the fountain and the flood:"], ["o oe lava, na mamate ai vaitafe tafe tetele.", "thou driedst up mighty rivers."]]},
  {num:16,words:[["O loo ia te oe le ao,", "The day is thine,"], ["o loo ia te oe ma le po;", "the night also is thine:"], ["o oe lava na e saunia le malamalama ma le la.", "thou hast prepared the light and the sun."]]},
  {num:17,words:[["O oe, na e tuuina tuaoi uma o le lalolagi;", "Thou hast set all the borders of the earth:"], ["o le tausaga vevela ma le tausaga maalili, o oe na e faia.", "thou hast made summer and winter."]]},
  {num:18,words:[["Ia manatua lenei mea,", "Remember this,"], ["ua faifaia Ieova e i latou ua ita mai;", "that the enemy hath reproached, O LORD,"], ["o le nuu valea foi ua latou 'ino'ino i lou suafa.", "and that the foolish people have blasphemed thy name."]]},
  {num:19,words:[["Aua e te tuuina atu lau manutagi i le manu feai;", "O deliver not the soul of thy turtledove unto the multitude of the wicked:"], ["aua ne'i e faagalogaloina pea o ou tagata ua puapuagaina.", "forget not the congregation of thy poor for ever."]]},
  {num:20,words:[["Ia e manatua le feagaiga;", "Have respect unto the covenant:"], ["auā ua tutumu mea pouliuli o le lalolagi i mea e nofo ai le saua.", "for the dark places of the earth are full of the habitations of cruelty."]]},
  {num:21,words:[["Aua ne'i foi mai ma le mā le ua sauaina;", "O let not the oppressed return ashamed:"], ["a ia viia lou suafa e le ua puapuagaina ma le ua mativa.", "let the poor and needy praise thy name."]]},
  {num:22,words:[["Le Atua e,", "Arise,"], ["ia e tulai mai,", "O God,"], ["ma e faia lau lava finauga;", "plead thine own cause:"], ["ia e manatua lou fāiga e le tagata valea i aso uma lava.", "remember how the foolish man reproacheth thee daily."]]},
  {num:23,words:[["Aua ne'i galo ia te oe le leo o e ua ita ia te oe;", "Forget not the voice of thine enemies:"], ["ua tupu pea lava le vāvāō o e laga atu ia te oe.", "the tumult of those that rise up against thee increaseth continually."]]},
];
renderVerseSet(psa_ch_74_Verses, 'psa-ch74-verses');

var psa_ch_75_Verses = [
  {num:1,words:[["Le Atua e,", "Unto thee,"], ["matou te vivii ia te oe;", "O God,"], ["matou te vivii lava;", "do we give thanks,"], ["auā ua latalata mai lou suafa;", "unto thee do we give thanks:"], ["ua ta'uatua ou vavega.", "for that thy name is near thy wondrous works declare."]]},
  {num:2,words:[["Pe a ou oo i ona po na tuu ai, ona a'u faamasino tonu lea e a'u.", "When I shall receive the congregation I will judge uprightly."]]},
  {num:3,words:[["Ua liu suāvai le lalolagi atoa ma i latou uma ua nonofo ai;", "The earth and all the inhabitants thereof are dissolved:"], ["o a'u nei ou te faatumauina ona poutu. Selā.", "I bear up the pillars of it. Selah."]]},
  {num:4,words:[["Na ou faapea atu i e ua valelea,", "I said unto the fools,"], ["Aua tou te amio faavalea;", "Deal not foolishly:"], ["na ou fai atu foi i e amio leaga,", "and to the wicked,"], ["Aua tou te faamaualugaina lo outou nifo;", "Lift not up the horn:"]]},
  {num:5,words:[["aua tou te matuā faamaualuga lo outou nifo;", "Lift not up your horn on high:"], ["aua tou te tautalatala ma le ūa maaa.", "speak not with a stiff neck."]]},
  {num:6,words:[["Auā e le o sasae,", "For promotion cometh neither from the east,"], ["po o sisifo, po o le vao e i ai mauga,", "nor from the west,"], ["a o le Atua na te faamasinoina;", "nor from the south."]]},
  {num:7,words:[["o ia na te faamaulaloina le tasi,", "But God is the judge: he putteth down one,"], ["o ia foi na te faaeaina i luga le tasi.", "and setteth up another."]]},
  {num:8,words:[["Auā o loo i le aao o Ieova le ipu,", "For in the hand of the LORD there is a cup,"], ["ua mūmū foi le auina;", "and the wine is red;"], ["ua tumu i le uaina filogia;", "it is full of mixture; and he poureth out of the same:"], ["e liligiina atu foi e ia ai lenei lava ipu;", "but the dregs thereof,"], ["a o ona 'alu,", "all the wicked of the earth shall wring them out,"], ["e tāulia a faainu a'i o e amio leaga uma i le lalolagi.", "and drink them."]]},
  {num:9,words:[["A o a'u, ou te ta'u atu e faavavau;", "But I will declare for ever;"], ["ou te fai pesega lava i le Atua o Iakopo.", "I will sing praises to the God of Jacob."]]},
  {num:10,words:[["O nifo uma foi o e amio leaga, ou te vavaeeseina ia;", "All the horns of the wicked also will I cut off;"], ["a e faamaualugaina nifo o lē amiotonu.", "but the horns of the righteous shall be exalted."]]},
];
renderVerseSet(psa_ch_75_Verses, 'psa-ch75-verses');

var psa_ch_76_Verses = [
  {num:1,words:[["Ua iloa le Atua i Iuta;", "In Judah is God known:"], ["ua silisili lona suafa i Isaraelu.", "his name is great in Israel."]]},
  {num:2,words:[["Ua i Salema foi lona fale apitaga;", "In Salem also is his tabernacle,"], ["ua i Siona foi lona afioaga.", "and his dwelling place in Zion."]]},
  {num:3,words:[["Na ia gauia i lea mea o u fanafana mu,", "There brake he the arrows of the bow,"], ["o le talita,", "the shield,"], ["le pelu,", "and the sword,"], ["ma le taua. Selā.", "and the battle. Selah."]]},
  {num:4,words:[["E pupula mai oe, e silisili, e sili i mauga o i ai mea e saeia.", "Thou art more glorious and excellent than the mountains of prey."]]},
  {num:5,words:[["O e loto tetele ua vetea a latou mea;", "The stouthearted are spoiled,"], ["ua latou momoe i o latou moe;", "they have slept their sleep:"], ["e leai foi so latou o e malolosi ua maua o latou lima.", "and none of the men of might have found their hands."]]},
  {num:6,words:[["Le Atua o Iakopo e,", "At thy rebuke, O God of Jacob,"], ["o le aoaiga mai ia te oe ua moe gagase ai le kariota atoa ma le solofanua.", "both the chariot and horse are cast into a dead sleep."]]},
  {num:7,words:[["O oe e matautia lava oe;", "Thou, even thou,"], ["o ai foi se tu atu i ou luma i ona po e te toasa mai ai?", "art to be feared: and who may stand in thy sight when once thou art angry?"]]},
  {num:8,words:[["Ua lagona atu mai ia te oe mai le lagi le faamasinoga;", "Thou didst cause judgment to be heard from heaven; the earth feared,"], ["ua matatau ai le lalolagi ma fifilemu,", "and was still,"]]},
  {num:9,words:[["ina ua tulai le Atua e faamasino ai,", "When God arose to judgment,"], ["e faaola ai i e puapuagatia uma lava o i le lalolagi. Selā.", "to save all the meek of the earth. Selah."]]},
  {num:10,words:[["Auā o le ita tele o tagata e viia ai oe;", "Surely the wrath of man shall praise thee:"], ["e te taofia foi le toe ita.", "the remainder of wrath shalt thou restrain."]]},
  {num:11,words:[["Ia outou tauto atu ia Ieova lo outou Atua,", "Vow,"], ["ma ia avatua ana mea; o i latou uma o e vagavagai ia te ia,", "and pay unto the LORD your God:"], ["ia latou avatu mea alofa i le ua matautia.", "let all that be round about him bring presents unto him that ought to be feared."]]},
  {num:12,words:[["E faamaulaloina e ia o loto o alii;", "He shall cut off the spirit of princes:"], ["e matautia o ia e tupu o le lalolagi.", "he is terrible to the kings of the earth."]]},
];
renderVerseSet(psa_ch_76_Verses, 'psa-ch76-verses');

var psa_ch_77_Verses = [
  {num:1,words:[["Na ou alaga atu i le Atua i lo'u leo,", "I cried unto God with my voice,"], ["na ou alaga atu i le Atua;", "even unto God with my voice;"], ["ona faafofoga mai lea o ia ia te au.", "and he gave ear unto me."]]},
  {num:2,words:[["O le aso na puapuagatia ai a'u na ou saili atu ai i le Alii;", "In the day of my trouble I sought the Lord:"], ["na ou faaloaloa lo'u lima i le po,", "my sore ran in the night,"], ["e lei gase lava;", "and ceased not:"], ["na le mafaia lo'u loto ona faamafanafanaina.", "my soul refused to be comforted."]]},
  {num:3,words:[["A ou manatua le Atua ou te atuatuvale ai;", "I remembered God, and was troubled:"], ["a ou mafaufau ou te loto vaivai ai.", "I complained, and my spirit was overwhelmed."], ["Selā.", "Selah."]]},
  {num:4,words:[["O loo ē taofia o'u mata ina ia le fia moe; ua ou atuatuvale;", "Thou holdest mine eyes waking:"], ["ou te le mafai ai ona tautala.", "I am so troubled that I cannot speak."]]},
  {num:5,words:[["Ou te manatunatu i ona po anamua;", "I have considered the days of old,"], ["o tausaga o le vavau.", "the years of ancient times."]]},
  {num:6,words:[["Ou te manatua la'u pese i le po;", "I call to remembrance my song in the night:"], ["ou te mafaufau i lo'u loto;", "I commune with mine own heart:"], ["e tausailiili foi lo'u agaga.", "and my spirit made diligent search."]]},
  {num:7,words:[["E faavavau lava ea ona lafoai e le Alii? E le toe fiafia mai ea o ia?", "Will the Lord cast off for ever? and will he be favourable no more?"]]},
  {num:8,words:[["Ua uma ea e faavavau lona alofa? E faaleiu ea lana afioga i lea tupulaga ma lea tupulaga?", "Is his mercy clean gone for ever? doth his promise fail for evermore?"]]},
  {num:9,words:[["Ua faagalogalo ea e le Atua ona alofa mai? Pe taofi ea e ia o lona alofa mutimuti vale i lona toasa? Selā.", "Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah."]]},
  {num:10,words:[["Ona ou faapea ane lea,", "And I said,"], ["O lo'u vaivai lenei,", "This is my infirmity:"], ["o tausaga o le aao taumatau o le Silisili ese.", "but I will remember the years of the right hand of the most High."]]},
  {num:11,words:[["Ou te manatua galuega a Ioa; e moni,", "I will remember the works of the LORD:"], ["ou te matuā manatua ou vavega anamua.", "surely I will remember thy wonders of old."]]},
  {num:12,words:[["Ou te manatunatu foi i au galuega uma,", "I will meditate also of all thy work,"], ["ou te mafaufau i mea na e faia.", "and talk of thy doings."]]},
  {num:13,words:[["Le Atua e,", "Thy way,"], ["e paia lava lou ala;", "O God, is in the sanctuary:"], ["o ai se atua e silisili e tusa ma le Atua?", "who is so great a God as our God?"]]},
  {num:14,words:[["O oe lava le Atua o lē fai vavega;", "Thou art the God that doest wonders:"], ["ua faailoa lou malosi i nuu.", "thou hast declared thy strength among the people."]]},
  {num:15,words:[["O lou aao na e faaolaina ai lou nuu,", "Thou hast with thine arm redeemed thy people,"], ["o le fanauga a Iakopo ma Iosefa. Selā.", "the sons of Jacob and Joseph. Selah."]]},
  {num:16,words:[["Na iloa atu le sami ia te oe le Atua e,", "The waters saw thee,"], ["na iloa atu le sami ia te oe,", "O God,"], ["ona fefe ai lea;", "the waters saw thee; they were afraid:"], ["na gatete foi le moana.", "the depths also were troubled."]]},
  {num:17,words:[["O ao uli na faamaligi ifo ai le vai;", "The clouds poured out water:"], ["o le lagi ua taalili mai lea,", "the skies sent out a sound:"], ["ua feoai foi āu u fanafana.", "thine arrows also went abroad."]]},
  {num:18,words:[["O le leo o lou faititili ua i le asiosio lea;", "The voice of thy thunder was in the heaven:"], ["ua malamalama le atu laulau i uila;", "the lightnings lightened the world:"], ["ua gatete ma luluina le lalolagi.", "the earth trembled and shook."]]},
  {num:19,words:[["Ua i le sami lou ala,", "Thy way is in the sea,"], ["ua i vai e tele lou savali,", "and thy path in the great waters,"], ["o ou tulagaaao foi e le iloa lava ia.", "and thy footsteps are not known."]]},
  {num:20,words:[["Na e ta'ita'iina lou nuu e pei o se lafu mamoe i lima o Mose ma Arona.", "Thou leddest thy people like a flock by the hand of Moses and Aaron."]]},
];
renderVerseSet(psa_ch_77_Verses, 'psa-ch77-verses');

var psa_ch_78_Verses = [
  {num:1,words:[["Lo'u nuu e,", "Give ear,"], ["ia outou faalogologo mai i la'u tulafono;", "O my people, to my law:"], ["ia uai mai o outou taliga i upu a lo'u gutu.", "incline your ears to the words of my mouth."]]},
  {num:2,words:[["Ou te tautala atu lava i le faataoto;", "I will open my mouth in a parable:"], ["ou te ta'u atu mea lilo talu anamuā,", "I will utter dark sayings of old:"]]},
  {num:3,words:[["o mea na tatou faalogologo i ai, ma tatou iloa;", "Which we have heard and known,"], ["na talaina mai foi ia te i tatou e o tatou tamā.", "and our fathers have told us."]]},
  {num:4,words:[["Tatou te le natia ia mea i a latou fanau,", "We will not hide them from their children,"], ["a e ta'uta'u atu i tupulaga amuli o viiga o Ieova,", "shewing to the generation to come the praises of the LORD,"], ["ma lona malosi,", "and his strength,"], ["ma ona vavega na na faia.", "and his wonderful works that he hath done."]]},
  {num:5,words:[["Ua ia faatuina le tulafono ia Iakopo,", "For he established a testimony in Jacob,"], ["ua ia tuuina foi le poloaiga ia Isaraelu,", "and appointed a law in Israel,"], ["o mea na ia poloai atu ai i o tatou tamā,", "which he commanded our fathers,"], ["ina ia latou faailoa ai i a latou fanau;", "that they should make them known to their children:"]]},
  {num:6,words:[["ina ia iloa ai e le tupulaga amuli,", "That the generation to come might know them,"], ["o fanau lava e fanau mai; e tutupu mai i latou,", "even the children which should be born;"], ["ma ta'u atu ai i a latou fanau;", "who should arise and declare them to their children:"]]},
  {num:7,words:[["ina ia fai le Atua mo latou faatuatuaga;", "That they might set their hope in God,"], ["ma ia le galo galuega a le Atua;", "and not forget the works of God,"], ["a ia latou tausi i ana poloaiga;", "but keep his commandments:"]]},
  {num:8,words:[["ina ia le pei o latou tamā i latou,", "And might not be as their fathers,"], ["o le tupulaga vaogata ma le fouvale;", "a stubborn and rebellious generation;"], ["o le tupulaga na le sauni o latou loto;", "a generation that set not their heart aright,"], ["e lei faamaoni foi o latou loto i le Atua.", "and whose spirit was not stedfast with God."]]},
  {num:9,words:[["O le fanauga a Efaraima ua i ai auupega,", "The children of Ephraim,"], ["e na fanafana i u;", "being armed, and carrying bows,"], ["na liutua i latou i le aso na tau ai le taua.", "turned back in the day of battle."]]},
  {num:10,words:[["Na latou le tausia le feagaiga a le Atua,", "They kept not the covenant of God,"], ["na le mafafai foi ona latou savavali i lana tulafono;", "and refused to walk in his law;"]]},
  {num:11,words:[["na latou faagalogaloina foi ana galuega,", "And forgat his works,"], ["ma ona vavega na ia faaali ia te i latou.", "and his wonders that he had shewed them."]]},
  {num:12,words:[["Na ia faia vavega i luma o latou tamā i le nuu o Aikupito o le laueleele o Soana.", "Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan."]]},
  {num:13,words:[["Na ia vavaeina le sami,", "He divided the sea,"], ["ma faaui ane ai i latou;", "and caused them to pass through;"], ["na ia faatuina foi le suāsami e pei o se mea maupuepue.", "and he made the waters to stand as an heap."]]},
  {num:14,words:[["Na ia ta'ita'i ia te i latou ina o ao i le ao a o le malamalama o le afi na ia ta'ita'i ai ia te i latou i le po atoa.", "In the daytime also he led them with a cloud, and all the night with a light of fire."]]},
  {num:15,words:[["Na ia vaevaea papa i le vao;", "He clave the rocks in the wilderness,"], ["na ia faainu ia i latou e peiseai sa i ai vai loloto.", "and gave them drink as out of the great depths."]]},
  {num:16,words:[["Na ia faaoso foi o vaitafe nai le papa,", "He brought streams also out of the rock,"], ["na ia faatafe ifo le vai e pei o vaitafe.", "and caused waters to run down like rivers."]]},
  {num:17,words:[["A ua faaopoopo ona toe agasala atu i latou ia te ia, i lo latou faaonoono i lē Silisili ese i le nuu naumati.", "And they sinned yet more against him by provoking the most High in the wilderness."]]},
  {num:18,words:[["Na latou tofotofo i le Atua i o latou loto i lo latou ole atu i mea e 'ai i lo latou tu'inanau.", "And they tempted God in their heart by asking meat for their lust."]]},
  {num:19,words:[["Na upuia le Atua e i latou;", "Yea,"], ["ua faapea a latou,", "they spake against God; they said,"], ["Ua mafaia ea e le Atua ona laulau mai mea e 'ai i le vao?", "Can God furnish a table in the wilderness?"]]},
  {num:20,words:[["Faauta,", "Behold,"], ["na ia taia le papa,", "he smote the rock,"], ["ua tafe mai ai le vai;", "that the waters gushed out,"], ["ona oso ai lea i tua o vaitafe;", "and the streams overflowed;"], ["e mafaia foi ea ona foai mai ni mea e 'ai? E mafaia ea ona aumai o aano o manu mā lona nuu?", "can he give bread also? can he provide flesh for his people?"]]},
  {num:21,words:[["O le mea lea na faafofoga mai ai Ieova,", "Therefore the LORD heard this,"], ["ona toasa ai ai lea o ia;", "and was wroth:"], ["na tŭtŭ ai le afi ia Iakopo,", "so a fire was kindled against Jacob,"], ["na oo ae foi le toatamai ia Isaraelu;", "and anger also came up against Israel;"]]},
  {num:22,words:[["auā ua latou le faatuatua i le Atua,", "Because they believed not in God,"], ["ua latou le faalagolago i le olataga mai ia te ia.", "and trusted not in his salvation:"]]},
  {num:23,words:[["Na ia poloai i ao mai luga;", "Though he had commanded the clouds from above,"], ["na ia to mai foi o puipui o le lagi,", "and opened the doors of heaven,"]]},
  {num:24,words:[["na ia faatotō faaua i luga ia te i latou le manai e aai ai;", "And had rained down manna upon them to eat,"], ["na ia avatua foi ia te i latou o mea e 'ai mai le lagi.", "and had given them of the corn of heaven."]]},
  {num:25,words:[["Na aai tagata i le mea e 'ai a e malolosi;", "Man did eat angels' food:"], ["na ia tuuina atu ia te i latou le mea e 'ai latou te maoona ai.", "he sent them meat to the full."]]},
  {num:26,words:[["Na ia faaoso mai i le lagi le matagi mai sasaē,", "He caused an east wind to blow in the heaven:"], ["o lona malosi foi na ia faaagi mai ai le toga.", "and by his power he brought in the south wind."]]},
  {num:27,words:[["Na ia faatotō faaua foi i luga ia te i latou o manu e pei o le efuefu;", "He rained flesh also upon them as dust,"], ["o manu felelei foi e pei o le oneone i le sami;", "and feathered fowls like as the sand of the sea:"]]},
  {num:28,words:[["na ia faatotōina ai i totonu i lo latou toagālauapi;", "And he let it fall in the midst of their camp,"], ["e faataaliolio ai i mea sa latou nonofo ai.", "round about their habitations."]]},
  {num:29,words:[["Na latou aai,", "So they did eat,"], ["ona matuā maoona ai lea o i latou;", "and were well filled:"], ["auā na ia avatu ia te i latou o mea na latou tu'inanau i ai.", "for he gave them their own desire;"]]},
  {num:30,words:[["Na le te'a i latou i le mea na latou tu'inanau i ai; a o i o latou gutu a latou mea e 'ai,", "They were not estranged from their lust. But while their meat was yet in their mouths,"]]},
  {num:31,words:[["ua oo ai ia te i latou le toasa o le Atua,", "The wrath of God came upon them,"], ["ua fasiotia foi o latou tagata puputa,", "and slew the fattest of them,"], ["ma na lafo i lalo taulelea o Isaraelu.", "and smote down the chosen men of Israel."]]},
  {num:32,words:[["E ui lava i ia mea uma, a ua latou agasala pea;", "For all this they sinned still,"], ["e ui lava i ona vavega, a e latou te lei faatuatua lava.", "and believed not for his wondrous works."]]},
  {num:33,words:[["Ona faaumatia faaleaoga ai lea e ia o latou olaga,", "Therefore their days did he consume in vanity,"], ["na faaumatia foi o latou tausaga i le atuatuvale.", "and their years in trouble."]]},
  {num:34,words:[["Na latou sailiili atu ia te ia ina o fasiotia i latou e ia;", "When he slew them, then they sought him:"], ["ona latou foi ai lea i le sailiili i latou i le Atua.", "and they returned and enquired early after God."]]},
  {num:35,words:[["Ona latou manatu ifo ai lea o le Atua o lo latou papa ia;", "And they remembered that God was their rock,"], ["o le Atua silisili o ia na te faaolaina i latou.", "and the high God their redeemer."]]},
  {num:36,words:[["A ua latou pepelo ia te ia i o latou gutu,", "Nevertheless they did flatter him with their mouth,"], ["ma ua latou faa'ole'ole ia te ia i o latou laulaufaiva.", "and they lied unto him with their tongues."]]},
  {num:37,words:[["E lei tutumau foi o latou loto ia te ia,", "For their heart was not right with him,"], ["e lei faamaoni foi latou i lana feagaiga.", "neither were they stedfast in his covenant."]]},
  {num:38,words:[["A o ia,", "But he,"], ["ua alofa mutimuti vale,", "being full of compassion,"], ["ua ia faamagaloina a latou amio leaga;", "forgave their iniquity, and destroyed them not:"], ["na ia le faaumatia ai i latou;", "yea,"], ["ua liliu ese faalasi e ia lona toasa,", "many a time turned he his anger away,"], ["na ia le faatupuina foi lona toatamai atoatoa;", "and did not stir up all his wrath."]]},
  {num:39,words:[["auā na ia manatua,", "For he remembered that they were but flesh;"], ["ua na o tagata lava i latou; o le matagi o loo mavae atu,", "a wind that passeth away,"], ["e le toe foi mai lava.", "and cometh not again."]]},
  {num:40,words:[["Na faalasi naua ona latou faaonoono ia te ia i le vao;", "How oft did they provoke him in the wilderness,"], ["na latou faalili lava ia te ia i le vao.", "and grieve him in the desert!"]]},
  {num:41,words:[["Na latou toe tofotofo lava i le Atua;", "Yea, they turned back and tempted God,"], ["ma latou faaonoono i le Paia o Isaraelu.", "and limited the Holy One of Israel."]]},
  {num:42,words:[["Latou te lei manatua lona aao,", "They remembered not his hand,"], ["o le aso na ia faaolaina ai i latou ai le puapuaga;", "nor the day when he delivered them from the enemy."]]},
  {num:43,words:[["o ona faailoga na na faia i Aikupito,", "How he had wrought his signs in Egypt,"], ["atoa ma ona vavega i le laueleele o Soana.", "and his wonders in the field of Zoan:"]]},
  {num:44,words:[["Na ia liua foi o latou vaitafe ma toto,", "And had turned their rivers into blood;"], ["atoa ma o latou vaita'i,", "and their floods,"], ["ina ia latou le inu ai.", "that they could not drink."]]},
  {num:45,words:[["Na ia aauina atu ia te i latou o garova,", "He sent divers sorts of flies among them,"], ["na 'aina ai i latou;", "which devoured them; and frogs,"], ["o rane foi na faaumatia ai i latou.", "which destroyed them."]]},
  {num:46,words:[["Na ia avatua foi o fua o lo latou fanua i le sē kasili,", "He gave also their increase unto the caterpiller,"], ["na avatua foi a latou galuega i le sē akerise.", "and their labour unto the locust."]]},
  {num:47,words:[["Na ia faamateina o a latou vine i le uato'a,", "He destroyed their vines with hail,"], ["na ia faamateina foi a latou sukamoru i le uato'a tetele.", "and their sycomore trees with frost."]]},
  {num:48,words:[["Na ia tuuina atu foi o a latou manu i le uato'a ma na tuuina a latou lafu mamoe i le uila.", "He gave up their cattle also to the hail, and their flocks to hot thunderbolts."]]},
  {num:49,words:[["Na ia faaoo ia te i latou o lona toasa mamafa,", "He cast upon them the fierceness of his anger,"], ["o le ma'ema'eā,", "wrath,"], ["le toatamai,", "and indignation,"], ["ma le puapuaga,", "and trouble,"], ["i lona aauina atu o auauna e i ai mala.", "by sending evil angels among them."]]},
  {num:50,words:[["Ua na saunia le ala o lona toasa;", "He made a way to his anger;"], ["e lei faasaoina e ia o i latou i le oti,", "he spared not their soul from death,"], ["a ua tuuina atu o latou ola i le faamai;", "but gave their life over to the pestilence;"]]},
  {num:51,words:[["na ia fasia foi ulumatua uma i Aikupito;", "And smote all the firstborn in Egypt;"], ["o le amataga o lo latou malosi na i fale ie o Hamo.", "the chief of their strength in the tabernacles of Ham:"]]},
  {num:52,words:[["Na ia aumaia foi lona nuu e pei o mamoe,", "But made his own people to go forth like sheep,"], ["ma na ta'ita'iina i latou i le vao e pei o se lafu.", "and guided them in the wilderness like a flock."]]},
  {num:53,words:[["Na ia ta'ita'iina i latou ua saogalemu,", "And he led them on safely,"], ["o lea na le fefefe ai i latou; a o e ua ita i ai,", "so that they feared not:"], ["ua lofia i latou i le sami.", "but the sea overwhelmed their enemies."]]},
  {num:54,words:[["Na ia faaoo ia te i latou i lona laueleele paia,", "And he brought them to the border of his sanctuary, even to this mountain,"], ["o lenei lava mauga na ia maua i lona aao taumatau.", "which his right hand had purchased."]]},
  {num:55,words:[["Na ia tulia foi nuu ese i o latou luma,", "He cast out the heathen also before them,"], ["ona vaevaeina atu lea e ia ia te i latou le tofi ua fuatia,", "and divided them an inheritance by line,"], ["ma na faanonofo o itu aiga o Isaraelu i o latou fale ie.", "and made the tribes of Israel to dwell in their tents."]]},
  {num:56,words:[["A ua latou tofotofo ma faaonoono i le Atua silisili ese;", "Yet they tempted and provoked the most high God,"], ["e lei tausi foi e i latou ana tulafono.", "and kept not his testimonies:"]]},
  {num:57,words:[["Ua toe liliu i latou,", "But turned back,"], ["ma faa'ole'ole e pei o latou tamā;", "and dealt unfaithfully like their fathers:"], ["ua liua i latou e pei o le aufana ua pepelo.", "they were turned aside like a deceitful bow."]]},
  {num:58,words:[["Na latou faalili foi ia te ia i a latou mea maualuluga;", "For they provoked him to anger with their high places,"], ["na latou faatupuina foi lona fuā i a latou tupua ua ta.", "and moved him to jealousy with their graven images."]]},
  {num:59,words:[["Ua faafofoga le Atua,", "When God heard this,"], ["ona toasa tele ai lea o ia,", "he was wroth,"], ["ona matuā 'ino'ino ai lea o ia ia Isaraelu;", "and greatly abhorred Israel:"]]},
  {num:60,words:[["na ia lafoai ai le malumalu i Sailo,", "So that he forsook the tabernacle of Shiloh,"], ["o le fale fetafai sa mau ai o ia ma tagata.", "the tent which he placed among men;"]]},
  {num:61,words:[["Na ia tuuina atu foi lona malosi ia tāfea,", "And delivered his strength into captivity,"], ["na ia tuuina atu foi lona matagofie i le lima o le ua ita mai.", "and his glory into the enemy's hand."]]},
  {num:62,words:[["Na ia tuuina foi o lona nuu i le pelu,", "He gave his people over also unto the sword;"], ["ma ua toasa tele ia i lona lava tofi.", "and was wroth with his inheritance."]]},
  {num:63,words:[["O latou taulelea ua faaumatia i le afi;", "The fire consumed their young men;"], ["o latou taupou foi ua le viia i latou.", "and their maidens were not given to marriage."]]},
  {num:64,words:[["O latou faitaulaga, ua oti i latou i le pelu;", "Their priests fell by the sword;"], ["e lei taufaiaue foi a latou avā.", "and their widows made no lamentation."]]},
  {num:65,words:[["Ona maleifua ai lea o le Alii e peiseai na tofa,", "Then the Lord awaked as one out of sleep,"], ["e pei o se tagata malosi ua alaga ona o le uaina.", "and like a mighty man that shouteth by reason of wine."]]},
  {num:66,words:[["Ua na taia e ua ita ia te ia i o latou tua;", "And he smote his enemies in the hinder parts:"], ["ua na faia lea mo latou luma e faavavau.", "he put them to a perpetual reproach."]]},
  {num:67,words:[["Na ia tetee atu foi i le fale ie o Iosefa,", "Moreover he refused the tabernacle of Joseph,"], ["na ia le filifilia foi le itu aiga o Efaraima.", "and chose not the tribe of Ephraim:"]]},
  {num:68,words:[["A ua ia filifilia le itu aiga o Iuta,", "But chose the tribe of Judah,"], ["o le mauga o Siona na ia finagalo i ai.", "the mount Zion which he loved."]]},
  {num:69,words:[["Ua na faia foi o lona malumalu e pei o mea maualuluga,", "And he built his sanctuary like high palaces,"], ["e pei o le lalolagi na ia faavaeina e faavavau lava.", "like the earth which he hath established for ever."]]},
  {num:70,words:[["Ua na filifilia foi Tavita lana auauna,", "He chose David also his servant,"], ["ma na aumaia o ia nai lotoā mamoe;", "and took him from the sheepfolds:"]]},
  {num:71,words:[["na ia aumaia o ia sa mulimuli i mamoe fananau, ina ia fafaga lava e ia ia Iakopo lona nuu,", "From following the ewes great with young he brought him to feed Jacob his people,"], ["o Isaraelu foi lona tofi.", "and Israel his inheritance."]]},
  {num:72,words:[["Na fafaga foi e ia ia te i latou e tusa ma le faamaoni o lona loto;", "So he fed them according to the integrity of his heart;"], ["na ia ta'ita'i ia te i latou i le poto o ona lima.", "and guided them by the skilfulness of his hands."]]},
];
renderVerseSet(psa_ch_78_Verses, 'psa-ch78-verses');

var psa_ch_79_Verses = [
  {num:1,words:[["Le Atua e,", "O God,"], ["ua oo mai nuu ese i lou tofi;", "the heathen are come into thine inheritance;"], ["ua latou faaleagaina lou malumalu paia;", "thy holy temple have they defiled;"], ["ua latou faia Ierusalema ma faupuegāmaa.", "they have laid Jerusalem on heaps."]]},
  {num:2,words:[["Ua latou avatu tino o au auauna ua oti e fai ma mea e 'ai a manu felelei,", "The dead bodies of thy servants have they given to be meat unto the fowls of the heaven,"], ["ua avatu tino o ou tagata amio Atua i manu feai e tataa.", "the flesh of thy saints unto the beasts of the earth."]]},
  {num:3,words:[["Ua latou faamaligi o latou toto e pei o le vai, ua soo ai Ierusalema;", "Their blood have they shed like water round about Jerusalem;"], ["na leai foi se na te tanua i latou .", "and there was none to bury them."]]},
  {num:4,words:[["Ua avea i matou ma gao a ē ua matou tuaoi,", "We are become a reproach to our neighbours,"], ["o ulaga ma tauemuga a e ua vagavagai mai ia te i matou.", "a scorn and derision to them that are round about us."]]},
  {num:5,words:[["Ieova e,", "How long,"], ["e te toasa mai seia afea? E faavavau ea? E mu ea pei o le afi lou fuā?", "LORD? wilt thou be angry for ever? shall thy jealousy burn like fire?"]]},
  {num:6,words:[["Ia e sasaaina atu lou toasa tele i nuu ese o e le iloa oe,", "Pour out thy wrath upon the heathen that have not known thee,"], ["atoa ma malo o e le valaau i lou suafa.", "and upon the kingdoms that have not called upon thy name."]]},
  {num:7,words:[["Auā ua latou 'aina Iakopo,", "For they have devoured Jacob,"], ["o le mea foi sa nofo ai o ia ua latou faatafunaina lea.", "and laid waste his dwelling place."]]},
  {num:8,words:[["Aua e te manatua a matou agasala anamua;", "O remember not against us former iniquities:"], ["ia vave ona tomua mai o lou alofa mutimuti vale ia te i matou;", "let thy tender mercies speedily prevent us:"], ["auā ua matuā vaivai i matou.", "for we are brought very low."]]},
  {num:9,words:[["Le Atua o lo matou faaolataga e,", "Help us, O God of our salvation,"], ["ia e fesoasoani mai ia te i matou ona o lou suafa mamalu;", "for the glory of thy name:"], ["ia e laveai mai foi ia te i matou,", "and deliver us,"], ["ma ia e faamagaloina a matou agasala ona o lou suafa.", "and purge away our sins, for thy name's sake."]]},
  {num:10,words:[["Se a le mea e fai ane ai o nuu ese,", "Wherefore should the heathen say,"], ["O ifea o i ai lo latou Atua? Ia iloa i nuu ese o loo i o matou luma le taui o le toto o au auauna na faamaligiina.", "Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed."]]},
  {num:11,words:[["Ia oo atu ia te oe le auega a le ua fusifusia;", "Let the sighing of the prisoner come before thee;"], ["e tusa ma lou aao malosi ia e faasaoina e ua tuu e oti;", "according to the greatness of thy power preserve thou those that are appointed to die;"]]},
  {num:12,words:[["ma ia e taui faafitu atu i fatafata o e ua matou tuaoi a latou upu na latou faifai ai ia te oe le Alii.", "And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord."]]},
  {num:13,words:[["O i matou foi o lou nuu ma le lafu mamoe na e fagaina, matou te vivii ia te oe e faavavau;", "So we thy people and sheep of thy pasture will give thee thanks for ever:"], ["matou te ta'uta'u atu ou viiga i lea tupulaga ma lea tupulaga.", "we will shew forth thy praise to all generations."]]},
];
renderVerseSet(psa_ch_79_Verses, 'psa-ch79-verses');

var psa_ch_80_Verses = [
  {num:1,words:[["Le leoleo o Isaraelu e,", "Give ear,"], ["ia e faafofoga mai,", "O Shepherd of Israel,"], ["o oe o lē ta'ita'i ia Iosefa e pei o se lafu mamoe;", "thou that leadest Joseph like a flock;"], ["o oe lē tietie i le va o kerupi,", "thou that dwellest between the cherubims,"], ["ia e faaali mai lou pupula.", "shine forth."]]},
  {num:2,words:[["Ia e faaoso lou malosi i luma o Efaraima, ma Peniamina,", "Before Ephraim and Benjamin and Manasseh stir up thy strength,"], ["ma Manase, ma e afio mai e faaola ia te i matou.", "and come and save us."]]},
  {num:3,words:[["Le Atua e,", "Turn us again,"], ["ia e faafoisia i matou,", "O God,"], ["ma ia malamalama mai ou fofoga;", "and cause thy face to shine;"], ["ona faaolaina ai lea o i matou.", "and we shall be saved."]]},
  {num:4,words:[["Ieova e, le Atua o 'au,", "O LORD God of hosts,"], ["e pusa mai lou toasa i le tatalo a lou nuu seia afea?", "how long wilt thou be angry against the prayer of thy people?"]]},
  {num:5,words:[["Ua e fafagaina i latou i loimata e fai ma mea e 'ai,", "Thou feedest them with the bread of tears;"], ["o loimata foi e tele ua e avane ia te i latou e inu ai.", "and givest them tears to drink in great measure."]]},
  {num:6,words:[["Ua e faia i matou ma mea e famisai ai ē ua matou tuaoi;", "Thou makest us a strife unto our neighbours:"], ["ua tauemu mai foi ia te i matou o e ita mai ia i matou.", "and our enemies laugh among themselves."]]},
  {num:7,words:[["Le Atua o 'au e,", "Turn us again,"], ["ia e toe faafoisia i matou,", "O God of hosts,"], ["ma ia malamalama mai ou fofoga;", "and cause thy face to shine;"], ["ona faaolaina ai lea o i matou.", "and we shall be saved."]]},
  {num:8,words:[["Na e aumaia le vine nai Aikupito;", "Thou hast brought a vine out of Egypt:"], ["na e tulia nuu ese,", "thou hast cast out the heathen,"], ["ma e totōina ai.", "and planted it."]]},
  {num:9,words:[["Na e teuteua le laueleele mo lea vine;", "Thou preparedst room before it,"], ["na e faasosoloina foi ona aa,", "and didst cause it to take deep root,"], ["ua tumu ai le nuu.", "and it filled the land."]]},
  {num:10,words:[["Ua maluia mauga i lona paolo,", "The hills were covered with the shadow of it,"], ["o ona la foi e pei o arasi silisili.", "and the boughs thereof were like the goodly cedars."]]},
  {num:11,words:[["Ua ia faasosolo atu ona lava la e oo atu i le sami,", "She sent out her boughs unto the sea,"], ["o ona tatupu foi e oo atu i le vaitafe.", "and her branches unto the river."]]},
  {num:12,words:[["Se a le mea na e sōloia ai ona pa,", "Why hast thou then broken down her hedges,"], ["ina ia tau ona fua e i latou uma o e ui ane i le ala?", "so that all they which pass by the way do pluck her?"]]},
  {num:13,words:[["Ua faataumaoi ai e le puaa mai le vao,", "The boar out of the wood doth waste it,"], ["o manu foi e tataa latou te aai ai.", "and the wild beast of the field doth devour it."]]},
  {num:14,words:[["Le Atua o 'au e,", "Return,"], ["ia e toe foi mai lava;", "we beseech thee,"], ["ia e silasila mai mai le lagi,", "O God of hosts: look down from heaven,"], ["ma e silafia,", "and behold,"], ["ma ia e asiasi i lenei vine,", "and visit this vine;"]]},
  {num:15,words:[["o le pogai lava na totōina e lou aao taumatau,", "And the vineyard which thy right hand hath planted,"], ["o le atalii foi na e faamalosia mo oe.", "and the branch that thou madest strong for thyself."]]},
  {num:16,words:[["Ua susunuina i le afi,", "It is burned with fire,"], ["ua tuu i lalo;", "it is cut down:"], ["e fano i latou i le aoaiga mai ou fofoga.", "they perish at the rebuke of thy countenance."]]},
  {num:17,words:[["Ia faaee lou aao i luga o le tagata o lou aao taumatau,", "Let thy hand be upon the man of thy right hand,"], ["o le atalii o le tagata na e faamalosia mo oe.", "upon the son of man whom thou madest strong for thyself."]]},
  {num:18,words:[["Matou te le tuumuli ia te oe;", "So will not we go back from thee:"], ["ia e faaola mai ia te i matou,", "quicken us,"], ["ona matou valaau atu ai lea i lou suafa.", "and we will call upon thy name."]]},
  {num:19,words:[["Ieova e,", "Turn us again,"], ["le Atua o 'au,", "O LORD God of hosts,"], ["ia e faafoisia i matou; ia malamalama mai ou fofoga;", "cause thy face to shine;"], ["ona faaolaina ai lea o i matou.", "and we shall be saved."]]},
];
renderVerseSet(psa_ch_80_Verses, 'psa-ch80-verses');

var psa_ch_81_Verses = [
  {num:1,words:[["Ia outou pepese ma le leo tele i le Atua lo tatou malosi;", "Sing aloud unto God our strength:"], ["ia outou alalaga i le Atua o Iakopo.", "make a joyful noise unto the God of Jacob."]]},
  {num:2,words:[["Ina usu ia le pese,", "Take a psalm,"], ["au mai ia le topa, o le kitara leo mălie,", "and bring hither the timbrel,"], ["atoa ma le napeli.", "the pleasant harp with the psaltery."]]},
  {num:3,words:[["Ia outou ilia le pu i le masina ua faatoa vaaia,", "Blow up the trumpet in the new moon, in the time appointed,"], ["o ona po ua tuu e fai ai le tausamiga.", "on our solemn feast day."]]},
  {num:4,words:[["Auā o le tulafono lenei mo Isaraelu,", "For this was a statute for Israel,"], ["o le pule a le Atua o Iakopo.", "and a law of the God of Jacob."]]},
  {num:5,words:[["Na ia faia lenei mea ma tulafono ia Iosefa,", "This he ordained in Joseph for a testimony,"], ["i lona afio atu i le nuu o Aikupito;", "when he went out through the land of Egypt:"], ["na ou faalogo ai i le gagana ou te lei iloa.", "where I heard a language that I understood not."]]},
  {num:6,words:[["Na ou tuueseina le avega i lona ua;", "I removed his shoulder from the burden:"], ["o le ato ua te'a ma ona lima.", "his hands were delivered from the pots."]]},
  {num:7,words:[["Na e valaau mai i le puapuaga,", "Thou calledst in trouble,"], ["ona ou laveaiina ai lea o oe;", "and I delivered thee;"], ["na ou tali atu ia te oe i le mea lilo ua i ai le faititili;", "I answered thee in the secret place of thunder:"], ["na ou tofotofo ia te oe i le vai o Meripa. Selā.", "I proved thee at the waters of Meribah. Selah."]]},
  {num:8,words:[["Lo'u nuu e,", "Hear,"], ["faalogologo mai ia,", "O my people,"], ["se'i ou ta'utino atu ia te oe;", "and I will testify unto thee:"], ["Isaraelu e,", "O Israel,"], ["e lelei ona e faalogo mai ia te au;", "if thou wilt hearken unto me;"]]},
  {num:9,words:[["aua ne'i ai se atua ese ia te oe;", "There shall no strange god be in thee;"], ["aua foi ne'i e ifo i se atua o se nuu ese.", "neither shalt thou worship any strange god."]]},
  {num:10,words:[["O a'u lava o Ieova lou Atua,", "I am the LORD thy God,"], ["o le na aveina ae ia te oe nai le nuu o Aikupito;", "which brought thee out of the land of Egypt:"], ["faamaga ia lou gutu,", "open thy mouth wide,"], ["ona ou faatumuina ai lea.", "and I will fill it."]]},
  {num:11,words:[["A e lei faalogo mai lo'u nuu i lo'u leo;", "But my people would not hearken to my voice;"], ["o Isaraelu foi e lei loto mai ia te au.", "and Israel would none of me."]]},
  {num:12,words:[["Ona ou tuuina atu ai lea o i latou i o latou loto finau vale;", "So I gave them up unto their own hearts' lust:"], ["na latou savavali i mea na latou filifili i ai.", "and they walked in their own counsels."]]},
  {num:13,words:[["E! A na faalogo mai lo'u nuu ia te au,", "Oh that my people had hearkened unto me,"], ["ana savavali Isaraelu i o'u ala;", "and Israel had walked in my ways!"]]},
  {num:14,words:[["po ua ou vave faatoilaloina e ua ita ia te i latou,", "I should soon have subdued their enemies,"], ["ma a'u faaoo atu lo'u lima i e ua fai i latou mo latou fili.", "and turned my hand against their adversaries."]]},
  {num:15,words:[["Po ua faatagā vivii ia te i latou e ua 'ino'ino ia Ieova;", "The haters of the LORD should have submitted themselves unto him:"], ["a e faavavau o latou aso.", "but their time should have endured for ever."]]},
  {num:16,words:[["Po ua fafaga e ia ia te i latou i le saito e sili ona lelei;", "He should have fed them also with the finest of the wheat:"], ["po ua ou faama'ona ia te oe i le meli nai le papa.", "and with honey out of the rock should I have satisfied thee."]]},
];
renderVerseSet(psa_ch_81_Verses, 'psa-ch81-verses');

var psa_ch_82_Verses = [
  {num:1,words:[["O loo tu le Atua i le faapotopotoga a le Atua;", "God standeth in the congregation of the mighty;"], ["o loo faamasino ia i luma o atua.", "he judgeth among the gods."]]},
  {num:2,words:[["Tou te faamasino ma le le tonu seia afea? Ma outou faailogaina e ua amio leaga seia afea? Selā.", "How long will ye judge unjustly, and accept the persons of the wicked? Selah."]]},
  {num:3,words:[["Ia outou faamasinoina e ua vaivai ma ē mātuaoti;", "Defend the poor and fatherless:"], ["ia outou ta'uamiotonuina e ua puapuaga ma ē matitiva.", "do justice to the afflicted and needy."]]},
  {num:4,words:[["Ia outou faaola i e vaivai ma ē matitiva;", "Deliver the poor and needy:"], ["ia outou laveaiina i latou ai le lima o e amio leaga.", "rid them out of the hand of the wicked."]]},
  {num:5,words:[["Latou te le iloa,", "They know not,"], ["e le mafaufau foi i latou;", "neither will they understand;"], ["e savavali pea i latou i le pouliuli;", "they walk on in darkness:"], ["e faagaeetia faavae uma o le lalolagi.", "all the foundations of the earth are out of course."]]},
  {num:6,words:[["O a'u,", "I have said,"], ["na ou faapea ane, O atua outou;", "Ye are gods;"], ["o fanau foi outou uma a lē Silisili ese.", "and all of you are children of the most High."]]},
  {num:7,words:[["A e moni, tou te oti lava e pei o tagata,", "But ye shall die like men,"], ["e pauu foi outou e pei o se tasi alii.", "and fall like one of the princes."]]},
  {num:8,words:[["Le Atua e,", "Arise,"], ["ia e tulai mai,", "O God,"], ["ia e faamasino le lalolagi; auā o oe,", "judge the earth:"], ["e te faia nuu uma lava mou tofi.", "for thou shalt inherit all nations."]]},
];
renderVerseSet(psa_ch_82_Verses, 'psa-ch82-verses');

var psa_ch_83_Verses = [
  {num:1,words:[["Le Atua e,", "Keep not thou silence,"], ["aua ne'i e le fetalai mai;", "O God:"], ["le Atua e,", "hold not thy peace,"], ["aua ne'i e le tali mai,", "and be not still,"], ["aua foi ne'i e mapu.", "O God."]]},
  {num:2,words:[["Auā faauta,", "For,"], ["ua vāvāō o e ua ita ia te oe;", "lo,"], ["o e ua 'ino'ino foi ia te oe,", "thine enemies make a tumult:"], ["ua latou faamaualuluga.", "and they that hate thee have lifted up the head."]]},
  {num:3,words:[["Ua latou togafiti faalilolilo i lou nuu,", "They have taken crafty counsel against thy people,"], ["ma latou taupulepule i e ua natia e oe.", "and consulted against thy hidden ones."]]},
  {num:4,words:[["Ua latou faapea ane,", "They have said,"], ["O mai ia,", "Come,"], ["ia tatou faaumatia i latou ia le toe fai ma nuu;", "and let us cut them off from being a nation;"], ["ia le toe manatua lava le igoa o Isaraelu.", "that the name of Israel may be no more in remembrance."]]},
  {num:5,words:[["Auā na latou taupulepule ma le loto gatasi;", "For they have consulted together with one consent:"], ["ua latou fai le feagaiga e tetee atu ia te oe;", "they are confederate against thee:"]]},
  {num:6,words:[["o fale ie o Etoma ma sa Isamaelī;", "The tabernacles of Edom, and the Ishmaelites;"], ["o Moapi ma sa Hakarā;", "of Moab, and the Hagarenes;"]]},
  {num:7,words:[["o Kavala,", "Gebal,"], ["ma Amoni,", "and Ammon,"], ["ma Amaleka;", "and Amalek;"], ["o Filisitia atoa ma e ua nonofo i Turo;", "the Philistines with the inhabitants of Tyre;"]]},
  {num:8,words:[["o Asuria foi ua faatasi ma i latou;", "Assur also is joined with them:"], ["ua faia i latou ma fesoasoani i le fanauga a Lota. Selā.", "they have holpen the children of Lot. Selah."]]},
  {num:9,words:[["Ia e fai ia te i latou e faapei ona e faia ia Mitiana,", "Do unto them as unto the Midianites;"], ["ma Sesera,", "as to Sisera, as to Jabin,"], ["ma Iapino i le alia o Kisona.", "at the brook of Kison:"]]},
  {num:10,words:[["Na faaumatia i latou i Enetoro;", "Which perished at En-dor:"], ["na avea i latou ma otaota mo le laueleele.", "they became as dung for the earth."]]},
  {num:11,words:[["Ia e faia o latou alii ia pei o Oreva ma Seeva;", "Make their nobles like Oreb, and like Zeeb:"], ["ia pei o Seva ma Salemuna foi o latou alii uma;", "yea, all their princes as Zebah, and as Zalmunna:"]]},
  {num:12,words:[["o e na faapea ane,", "Who said,"], ["Ia tatou fai mo i tatou o mea e afio ai le Atua.", "Let us take to ourselves the houses of God in possession."]]},
  {num:13,words:[["Lo'u Atua e,", "O my God,"], ["ia e faia i latou ia pei o le mea faataavalevale;", "make them like a wheel;"], ["ia pei o le aputi o saito e lelea i le matagi.", "as the stubble before the wind."]]},
  {num:14,words:[["Ia pei o le afi ona susunu le vaomatua,", "As the fire burneth a wood,"], ["ia pei o le mumū o le afi ona faamu a'i mauga;", "and as the flame setteth the mountains on fire;"]]},
  {num:15,words:[["ia faapea ona e tuliloa ia te i latou i lou afā,", "So persecute them with thy tempest,"], ["ia e faaatuatuvale ia te i latou i lou asiosio.", "and make them afraid with thy storm."]]},
  {num:16,words:[["Ia e matuā faama ia te i latou;", "Fill their faces with shame;"], ["ina ia latou saili i lou suafa,", "that they may seek thy name,"], ["Ieova e.", "O LORD."]]},
  {num:17,words:[["Ia faamaina i latou ma ia faaatuatuvaleina i latou e faavavau faavavau lava;", "Let them be confounded and troubled for ever;"], ["ia masiasi i latou,", "yea, let them be put to shame,"], ["ma ia fano i latou;", "and perish:"]]},
  {num:18,words:[["ina ia iloa e i latou,", "That men may know that thou,"], ["o oe, e ou le suafa o IEOVA,", "whose name alone is JEHOVAH,"], ["na o oe lava o le Silisili ese i le lalolagi uma.", "art the most high over all the earth."]]},
];
renderVerseSet(psa_ch_83_Verses, 'psa-ch83-verses');

var psa_ch_84_Verses = [
  {num:1,words:[["Ieova o 'au e,", "How amiable are thy tabernacles,"], ["e matuā manaomia ou afioaga.", "O LORD of hosts!"]]},
  {num:2,words:[["O loo naunau lo'u agaga,", "My soul longeth,"], ["ma ua lailoa i le fia alu atu i lotoā o Ieova;", "yea, even fainteth for the courts of the LORD:"], ["o loo alaga fiafia lo'u loto ma lo'u tino i le Atua soifua.", "my heart and my flesh crieth out for the living God."]]},
  {num:3,words:[["E moni,", "Yea,"], ["o le manulele ua maua se fale,", "the sparrow hath found an house, and the swallow a nest for herself,"], ["o le pe'ape'a foi ua maua sona ofaga e tuu ai lana toloai,", "where she may lay her young,"], ["o au lava fata faitaulaga,", "even thine altars,"], ["Ieova o 'au e,", "O LORD of hosts, my King,"], ["o lo'u Tupu ma lo'u Atua.", "and my God."]]},
  {num:4,words:[["Amuia i latou ua nonofo i lou fale;", "Blessed are they that dwell in thy house:"], ["latou te vivii pea ia te oe. Selā.", "they will be still praising thee. Selah."]]},
  {num:5,words:[["Amuia le tagata o loo ia te oe lona malosi;", "Blessed is the man whose strength is in thee;"], ["o ala ua i o latou loto ia.", "in whose heart are the ways of them."]]},
  {num:6,words:[["Ua ui ane i latou i le vanu o Peka, ua faia lea e i latou ma vaipuna;", "Who passing through the valley of Baca make it a well;"], ["ua ufitia ai i le manuia ona o le uaga muamua.", "the rain also filleth the pools."]]},
  {num:7,words:[["Latou te savavali ma le malosi e tupu pea;", "They go from strength to strength,"], ["e iloa i latou i Siona i luma o le Atua.", "every one of them in Zion appeareth before God."]]},
  {num:8,words:[["Ieova e,", "O LORD God of hosts,"], ["le Atua o 'au,", "hear my prayer:"], ["ia e faafofoga mai i la'u tatalo; le Atua o Iakopo e,", "give ear,"], ["ia liliu mai ou fofogā.", "O God of Jacob."], ["Selā.", "Selah."]]},
  {num:9,words:[["Le Atua e,", "Behold,"], ["lo matou talita, ia e silasila mai,", "O God our shield,"], ["ia e matuā silasila mai i fofoga o lē na e faauuina.", "and look upon the face of thine anointed."]]},
  {num:10,words:[["Auā e sili le aso e tasi i ou lotoā i lo le afe. E sili lo'u manao ia a'u tu i le faitotoa o le fale o lo'u Atua,", "For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God,"], ["i le manao e mau i fale ie o e amio leaga.", "than to dwell in the tents of wickedness."]]},
  {num:11,words:[["Auā o Ieova le Atua o le la lava ia ma le talita;", "For the LORD God is a sun and shield:"], ["e foaiina mai e Ieova le alofa tunoa ma le manuia;", "the LORD will give grace and glory:"], ["e le taofia e ia se mea lelei i e ua sao lo latou savavali.", "no good thing will he withhold from them that walk uprightly."]]},
  {num:12,words:[["Ieova o 'au e,", "O LORD of hosts,"], ["amuia le tagata ua faatuatua ia te oe.", "blessed is the man that trusteth in thee."]]},
];
renderVerseSet(psa_ch_84_Verses, 'psa-ch84-verses');

var psa_ch_85_Verses = [
  {num:1,words:[["Ieova e,", "LORD,"], ["ua e fiafia lava i lou nuu;", "thou hast been favourable unto thy land:"], ["ua e faafoisia mai le tafeaga o Iakopo.", "thou hast brought back the captivity of Jacob."]]},
  {num:2,words:[["Ua e faamagaloina le amio leaga a lou nuu,", "Thou hast forgiven the iniquity of thy people,"], ["ua e ufitia a latou agasala uma lava. Selā.", "thou hast covered all their sin. Selah."]]},
  {num:3,words:[["Ua e aveesea lou ma'ema'eā uma lava;", "Thou hast taken away all thy wrath:"], ["ua e liliu ese lou toasa mamafa.", "thou hast turned thyself from the fierceness of thine anger."]]},
  {num:4,words:[["Le Atua e,", "Turn us,"], ["o lo matou faaolataga, ia e faafoisia mai i matou;", "O God of our salvation,"], ["ia e faamavae atu foi lou toatamai ia te i matou.", "and cause thine anger toward us to cease."]]},
  {num:5,words:[["E faavavau ea lou toasa ia te i matou? E te faauaoloa ea lou ma'ema'eā e au tupulaga?", "Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?"]]},
  {num:6,words:[["E te le toe faaolaola mai ea ia te i matou;", "Wilt thou not revive us again:"], ["ina ia fiafia lava lou nuu ia te oe?", "that thy people may rejoice in thee?"]]},
  {num:7,words:[["Ieova e,", "Shew us thy mercy,"], ["ia e faailoa mai ia te i matou lou alofa;", "O LORD,"], ["ia e foaiina mai foi ia te i matou le olataga mai ia te oe.", "and grant us thy salvation."]]},
  {num:8,words:[["Ou te faalogologo atu i mea e fetalaia mai e Ieova le Atua;", "I will hear what God the LORD will speak:"], ["auā na te fetalai mai ia manuia lona nuu atoa ma ona tagata amio Atua;", "for he will speak peace unto his people, and to his saints:"], ["a e aua ne'i latou toe liliu atu i le valea.", "but let them not turn again to folly."]]},
  {num:9,words:[["E moni, ua latalata lana olataga i e ua matatau ia te ia;", "Surely his salvation is nigh them that fear him;"], ["ina ia tumau ai le mamalu i lo tatou nuu.", "that glory may dwell in our land."]]},
  {num:10,words:[["O le alofa ma le faamaoni ua la fetaiai;", "Mercy and truth are met together;"], ["o le amiotonu ma le filemu ua la feasogi.", "righteousness and peace have kissed each other."]]},
  {num:11,words:[["E tupu ae le faamaoni ai le lalolagi;", "Truth shall spring out of the earth;"], ["e vaavaai ifo foi le amiotonu mai le lagi.", "and righteousness shall look down from heaven."]]},
  {num:12,words:[["E foaiina mai e Ieova lava le manuia;", "Yea, the LORD shall give that which is good;"], ["e fua mai foi e lo tatou laueleele ona lava fua.", "and our land shall yield her increase."]]},
  {num:13,words:[["E muamua atu i ona luma le amiotonu;", "Righteousness shall go before him;"], ["na te faatumauina foi ona vae i le ala.", "and shall set us in the way of his steps."]]},
];
renderVerseSet(psa_ch_85_Verses, 'psa-ch85-verses');

var psa_ch_86_Verses = [
  {num:1,words:[["Ieova e,", "Bow down thine ear,"], ["ia liliu mai ou fofoga,", "O LORD,"], ["ia e faafofoga mai ia te au;", "hear me:"], ["auā ua puapuagaina ma ua mativa lava a'u.", "for I am poor and needy."]]},
  {num:2,words:[["Ia e leoleoina lo'u agaga,", "Preserve my soul;"], ["auā ua amio Atua lava au;", "for I am holy:"], ["o oe na, lo'u Atua e,", "O thou my God,"], ["ia e faaola mai i lau auauna o le ua faatuatua ia te oe.", "save thy servant that trusteth in thee."]]},
  {num:3,words:[["Le Alii e,", "Be merciful unto me,"], ["ia e alofa mai ia te au;", "O Lord:"], ["auā ou te valaau atu ia te oe i aso uma lava.", "for I cry unto thee daily."]]},
  {num:4,words:[["Ia e faafiafia mai le loto o lau auauna;", "Rejoice the soul of thy servant:"], ["auā ua faanaunau atu lo'u loto ia te oe,", "for unto thee, O Lord,"], ["le Alii e.", "do I lift up my soul."]]},
  {num:5,words:[["Auā le Alii e,", "For thou,"], ["o oe e lelei,", "Lord,"], ["ma ua e faamagalo sala;", "art good, and ready to forgive;"], ["e tele foi lou alofa ia te i latou uma o e valaau atu ia te oe.", "and plenteous in mercy unto all them that call upon thee."]]},
  {num:6,words:[["Ieova e,", "Give ear,"], ["ia e faafofoga mai i la'u tatalo;", "O LORD, unto my prayer;"], ["ma e liliu mai i le leo o la'u aioi.", "and attend to the voice of my supplications."]]},
  {num:7,words:[["O le aso e puapuagaina ai a'u, ou te valaau atu ai ia te oe;", "In the day of my trouble I will call upon thee:"], ["auā e te tali mai ia te au.", "for thou wilt answer me."]]},
  {num:8,words:[["Le Alii e,", "Among the gods there is none like unto thee,"], ["e leai lava so le vao atua e tusa ma oe;", "O Lord;"], ["e leai foi se galuega e tusa ma au galuega.", "neither are there any works like unto thy works."]]},
  {num:9,words:[["O nuu uma na e faia latou te o mai,", "All nations whom thou hast made shall come and worship before thee,"], ["ma latou ifo atu i ou luma, le Alii e;", "O Lord;"], ["ma latou faaneenee atu i lou suafa.", "and shall glorify thy name."]]},
  {num:10,words:[["Auā e sili oe,", "For thou art great,"], ["o loo e fai foi vavega; o le Atua oe,", "and doest wondrous things:"], ["na o oe lava.", "thou art God alone."]]},
  {num:11,words:[["Ieova e,", "Teach me thy way,"], ["ia e faasino mai ia te au lou ala,", "O LORD;"], ["ou te savali i le mea moni mai ia te oe;", "I will walk in thy truth:"], ["ia e faia ina ia tasi lo'u loto e mata'u i lou suafa.", "unite my heart to fear thy name."]]},
  {num:12,words:[["Le Alii e,", "I will praise thee,"], ["lo'u Atua,", "O Lord my God,"], ["ou te vivii atu ia te oe i lo'u loto atoa;", "with all my heart:"], ["ou te faaneenee atu lava i lou suafa e faavavau.", "and I will glorify thy name for evermore."]]},
  {num:13,words:[["Auā e tele lava lou alofa ia te au;", "For great is thy mercy toward me:"], ["na e laveai mai lo'u agaga ai seoli e maulalo lava.", "and thou hast delivered my soul from the lowest hell."]]},
  {num:14,words:[["Le Atua e,", "O God,"], ["ua laga mai ia te au o e faamaualuga,", "the proud are risen against me,"], ["o le faapotopotoga foi o e saua ua latou sailia mai a'u e fasioti;", "and the assemblies of violent men have sought after my soul;"], ["latou te lei tuuina atu oe i o latou luma.", "and have not set thee before them."]]},
  {num:15,words:[["A o oe le Alii e,", "But thou, O Lord,"], ["o le Atua oe lē alofa mutimuti vale ma lē alofa fua,", "art a God full of compassion,"], ["o lē telegese lona toasa,", "and gracious,"], ["a e tele le alofa ma le faamaoni.", "longsuffering, and plenteous in mercy and truth."]]},
  {num:16,words:[["Ia e liuliu alo mai ia te au,", "O turn unto me,"], ["ma ia e alofa mai ia te au;", "and have mercy upon me;"], ["ia e foai mai lou malosi i lau auauna,", "give thy strength unto thy servant,"], ["ma ia e faaola mai i le tama tane a lau auauna fafine.", "and save the son of thine handmaid."]]},
  {num:17,words:[["Ia e faia se faailoga mo a'u ou te lelei ai;", "Shew me a token for good;"], ["ina ia iloa ai e o 'ino'ino mai ia te au,", "that they which hate me may see it,"], ["latou te mamā ai;", "and be ashamed:"], ["auā o oe,", "because thou,"], ["Ieova e,", "LORD,"], ["ua e fesoasoani mai ia te au,", "hast holpen me,"], ["ma e faamafanafana mai ia te au.", "and comforted me."]]},
];
renderVerseSet(psa_ch_86_Verses, 'psa-ch86-verses');

var psa_ch_87_Verses = [
  {num:1,words:[["O Lona faavae o i le atu mauga paia lea.", "His foundation is in the holy mountains."]]},
  {num:2,words:[["E sili le fiafia o Ieova i faitotoa o Siona, i lona fiafia i mea uma e nonofo ai Iakopo.", "The LORD loveth the gates of Zion more than all the dwellings of Jacob."]]},
  {num:3,words:[["O mea e viia ua ta'ua lava ia te oe,", "Glorious things are spoken of thee,"], ["le aai a le Atua. Selā.", "O city of God. Selah."]]},
  {num:4,words:[["Ou te ta'ua Raava ma Papelonia faatasi ma e ua iloa a'u;", "I will make mention of Rahab and Babylon to them that know me:"], ["faauta,", "behold Philistia,"], ["o Filisitia, ma Turo,", "and Tyre,"], ["atoa ma Aitiope;", "with Ethiopia;"], ["na fanau ai lenei tagata .", "this man was born there."]]},
  {num:5,words:[["E faapea ane foi ia Siona,", "And of Zion it shall be said,"], ["O lea tagata ma lea tagata na fanau ai; o lē Silisili ese foi,", "This and that man was born in her:"], ["o ia lea na te faatumauina o ia.", "and the highest himself shall establish her."]]},
  {num:6,words:[["O Ieova na te faitauina pe a tusia e ia le nuu,", "The LORD shall count,"], ["e faapea ane ,", "when he writeth up the people,"], ["Na fanau ai lenei tagata . Selā.", "that this man was born there. Selah."]]},
  {num:7,words:[["O e pepese atoa ma e sisiva;", "As well the singers as the players on instruments shall be there:"], ["o ia te oe o'u punāvai uma.", "all my springs are in thee."]]},
];
renderVerseSet(psa_ch_87_Verses, 'psa-ch87-verses');

var psa_ch_88_Verses = [
  {num:1,words:[["Ieova e, le Atua o lo'u olataga,", "O LORD God of my salvation,"], ["ua ou alaga atu i ou luma i le ao ma le po;", "I have cried day and night before thee:"]]},
  {num:2,words:[["ia oo atu i ou luma la'u tatalo;", "Let my prayer come before thee:"], ["ia liliu mai ou fofoga i la'u valaau;", "incline thine ear unto my cry;"]]},
  {num:3,words:[["auā ua tumu lava lo'u agaga i mea e tiga ai;", "For my soul is full of troubles:"], ["ua toe lava ina ou oo i le tuugamau.", "and my life draweth nigh unto the grave."]]},
  {num:4,words:[["Ua ta'ufaatasiina a'u ma e ua o ifo i le lua;", "I am counted with them that go down into the pit:"], ["e tusa a'u ma le tagata e leai sona malosi;", "I am as a man that hath no strength:"]]},
  {num:5,words:[["ua sa'oloto a'u faatasi ma e ua oti,", "Free among the dead,"], ["e pei o e ua fasia,", "like the slain that lie in the grave,"], ["ua taatitia i le tuugamau, o e ua le toe manatua e oe;", "whom thou rememberest no more:"], ["o i latou foi ua faateaeseina ma lou aao.", "and they are cut off from thy hand."]]},
  {num:6,words:[["Ua e tuuina ifo a'u i le lua e maulalo lava,", "Thou hast laid me in the lowest pit,"], ["o mea pogisa,", "in darkness,"], ["o mea loloto lava.", "in the deeps."]]},
  {num:7,words:[["Ua mamafa lou toasa i luga ia te au,", "Thy wrath lieth hard upon me,"], ["o au galu uma ua e faatigaina ai a'u . Selā.", "and thou hast afflicted me with all thy waves. Selah."]]},
  {num:8,words:[["Ua e ave mamao ia te au o e na matou masani;", "Thou hast put away mine acquaintance far from me;"], ["ua e faainosia a'u e i latou;", "thou hast made me an abomination unto them:"], ["ua punitia a'u ,", "I am shut up,"], ["ou te le mafai ona ulufafo.", "and I cannot come forth."]]},
  {num:9,words:[["Ua totō o'u mata ona o le puapuaga;", "Mine eye mourneth by reason of affliction:"], ["Ieova e,", "LORD,"], ["ua ou valaau atu ia te oe i aso uma,", "I have called daily upon thee,"], ["ua ou faaloaloa atu o'u lima ia te oe.", "I have stretched out my hands unto thee."]]},
  {num:10,words:[["E te faia ea vavega i e ua oti? E tutū mai ea e ua oti e vivii atu ia te oe? Selā.", "Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah."]]},
  {num:11,words:[["E ta'ua ea lou alofa i le tuugamau? Pe ta'ua lou faamaoni i le mea e malaia ai?", "Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?"]]},
  {num:12,words:[["E iloa ea lou vavega i le pouliuli, ma lau amiotonu i le nuu e galo ai mea?", "Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?"]]},
  {num:13,words:[["A o a'u,", "But unto thee have I cried,"], ["Ieova e, na ou alaga atu ia te oe;", "O LORD;"], ["e tomua foi la'u tatalo ia te oe i le taeao.", "and in the morning shall my prayer prevent thee."]]},
  {num:14,words:[["Ieova e,", "LORD,"], ["se a le mea ua e lafoai mai ai ia te au? Se a le mea e te liliuese ai ou fofoga ia te au?", "why castest thou off my soul? why hidest thou thy face from me?"]]},
  {num:15,words:[["Ua puapuagatia lava a'u, ma ua toe ina oti talu ina ou taulealea;", "I am afflicted and ready to die from my youth up:"], ["ua mafatia lava a'u i āu mea e mata'u ai, ua ou fememeai.", "while I suffer thy terrors I am distracted."]]},
  {num:16,words:[["Ua oo mai i o'u luga lou toasa mamafa;", "Thy fierce wrath goeth over me;"], ["ua faaumatia lava a'u e āu mea e mata'u ai.", "thy terrors have cut me off."]]},
  {num:17,words:[["E pei o le vai ona latou siosio mai ai ia te au i le aso atoa;", "They came round about me daily like water;"], ["latou te puipui faatasi mai ia te au.", "they compassed me about together."]]},
  {num:18,words:[["O le uo ma le aumea ua e ave mamao ia te au,", "Lover and friend hast thou put far from me,"], ["ua i le pouliuli foi e na matou masani.", "and mine acquaintance into darkness."]]},
];
renderVerseSet(psa_ch_88_Verses, 'psa-ch88-verses');

var psa_ch_89_Verses = [
  {num:1,words:[["O le alofa mai o Ieova ou te pese ai lava e faavavau;", "I will sing of the mercies of the LORD for ever:"], ["ou te faailoa atu i lo'u gutu lou faamaoni i lea tupulaga ma lea tupulaga.", "with my mouth will I make known thy faithfulness to all generations."]]},
  {num:2,words:[["Auā na ou faapea ane,", "For I have said,"], ["E atiina ae le alofa e faavavau lava;", "Mercy shall be built up for ever:"], ["o le lagi lava e te faatumauina i ai lou faamaoni.", "thy faithfulness shalt thou establish in the very heavens."]]},
  {num:3,words:[["Ua ma osia le feagaiga ma le na ou fiilfilia,", "I have made a covenant with my chosen,"], ["na ou tauto lava ia Tavita la'u auauna.", "I have sworn unto David my servant,"]]},
  {num:4,words:[["Ou te faatumauina lau fanau e faavavau lava;", "Thy seed will I establish for ever,"], ["ou te atiina ae foi lou nofoālii i lea tupulaga ma lea tupulaga. Selā.", "and build up thy throne to all generations. Selah."]]},
  {num:5,words:[["Ieova e,", "And the heavens shall praise thy wonders,"], ["e vivii le lagi i ou vavega;", "O LORD:"], ["e viia foi lou faamaoni i le faapotopotoga o le au paia.", "thy faithfulness also in the congregation of the saints."]]},
  {num:6,words:[["Auā o ai ea i le lagi e faatusaina Ieova? O ai so le fanau a e malolosi e tusa ma Ieova?", "For who in the heaven can be compared unto the LORD? who among the sons of the mighty can be likened unto the LORD?"]]},
  {num:7,words:[["O le Atua e tatau ona matautia tele i le faapotopotoga o le au paia;", "God is greatly to be feared in the assembly of the saints,"], ["e tatau foi ona matautia o ia e i latou uma o e vagavagai ia te ia.", "and to be had in reverence of all them that are about him."]]},
  {num:8,words:[["Ieova e, le Atua o 'au,", "O LORD God of hosts,"], ["o ai sē malosi e tusa ma oe Ioa e? O lou faamaoni foi e siosio ai ia te oe.", "who is a strong LORD like unto thee? or to thy faithfulness round about thee?"]]},
  {num:9,words:[["O oe lava,", "Thou rulest the raging of the sea:"], ["e te pule i le faamaualuga o le sami; a sousou ona peau,", "when the waves thereof arise,"], ["o oe lava e laolao ai.", "thou stillest them."]]},
  {num:10,words:[["O oe lava,", "Thou hast broken Rahab in pieces,"], ["na e tu'imomomoina Raava e pei o se ua fasiotia;", "as one that is slain;"], ["o lou aao malosi ua e faataapeape ai i e na ita ia te oe.", "thou hast scattered thine enemies with thy strong arm."]]},
  {num:11,words:[["E ou le lagi,", "The heavens are thine,"], ["e ou foi ma le lalolagi;", "the earth also is thine:"], ["o oe,", "as for the world and the fulness thereof,"], ["na e faavaeina le atu laulau atoa ma mea ua tumu ai.", "thou hast founded them."]]},
  {num:12,words:[["O oe, na e faia le itu i matu ma le itu i toga;", "The north and the south thou hast created them:"], ["o Tapora ma Heremoni la te alaga fiafia lava i lou suafa.", "Tabor and Hermon shall rejoice in thy name."]]},
  {num:13,words:[["O ia te oe le aao malosi;", "Thou hast a mighty arm:"], ["e malosi lava lou aao,", "strong is thy hand,"], ["o loo maualuga lou aao taumatau.", "and high is thy right hand."]]},
  {num:14,words:[["O le amiotonu ma le faamasinoga o loo tumau ai lou nofoālii;", "Justice and judgment are the habitation of thy throne:"], ["o le alofa ma le faamaoni la te muamua atu i ou luma.", "mercy and truth shall go before thy face."]]},
  {num:15,words:[["Amuia le nuu ua latou lagona le leo fiafia;", "Blessed is the people that know the joyful sound:"], ["Ieova e,", "they shall walk, O LORD,"], ["latou te savavali i le malamalama o ou fofoga.", "in the light of thy countenance."]]},
  {num:16,words:[["Latou te fiafia lava i lou suafa i aso uma lava;", "In thy name shall they rejoice all the day:"], ["o lau amiotonu foi e maualuluga ai i latou.", "and in thy righteousness shall they be exalted."]]},
  {num:17,words:[["Auā o oe lo latou matagofie e i ai le malosi;", "For thou art the glory of their strength:"], ["o lou finagalo alofa foi ua faamaualugaina ai lo matou nifo.", "and in thy favour our horn shall be exalted."]]},
  {num:18,words:[["Auā o lo matou talita o Ieova lava lea; o le Paia foi o Isaraelu,", "For the LORD is our defence;"], ["o lo matou tupu lava ia.", "and the Holy One of Israel is our king."]]},
  {num:19,words:[["Ona e fetalai ane ai lea i le faaaliga i lou tagata amio Atua,", "Then thou spakest in vision to thy holy one,"], ["ma e faapea ane,", "and saidst,"], ["Ua a'u tuuina atu le fesoasoani i le ua malosi;", "I have laid help upon one that is mighty;"], ["ua ou faaeaina le ua filifilia mai le nuu.", "I have exalted one chosen out of the people."]]},
  {num:20,words:[["Ua ou maua Tavita la'u auauna;", "I have found David my servant;"], ["ua ou faauuina o ia i la'u uu paia;", "with my holy oil have I anointed him:"]]},
  {num:21,words:[["o le e tumau ia te ia lo'u lima;", "With whom my hand shall be established:"], ["e faamalosia foi o ia e lo'u lima.", "mine arm also shall strengthen him."]]},
  {num:22,words:[["E le faasaua ia te ia le ua ita ia te ia;", "The enemy shall not exact upon him;"], ["e le faatigaina foi o ia e le tagata amio leaga.", "nor the son of wickedness afflict him."]]},
  {num:23,words:[["Ou te tu'ipalaina i ona luma e ua ita ia te ia;", "And I will beat down his foes before his face,"], ["ou te taia foi e ua 'ino'ino ia te ia.", "and plague them that hate him."]]},
  {num:24,words:[["A e ia te ia lava lo'u faamaoni ma lo'u alofa;", "But my faithfulness and my mercy shall be with him:"], ["o lo'u igoa foi e faamaualugaina ai lona nifo.", "and in my name shall his horn be exalted."]]},
  {num:25,words:[["Ou te faaoo atu foi lona lima i le sami ma lona lima taumatau i vaitafe.", "I will set his hand also in the sea, and his right hand in the rivers."]]},
  {num:26,words:[["E valaau mai o ia ia te au,", "He shall cry unto me,"], ["O lo'u Tamā lava oe,", "Thou art my father,"], ["o lo'u Atua,", "my God,"], ["ma le papa o lo'u olataga.", "and the rock of my salvation."]]},
  {num:27,words:[["O a'u foi, ou te faia o ia ma ulumatua,", "Also I will make him my firstborn,"], ["e silisili o ia i tupu o le lalolagi.", "higher than the kings of the earth."]]},
  {num:28,words:[["E tumau pea lo'u alofa ia te ia e faavavau,", "My mercy will I keep for him for evermore,"], ["e faamaonia foi la'u feagaiga ia te ia.", "and my covenant shall stand fast with him."]]},
  {num:29,words:[["Ou te tofia lana fanau ia faavavau,", "His seed also will I make to endure for ever,"], ["o lona nofoālii foi e pei o aso o le lagi.", "and his throne as the days of heaven."]]},
  {num:30,words:[["Afai e lafoaiina la'u tulafono e ana fanau,", "If his children forsake my law,"], ["ma latou le savavali i a'u faamasinoga;", "and walk not in my judgments;"]]},
  {num:31,words:[["afai latou te solia a'u tulafono,", "If they break my statutes,"], ["ma latou le tausia a'u poloaiga.", "and keep not my commandments;"]]},
  {num:32,words:[["Ona ou asiasia ai lea o latou solitulafono i le sasa,", "Then will I visit their transgression with the rod,"], ["ou te asiasia foi a latou amio leaga i ta.", "and their iniquity with stripes."]]},
  {num:33,words:[["A o lo'u alofa e le mavae atu lea ia te ia,", "Nevertheless my lovingkindness will I not utterly take from him,"], ["ou te le pepelo foi i lo'u faamaoni.", "nor suffer my faithfulness to fail."]]},
  {num:34,words:[["Ou te le tuumavaega la'u feagaiga,", "My covenant will I not break,"], ["ou te le liliu lava le upu ua paū atu i o'u laugutu.", "nor alter the thing that is gone out of my lips."]]},
  {num:35,words:[["Na ou tauto faatasi i lo'u paia, ou te le pepelo lava ia Tavita.", "Once have I sworn by my holiness that I will not lie unto David."]]},
  {num:36,words:[["E faavavau lava lana fanau,", "His seed shall endure for ever,"], ["o lona nofoālii foi e pei o le la lea i o'u luma.", "and his throne as the sun before me."]]},
  {num:37,words:[["Pei o le masina e faatumauina ia e faavavau,", "It shall be established for ever as the moon,"], ["ma le molimau i le lagi e faamaoni lava. Selā.", "and as a faithful witness in heaven. Selah."]]},
  {num:38,words:[["A o oe, ua e teteeina mai ma e inosia mai,", "But thou hast cast off and abhorred,"], ["ua e matuā toasa mai i le na e faauuina.", "thou hast been wroth with thine anointed."]]},
  {num:39,words:[["Ua e lafoai le feagaiga a lau auauna;", "Thou hast made void the covenant of thy servant:"], ["ua e solia lona palealii i le eleele.", "thou hast profaned his crown by casting it to the ground."]]},
  {num:40,words:[["Ua e faasoloina ona pa uma lava;", "Thou hast broken down all his hedges;"], ["ua e faia foi ona 'olo ma faupuegamaa.", "thou hast brought his strong holds to ruin."]]},
  {num:41,words:[["Ua vete foi ana mea e i latou uma ua ui ane i le ala;", "All that pass by the way spoil him:"], ["ua faalumaina o ia e i latou ua tuaoi ma ia.", "he is a reproach to his neighbours."]]},
  {num:42,words:[["Ua e faamaualugaina le lima taumatau o e ita ia te ia;", "Thou hast set up the right hand of his adversaries;"], ["ua e faa'oli'olia i latou uma o e fai o ia mo latou fili.", "thou hast made all his enemies to rejoice."]]},
  {num:43,words:[["Ua e liliuesea foi le mata o lana pelu,", "Thou hast also turned the edge of his sword,"], ["ma ua e le faatumauina o ia i le taua.", "and hast not made him to stand in the battle."]]},
  {num:44,words:[["Ua e faaiuina lona mamalu,", "Thou hast made his glory to cease,"], ["ua e lafo i lalo i le eleele lona nofoālii.", "and cast his throne down to the ground."]]},
  {num:45,words:[["Ua e faapuupuuina aso o lona taulealea;", "The days of his youth hast thou shortened:"], ["ua e faaofu ia te ia i le mā. Selā.", "thou hast covered him with shame. Selah."]]},
  {num:46,words:[["Ieova e,", "How long,"], ["e te lafi oe seia afea? E faavavau ea? E mu lou toasa e pei o le afi seia afea?", "LORD? wilt thou hide thyself for ever? shall thy wrath burn like fire?"]]},
  {num:47,words:[["Ia e manatua le puupuu o lo'u olaga;", "Remember how short my time is:"], ["se a le mea ua e faia ai fua le fanau uma a tagata.", "wherefore hast thou made all men in vain?"]]},
  {num:48,words:[["O ai se tagata ola na te le iloa le oti? Na te laveaiina ea lona agaga ai le pule a le tuugamau? Selā.", "What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah."]]},
  {num:49,words:[["Le Alii e,", "Lord,"], ["o i fea lou alofa anamua,", "where are thy former lovingkindnesses,"], ["na e tauto ai i lou faamaoni ia Tavita?", "which thou swarest unto David in thy truth?"]]},
  {num:50,words:[["Le Alii e,", "Remember,"], ["ia e manatua le faalumaina o au auauna;", "Lord, the reproach of thy servants;"], ["ua ou tauave i lo'u fatafata upu uma a nuu e tele;", "how I do bear in my bosom the reproach of all the mighty people;"]]},
  {num:51,words:[["ua faaluma mai ai o e ua ita ia te oe Ieova e;", "Wherewith thine enemies have reproached, O LORD;"], ["ua latou faalumaina ai tulagāvae o le na e faauuina.", "wherewith they have reproached the footsteps of thine anointed."]]},
  {num:52,words:[["Ia faafetaia Ieova e faavavau lava.", "Blessed be the LORD for evermore."], ["Amene ma Amene.", "Amen, and Amen."]]},
];
renderVerseSet(psa_ch_89_Verses, 'psa-ch89-verses');

var psa_ch_90_Verses = [
  {num:1,words:[["Le Alii e,", "Lord,"], ["ua fai oe ma mea matou te nonofo ai i lea tupulaga ma lea tupulaga.", "thou hast been our dwelling place in all generations."]]},
  {num:2,words:[["A o lei fanaua mai mauga,", "Before the mountains were brought forth,"], ["e lei faia foi e oe le lalolagi ma le atu laulau,", "or ever thou hadst formed the earth and the world, even from everlasting to everlasting,"], ["o le Atua oe mai le vavau e oo i le faavavau.", "thou art God."]]},
  {num:3,words:[["Ua e liua tagata ia momomo;", "Thou turnest man to destruction;"], ["ma e fetalai mai,", "and sayest, Return,"], ["Outou na le fanau a tagata ia liu outou;", "ye children of men."]]},
  {num:4,words:[["auā e tusa i ou luma le afe o tausaga ma le aso ananafi ina o mavae atu,", "For a thousand years in thy sight are but as yesterday when it is past,"], ["ma se leoleoga i le po.", "and as a watch in the night."]]},
  {num:5,words:[["Ua e faatafea i latou i le lolo;", "Thou carriest them away as with a flood;"], ["ua se moe i latou;", "they are as a sleep:"], ["e pei o le mutia i latou ona olaola i le taeao.", "in the morning they are like grass which groweth up."]]},
  {num:6,words:[["O le taeao e fuga mai ai,", "In the morning it flourisheth,"], ["ma olaola mai ai;", "and groweth up;"], ["a oo i le afiafi, ona seleeseina ai lea,", "in the evening it is cut down,"], ["ua magumagu ai.", "and withereth."]]},
  {num:7,words:[["Auā ua faaumatia i matou i lou toasa,", "For we are consumed by thine anger,"], ["o lou toatamai foi ua atuatuvale ai i matou.", "and by thy wrath are we troubled."]]},
  {num:8,words:[["Ua e tuuina a matou amio leaga i ou luma,", "Thou hast set our iniquities before thee,"], ["ua tuuina foi a matou agasala lilo i le malamalama o ou fofoga.", "our secret sins in the light of thy countenance."]]},
  {num:9,words:[["Auā ua mavae atu o matou aso uma a o e toasa mai;", "For all our days are passed away in thy wrath:"], ["ua uma atu o matou tausaga e pei o se manatu.", "we spend our years as a tale that is told."]]},
  {num:10,words:[["O tausaga o matou olaga e fitugafulu ia tausaga;", "The days of our years are threescore years and ten;"], ["a e afai e valugafulu tausaga ona o le malosi,", "and if by reason of strength they be fourscore years,"], ["a o lo latou malosi o i ai le tiga ma le puapuaga;", "yet is their strength labour and sorrow;"], ["auā e vave ona mavae atu ia,", "for it is soon cut off,"], ["ma matou lele ese.", "and we fly away."]]},
  {num:11,words:[["O ai se na te iloa le malosi o lou toasa? Auā e pei ona matautia oe e faapea lou toatamai.", "Who knoweth the power of thine anger? even according to thy fear, so is thy wrath."]]},
  {num:12,words:[["Ia faapea ona e a'oa'o mai ia i matou e faitauina o matou aso,", "So teach us to number our days,"], ["ina ia maua ai le poto i o matou loto.", "that we may apply our hearts unto wisdom."]]},
  {num:13,words:[["Ieova e,", "Return,"], ["ia e toe liliu mai,", "O LORD,"], ["seia afea? Ia e salamo ona o au auauna.", "how long? and let it repent thee concerning thy servants."]]},
  {num:14,words:[["Ia e faamalilie mai ia te i matou i le taeao i lou alofa; ina ia matou alalaga fiafia,", "O satisfy us early with thy mercy;"], ["ma ia olioli i o matou aso uma.", "that we may rejoice and be glad all our days."]]},
  {num:15,words:[["Ia e faafiafia mai ia i matou ia tusa ma ona po na e faatigaina ai i matou,", "Make us glad according to the days wherein thou hast afflicted us,"], ["o tausaga na matou iloa ai le leaga.", "and the years wherein we have seen evil."]]},
  {num:16,words:[["Ia faaalia mai au galuega i au auauna,", "Let thy work appear unto thy servants,"], ["ia faaalia foi lou matagofie i a latou fanau.", "and thy glory unto their children."]]},
  {num:17,words:[["Ia oo mai foi ia te i matou le matagofie mai ia Ieova lo matou Atua;", "And let the beauty of the LORD our God be upon us:"], ["ia e faatumauina ia te i matou le galuega a o matou lima;", "and establish thou the work of our hands upon us; yea,"], ["o le galuega lava a o matou lima ia e faatumauina.", "the work of our hands establish thou it."]]},
];
renderVerseSet(psa_ch_90_Verses, 'psa-ch90-verses');

var psa_ch_91_Verses = [
  {num:1,words:[["O le nofo i le mea lilo o i ai lē Silisili ese, e mau o ia i le paolo o Le e ona le malosi uma lava.", "He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty."]]},
  {num:2,words:[["Ou te faapea atu ia Ieova,", "I will say of the LORD,"], ["O lo'u malu o ia ma lo'u 'olo;", "He is my refuge and my fortress: my God;"], ["o lo'u Atua ou te faatuatua ia te ia.", "in him will I trust."]]},
  {num:3,words:[["Auā o ia na te laveaiina oe i le mailei a lē fai manu,", "Surely he shall deliver thee from the snare of the fowler,"], ["ma le faamai e oti ai.", "and from the noisome pestilence."]]},
  {num:4,words:[["E ufiufi ifo o ia ia te oe i ona apaau,", "He shall cover thee with his feathers,"], ["e te sulufai foi i lalo o ona apaau;", "and under his wings shalt thou trust:"], ["e faia lona faamaoni māu talipupuni ma mea e puipuiina ai oe .", "his truth shall be thy shield and buckler."]]},
  {num:5,words:[["E te le mata'u i le mea matautia i le po,", "Thou shalt not be afraid for the terror by night;"], ["ma le u fanafana e lele i le ao,", "nor for the arrow that flieth by day;"]]},
  {num:6,words:[["o le faamai e fealuai i le pogisa,", "Nor for the pestilence that walketh in darkness;"], ["ma le mala e fano ai i le aoatea.", "nor for the destruction that wasteth at noonday."]]},
  {num:7,words:[["E pauu se toaafe i ou tafatafa,", "A thousand shall fall at thy side,"], ["ma le mano i lou itu taumatau;", "and ten thousand at thy right hand;"], ["a e le tāitāi ane ia te oe.", "but it shall not come nigh thee."]]},
  {num:8,words:[["Na ona vaai i ai ou mata, e te iloa atu foi le taui o e amio leaga.", "Only with thine eyes shalt thou behold and see the reward of the wicked."]]},
  {num:9,words:[["Auā o oe,", "Because thou hast made the LORD,"], ["Ieova e,", "which is my refuge,"], ["o lo'u malu oe,", "even the most High,"], ["na e faia lē Silisili ese ma mea e te nofo ai;", "thy habitation;"]]},
  {num:10,words:[["e le oo ia te oe se mea leaga,", "There shall no evil befall thee,"], ["e le tāitāi ane foi se mala i lou fale ie.", "neither shall any plague come nigh thy dwelling."]]},
  {num:11,words:[["Auā e poloai atu ia i ana agelu ia te oe,", "For he shall give his angels charge over thee,"], ["e tausi ia te oe i ou ala uma.", "to keep thee in all thy ways."]]},
  {num:12,words:[["Latou te ave ia te oe i o latou lima,", "They shall bear thee up in their hands,"], ["ne'i tū'ia lou vae i se maa.", "lest thou dash thy foot against a stone."]]},
  {num:13,words:[["E te solia le leona ma le asipi;", "Thou shalt tread upon the lion and adder:"], ["e te solia lava le leona taanoa ma le tanimo.", "the young lion and the dragon shalt thou trample under feet."]]},
  {num:14,words:[["Ona ua naunau mai o ia ia te au,", "Because he hath set his love upon me,"], ["o le mea lea ou te faaolaina ai o ia;", "therefore will I deliver him: I will set him on high,"], ["ou te faamamalu ia te ia ona ua iloa e ia lo'u igoa.", "because he hath known my name."]]},
  {num:15,words:[["E valaau mai o ia ia te au,", "He shall call upon me,"], ["ona ou tali atu ai lea ia te ia;", "and I will answer him:"], ["o a'u, ou te ia te ia i le puapuaga;", "I will be with him in trouble;"], ["ou te laveaiina o ia,", "I will deliver him,"], ["ma ou faatupuina lona mamalu.", "and honour him."]]},
  {num:16,words:[["O le olaga faafualoa e mălie ai o ia ia te au;", "With long life will I satisfy him,"], ["ou te faaali atu foi ia te ia la'u faaolataga.", "and shew him my salvation."]]},
];
renderVerseSet(psa_ch_91_Verses, 'psa-ch91-verses');

var psa_ch_92_Verses = [
  {num:1,words:[["E lelei ona vivii atu ia Ieova,", "It is a good thing to give thanks unto the LORD, and to sing praises unto thy name,"], ["ma ia fai pesega i lou suafa lē Silisili ese e;", "O most High:"]]},
  {num:2,words:[["ia ta'u atu i le taeao lou alofa ia ta'u atu foi i le po lou faamaoni,", "To shew forth thy lovingkindness in the morning, and thy faithfulness every night,"]]},
  {num:3,words:[["i le laaupese e sefulu ona manoa,", "Upon an instrument of ten strings,"], ["ma le napeli,", "and upon the psaltery;"], ["ma le leo o le kitara.", "upon the harp with a solemn sound."]]},
  {num:4,words:[["Auā ua e faafiafia mai ia te au i lau galuega,", "For thou,"], ["Ieova e;", "LORD, hast made me glad through thy work:"], ["ou te alaga fiafia ona o mea ua faia e ou aao.", "I will triumph in the works of thy hands."]]},
  {num:5,words:[["Ieova e, e matuā sili lava mea ua e faia;", "O LORD,"], ["e loloto lava ou manatu.", "how great are thy works! and thy thoughts are very deep."]]},
  {num:6,words:[["O le tagata valea na te le iloa;", "A brutish man knoweth not;"], ["ma le vale na te le lagona lenei mea.", "neither doth a fool understand this."]]},
  {num:7,words:[["A tupu olaola o e amio leaga e pei o le vao iti,", "When the wicked spring as the grass,"], ["a fuga mai foi i latou uma o e fai mea leaga,", "and when all the workers of iniquity do flourish;"], ["e faapea i latou ina ia faaumatia e oo i le faavavau lava.", "it is that they shall be destroyed for ever:"]]},
  {num:8,words:[["A o oe Ieova e,", "But thou, LORD,"], ["o loo silisili oe e faavavau.", "art most high for evermore."]]},
  {num:9,words:[["Auā Ieova e,", "For, lo,"], ["faauta i e ita ia te oe,", "thine enemies,"], ["auā faauta i e ita ia te oe,", "O LORD, for,"], ["e fano i latou;", "lo,"], ["e faataapeapeina i latou uma o e fai amio leaga.", "thine enemies shall perish; all the workers of iniquity shall be scattered."]]},
  {num:10,words:[["A e faamaualugaina e oe lo'u nifo e pei o le rema;", "But my horn shalt thou exalt like the horn of an unicorn:"], ["e faauuina a'u i le suāuu fou.", "I shall be anointed with fresh oil."]]},
  {num:11,words:[["E iloa atu foi o'u mata i e lamalama mai ia te au,", "Mine eye also shall see my desire on mine enemies,"], ["e faalogo foi o'u taliga i e amio leaga e ua laga mai ia te au.", "and mine ears shall hear my desire of the wicked that rise up against me."]]},
  {num:12,words:[["E tupu olaola le tagata amiotonu e pei o le pama;", "The righteous shall flourish like the palm tree:"], ["e tupu tele e pei o le arasi i Lepanona.", "he shall grow like a cedar in Lebanon."]]},
  {num:13,words:[["O e ua totōina i le fale o Ieova, e tupu olaola i latou i lotoā o lo tatou Atua.", "Those that be planted in the house of the LORD shall flourish in the courts of our God."]]},
  {num:14,words:[["A oo ina ulusinā, latou te fua mai pea lava;", "They shall still bring forth fruit in old age;"], ["e malolosi ma lauolaola i latou;", "they shall be fat and flourishing;"]]},
  {num:15,words:[["ina ia iloa ai o Ieova e tonu ia;", "To shew that the LORD is upright:"], ["o lo'u papa ia,", "he is my rock,"], ["e le o ia te ia foi se amio leaga.", "and there is no unrighteousness in him."]]},
];
renderVerseSet(psa_ch_92_Verses, 'psa-ch92-verses');

var psa_ch_93_Verses = [
  {num:1,words:[["O loo fai Ieova ma tupu,", "The LORD reigneth,"], ["e ofu o ia i le mamalu;", "he is clothed with majesty;"], ["e ofu Ieova i le malosi,", "the LORD is clothed with strength,"], ["ua fusia ai o ia e ia;", "wherewith he hath girded himself:"], ["e faatumauina foi le lalolagi,", "the world also is stablished,"], ["e le faagaeetia.", "that it cannot be moved."]]},
  {num:2,words:[["O tumau lou nofoālii talu anamuā;", "Thy throne is established of old:"], ["talu mai le vavau lava oe.", "thou art from everlasting."]]},
  {num:3,words:[["Ieova e,", "The floods have lifted up,"], ["ua taalili mai vaitafe,", "O LORD,"], ["o vaitafe ua taalili ae o latou leo;", "the floods have lifted up their voice;"], ["o vaitafe ua taalili ae o latou gogolo.", "the floods lift up their waves."]]},
  {num:4,words:[["O Ieova o i le mea maualuga,", "The LORD on high is mightier than the noise of many waters,"], ["e sili ona malosi o ia i le taalili o vai e tele,", "yea,"], ["o peau malolosi o le sami.", "than the mighty waves of the sea."]]},
  {num:5,words:[["O āu mau e matuā faamaoni ia;", "Thy testimonies are very sure:"], ["e onomea lava ona paia o lou fale,", "holiness becometh thine house,"], ["Ieova e,", "O LORD,"], ["e faavavau lava.", "for ever."]]},
];
renderVerseSet(psa_ch_93_Verses, 'psa-ch93-verses');

var psa_ch_94_Verses = [
  {num:1,words:[["Ieova e,", "O LORD God,"], ["le Atua o lē taui ma sui,", "to whom vengeance belongeth;"], ["le Atua e o lē taui ma sui,", "O God, to whom vengeance belongeth,"], ["ia e faaali mai lou pupula.", "shew thyself."]]},
  {num:2,words:[["Ia e tulai mai,", "Lift up thyself,"], ["o oe le faamasino o le lalolagi;", "thou judge of the earth:"], ["ia e tuu atu le taui i e ua faasausili.", "render a reward to the proud."]]},
  {num:3,words:[["Ieova e,", "LORD,"], ["e mitamita seia afea o e amio leaga;", "how long shall the wicked,"], ["e mitamita o e amio leaga seia afea?", "how long shall the wicked triumph?"]]},
  {num:4,words:[["Ua latou soona tautala i upu faamaualuga, ua mitamita vale o i latou uma o e fai amio leaga.", "How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?"]]},
  {num:5,words:[["Ieova e,", "They break in pieces thy people,"], ["ua latou tu'imomomoina lou nuu,", "O LORD,"], ["ua latou faatigaina foi lou tofi.", "and afflict thine heritage."]]},
  {num:6,words:[["O le fafine ua oti lana tane atoa ma le tagata ese, ua latou fasiotia,", "They slay the widow and the stranger,"], ["ua latou fasiotia foi ma ē mātuaoti;", "and murder the fatherless."]]},
  {num:7,words:[["ma ua faapea a latou,", "Yet they say,"], ["E le silasila mai e Ioa,", "The LORD shall not see,"], ["e le manatua foi e le Atua o Iakopo.", "neither shall the God of Jacob regard it."]]},
  {num:8,words:[["Ia outou iloa,", "Understand,"], ["outou e valelea i le nuu;", "ye brutish among the people:"], ["o outou vale foi,", "and ye fools,"], ["tou te popoto afea?", "when will ye be wise?"]]},
  {num:9,words:[["O le na faia le taliga,", "He that planted the ear,"], ["e le lagona ea e ia? O le na faia le mata,", "shall he not hear? he that formed the eye,"], ["e le silasila atu ea o ia?", "shall he not see?"]]},
  {num:10,words:[["O lē sasa i nuu ese,", "He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge,"], ["e le aoai atu ea e ia? O lē a'oa'o i tagata ia popoto.", "shall not he know?"]]},
  {num:11,words:[["O loo silafia e Ieova o mafaufau o tagata,", "The LORD knoweth the thoughts of man,"], ["e faatauvaa lava ia.", "that they are vanity."]]},
  {num:12,words:[["Ioa e,", "Blessed is the man whom thou chastenest,"], ["amuia le tagata ua e aoaiina;", "O LORD,"], ["ma e a'oa'oina o ia i lau tulafono.", "and teachest him out of thy law;"]]},
  {num:13,words:[["Ina ia e tuuina atu se mapu ia te ia i ona po ua puapuaga ai,", "That thou mayest give him rest from the days of adversity,"], ["seia elia le lua mo le ua amio leaga.", "until the pit be digged for the wicked."]]},
  {num:14,words:[["Auā e le tuuna e Ieova lona nuu,", "For the LORD will not cast off his people,"], ["na te le tuulafoaiina foi lona tofi.", "neither will he forsake his inheritance."]]},
  {num:15,words:[["Auā e toe foi atu le faamasinoga i le amiotonu;", "But judgment shall return unto righteousness:"], ["e mulimuli atu foi i ai o i latou uma ua loto faamaoni.", "and all the upright in heart shall follow it."]]},
  {num:16,words:[["O ai se tulai mai mo a'u e tetee i e ua amio leaga? O ai se tu atu mo a'u e tetee i e ua fai mea leaga?", "Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?"]]},
  {num:17,words:[["Ana le fesoasoani mai ia te au o Ieova,", "Unless the LORD had been my help,"], ["po ua toe itiiti ona nofo lea o lo'u agaga i le mea taaligoligoa.", "my soul had almost dwelt in silence."]]},
  {num:18,words:[["Na ou fai ane,", "When I said,"], ["O loo mapeva lo'u vae;", "My foot slippeth;"], ["ona taofi ae lea o a'u e lou alofa,", "thy mercy, O LORD,"], ["Ieova e.", "held me up."]]},
  {num:19,words:[["O le tele o manatunatu i lo'u loto ua fiafia ai lo'u agaga ona o faamafanafanaga mai ia te oe.", "In the multitude of my thoughts within me thy comforts delight my soul."]]},
  {num:20,words:[["E faatasi ea ma oe le nofoālii o i ai amio leaga,", "Shall the throne of iniquity have fellowship with thee,"], ["o le ua fai ma tulafono le faatiga?", "which frameth mischief by a law?"]]},
  {num:21,words:[["Ua latou feosofi mai i le agaga o lē amiotonu;", "They gather themselves together against the soul of the righteous,"], ["ua latou faasalaina le tagata e leai sana agasala.", "and condemn the innocent blood."]]},
  {num:22,words:[["A e faia Ieova mo'u 'olo maualuga;", "But the LORD is my defence;"], ["o lo'u Atua foi o le papa lea ou te malu ai.", "and my God is the rock of my refuge."]]},
  {num:23,words:[["E taui atu foi e ia ia te i latou a latou agasala,", "And he shall bring upon them their own iniquity,"], ["na te faaumatia foi i latou i a latou amio leaga;", "and shall cut them off in their own wickedness; yea,"], ["o Ieova lo matou Atua na te faaumatia i latou.", "the LORD our God shall cut them off."]]},
];
renderVerseSet(psa_ch_94_Verses, 'psa-ch94-verses');

var psa_ch_95_Verses = [
  {num:1,words:[["O mai ia,", "O come,"], ["ia tatou alalaga fiafia ia Ieova;", "let us sing unto the LORD:"], ["ia tatou alalaga i le papa o lo tatou olataga.", "let us make a joyful noise to the rock of our salvation."]]},
  {num:2,words:[["Ia tatou o atu i ona luma ma le viiga;", "Let us come before his presence with thanksgiving,"], ["ia tatou alalaga ia te ia i pese.", "and make a joyful noise unto him with psalms."]]},
  {num:3,words:[["Auā o Ieova o le Atua sili lea,", "For the LORD is a great God,"], ["o le Tupu tele lava o ia e sili i atua uma lava.", "and a great King above all gods."]]},
  {num:4,words:[["O loo i lona aao o mea loloto o i le lalolagi;", "In his hand are the deep places of the earth:"], ["e ona foi mauga maualuluga.", "the strength of the hills is his also."]]},
  {num:5,words:[["E ona le sami,", "The sea is his,"], ["na faia lava e ia;", "and he made it:"], ["na faia foi le laueleele i ona aao.", "and his hands formed the dry land."]]},
  {num:6,words:[["O mai ia,", "O come,"], ["ia tatou ifo, ma ia tatou punonou;", "let us worship and bow down:"], ["ia tatou tootuli i luma o Ieova o le na faia i tatou.", "let us kneel before the LORD our maker."]]},
  {num:7,words:[["Auā o lo tatou Atua lava ia;", "For he is our God;"], ["o i tatou foi o le nuu ua fagaina e ia,", "and we are the people of his pasture,"], ["ma le lafu mamoe o i lona aao. O le aso nei afai tou te faalogo ai i lona siufofoga,", "and the sheep of his hand. To day if ye will hear his voice,"]]},
  {num:8,words:[["aua ne'i faamaaa o outou loto e pei ona faia i Meripa,", "Harden not your heart, as in the provocation,"], ["e pei ona faia i le aso na i Mase i le vao;", "and as in the day of temptation in the wilderness:"]]},
  {num:9,words:[["na faaosooso mai ai ia te au o outou tamā,", "When your fathers tempted me,"], ["na latou tofotofoina a'u,", "proved me,"], ["a o latou iloa atu la'u galuega.", "and saw my work."]]},
  {num:10,words:[["E fagafulu tausaga na ou 'ino'ino ai i lea tupulaga,", "Forty years long was I grieved with this generation,"], ["ma a'u fai ane,", "and said,"], ["O le nuu lenei e sese i o latou lava loto,", "It is a people that do err in their heart,"], ["e lei iloa foi e i latou o'u ala;", "and they have not known my ways:"]]},
  {num:11,words:[["na ou tauto ai i lo'u ita, Latou te le sao atu lava i lo'u malologa.", "Unto whom I sware in my wrath that they should not enter into my rest."]]},
];
renderVerseSet(psa_ch_95_Verses, 'psa-ch95-verses');

var psa_ch_96_Verses = [
  {num:1,words:[["Ia outou pepese atu ia Ieova i le pese fou;", "O sing unto the LORD a new song:"], ["le lalolagi uma e,", "sing unto the LORD,"], ["ia outou pepese atu ia Ieova.", "all the earth."]]},
  {num:2,words:[["Ia outou pepese atu ia Ieova,", "Sing unto the LORD,"], ["ia outou faafetaia lona suafa;", "bless his name;"], ["ia outou tala'i atu lana faaolataga i lea aso ma lea aso.", "shew forth his salvation from day to day."]]},
  {num:3,words:[["Ia outou ta'uta'u atu lona mamalu i nuu ese,", "Declare his glory among the heathen,"], ["ma ona vavega i nuu uma lava.", "his wonders among all people."]]},
  {num:4,words:[["Auā e silisili Ieova,", "For the LORD is great,"], ["e tusa foi ona matuā viia o ia;", "and greatly to be praised:"], ["e sili ona matautia o ia i atua uma.", "he is to be feared above all gods."]]},
  {num:5,words:[["Auā o atua uma o nuu o tupua lava ia; ao Ieova,", "For all the gods of the nations are idols:"], ["na ia faia le lagi.", "but the LORD made the heavens."]]},
  {num:6,words:[["O loo i ona luma le viiga ma le matagofie;", "Honour and majesty are before him:"], ["o loo i lona malumalu le malosi ma le mamalu.", "strength and beauty are in his sanctuary."]]},
  {num:7,words:[["Outou o itu aiga o le nuu,", "Give unto the LORD,"], ["ia outou avatua ia Ieova,", "O ye kindreds of the people,"], ["ia outou avatua ia Ieova le viiga ma le malosi.", "give unto the LORD glory and strength."]]},
  {num:8,words:[["Ia outou avatua ia Ieova le viiga o lona suafa;", "Give unto the LORD the glory due unto his name:"], ["ia outou avatu taulaga,", "bring an offering,"], ["ma outou o atu i ona lotoā.", "and come into his courts."]]},
  {num:9,words:[["Ia outou ifo atu ia Ieova i le malumalu e matagofie;", "O worship the LORD in the beauty of holiness: fear before him,"], ["ia outou gatete i ona luma le lalolagi uma.", "all the earth."]]},
  {num:10,words:[["Ia outou fai atu i nuu ese,", "Say among the heathen that the LORD reigneth:"], ["Ua fai Ieova ma tupu; e faatumauina ai le lalolagi ne'i faagaeetia;", "the world also shall be established that it shall not be moved:"], ["na te faamasinotonuina le nuu.", "he shall judge the people righteously."]]},
  {num:11,words:[["Ia fiafia le lagi,", "Let the heavens rejoice,"], ["ia olioli foi le lalolagi;", "and let the earth be glad; let the sea roar,"], ["ia taalili mai le sami ma mea ua tumu ai.", "and the fulness thereof."]]},
  {num:12,words:[["Ia fiafia lava le laueleele ma mea uma o i ai;", "Let the field be joyful,"], ["ona alalaga fiafia ai lea o laau uma o i le vao matua,", "and all that is therein:"], ["i luma o Ieova;", "then shall all the trees of the wood rejoice"]]},
  {num:13,words:[["auā o loo afio mai,", "Before the LORD:"], ["auā o loo afio mai e faamasino le lalolagi;", "for he cometh,"], ["na te faamasinoina le atu laulau i le amiotonu,", "for he cometh to judge the earth: he shall judge the world with righteousness,"], ["atoa ma nuu i lona faamaoni.", "and the people with his truth."]]},
];
renderVerseSet(psa_ch_96_Verses, 'psa-ch96-verses');

var psa_ch_97_Verses = [
  {num:1,words:[["Ua fai Ieova ma tupu;", "The LORD reigneth;"], ["ina olioli ia le lalolagi;", "let the earth rejoice;"], ["ia fiafia le vao nuu o tu matafaga.", "let the multitude of isles be glad thereof."]]},
  {num:2,words:[["Ua siosiomia o ia i ao ma le pogisa;", "Clouds and darkness are round about him:"], ["o le amiotonu ma le faamasinoga o loo tumau ai lona nofoālii.", "righteousness and judgment are the habitation of his throne."]]},
  {num:3,words:[["Ua muamua i ona luma le afi,", "A fire goeth before him,"], ["e susunu faataaliolio ai e ua ita ia te ia.", "and burneth up his enemies round about."]]},
  {num:4,words:[["O ona uila ua malamalama ai le atu laulau;", "His lightnings enlightened the world:"], ["ua iloa e le lalolagi,", "the earth saw,"], ["ona gatete ai lea.", "and trembled."]]},
  {num:5,words:[["Ua liu suāvai mauga e pei o le pulu, i luma o Ieova,", "The hills melted like wax at the presence of the LORD,"], ["i luma o le Alii o le lalolagi uma.", "at the presence of the Lord of the whole earth."]]},
  {num:6,words:[["O loo faaali mai e le lagi lana amiotonu,", "The heavens declare his righteousness,"], ["o loo iloa atu foi e nuu uma lona mamalu.", "and all the people see his glory."]]},
  {num:7,words:[["Ia mamā i latou uma o e auauna i tupua ua ta,", "Confounded be all they that serve graven images,"], ["o e ua mitamita i tupua;", "that boast themselves of idols:"], ["outou atua uma e,", "worship him,"], ["ia outou ifo atu ia te ia.", "all ye gods."]]},
  {num:8,words:[["Ua faalogo Siona ona olioli lea o ia;", "Zion heard, and was glad;"], ["e fiafia tama fafine a Iuta ona o au faamasinoga Ieova e.", "and the daughters of Judah rejoiced because of thy judgments, O LORD."]]},
  {num:9,words:[["Auā o oe Ieova e,", "For thou,"], ["e sili lava oe i le lalolagi uma;", "LORD, art high above all the earth:"], ["e matuā silisili ese lava oe i atua uma lava.", "thou art exalted far above all gods."]]},
  {num:10,words:[["Outou e ua alolofa atu ia Ieova,", "Ye that love the LORD,"], ["ia outou 'ino'ino i mea leaga;", "hate evil:"], ["o loo tausi e ia i agaga o ona tagata amio Atua;", "he preserveth the souls of his saints;"], ["na te laveaiina i latou ai lima o e amio leaga.", "he delivereth them out of the hand of the wicked."]]},
  {num:11,words:[["Ua luluina le malamalama mo lē amiotonu,", "Light is sown for the righteous,"], ["ua luluina foi le olioli mo e ua loto faamaoni.", "and gladness for the upright in heart."]]},
  {num:12,words:[["Outou e ua amiotonu,", "Rejoice in the LORD,"], ["ia outou fiafia ia Ieova;", "ye righteous;"], ["ia outou vivii pe a manatua lona paia.", "and give thanks at the remembrance of his holiness."]]},
];
renderVerseSet(psa_ch_97_Verses, 'psa-ch97-verses');

var psa_ch_98_Verses = [
  {num:1,words:[["Ia outou pepese atu ia Ieova i le pese fou;", "O sing unto the LORD a new song;"], ["auā o vavega na na faia;", "for he hath done marvellous things:"], ["o lona aao taumatau,", "his right hand,"], ["o lona lava aao paia,", "and his holy arm,"], ["ua ia fai ai le olataga.", "hath gotten him the victory."]]},
  {num:2,words:[["Ua faailoa mai e Ieova o lana lava faaolataga;", "The LORD hath made known his salvation:"], ["ua ia faaalia lana amiotonu i luma o nuu ese.", "his righteousness hath he openly shewed in the sight of the heathen."]]},
  {num:3,words:[["Na ia manatua lona alofa ma lona famaoni i le aiga o Isaraelu;", "He hath remembered his mercy and his truth toward the house of Israel:"], ["ua iloa e tulu'iga uma o le lalolagi le olataga mai lo tatou Atua.", "all the ends of the earth have seen the salvation of our God."]]},
  {num:4,words:[["Ia alalaga ia Ieova le lalolagi uma;", "Make a joyful noise unto the LORD,"], ["ia leo tele lava,", "all the earth:"], ["ma ia alalaga fiafia,", "make a loud noise, and rejoice,"], ["ma ia fai pesega.", "and sing praise."]]},
  {num:5,words:[["Ia outou fai pesega ia Ieova i le kitara;", "Sing unto the LORD with the harp; with the harp,"], ["o le kitara ma le leo o le pese.", "and the voice of a psalm."]]},
  {num:6,words:[["O pu ma le leo o le sofao ia outou alalaga ai i luma o Ieova le Tupu.", "With trumpets and sound of cornet make a joyful noise before the LORD, the King."]]},
  {num:7,words:[["Ia taalili le sami atoa ma mea ua tumu ai,", "Let the sea roar, and the fulness thereof;"], ["o le atu laulau atoa ma e o nonofo ai.", "the world, and they that dwell therein."]]},
  {num:8,words:[["Ia pāti lima vaitafe, ia alalaga fāatasi ai mauga ma le fiafia,", "Let the floods clap their hands:"], ["i luma o Ieova;", "let the hills be joyful together"]]},
  {num:9,words:[["auā o loo afio mai o ia e faamasino le lalolagi;", "Before the LORD;"], ["na te faamasino le atu laulau ma le amiotonu,", "for he cometh to judge the earth: with righteousness shall he judge the world,"], ["atoa ma nuu i le tonu.", "and the people with equity."]]},
];
renderVerseSet(psa_ch_98_Verses, 'psa-ch98-verses');

var psa_ch_99_Verses = [
  {num:1,words:[["Ua fai Ieova ma tupu,", "The LORD reigneth;"], ["ia gatete nuu;", "let the people tremble:"], ["o loo tietie o ia i le va o kerupi,", "he sitteth between the cherubims;"], ["ia faagaeetia le lalolagi.", "let the earth be moved."]]},
  {num:2,words:[["E silisili Ieova o i Siona;", "The LORD is great in Zion;"], ["e maualuga foi o ia i luga o nuu uma.", "and he is high above all the people."]]},
  {num:3,words:[["Ia latou vivii atu i lou suafa e sili ia ma le matautia;", "Let them praise thy great and terrible name;"], ["e paia lava ia.", "for it is holy."]]},
  {num:4,words:[["O le malosi foi o le tupu o loo fiafia ia i le faamasinoga;", "The king's strength also loveth judgment;"], ["o oe ua e faatumauina le amiotonu,", "thou dost establish equity,"], ["o oe foi ua e faia le faamasinoga tonu ia Iakopo.", "thou executest judgment and righteousness in Jacob."]]},
  {num:5,words:[["Ia outou faaneenee atu ia Ieova lo tatou Atua,", "Exalt ye the LORD our God,"], ["ia outou ifo atu i le mea e tu ai ona aao;", "and worship at his footstool;"], ["e paia lava o ia.", "for he is holy."]]},
  {num:6,words:[["O Mose ma Arona i ona faitaulaga,", "Moses and Aaron among his priests,"], ["o Samuelu foi i e o valaau atu i lona suafa;", "and Samuel among them that call upon his name;"], ["ua latou valaau atu ia Ieova,", "they called upon the LORD,"], ["ona tali mai lea o ia ia te i latou.", "and he answered them."]]},
  {num:7,words:[["Na ia fetalai atu ia te i latou i le ao faaniutu;", "He spake unto them in the cloudy pillar: they kept his testimonies,"], ["na latou tausi i ana poloaiga ma tulafono na ia tuuina atu ai ia te i latou.", "and the ordinance that he gave them."]]},
  {num:8,words:[["Ieova e,", "Thou answeredst them,"], ["lo matou Atua,", "O LORD our God:"], ["o oe lava na e tali atu ia te i latou; o oe lava le Atua na e faamagaloina i latou,", "thou wast a God that forgavest them,"], ["a ua e taui i a latou amioga.", "though thou tookest vengeance of their inventions."]]},
  {num:9,words:[["Ia outou faaneenee atu ia Ieova lo tatou Atua,", "Exalt the LORD our God,"], ["ia outou ifo atu foi i lona mauga paia;", "and worship at his holy hill;"], ["auā e paia lava Ieova lo tatou Atua.", "for the LORD our God is holy."]]},
];
renderVerseSet(psa_ch_99_Verses, 'psa-ch99-verses');

var psa_ch_100_Verses = [
  {num:1,words:[["Ia alalaga ia Ieova le lalolagi uma.", "Make a joyful noise unto the LORD, all ye lands."]]},
  {num:2,words:[["Ia outou auauna atu ia Ieova ma le fiafia;", "Serve the LORD with gladness:"], ["o mai ia outou i ona luma ma le alaga fiafia.", "come before his presence with singing."]]},
  {num:3,words:[["Ia outou iloa o Ieova o ia lava le Atua;", "Know ye that the LORD he is God:"], ["o ia na faia i tatou,", "it is he that hath made us,"], ["ua fai i tatou mona;", "and not we ourselves;"], ["o lona nuu i tatou ,", "we are his people,"], ["o le lafu mamoe ua ia fagaina.", "and the sheep of his pasture."]]},
  {num:4,words:[["Ia outou ulu atu i ona faitotoa ma le viiga,", "Enter into his gates with thanksgiving,"], ["ma ona lotoā ma le pese;", "and into his courts with praise:"], ["ia outou vivii atu ia te ia,", "be thankful unto him,"], ["ia outou faamanu atu i lona suafa.", "and bless his name."]]},
  {num:5,words:[["Auā e lelei Ieova;", "For the LORD is good;"], ["e faavavau lava lona alofa;", "his mercy is everlasting;"], ["e oo atu lava lona faamaoni i lea tupulaga ma lea tupulaga.", "and his truth endureth to all generations."]]},
];
renderVerseSet(psa_ch_100_Verses, 'psa-ch100-verses');

var psa_ch_101_Verses = [
  {num:1,words:[["Ou te pese i le alofa ma le faamasinoga,", "I will sing of mercy and judgment:"], ["Ieova e,", "unto thee, O LORD,"], ["ou te fai pesega ia te oe.", "will I sing."]]},
  {num:2,words:[["Ou te faautauta i le ala e sao ona lelei; e te afio mai ea afea ia te au? Ou te savali a'u ma le loto sao i totonu o lo'u fale.", "I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart."]]},
  {num:3,words:[["Ou te le tuu i o'u luma se mea leaga;", "I will set no wicked thing before mine eyes:"], ["ou te 'ino'ino i le amio a ē liliu ese,", "I hate the work of them that turn aside;"], ["e le pipii mai lea ia te au.", "it shall not cleave to me."]]},
  {num:4,words:[["E te'a lava ma a'u o le ua faapiopio lona loto;", "A froward heart shall depart from me:"], ["mā te le feoai ma le ua amio leaga.", "I will not know a wicked person."]]},
  {num:5,words:[["O lē tuaupua i le la te tuaoi,", "Whoso privily slandereth his neighbour,"], ["e fano lea ia te au; o le ua mata faamaualuga ma le loto fefete,", "him will I cut off:"], ["ou te le mafaia lava lea.", "him that hath an high look and a proud heart will not I suffer."]]},
  {num:6,words:[["Ou te fia vaai i e o faamaoni i le nuu,", "Mine eyes shall be upon the faithful of the land,"], ["matou te nonofo ma a'u;", "that they may dwell with me:"], ["o lē savali i le ala ua sao ona lelei,", "he that walketh in a perfect way,"], ["o ia lava lea e auauna mai ia te au.", "he shall serve me."]]},
  {num:7,words:[["E le nofo i lo'u fale o se fai mea faa'ole'ole;", "He that worketh deceit shall not dwell within my house:"], ["o lē tala pepelo foi e le tumau ia i o'u luma.", "he that telleth lies shall not tarry in my sight."]]},
  {num:8,words:[["E fano ia te au i taeao fai soo o i latou uma o e amio leaga o i le nuu,", "I will early destroy all the wicked of the land;"], ["ina ia vavaeeseina i le aai a Ieova o i latou uma lava o e fai mea leaga.", "that I may cut off all wicked doers from the city of the LORD."]]},
];
renderVerseSet(psa_ch_101_Verses, 'psa-ch101-verses');

var psa_ch_102_Verses = [
  {num:1,words:[["Ieova e,", "Hear my prayer,"], ["faafofoga mai ia i la'u tatalo,", "O LORD,"], ["ma ia oo atu la'u alaga ia te oe.", "and let my cry come unto thee."]]},
  {num:2,words:[["Aua le 'alo ou fofoga ia te au i le aso e puapuagatia ai a'u;", "Hide not thy face from me in the day when I am in trouble;"], ["ia liliu mai ou fofoga ia te au;", "incline thine ear unto me:"], ["ia taalise ona e tali mai ia te au i le aso ou te valaau atu ai ia te oe.", "in the day when I call answer me speedily."]]},
  {num:3,words:[["Auā ua mavae o'u aso faapei o le asu,", "For my days are consumed like smoke,"], ["o o'u ivi foi ua mu e pei o le motumotu.", "and my bones are burned as an hearth."]]},
  {num:4,words:[["Ua sasaina ma ua magumagu lo'u loto pei o le vao iti;", "My heart is smitten, and withered like grass;"], ["o lea ua galo ai ia te au ona 'ai i la'u mea e 'ai.", "so that I forget to eat my bread."]]},
  {num:5,words:[["O le leo o lo'u mapuitiga ua pipii ai o'u ivi i lo'u aano.", "By reason of the voice of my groaning my bones cleave to my skin."]]},
  {num:6,words:[["Ua tusa a'u ma le kati o le vao;", "I am like a pelican of the wilderness:"], ["ua avea a'u pei o le kusa i mea ua faatafunaina.", "I am like an owl of the desert."]]},
  {num:7,words:[["O loo ou mataala,", "I watch,"], ["ma ua avea a'u e pei o le manu itiiti e nofo toatasi i luga i le fale.", "and am as a sparrow alone upon the house top."]]},
  {num:8,words:[["O le aso atoa ua gaogao mai ai o e ita mai ia te au;", "Mine enemies reproach me all the day;"], ["o e ua faavalemalosi mai ia te au ua tauto i latou e agaleaga ia te au.", "and they that are mad against me are sworn against me."]]},
  {num:9,words:[["Auā o loo 'aina e a'u o le lefulefu e pei o le mea e 'ai,", "For I have eaten ashes like bread,"], ["ua ou filogia foi la'u mea e inu ma le tagi,", "and mingled my drink with weeping,"]]},
  {num:10,words:[["ona o lou toatamai ma lou toasa;", "Because of thine indignation and thy wrath:"], ["auā na e siitia a'u i luga,", "for thou hast lifted me up,"], ["na e lafotuina foi a'u i lalo.", "and cast me down."]]},
  {num:11,words:[["O o'u aso ua pei o le ata ua lafoia;", "My days are like a shadow that declineth;"], ["o a'u nei foi ua pei o le vao iti ona magumagu.", "and I am withered like grass."]]},
  {num:12,words:[["A o oe,", "But thou,"], ["Ieova e,", "O LORD,"], ["e afio oe e faavavau lava, ma le faamanatuga ia te oe,", "shalt endure for ever;"], ["e āu tupulaga lava lea.", "and thy remembrance unto all generations."]]},
  {num:13,words:[["E te tulai mai oe,", "Thou shalt arise, and have mercy upon Zion:"], ["e mutimuti vale lou alofa i Siona;", "for the time to favour her,"], ["auā ua oo mai ona po e alofaina ai o ia,", "yea,"], ["ua oo lava i ona aso na tuupoina.", "the set time, is come."]]},
  {num:14,words:[["Auā o loo fiafia au auauna i ona maa,", "For thy servants take pleasure in her stones,"], ["o loo alolofa lava i lona efuefu.", "and favour the dust thereof."]]},
  {num:15,words:[["E matatau foi nuu ese i le suafa o Ieova,", "So the heathen shall fear the name of the LORD,"], ["ma tupu uma o le lalolagi e matatau i lou mamalu.", "and all the kings of the earth thy glory."]]},
  {num:16,words:[["Auā e atiina ae Siona e Ieova,", "When the LORD shall build up Zion,"], ["e iloa mai o ia i lona mamalu.", "he shall appear in his glory."]]},
  {num:17,words:[["E liuliualo mai o ia i le tatalo a le ua mativa,", "He will regard the prayer of the destitute,"], ["e le 'ino'ino foi o ia i la latou tatalo.", "and not despise their prayer."]]},
  {num:18,words:[["E tusia lenei mea mo le tupulaga amuli; o le nuu foi e faia,", "This shall be written for the generation to come:"], ["latou te vivii atu ia Ioa.", "and the people which shall be created shall praise the LORD."]]},
  {num:19,words:[["Auā ua silasila mai o ia mai luga i lona afioaga paia;", "For he hath looked down from the height of his sanctuary;"], ["ua silasila Ieova mai le lagi i le lalolagi;", "from heaven did the LORD behold the earth;"]]},
  {num:20,words:[["ina ia faafofoga o ia i le ōi o le ua noanoatia;", "To hear the groaning of the prisoner;"], ["ina ia tālaina e ia o e na tuu e oti;", "to loose those that are appointed to death;"]]},
  {num:21,words:[["e ta'uta'u atu ai le suafa o Ieova i Siona,", "To declare the name of the LORD in Zion,"], ["ma lona viiga i Ierusalema;", "and his praise in Jerusalem;"]]},
  {num:22,words:[["pe a faapotopotoina faatasi o nuu ma malo e auauna ai ia Ieova.", "When the people are gathered together, and the kingdoms, to serve the LORD."]]},
  {num:23,words:[["Na ia faavaivaia lo'u malosi i le ala,", "He weakened my strength in the way;"], ["na ia faaitiitiina foi o'u aso.", "he shortened my days."]]},
  {num:24,words:[["Na ou fai atu,", "I said,"], ["Lo'u Atua e,", "O my God,"], ["aua le aveeseina a'u i le tautuluaga o o'u aso;", "take me not away in the midst of my days:"], ["e āu tupulaga lava ou tausaga.", "thy years are throughout all generations."]]},
  {num:25,words:[["O anamua na e faavaeina ai le lalolagi;", "Of old hast thou laid the foundation of the earth:"], ["o le lagi foi o le galuega lea a ou aao.", "and the heavens are the work of thy hands."]]},
  {num:26,words:[["E faaumatia ia mea,", "They shall perish,"], ["a o oe,", "but thou shalt endure:"], ["e te tumau pea;", "yea,"], ["e pala ia mea uma e pei o le ofu tele,", "all of them shall wax old like a garment;"], ["e te liua ia e pei o le ofu,", "as a vesture shalt thou change them,"], ["ona liua lava lea;", "and they shall be changed:"]]},
  {num:27,words:[["a o oe, e faapea lava pea oe;", "But thou art the same,"], ["e le iu lava ou tausaga.", "and thy years shall have no end."]]},
  {num:28,words:[["E nofo mau atalii o au auauna,", "The children of thy servants shall continue,"], ["o la latou fanau foi e faatumauina ia i ou luma.", "and their seed shall be established before thee."]]},
];
renderVerseSet(psa_ch_102_Verses, 'psa-ch102-verses');

var psa_ch_103_Verses = [
  {num:1,words:[["Lo'u agaga e,", "Bless the LORD,"], ["ia e faamanū atu ia Ieova,", "O my soul: and all that is within me,"], ["o mea uma foi o i totonu ia te au ia faamanū i lona suafa paia.", "bless his holy name."]]},
  {num:2,words:[["Lo'u agaga e,", "Bless the LORD,"], ["ia e faamanū atu ia Ieova,", "O my soul,"], ["aua foi ne'i galo se mea e tasi o ana meaalofa;", "and forget not all his benefits:"]]},
  {num:3,words:[["o lē faamagaloina au amio leaga uma lava;", "Who forgiveth all thine iniquities;"], ["o lē faamaloloina ou ma'i atoa uma;", "who healeth all thy diseases;"]]},
  {num:4,words:[["o lē faaolaina mai lou ola ai le tuugamau;", "Who redeemeth thy life from destruction;"], ["o lē faapaleina oe i le alofa ma le alofa mutimuti vale;", "who crowneth thee with lovingkindness and tender mercies;"]]},
  {num:5,words:[["o lē e mălie ai lou manao i mea lelei;", "Who satisfieth thy mouth with good things;"], ["o le faafouina lou taulealea faapei o le aeto.", "so that thy youth is renewed like the eagle's."]]},
  {num:6,words:[["E faia e Ieova mea tonu, ma faamasinoga mo e ua sauaina uma lava.", "The LORD executeth righteousness and judgment for all that are oppressed."]]},
  {num:7,words:[["Na ia faailoa ona ala ia Mose,", "He made known his ways unto Moses,"], ["o ana galuega i le fanauga a Isaraelu.", "his acts unto the children of Israel."]]},
  {num:8,words:[["E alofa mutimuti vale ma alofa fua mai Ieova;", "The LORD is merciful and gracious,"], ["e tele gese lona toasa,", "slow to anger,"], ["a e tele lona alofa.", "and plenteous in mercy."]]},
  {num:9,words:[["E le aoai mai pea lava ia;", "He will not always chide:"], ["e le faamoemoe foi lona toasa e faavavau.", "neither will he keep his anger for ever."]]},
  {num:10,words:[["E lei faia e ia ia i tatou e tusa ma a tatou agasala;", "He hath not dealt with us after our sins;"], ["e lei taui mai foi o ia ia i tatou e tusa ma a tatou amio leaga.", "nor rewarded us according to our iniquities."]]},
  {num:11,words:[["Auā e pei ona maualuga o le lagi i le lalolagi,", "For as the heaven is high above the earth,"], ["e faapea ona tele o lona alofa i e matatau ia te ia.", "so great is his mercy toward them that fear him."]]},
  {num:12,words:[["E pei ona vava mamao o sasae ma sisifo,", "As far as the east is from the west,"], ["e faapea lava ona faamamao e ia ia i tatou o a tatou solitulafono.", "so far hath he removed our transgressions from us."]]},
  {num:13,words:[["E faapei ona alofa mutumuti vale o le tamā i lana fanau,", "Like as a father pitieth his children,"], ["e faapea lava ona alofa mutimuti vale o Ieova i e matatau ia te ia.", "so the LORD pitieth them that fear him."]]},
  {num:14,words:[["Auā ua silafia lava e ia le mea na fai a'i i tatou;", "For he knoweth our frame;"], ["ua manatu ia o le efuefu lava i tatou.", "he remembereth that we are dust."]]},
  {num:15,words:[["O le tagata,", "As for man,"], ["e pei o le mutia ona aso;", "his days are as grass:"], ["e pei o le fuga o le vao,", "as a flower of the field,"], ["e faapea ona fuga mai o ia;", "so he flourisheth."]]},
  {num:16,words:[["auā a agi mai i ai le matagi,", "For the wind passeth over it,"], ["ona leai lea o ia;", "and it is gone;"], ["ua le toe iloa foi o ia i le mea sa i ai.", "and the place thereof shall know it no more."]]},
  {num:17,words:[["A o le alofa o Ieova, mai le vavau lava lea,", "But the mercy of the LORD is from everlasting to everlasting upon them that fear him,"], ["e oo i le faavavau i e matatau ia te ia; o lana amiotonu foi e oo i le fanau a latou fanau,", "and his righteousness unto children's children;"]]},
  {num:18,words:[["i e tausi i lana feagaiga,", "To such as keep his covenant,"], ["o e manatua foi ana poloaiga e fai ai.", "and to those that remember his commandments to do them."]]},
  {num:19,words:[["Ua faatumauina e Ieova o lona nofoālii i le lagi;", "The LORD hath prepared his throne in the heavens;"], ["ua pule aoao foi lona malo.", "and his kingdom ruleth over all."]]},
  {num:20,words:[["Faamanū atu ia ia Ieova outou ana agelu o e malolosi tele,", "Bless the LORD, ye his angels,"], ["o e faia lana afioga,", "that excel in strength,"], ["o loo faalogo i lona siufofoga.", "that do his commandments, hearkening unto the voice of his word."]]},
  {num:21,words:[["Faamanū atu ia ia Ieova outou ana 'au uma lava,", "Bless ye the LORD,"], ["o outou ana auauna,", "all ye his hosts; ye ministers of his,"], ["o e faia lona finagalo.", "that do his pleasure."]]},
  {num:22,words:[["Faamanū atu ia ia Ieova o mea uma na ia faia i mea uma lava ua pule i ai o ia. Lo'u agaga e,", "Bless the LORD, all his works in all places of his dominion:"], ["ia e faamanū atu ia Ieova.", "bless the LORD, O my soul."]]},
];
renderVerseSet(psa_ch_103_Verses, 'psa-ch103-verses');

var psa_ch_104_Verses = [
  {num:1,words:[["Lo'u agaga e, ia e faamanū atu ia Ieova;", "Bless the LORD,"], ["Ieova e,", "O my soul. O LORD my God,"], ["lo'u Atua,", "thou art very great;"], ["e matuā silisili lava oe, e ofu oe i le viiga ma le matagofie.", "thou art clothed with honour and majesty."]]},
  {num:2,words:[["O loo e pulupulu i le malamalama pei o se ie pulupulu;", "Who coverest thyself with light as with a garment:"], ["o loo e fofola le lagi faapei o se ie puipui.", "who stretchest out the heavens like a curtain:"]]},
  {num:3,words:[["O loo faia e ia o ona afeafe aupitoaluga i le vai;", "Who layeth the beams of his chambers in the waters:"], ["o loo faia e ia o ao mona nofoa faataavalevale;", "who maketh the clouds his chariot:"], ["e feafioai o ia i apaau o le matagi.", "who walketh upon the wings of the wind:"]]},
  {num:4,words:[["O lē fai o ana agelu ma agaga,", "Who maketh his angels spirits;"], ["o ana auauna o le afi mumū ia.", "his ministers a flaming fire:"]]},
  {num:5,words:[["O le na faavaeina le lalolagi i luga o ona lava faavae,", "Who laid the foundations of the earth,"], ["ina ia le gaee e faavavau faavavau lava.", "that it should not be removed for ever."]]},
  {num:6,words:[["Ua e ufitia ia i le moana e pei o se ofu;", "Thou coveredst it with the deep as with a garment:"], ["o le vai ua lofia ai mauga.", "the waters stood above the mountains."]]},
  {num:7,words:[["O lau aoai atu na sola ai o ia,", "At thy rebuke they fled;"], ["na taalise atu i le leo o lou faititili.", "at the voice of thy thunder they hasted away."]]},
  {num:8,words:[["Ua o ae mauga, ua o ifo vanu,", "They go up by the mountains;"], ["e oo i lea lava mea na e saunia mo i latou.", "they go down by the valleys unto the place which thou hast founded for them."]]},
  {num:9,words:[["Ua e tuuina i ai le tuaoi ne'i sopoia e ia,", "Thou hast set a bound that they may not pass over;"], ["ne'i toe foi mai ia e lofia le laueleele.", "that they turn not again to cover the earth."]]},
  {num:10,words:[["Ua aunai atu e ia o vaipuna i vanu,", "He sendeth the springs into the valleys,"], ["ua tafe ia i va o mauga.", "which run among the hills."]]},
  {num:11,words:[["E inu ai manu uma lava o le vao,", "They give drink to every beast of the field:"], ["e malilie ai foi asini o le vao.", "the wild asses quench their thirst."]]},
  {num:12,words:[["E nonofo latalata ane i ai o manu felelei,", "By them shall the fowls of the heaven have their habitation,"], ["e lagona o latou leo i totonu o la laau.", "which sing among the branches."]]},
  {num:13,words:[["O lē faasūsū mauga mai ona afeafe aupitoaluga;", "He watereth the hills from his chambers:"], ["o fua o au galuega e ma'ona ai le laueleele.", "the earth is satisfied with the fruit of thy works."]]},
  {num:14,words:[["Ua faatupu e ia mutia mo manu vaefa,", "He causeth the grass to grow for the cattle,"], ["atoa ma mea totō e aoga i tagata;", "and herb for the service of man:"], ["e faatupu mai le mea e 'ai i le eleele;", "that he may bring forth food out of the earth;"]]},
  {num:15,words:[["ma le uaina e faafiafia ai loto o tagata,", "And wine that maketh glad the heart of man,"], ["ina ia pupula ai o latou mata e sili i le suāuu,", "and oil to make his face to shine,"], ["o le mea e 'ai foi e malosi ai tagata.", "and bread which strengtheneth man's heart."]]},
  {num:16,words:[["Ua lauolaola laau o Ieova,", "The trees of the LORD are full of sap; the cedars of Lebanon,"], ["o arasi o Lepanona na totōina e ia.", "which he hath planted;"]]},
  {num:17,words:[["E fai ai e manu iti o latou ofaga;", "Where the birds make their nests: as for the stork,"], ["o le kasita o i perosi lona fale.", "the fir trees are her house."]]},
  {num:18,words:[["O mauga maualuluga mo 'oti o le vao ia;", "The high hills are a refuge for the wild goats;"], ["o papa o mea ia e malu ai sefanai.", "and the rocks for the conies."]]},
  {num:19,words:[["Na ia faia le masina e atofaina ai aso;", "He appointed the moon for seasons:"], ["ua iloa e le la le mea e goto i ai.", "the sun knoweth his going down."]]},
  {num:20,words:[["Ua e faia le pouliuli,", "Thou makest darkness,"], ["ona po lava lea,", "and it is night:"], ["e fetolofi mai ai o manu feai uma lava o le vao.", "wherein all the beasts of the forest do creep forth."]]},
  {num:21,words:[["Ua tagi leona taanoa i mea e saeia,", "The young lions roar after their prey,"], ["ma sailiili mai i le Atua la latou mea e 'ai.", "and seek their meat from God."]]},
  {num:22,words:[["Ua alu ae le la,", "The sun ariseth,"], ["ona faapotopotoina ai lea o i latou,", "they gather themselves together,"], ["ma taooto i o latou ana.", "and lay them down in their dens."]]},
  {num:23,words:[["E alu atu ai le tagata i lana galuega, ma ana mea e fai seia oo i le afiafi.", "Man goeth forth unto his work and to his labour until the evening."]]},
  {num:24,words:[["Ieova e,", "O LORD,"], ["ua matuā tele au galuega. Ua e faia ia mea uma i le poto;", "how manifold are thy works! in wisdom hast thou made them all:"], ["ua tumu le lalolagi i au oloa.", "the earth is full of thy riches."]]},
  {num:25,words:[["O lenei sami tele ma le lautele,", "So is this great and wide sea,"], ["o i ai mea fetolofi e le masino,", "wherein are things creeping innumerable,"], ["o meaola iti atoa ma e tetele.", "both small and great beasts."]]},
  {num:26,words:[["E feoai ai vaa;", "There go the ships: there is that leviathan,"], ["o le leviatana na e faia e taalo ai.", "whom thou hast made to play therein."]]},
  {num:27,words:[["O loo faatalitali ia mea uma ia te oe,", "These wait all upon thee;"], ["ina ia e avatu i ai la latou mea e 'ai i ona aso e tatau ai;", "that thou mayest give them their meat in due season."]]},
  {num:28,words:[["e te avatua i ai,", "That thou givest them they gather:"], ["ua faaputuina e i latou; e te faamafolafola lou aao,", "thou openest thine hand,"], ["ua maoona ai i latou i mea lelei.", "they are filled with good."]]},
  {num:29,words:[["Ua 'alo ou fofoga,", "Thou hidest thy face,"], ["ona atuatuvale ai lea o i latou;", "they are troubled:"], ["ua e aveeseina a latou mānava,", "thou takest away their breath,"], ["ona mamate ai lea,", "they die,"], ["ua toe liu efuefu.", "and return to their dust."]]},
  {num:30,words:[["E te auina atu lou Agaga,", "Thou sendest forth thy spirit,"], ["ua faia ai i latou;", "they are created:"], ["e te toe fuataiina foi le fogaeleele.", "and thou renewest the face of the earth."]]},
  {num:31,words:[["E tumau le mamalu o Ieova e faavavau;", "The glory of the LORD shall endure for ever:"], ["e fiafia Ieova i ana mea na fai.", "the LORD shall rejoice in his works."]]},
  {num:32,words:[["E silasila mai o ia i le lalolagi,", "He looketh on the earth,"], ["ona gatete ai lea;", "and it trembleth:"], ["e papai atu ia i mauga,", "he toucheth the hills,"], ["ona pupusa ai lea.", "and they smoke."]]},
  {num:33,words:[["Ou te pese ia Ieova i lo'u nei olaga;", "I will sing unto the LORD as long as I live:"], ["ou te fai pesega i lo'u Atua a o au ola.", "I will sing praise to my God while I have my being."]]},
  {num:34,words:[["E mălie lo'u mafaufau ia te ia;", "My meditation of him shall be sweet:"], ["ou te fiafia lava a'u ia Ieova.", "I will be glad in the LORD."]]},
  {num:35,words:[["E faaumatia o e agasala ai le lalolagi,", "Let the sinners be consumed out of the earth,"], ["ma e amio leaga e le toe i ai i latou. Lo'u agaga e,", "and let the wicked be no more. Bless thou the LORD,"], ["ia e faamanū atu ia Ieova. Ia outou vivii atu ia Ioa.", "O my soul. Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_104_Verses, 'psa-ch104-verses');

var psa_ch_105_Verses = [
  {num:1,words:[["Vivii atu ia outou ia Ieova;", "O give thanks unto the LORD;"], ["valaau atu ia i lona suafa;", "call upon his name:"], ["ia outou faailo atu i nuu ana mea na fai.", "make known his deeds among the people."]]},
  {num:2,words:[["Ia pepese outou ia te ia,", "Sing unto him,"], ["ia outou fai pesega ia te ia;", "sing psalms unto him:"], ["talatala atu ia outou i ona vavega uma lava.", "talk ye of all his wondrous works."]]},
  {num:3,words:[["Ia outou mitamita i lona suafa paia;", "Glory ye in his holy name:"], ["ia olioli loto o e sailiili ia Ieova.", "let the heart of them rejoice that seek the LORD."]]},
  {num:4,words:[["Sailiili ia outou ia Ieova ma lona malosi;", "Seek the LORD,"], ["sailiili i ona fofoga,", "and his strength:"], ["aua le aunoa.", "seek his face evermore."]]},
  {num:5,words:[["Ia outou manatua ana mea mamana na ia faia,", "Remember his marvellous works that he hath done;"], ["o ona vavega,", "his wonders,"], ["atoa ma faamasinoga a lona fofoga;", "and the judgments of his mouth;"]]},
  {num:6,words:[["o outou le fanauga a lana auauna o Aperaamo,", "O ye seed of Abraham his servant,"], ["o atalii o Iakopo na ia filifilia.", "ye children of Jacob his chosen."]]},
  {num:7,words:[["O ia lava o Ieova lo tatou Atua;", "He is the LORD our God:"], ["o i le lalolagi uma lava ana faamasinoga.", "his judgments are in all the earth."]]},
  {num:8,words:[["E manatua e ia e faavavau o lana feagaiga,", "He hath remembered his covenant for ever,"], ["o le upu na ia poloai mai i tupulaga e afe.", "the word which he commanded to a thousand generations."]]},
  {num:9,words:[["O le feagaiga sa la osia ma Aperaamo,", "Which covenant he made with Abraham,"], ["ma lana tautoga ia Isaako;", "and his oath unto Isaac;"]]},
  {num:10,words:[["ua ia faamauina foi ia Iakopo e fai ma tulafono,", "And confirmed the same unto Jacob for a law,"], ["o le feagaiga e faavavau mā Isaraelu;", "and to Israel for an everlasting covenant:"]]},
  {num:11,words:[["ua faapea atu ia te ia ,", "Saying,"], ["Ou te avatu ia te oe le laueleele o Kanana,", "Unto thee will I give the land of Canaan,"], ["o le vaega lea o lo outou tofi;", "the lot of your inheritance:"]]},
  {num:12,words:[["ina o toaitiiti i latou,", "When they were but a few men in number;"], ["e toaitiiti lava,", "yea, very few,"], ["mona o tagata ese i lea mea", "and strangers in it."]]},
  {num:13,words:[["Na feoai foi i latou i lea nuu ma lea nuu,", "When they went from one nation to another,"], ["nai le tasi itu malo i le tasi nuu.", "from one kingdom to another people;"]]},
  {num:14,words:[["Ua le tuua e ia ia faasaua se tagata ia i latou;", "He suffered no man to do them wrong: yea,"], ["ua ia aoai atu foi i tupu ona o i latou.", "he reproved kings for their sakes;"]]},
  {num:15,words:[["Ua faapea atu i ai ,", "Saying,"], ["Aua le tago i e ua ou faauuina,", "Touch not mine anointed,"], ["aua foi le agaleaga atu i a'u perofeta.", "and do my prophets no harm."]]},
  {num:16,words:[["Ua ia valaau foi i le oge e oo i le nuu,", "Moreover he called for a famine upon the land:"], ["ua ia gagau le tootoo o le mea e 'ai uma.", "he brake the whole staff of bread."]]},
  {num:17,words:[["Ua auina atu e ia o le tagata e muamua atu ia i latou,", "He sent a man before them, even Joseph,"], ["o Iosefa lea na faatauina e fai ma auauna.", "who was sold for a servant:"]]},
  {num:18,words:[["Ua latou faatiga i ona vae i le noanoaga;", "Whose feet they hurt with fetters:"], ["ua oo lava o ia i le uamea;", "he was laid in iron:"]]},
  {num:19,words:[["ua oo i le tau na taunuu ai lana afioga,", "Until the time that his word came:"], ["o le afioga a Ieova na tofotofo ai ia te ia.", "the word of the LORD tried him."]]},
  {num:20,words:[["Ua aauina atu nisi e le tupu e tatala ia te ia;", "The king sent and loosed him; even the ruler of the people,"], ["o le na pule i le nuu ua faasa'oloto ia te ia.", "and let him go free."]]},
  {num:21,words:[["Ua na tofia o ia e fai ma alii i lona aiga,", "He made him lord of his house,"], ["ma ia pule i ana mea uma lava.", "and ruler of all his substance:"]]},
  {num:22,words:[["Ina ia noanoa e ia alii na ia te ia i lana faitalia,", "To bind his princes at his pleasure;"], ["ma a'oa'o atu i lona au faipule ia popoto.", "and teach his senators wisdom."]]},
  {num:23,words:[["Ua oo atu foi Isaraelu i Aikupito,", "Israel also came into Egypt;"], ["ua āumau foi Iakopo i le nuu o Hamo.", "and Jacob sojourned in the land of Ham."]]},
  {num:24,words:[["Ua ia faatoateleina foi lona nuu,", "And he increased his people greatly;"], ["ua na faamalolosia i latou e sili i e na faasaua ia i latou.", "and made them stronger than their enemies."]]},
  {num:25,words:[["Ua ia liua foi o latou loto e 'ino'ino atu i lona nuu,", "He turned their heart to hate his people,"], ["ma ia togafiti pepelo i ana auauna.", "to deal subtilly with his servants."]]},
  {num:26,words:[["Ua ia auina atu lana auauna o Mose,", "He sent Moses his servant;"], ["o Arona foi na filifilia e ia.", "and Aaron whom he had chosen."]]},
  {num:27,words:[["Ua la tuu atu ia i latou ona lava faailoga,", "They shewed his signs among them,"], ["o vavega foi i le nuu o Hamo.", "and wonders in the land of Ham."]]},
  {num:28,words:[["Ua na auina atu le pouliuli,", "He sent darkness,"], ["i le ua faapouliuligia ai,", "and made it dark;"], ["e lei foua foi lana afioga.", "and they rebelled not against his word."]]},
  {num:29,words:[["Ua ia liua o latou vai i le toto,", "He turned their waters into blood,"], ["ma faamamate i o latou i'a.", "and slew their fish."]]},
  {num:30,words:[["Ua faatutupu tele mai o rane i lo latou laueleele,", "Their land brought forth frogs in abundance,"], ["ua oo lava i afeafe o latou tupu.", "in the chambers of their kings."]]},
  {num:31,words:[["Ua ia fetalai ane,", "He spake,"], ["ona o mai ai lea o le vao garova ma 'utu,", "and there came divers sorts of flies,"], ["ua oo i o latou nuu uma lava.", "and lice in all their coasts."]]},
  {num:32,words:[["Ua ia tuuina atu ia i latou o le uato'a e sui a'i le ua,", "He gave them hail for rain,"], ["ma le afi mumū i lo latou nuu.", "and flaming fire in their land."]]},
  {num:33,words:[["Ua na taia foi o latou vine ma o latou mati;", "He smote their vines also and their fig trees;"], ["ua gauia foi laau i lo latou nuu.", "and brake the trees of their coasts."]]},
  {num:34,words:[["Ua fetalai ia,", "He spake,"], ["ona o mai lea o sē akerise,", "and the locusts came, and caterpillers,"], ["ma sē aleka e le mafaitaulia.", "and that without number,"]]},
  {num:35,words:[["Ua 'aina ai le vao iti uma i lo latou nuu,", "And did eat up all the herbs in their land,"], ["ua 'aina lava le fua o lo latou laueleele.", "and devoured the fruit of their ground."]]},
  {num:36,words:[["Ua ia fafasi i ulumatua uma lava i lo latou nuu,", "He smote also all the firstborn in their land,"], ["o le amataga lea o lo latou malosi uma.", "the chief of all their strength."]]},
  {num:37,words:[["Ua ia aumaia i latou ma le ario atoa ma le auro;", "He brought them forth also with silver and gold:"], ["e leai foi se tasi sa vaivai i o latou itu aiga.", "and there was not one feeble person among their tribes."]]},
  {num:38,words:[["Ua fiafia Aikupito ina ua o atu i latou;", "Egypt was glad when they departed:"], ["auā na maua i latou i le fefe ona o i latou.", "for the fear of them fell upon them."]]},
  {num:39,words:[["Ua ia fofola le ao e fai ma faapaologa,", "He spread a cloud for a covering;"], ["o le afi foi e faamalamalama a'i le po.", "and fire to give light in the night."]]},
  {num:40,words:[["Ua ole atu i latou,", "The people asked,"], ["ona avatu lea e ia o salu,", "and he brought quails,"], ["ma le mea e 'ai mai le lagi ua ia faamaoona ai ia te i latou.", "and satisfied them with the bread of heaven."]]},
  {num:41,words:[["Ua ia susue le papa,", "He opened the rock,"], ["i le ua puna mai ai le vai; ua tafe i le nuu naumati,", "and the waters gushed out;"], ["o le vaitafe lava.", "they ran in the dry places like a river."]]},
  {num:42,words:[["Auā ua ia manatua lana afioga paia i lana auauna o Aperaamo.", "For he remembered his holy promise, and Abraham his servant."]]},
  {num:43,words:[["Ua na aumaia lona nuu ma le olioli,", "And he brought forth his people with joy,"], ["o e na filifilia e ia ua ia aumaia ma le leo fiafia.", "and his chosen with gladness:"]]},
  {num:44,words:[["Ua ia avatu foi ia i latou o fanua o nuu ese;", "And gave them the lands of the heathen:"], ["na maua foi e i latou o mea sa galulue ai nuu;", "and they inherited the labour of the people;"]]},
  {num:45,words:[["ina ia tausi i latou i ana sauniga,", "That they might observe his statutes,"], ["ma usiusitai i ana tulafono. Ia outou vivii atu ia Ioa.", "and keep his laws. Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_105_Verses, 'psa-ch105-verses');

var psa_ch_106_Verses = [
  {num:1,words:[["Ia outou vivii atu ia Ioa,", "Praise ye the LORD. O give thanks unto the LORD;"], ["Vivii atu outou ia Ieova, auā e lelei lava o ia;", "for he is good:"], ["auā e faavavau lava lona alofa.", "for his mercy endureth for ever."]]},
  {num:2,words:[["O ai se na te mafaia ona ta'u atu i mea mamana a Ieova? O ai se na te faailoa ona viiga uma lava?", "Who can utter the mighty acts of the LORD? who can shew forth all his praise?"]]},
  {num:3,words:[["Amuia i latou o e tausi i le faamasinoga,", "Blessed are they that keep judgment,"], ["o e fai le amiotonu e le aunoa.", "and he that doeth righteousness at all times."]]},
  {num:4,words:[["Ieova e,", "Remember me, O LORD,"], ["ia e manatu mai ia te au e tusa ma lou finagalo alofa i ou tagata. Ia e asiasi mai ia te au ma lau faaolataga;", "with the favour that thou bearest unto thy people: O visit me with thy salvation;"]]},
  {num:5,words:[["ina ia ou iloa atu le manuia o e na e filifilia,", "That I may see the good of thy chosen,"], ["ina ia ou fiafia i le fiafia o lou nuu;", "that I may rejoice in the gladness of thy nation,"], ["ina ia ou mitamita faatasi ma e ua fai mou tofi.", "that I may glory with thine inheritance."]]},
  {num:6,words:[["Ua matou agasala atoa ma o matou tamā,", "We have sinned with our fathers,"], ["ua amio faapiopio i matou,", "we have committed iniquity,"], ["ua matou amio leaga lava.", "we have done wickedly."]]},
  {num:7,words:[["E lei mafaufau o matou tamā i ou vavega i Aikupito;", "Our fathers understood not thy wonders in Egypt;"], ["e lei manatua e i latou le tele o au meaalofa;", "they remembered not the multitude of thy mercies;"], ["a ua fouvale i tala ane o le sami,", "but provoked him at the sea,"], ["o le sami Ulaula.", "even at the Red sea."]]},
  {num:8,words:[["A ua na faaola ia i latou ona o lona lava suafa,", "Nevertheless he saved them for his name's sake,"], ["ina ia faailoa atu ai lona mana.", "that he might make his mighty power to be known."]]},
  {num:9,words:[["Ua ia aoai atu i le sami Ulaula,", "He rebuked the Red sea also,"], ["i le ua matutu;", "and it was dried up: so he led them through the depths,"], ["ua ia aumaia i latou i mea loloto e pei o le vao.", "as through the wilderness."]]},
  {num:10,words:[["Ua na faaola ia i latou nai le lima o le na 'ino'ino ia i latou ,", "And he saved them from the hand of him that hated them,"], ["ma na faaolaina ai nai le lima o le na ita i ai.", "and redeemed them from the hand of the enemy."]]},
  {num:11,words:[["A ua lofia i le sami e na faasaua ia i latou;", "And the waters covered their enemies:"], ["ua leai so latou na toe.", "there was not one of them left."]]},
  {num:12,words:[["Ona talitonu lea o i latou i ana afioga,", "Then believed they his words;"], ["ua latou pepese i ona viiga.", "they sang his praise."]]},
  {num:13,words:[["Ua vave galo ia te i latou o ana mea na fai;", "They soon forgat his works;"], ["e lei faatali atu i latou i lana pule.", "they waited not for his counsel:"]]},
  {num:14,words:[["Ua latou tu'inanau lava i le vao,", "But lusted exceedingly in the wilderness,"], ["ua latou tofotofo foi i le Atua i le vao.", "and tempted God in the desert."]]},
  {num:15,words:[["Ona foaiina atu ai lea e ia ia i latou o le mea na latou manao ai;", "And he gave them their request;"], ["a ua faatupuina le tinovale ia te i latou.", "but sent leanness into their soul."]]},
  {num:16,words:[["Ua matataua foi i latou ia Mose i le toagalauapi,", "They envied Moses also in the camp,"], ["ma Arona le tagata paia o Ieova.", "and Aaron the saint of the LORD."]]},
  {num:17,words:[["Ua faamaga le eleele, ona foloina ai lea o Tatano,", "The earth opened and swallowed up Dathan,"], ["ua ufitia ai e na faapotopoto ia Apiramo.", "and covered the company of Abiram."]]},
  {num:18,words:[["Ua mu foi le afi i lo latou faapotopotoga,", "And a fire was kindled in their company;"], ["ua susunuina i le afi mumū o e na amio leaga.", "the flame burned up the wicked."]]},
  {num:19,words:[["Ua faia e i latou le tamai povi i Horepa,", "They made a calf in Horeb,"], ["ua latou ifo foi i le tupua uamea.", "and worshipped the molten image."]]},
  {num:20,words:[["Sa liliu e i latou lo latou mamalu i le faatusa o le povi na te 'ai vao.", "Thus they changed their glory into the similitude of an ox that eateth grass."]]},
  {num:21,words:[["Ua galo ia te i latou lo latou Faaola le Atua,", "They forgat God their saviour,"], ["o le na faia mea tetele i Aikupito;", "which had done great things in Egypt;"]]},
  {num:22,words:[["o vavega i le nuu o Hamo,", "Wondrous works in the land of Ham,"], ["ma mea e matautia i le sami Ulaula.", "and terrible things by the Red sea."]]},
  {num:23,words:[["Ona ia fetalai mai lea e faaumatia i latou e ia,", "Therefore he said that he would destroy them,"], ["ana le seanoa Mose na filifilia e ia,", "had not Moses his chosen stood before him in the breach,"], ["na tu i ona luma i le mea ua sofaia,", "to turn away his wrath,"], ["ia liliueseina lona toasa ina ne'i faaumatia i latou .", "lest he should destroy them."]]},
  {num:24,words:[["Ua 'ino'ino foi i latou i le nuu matagofie;", "Yea, they despised the pleasant land,"], ["e lei talitonu i latou i lana afioga.", "they believed not his word:"]]},
  {num:25,words:[["A ua latou muimui i totonu o latou fale ie,", "But murmured in their tents,"], ["e lei faalogo i latou i le siufofoga o Ieova.", "and hearkened not unto the voice of the LORD."]]},
  {num:26,words:[["Ona ia sii ai lea o lona aao ia i latou,", "Therefore he lifted up his hand against them,"], ["e fasi ai ia te i latou i le vao;", "to overthrow them in the wilderness:"]]},
  {num:27,words:[["ina ia fasi foi la latou fanau i nuu ese,", "To overthrow their seed also among the nations,"], ["ma faataapeape ia te i latou i nuu.", "and to scatter them in the lands."]]},
  {num:28,words:[["Ua latou faatasi atu foi ia Paalapeoro,", "They joined themselves also unto Baal-peor,"], ["ma latou aai i taulaga i e ua oti.", "and ate the sacrifices of the dead."]]},
  {num:29,words:[["Sa latou faalili atu ia te ia i a latou mea na fai;", "Thus they provoked him to anger with their inventions:"], ["ona oso mai lea ia i latou o le faamai.", "and the plague brake in upon them."]]},
  {num:30,words:[["Ona tulai ai lea o Fineaso,", "Then stood up Phinehas,"], ["ma na fai le faamasinoga;", "and executed judgment:"], ["ona taofia ai lea o le faamai.", "and so the plague was stayed."]]},
  {num:31,words:[["Sa ta'ua foi lea mea ia te ia e fai ma amiotonu i lea tupulaga ma lea tupulaga e faavavau.", "And that was counted unto him for righteousness unto all generations for evermore."]]},
  {num:32,words:[["Ua faatupu foi e i latou lona toasa i le vai o Meripa,", "They angered him also at the waters of strife,"], ["na leaga ai foi Mose ona o i latou.", "so that it went ill with Moses for their sakes:"]]},
  {num:33,words:[["Auā na latou faaonoono i lona loto,", "Because they provoked his spirit,"], ["i le ua soona tautala ona laugutu.", "so that he spake unadvisedly with his lips."]]},
  {num:34,words:[["E lei faaumatia e i latou o ia nuu na fetalai atu ai Ieova ia te i latou.", "They did not destroy the nations, concerning whom the LORD commanded them:"]]},
  {num:35,words:[["A ua latou nofo fefiloi ma nuu ese,", "But were mingled among the heathen,"], ["ona a'oa'oina ai lea o i latou i a latou amioga.", "and learned their works."]]},
  {num:36,words:[["Ua latou auauna foi i o latou tupua;", "And they served their idols:"], ["ua fai foi ia mea ma mailei ia i latou.", "which were a snare unto them."]]},
  {num:37,words:[["Ua latou fai foi o latou atalii ma o latou afafine ma taulaga i temoni;", "Yea, they sacrificed their sons and their daughters unto devils,"]]},
  {num:38,words:[["ma latou sasaa le toto o e le sala,", "And shed innocent blood,"], ["o toto o latou atalii ma o latou afafine,", "even the blood of their sons and of their daughters,"], ["e na latou fai ma taulaga i tupua o Kanana;", "whom they sacrificed unto the idols of Canaan:"], ["ona leaga ai lea o le laueleele i le toto.", "and the land was polluted with blood."]]},
  {num:39,words:[["Ona leaga ai lea o i latou i a latou lava amio,", "Thus were they defiled with their own works,"], ["ua latou faitaaga foi i a latou mea na fai.", "and went a whoring with their own inventions."]]},
  {num:40,words:[["Ona mumū ai lea o le toasa o Ieova i lona nuu,", "Therefore was the wrath of the LORD kindled against his people,"], ["ua ia 'ino'ino foi i lona tofi.", "insomuch that he abhorred his own inheritance."]]},
  {num:41,words:[["Ua na tuuina atu ai i latou i lima o nuu ese;", "And he gave them into the hand of the heathen;"], ["ua pule foi ia i latou o e na 'ino'ino ia te i latou.", "and they that hated them ruled over them."]]},
  {num:42,words:[["Ua faasaua foi ia i latou o e na ita i ai,", "Their enemies also oppressed them,"], ["ua faatoilaloina foi i latou i o latou lima.", "and they were brought into subjection under their hand."]]},
  {num:43,words:[["Ua atu lasi ona laveai o ia ia te i latou,", "Many times did he deliver them;"], ["a o i latou ua latou faaonoono ia te ia i a latou pulega;", "but they provoked him with their counsel,"], ["na solia foi i latou ona o a latou amio leaga.", "and were brought low for their iniquity."]]},
  {num:44,words:[["A ua silasila mai o ia i lo latou puapuaga,", "Nevertheless he regarded their affliction,"], ["ina ua faafofoga i lo latou alalaga.", "when he heard their cry:"]]},
  {num:45,words:[["Ona ia manatua lea mo i latou o lana feagaiga,", "And he remembered for them his covenant,"], ["ma ua salamo e tusa ma lona alofa tele.", "and repented according to the multitude of his mercies."]]},
  {num:46,words:[["Ua ia avatu foi ia i latou ia alofagia e i latou uma e na faatagataotauaina i latou.", "He made them also to be pitied of all those that carried them captives."]]},
  {num:47,words:[["Ieova e,", "Save us,"], ["lo matou Atua,", "O LORD our God,"], ["ia e faaola mai ia te i matou, ma e faapotopoto ia i matou ai nuu ese,", "and gather us from among the heathen,"], ["ina ia vivii i lou suafa paia,", "to give thanks unto thy holy name,"], ["ia mitamita foi i viiga ia te oe.", "and to triumph in thy praise."]]},
  {num:48,words:[["Ia faafetaia Ieova,", "Blessed be the LORD God of Israel from everlasting to everlasting:"], ["o le Atua o Isaraelu mai le vavau ma ia oo i le faavavau; ma ia faapea mai o le nuu uma lava,", "and let all the people say,"], ["Amene.", "Amen."], ["Ia outou vivii atu ia Ioa.", "Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_106_Verses, 'psa-ch106-verses');

var psa_ch_107_Verses = [
  {num:1,words:[["Vivii atu ia outou ia Ieova,", "O give thanks unto the LORD,"], ["auā e lelei lava o ia ,", "for he is good:"], ["auā e faavavau lava lona alofa.", "for his mercy endureth for ever."]]},
  {num:2,words:[["Ia faapea lava o e ua faaolaina e Ieova,", "Let the redeemed of the LORD say so,"], ["o i latou na ia faaolaina nai le lima o lē faasaua,", "whom he hath redeemed from the hand of the enemy;"]]},
  {num:3,words:[["ma ua faapotopotoina i latou mai nuu,", "And gathered them out of the lands, from the east,"], ["mai sasae ma sisifo,", "and from the west,"], ["mai le itu i matu ma le itu i toga.", "from the north, and from the south."]]},
  {num:4,words:[["Na feseai i latou i le vao, i le ala e lei uia;", "They wandered in the wilderness in a solitary way;"], ["e lei maua e i latou se aai e nonofo ai.", "they found no city to dwell in."]]},
  {num:5,words:[["Sa matelaina i latou, ma fia inu,", "Hungry and thirsty,"], ["na lailoa o latou loto i totonu ia i latou.", "their soul fainted in them."]]},
  {num:6,words:[["Ona alalaga lea o i latou ia Ieova i lo latou puapuaga;", "Then they cried unto the LORD in their trouble,"], ["na ia laveai ia te i latou nai o latou tiga.", "and he delivered them out of their distresses."]]},
  {num:7,words:[["Na ia ta'ita'iina foi i latou i le ala tonu,", "And he led them forth by the right way,"], ["ina ia latou o atu ai i se aai e nonofo ai.", "that they might go to a city of habitation."]]},
  {num:8,words:[["Ia vivii atu i latou ia Ieova ona o lona alofa,", "Oh that men would praise the LORD for his goodness,"], ["ma ona vavega na fai i le fanau a tagata.", "and for his wonderful works to the children of men!"]]},
  {num:9,words:[["Auā ua na faamălie i le tagata fia inu,", "For he satisfieth the longing soul,"], ["o le tagata matelaina foi ua ma'ona mai ia te ia i le mea lelei.", "and filleth the hungry soul with goodness."]]},
  {num:10,words:[["O e nonofo i le pouliuli ma le ata o le oti,", "Such as sit in darkness and in the shadow of death,"], ["e ua noanoatia i le tiga ma le uamea;", "being bound in affliction and iron;"]]},
  {num:11,words:[["auā na latou fouvale i afioga a le Atua,", "Because they rebelled against the words of God,"], ["ma latou 'ino'ino i le pule a lē Silisili ese;", "and contemned the counsel of the most High:"]]},
  {num:12,words:[["o le mea lea na ia faamaulaloina ai o latou loto i le galuega mamafa;", "Therefore he brought down their heart with labour;"], ["na pauu i latou,", "they fell down,"], ["a e leai se fesoasoani.", "and there was none to help."]]},
  {num:13,words:[["Ona latou alalaga atu lea ia Ieova i lo latou puapuaga;", "Then they cried unto the LORD in their trouble,"], ["na ia faaolaina i latou nai o latou tiga.", "and he saved them out of their distresses."]]},
  {num:14,words:[["Na ia aumaia i latou nai le pouliuli ma le ata o le oti,", "He brought them out of darkness and the shadow of death,"], ["ua na motusia foi o latou noanoaga.", "and brake their bands in sunder."]]},
  {num:15,words:[["Ia vivii atu i latou ia Ieova ona o lona alofa,", "Oh that men would praise the LORD for his goodness,"], ["ma ona vavega na fai i le fanau a tagata.", "and for his wonderful works to the children of men!"]]},
  {num:16,words:[["Auā na ia lepeti i puipui 'apa memea,", "For he hath broken the gates of brass,"], ["ma ua vavaeina faamau uamea.", "and cut the bars of iron in sunder."]]},
  {num:17,words:[["O tagata vālea ona o lo latou solitulafono,", "Fools because of their transgression,"], ["ma la latou amio leaga,", "and because of their iniquities,"], ["ua faatigaina ai i latou;", "are afflicted."]]},
  {num:18,words:[["ua 'ino'ino i latou i mea e 'ai uma lava,", "Their soul abhorreth all manner of meat;"], ["ua faalatalata foi i latou i faitotoa o le oti.", "and they draw near unto the gates of death."]]},
  {num:19,words:[["Ona alalaga lea o i latou ia Ieova i lo latou puapuaga;", "Then they cry unto the LORD in their trouble,"], ["na ia faaolaina i latou nai o latou tiga.", "and he saveth them out of their distresses."]]},
  {num:20,words:[["Ua ia auina atu lana afioga,", "He sent his word,"], ["ma faamalolo ia i latou,", "and healed them,"], ["ma laveaiina ai nai lo latou malaia.", "and delivered them from their destructions."]]},
  {num:21,words:[["Ia vivii atu i latou ia Ieova ona o lona alofa,", "Oh that men would praise the LORD for his goodness,"], ["ma ona vavega na fai i le fanau a tagata.", "and for his wonderful works to the children of men!"]]},
  {num:22,words:[["Ia latou fai taulaga foi i taulaga o le viiga,", "And let them sacrifice the sacrifices of thanksgiving,"], ["ma ta'u atu ma le olioli ana galuega.", "and declare his works with rejoicing."]]},
  {num:23,words:[["O i latou o e folau i vaa i le sami,", "They that go down to the sea in ships,"], ["o e fai galuega i le vasa tele;", "that do business in great waters;"]]},
  {num:24,words:[["o i latou ia latou te vaaia galuega a Ieova,", "These see the works of the LORD,"], ["ma ona vavega e fai i le moana.", "and his wonders in the deep."]]},
  {num:25,words:[["Auā ua fetalai ane ia,", "For he commandeth,"], ["ma faatupuina le afā, ua laga ai ona peau;", "and raiseth the stormy wind,"], ["e o ae i latou i le lagi,", "which lifteth up the waves thereof."]]},
  {num:26,words:[["e toe o ifo i lalo,", "They mount up to the heaven, they go down again to the depths:"], ["ua liu suāvai ai o latou loto i le atuatuvale;", "their soul is melted because of trouble."]]},
  {num:27,words:[["e tautevateva i latou ma tausuai pei o le tagata onā,", "They reel to and fro, and stagger like a drunken man,"], ["ua faaumatia foi o latou atamamai uma lava.", "and are at their wits' end."]]},
  {num:28,words:[["Ona latou alalaga atu lea ia Ieova i lo latou puapuaga;", "Then they cry unto the LORD in their trouble,"], ["ua ia aumaia i latou nai o latou tiga.", "and he bringeth them out of their distresses."]]},
  {num:29,words:[["Ua liua e ia le afā i le malū,", "He maketh the storm a calm,"], ["ua taoto ia te ia le au peau.", "so that the waves thereof are still."]]},
  {num:30,words:[["Ona latou fiafia lea, auā ua malū;", "Then are they glad because they be quiet;"], ["ua na ta'ita'iina foi i latou i le taulaga na latou loto i ai.", "so he bringeth them unto their desired haven."]]},
  {num:31,words:[["Ia vivii atu i latou ia Ieova ona o lona alofa,", "Oh that men would praise the LORD for his goodness,"], ["ma ona vavega na fai i le fanau a tagata.", "and for his wonderful works to the children of men!"]]},
  {num:32,words:[["Ia latou faaneenee ia te ia i le faapotopotoga o le nuu,", "Let them exalt him also in the congregation of the people,"], ["ma ia vivii atu ia te ia i le saofaiga a toeaina.", "and praise him in the assembly of the elders."]]},
  {num:33,words:[["E liua e ia o vaitafe e fai ma vao,", "He turneth rivers into a wilderness,"], ["o vaipuna foi e fai ma fanua naumati;", "and the watersprings into dry ground;"]]},
  {num:34,words:[["o le fanua lafulemu e fai ma mea lafulafua,", "A fruitful land into barrenness,"], ["ona o le amio leaga a e nonofo ai.", "for the wickedness of them that dwell therein."]]},
  {num:35,words:[["E liua e ia le vao e fai ma vailepa,", "He turneth the wilderness into a standing water,"], ["o le fanua naumati foi e fai ma vaipuna.", "and dry ground into watersprings."]]},
  {num:36,words:[["Na te faanofo ai foi e ua matelaina;", "And there he maketh the hungry to dwell,"], ["e sauniuni ai foi e i latou o le aai e nonofo ai;", "that they may prepare a city for habitation;"]]},
  {num:37,words:[["ma latou lulu ai saito i fanua,", "And sow the fields,"], ["ma totō ai tovine,", "and plant vineyards,"], ["e fua mai ai ona fua e tele.", "which may yield fruits of increase."]]},
  {num:38,words:[["E faamanuia foi e ia i latou,", "He blesseth them also,"], ["e matuā faatoateleina foi i latou;", "so that they are multiplied greatly;"], ["e le faaitiitia foi e ia a latou manu.", "and suffereth not their cattle to decrease."]]},
  {num:39,words:[["Ua faatoaitiitia foi i latou ma faamaulaloina,", "Again,"], ["ona o le faasaua,", "they are minished and brought low through oppression,"], ["ma le agaleagaina,", "affliction,"], ["ma le faanoanoa.", "and sorrow."]]},
  {num:40,words:[["E faainosia e ia o alii,", "He poureth contempt upon princes,"], ["ma faaseseina i latou i le mea gaogao,", "and causeth them to wander in the wilderness,"], ["e le o i ai se ala.", "where there is no way."]]},
  {num:41,words:[["A e faaeaina e ia o le ua mativa nai le puapuaga, ma tuuina atu o aiga mo ia ,", "Yet setteth he the poor on high from affliction,"], ["e pei o se lafu mamoe.", "and maketh him families like a flock."]]},
  {num:42,words:[["E iloa atu e ua amiotonu ma latou olioli ai;", "The righteous shall see it, and rejoice:"], ["a o e amio leaga uma lava e mapuni ai o latou gutu.", "and all iniquity shall stop her mouth."]]},
  {num:43,words:[["O le ua poto na te tausia nei mea;", "Whoso is wise, and will observe these things,"], ["e iloa e i latou o mea alofa a Ieova.", "even they shall understand the lovingkindness of the LORD."]]},
];
renderVerseSet(psa_ch_107_Verses, 'psa-ch107-verses');

var psa_ch_108_Verses = [
  {num:1,words:[["Le Atua e,", "O God,"], ["ua mau lo'u nei loto,", "my heart is fixed;"], ["ou te pese lava,", "I will sing and give praise,"], ["e fai pesega lo'u lava mamalu.", "even with my glory."]]},
  {num:2,words:[["Ala mai ia le napeli ma le kitara,", "Awake, psaltery and harp:"], ["ou te ala i le taeao lava.", "I myself will awake early."]]},
  {num:3,words:[["Ieova e,", "I will praise thee,"], ["ou te vivii ia te oe i luma o le nuu,", "O LORD, among the people:"], ["ou te fai pesega foi ia te oe i luma o tagata.", "and I will sing praises unto thee among the nations."]]},
  {num:4,words:[["Auā ua sili lou alofa i le maualuga o le lagi,", "For thy mercy is great above the heavens:"], ["o lou faamaoni foi ua oo i ao.", "and thy truth reacheth unto the clouds."]]},
  {num:5,words:[["Le Atua e,", "Be thou exalted,"], ["ia faasilisiliina oe i le lagi,", "O God, above the heavens:"], ["ia i ai i le lalolagi uma lou mamalu.", "and thy glory above all the earth;"]]},
  {num:6,words:[["Ina ia laveaiina au pele,", "That thy beloved may be delivered:"], ["ia e faaola mai i lou aao taumatau,", "save with thy right hand,"], ["ma ia e tali mai ia te au.", "and answer me."]]},
  {num:7,words:[["Ua fetalai mai le Atua i lona malumalu,", "God hath spoken in his holiness;"], ["Ou te fiafia,", "I will rejoice,"], ["ou te tofitofia Sekema,", "I will divide Shechem,"], ["o le vanu o Sukota ou te fuafuatia lea.", "and mete out the valley of Succoth."]]},
  {num:8,words:[["O loo ia te au Kiliata,", "Gilead is mine;"], ["o loo ia te au Manase;", "Manasseh is mine;"], ["e fai foi Efaraima ma malosi o lo'u ulu; o la'u faipule,", "Ephraim also is the strength of mine head;"], ["o Iuta lea.", "Judah is my lawgiver;"]]},
  {num:9,words:[["O Moapi,", "Moab is my washpot;"], ["o le ipu lea ou te mulumulu ai; ou te lafoina lo'u seevae i Etoma;", "over Edom will I cast out my shoe;"], ["ou te alaga i lo'u manumalo ia Filisitia.", "over Philistia will I triumph."]]},
  {num:10,words:[["O ai se na te avea a'u i le aai nofo 'olo? O ai se na te ta'ita'iina a'u i Etoma?", "Who will bring me into the strong city? who will lead me into Edom?"]]},
  {num:11,words:[["E le o oe ea le Atua,", "Wilt not thou,"], ["sa e lafoaiina mai i matou,", "O God,"], ["ma ua e le afio atu,", "who hast cast us off? and wilt not thou,"], ["o oe le Atua e,", "O God,"], ["faatasi ma la matou itu taua?", "go forth with our hosts?"]]},
  {num:12,words:[["Foai mai ia le fesoasoani ia te i matou i le puapuaga,", "Give us help from trouble:"], ["auā e le aoga le olataga mai tagata.", "for vain is the help of man."]]},
  {num:13,words:[["O le Atua lava e fai ai i matou ma toa,", "Through God we shall do valiantly:"], ["auā o ia lava na te solia e ua faasaua mai ia i matou.", "for he it is that shall tread down our enemies."]]},
];
renderVerseSet(psa_ch_108_Verses, 'psa-ch108-verses');

var psa_ch_109_Verses = [
  {num:1,words:[["Le Atua e, o lē ou te vivii atu i ai,", "Hold not thy peace,"], ["aua ne'i e le tali mai.", "O God of my praise;"]]},
  {num:2,words:[["Auā ua faamaga mai ia te au le gutu o lē amio leaga, ma le gutu o lē taupelopelo;", "For the mouth of the wicked and the mouth of the deceitful are opened against me:"], ["ua latou fai upu mai ia te au i le laulaufaiva pepelo.", "they have spoken against me with a lying tongue."]]},
  {num:3,words:[["Ua latou siosio ia te au ma upu faa'ino'ino,", "They compassed me about also with words of hatred;"], ["ma ua latou tau fua mai le taua ia te au.", "and fought against me without a cause."]]},
  {num:4,words:[["Ua fai a'u mo latou fili e taui a'i lo'u alofa; a o a'u nei,", "For my love they are my adversaries:"], ["ou te tatalo.", "but I give myself unto prayer."]]},
  {num:5,words:[["Ua tuuina mai i latou ia te au o le leaga e taui a'i le lelei,", "And they have rewarded me evil for good,"], ["ma le 'ino'ino e taui a'i lo'u alofa.", "and hatred for my love."]]},
  {num:6,words:[["Ia e tofia se ua amio leaga e pule ia te ia,", "Set thou a wicked man over him:"], ["ma se ua fai o ia ma fili e tu i lona itu taumatau.", "and let Satan stand at his right hand."]]},
  {num:7,words:[["Ia faasalaina o ia pe a faamasinoina;", "When he shall be judged, let him be condemned:"], ["ia fai foi ma agasala lana tatalo.", "and let his prayer become sin."]]},
  {num:8,words:[["Ia faaitiitia ona aso;", "Let his days be few;"], ["ia avea lona faiva mo se tasi.", "and let another take his office."]]},
  {num:9,words:[["Ia avea ana fanau e aumatuā,", "Let his children be fatherless,"], ["o lana avā foi ia fai ma fafine ua oti lana tane.", "and his wife a widow."]]},
  {num:10,words:[["Ia feoai solo lana fanau,", "Let his children be continually vagabonds,"], ["ma aiisi,", "and beg:"], ["ma ia sailiili mea e 'ai i a latou mea ua faatafunaina.", "let them seek their bread also out of their desolate places."]]},
  {num:11,words:[["Ia maua ana mea uma lava e le ua ia aitalafu i ai;", "Let the extortioner catch all that he hath;"], ["ia faoa foi e tagata ese o mea ua na galue ai.", "and let the strangers spoil his labour."]]},
  {num:12,words:[["Aua ne'i faaoo atu e se tasi le alofa ia te ia;", "Let there be none to extend mercy unto him:"], ["aua foi ne'i agalelei atu se tasi i lana fanau ua aumatuā.", "neither let there be any to favour his fatherless children."]]},
  {num:13,words:[["Ia le au lona gafa;", "Let his posterity be cut off;"], ["ia sōloiesea o latou igoa i le tupulaga amuli.", "and in the generation following let their name be blotted out."]]},
  {num:14,words:[["Ia manatua le amio leaga a ona tamā i luma o Ieova;", "Let the iniquity of his fathers be remembered with the LORD;"], ["aua ne'i sōloia le agasala a lona tinā;", "and let not the sin of his mother be blotted out."]]},
  {num:15,words:[["ia i ai pea lava i luma o Ieova,", "Let them be before the LORD continually,"], ["ina ia tineia e ia o latou faamanatuga ai le lalolagi.", "that he may cut off the memory of them from the earth."]]},
  {num:16,words:[["Auā e lei manatu ia e fai meaalofa,", "Because that he remembered not to shew mercy,"], ["a ua faasaua i le tagata ua puapuagatia ma le mativa,", "but persecuted the poor and needy man,"], ["ina ia fasiotia e ia le ua loto momomo.", "that he might even slay the broken in heart."]]},
  {num:17,words:[["Na loto o ia i le fetuu,", "As he loved cursing,"], ["ia oo foi ia te ia;", "so let it come unto him:"], ["na le fiafia foi o ia i le faamanuia,", "as he delighted not in blessing,"], ["o lea ia vava mamao ai ma ia.", "so let it be far from him."]]},
  {num:18,words:[["Na pulupulu o ia i le fetuu e pei o se ie pulupulu,", "As he clothed himself with cursing like as with his garment,"], ["ia oo foi lea e pei o le vai i totonu ia te ia,", "so let it come into his bowels like water,"], ["ia pei o le suāuu foi i ona ivi.", "and like oil into his bones."]]},
  {num:19,words:[["Ia ia te ia e pei o le ofu ua ofu ai o ia,", "Let it be unto him as the garment which covereth him,"], ["ma le fusi ua fusi ai o ia e le aunoa.", "and for a girdle wherewith he is girded continually."]]},
  {num:20,words:[["O le taui lava lea mai ia Ieova i e fai a'u mo latou fili,", "Let this be the reward of mine adversaries from the LORD,"], ["ma e ua fai upu leaga ia oti ai a'u.", "and of them that speak evil against my soul."]]},
  {num:21,words:[["A o oe,", "But do thou for me,"], ["Ieova e,", "O GOD the Lord,"], ["lo'u Alii, ia e aga lelei mai ia te au ona o lou suafa;", "for thy name's sake:"], ["auā e lelei lou alofa,", "because thy mercy is good,"], ["ia e laveai mai ia te au.", "deliver thou me."]]},
  {num:22,words:[["Auā o a'u ua puapuagatia ma le mativa,", "For I am poor and needy,"], ["ua manua lo'u loto i totonu ia te au.", "and my heart is wounded within me."]]},
  {num:23,words:[["Ua ou mavae atu pei o le ata ua lafoia;", "I am gone like the shadow when it declineth:"], ["ua lulueseina a'u e pei o le sē akerise.", "I am tossed up and down as the locust."]]},
  {num:24,words:[["Ua vaivai o'u tulivae i le anapogi,", "My knees are weak through fasting;"], ["ma ua tinovale lava a'u.", "and my flesh faileth of fatness."]]},
  {num:25,words:[["O a'u nei foi ua faalumaina a'u e i latou;", "I became also a reproach unto them:"], ["e vaai mai i latou ia te au ma lialiai o latou ulu.", "when they looked upon me they shaked their heads."]]},
  {num:26,words:[["Ieova e,", "Help me,"], ["lo'u Atua, ia e fesoasoani mai ia te au;", "O LORD my God:"], ["ia e faaola mai ia te au e tusa ma lou alofa;", "O save me according to thy mercy:"]]},
  {num:27,words:[["ina ia iloa ai e i latou,", "That they may know that this is thy hand;"], ["o lou aao lava lenei;", "that thou,"], ["o oe, Ieova e,", "LORD,"], ["na e faia lava.", "hast done it."]]},
  {num:28,words:[["O i latou,", "Let them curse,"], ["ia fetuu mai pea i latou, a o oe,", "but bless thou:"], ["ia e faamanuia mai;", "when they arise,"], ["ua latou tutū mai, a ia mamā i latou,", "let them be ashamed;"], ["a ia fiafia lava lau auauna.", "but let thy servant rejoice."]]},
  {num:29,words:[["Ia oofu i le masiasi e ua fai a'u mo latou fili,", "Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion,"], ["ia ufitia i latou i lo latou lava ma pei o le ofu tele.", "as with a mantle."]]},
  {num:30,words:[["Ou te matuā vivii atu ia Ieova i lo'u gutu,", "I will greatly praise the LORD with my mouth; yea,"], ["ou te faaneenee atu ia te ia i totonu o le toatele.", "I will praise him among the multitude."]]},
  {num:31,words:[["Auā e tulai o ia i le lima taumatau o le ua puapuagatia,", "For he shall stand at the right hand of the poor,"], ["ina ia faaola ia te ia i e faasala ia te ia ia oti.", "to save him from those that condemn his soul."]]},
];
renderVerseSet(psa_ch_109_Verses, 'psa-ch109-verses');

var psa_ch_110_Verses = [
  {num:1,words:[["Ua tŭlei mai le afioga a Ieova i lo'u Alii,", "The LORD said unto my Lord,"], ["Ia e nofo i lo'u itu taumatau,", "Sit thou at my right hand,"], ["seia ou faia e ua ita ia te oe ma mea e tu ai ou vae.", "until I make thine enemies thy footstool."]]},
  {num:2,words:[["E auina atu e Ieova lou tootoo malosi mai Siona? Ia pule oe i totonu o e ita ia te oe.", "The LORD shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies."]]},
  {num:3,words:[["E fai taulaga ma le loto ou tagata i le aso o lou malosi i au mea paia e matagofie mai le manava o le vave ao;", "Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning:"], ["e ia te oe le sau o lou taulealea.", "thou hast the dew of thy youth."]]},
  {num:4,words:[["Ua tauto Ieova,", "The LORD hath sworn,"], ["e le salamo lava ia, O oe lava o le ositaulaga e faavavau,", "and will not repent,"], ["e uiga faatasi ma Mekisateko.", "Thou art a priest for ever after the order of Melchizedek."]]},
  {num:5,words:[["O le Alii o loo i lou itu taumatau, e fasi e ia o tupu i le aso o lona toasa.", "The Lord at thy right hand shall strike through kings in the day of his wrath."]]},
  {num:6,words:[["E faamasino e ia o nuu ese,", "He shall judge among the heathen,"], ["e faatumuina e ia i tino o tagata ua oti,", "he shall fill the places with the dead bodies;"], ["e foaina e ia ulu o nuu e tele.", "he shall wound the heads over many countries."]]},
  {num:7,words:[["E inu ia i le alia i le ala,", "He shall drink of the brook in the way:"], ["o le mea lea e ea ai lona ao.", "therefore shall he lift up the head."]]},
];
renderVerseSet(psa_ch_110_Verses, 'psa-ch110-verses');

var psa_ch_111_Verses = [
  {num:1,words:[["Ia outou vivii atu ia Ioa.", "Praise ye the LORD."], ["Ou te vivii atu ia Ieova ma le loto atoa i le saofaiga a e amiotonu,", "I will praise the LORD with my whole heart, in the assembly of the upright,"], ["atoa ma le faapotopotoga.", "and in the congregation."]]},
  {num:2,words:[["O mea ua faia e Ieova, o mea tetele lava ia,", "The works of the LORD are great,"], ["o loo sailia e i latou uma lava o e fiafia i ai.", "sought out of all them that have pleasure therein."]]},
  {num:3,words:[["O mea e viia ma le matagofie o ana galuega ia,", "His work is honourable and glorious:"], ["e tumau foi lana amiotonu e faavavau.", "and his righteousness endureth for ever."]]},
  {num:4,words:[["Ua fai ma faamanatuga ona vavega;", "He hath made his wonderful works to be remembered:"], ["o loo alofa fua mai ma alofa mutimuti vale mai Ieova.", "the LORD is gracious and full of compassion."]]},
  {num:5,words:[["Ua foaiina mai e ia le mea e 'ai i e matatau ia te ia;", "He hath given meat unto them that fear him:"], ["e manatua e ia lana feagaiga e faavavau.", "he will ever be mindful of his covenant."]]},
  {num:6,words:[["Ua na faaali atu le mana o ana galuega i lona nuu,", "He hath shewed his people the power of his works,"], ["ina ua avatu ia i latou le tofi o nuu ese.", "that he may give them the heritage of the heathen."]]},
  {num:7,words:[["O galuega a ona aao e moni ia ma le tonu;", "The works of his hands are verity and judgment;"], ["e faamaoni ana feau uma lava.", "all his commandments are sure."]]},
  {num:8,words:[["E faatumauina ia mea e faavavau faavavau lava;", "They stand fast for ever and ever,"], ["ua faia i le faamaoni ma le tonu.", "and are done in truth and uprightness."]]},
  {num:9,words:[["Na ia avatu le togiola mo lona nuu;", "He sent redemption unto his people:"], ["na poloai i lana feagaiga ia faavavau lava;", "he hath commanded his covenant for ever:"], ["e paia ma le matautia lona suafa.", "holy and reverend is his name."]]},
  {num:10,words:[["O le mata'u ia Ieova,", "The fear of the LORD is the beginning of wisdom:"], ["o le amataga lea o le poto; ua i ai le mafaufau lelei ia te i latou uma o e fai ia mea;", "a good understanding have all they that do his commandments:"], ["e tumau lona viiga e faavavau lava.", "his praise endureth for ever."]]},
];
renderVerseSet(psa_ch_111_Verses, 'psa-ch111-verses');

var psa_ch_112_Verses = [
  {num:1,words:[["Ia outou vivii atu ia Ioa. Amuia le tagata o lē mata'u ia Ieova,", "Praise ye the LORD. Blessed is the man that feareth the LORD,"], ["o loo o fiafia tele i ana poloaiga.", "that delighteth greatly in his commandments."]]},
  {num:2,words:[["E malolosi lana fanau i le nuu;", "His seed shall be mighty upon earth:"], ["e manuia le tupulaga o e amiotonu.", "the generation of the upright shall be blessed."]]},
  {num:3,words:[["E i lona fale le oloa ma mea e tele;", "Wealth and riches shall be in his house:"], ["e tumau foi lana amiotonu e faavavau.", "and his righteousness endureth for ever."]]},
  {num:4,words:[["E alu ae le malamalama i le pouliuli mo e ua amiotonu;", "Unto the upright there ariseth light in the darkness:"], ["o ia o le alofa fua,", "he is gracious,"], ["ma lē alofa mutimuti vale,", "and full of compassion,"], ["ma lē amiotonu.", "and righteous."]]},
  {num:5,words:[["E manuia le tagata ua alofa fua,", "A good man sheweth favour,"], ["ma tuuina atu ana mea i e nono mai;", "and lendeth:"], ["na te tausia ana mea ma le faautauta tonu.", "he will guide his affairs with discretion."]]},
  {num:6,words:[["E moni, e le faagaeetia o ia e faavavau;", "Surely he shall not be moved for ever:"], ["e manatua le tagata amiotonu e faavavau.", "the righteous shall be in everlasting remembrance."]]},
  {num:7,words:[["E le mata'u o ia i le tala leaga;", "He shall not be afraid of evil tidings:"], ["ua mau lona loto,", "his heart is fixed,"], ["o loo faalagolago ia Ieova.", "trusting in the LORD."]]},
  {num:8,words:[["Ua mausali lona loto,", "His heart is established,"], ["e le fefe lava ia,", "he shall not be afraid,"], ["seia iloa atu e ia le taui o e ita ia te ia.", "until he see his desire upon his enemies."]]},
  {num:9,words:[["Ua faasalalauina e ia ana mea ,", "He hath dispersed,"], ["ua avatua e ia i e matitiva;", "he hath given to the poor;"], ["e tumau lana amiotonu e faavavau;", "his righteousness endureth for ever;"], ["e faamaualugaina lona nifo ma le mamalu.", "his horn shall be exalted with honour."]]},
  {num:10,words:[["E iloa atu ai e le tagata amio leaga,", "The wicked shall see it,"], ["ona ita ai lea o ia;", "and be grieved;"], ["e lilivau ona nifo,", "he shall gnash with his teeth,"], ["e liu suāvai lava ia;", "and melt away:"], ["e faaumatia le manao o e amio leaga.", "the desire of the wicked shall perish."]]},
];
renderVerseSet(psa_ch_112_Verses, 'psa-ch112-verses');

var psa_ch_113_Verses = [
  {num:1,words:[["Ia outou vivii atu ia Ioa.", "Praise ye the LORD."], ["Vivii atu ia outou o auauna a Ieova;", "Praise, O ye servants of the LORD,"], ["vivii atu ia i le suafa o Ieova.", "praise the name of the LORD."]]},
  {num:2,words:[["Ia faafetaia le suafa o Ieova, e amata mai nei lava, a ia oo i le faavavau.", "Blessed be the name of the LORD from this time forth and for evermore."]]},
  {num:3,words:[["Ia viia le suafa o Ieova, e afua mai i le mea e alu ae ai le la, e oo atu i le mea e goto ai.", "From the rising of the sun unto the going down of the same the LORD'S name is to be praised."]]},
  {num:4,words:[["Ua sili lava Ieova i luga o nuu ese uma lava,", "The LORD is high above all nations,"], ["o lona mamalu ua sili i le lagi.", "and his glory above the heavens."]]},
  {num:5,words:[["O ai ea sē tusa ma Ieova lo tatou Atua,", "Who is like unto the LORD our God,"], ["o lē faamaualugaina e ia lona afioaga?", "who dwelleth on high,"]]},
  {num:6,words:[["O lē faamaulaloina e ia ia ia e silasila mai i le lagi atoa ma le lalolagi.", "Who humbleth himself to behold the things that are in heaven, and in the earth!"]]},
  {num:7,words:[["Na te faatulaiina mai le tagatā lautele nai le efuefu,", "He raiseth up the poor out of the dust,"], ["na te faaeaina le ua mativa nai le faatăfuna;", "and lifteth the needy out of the dunghill;"]]},
  {num:8,words:[["ina ia faanofo faatasi o ia ma alii,", "That he may set him with princes,"], ["o alii lava o lona nuu;", "even with the princes of his people."]]},
  {num:9,words:[["o ia e avea ai le fafine pa ia nofo o ia ma le olioli,", "He maketh the barren woman to keep house,"], ["o le tinā o tama. Ia outou vivii atu ia Ioa.", "and to be a joyful mother of children. Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_113_Verses, 'psa-ch113-verses');

var psa_ch_114_Verses = [
  {num:1,words:[["Na alu atu Isaraelu nai Aikupito,", "When Israel went out of Egypt,"], ["o le aiga o Iakopo nai le nuu gagana ese;", "the house of Jacob from a people of strange language;"]]},
  {num:2,words:[["ona fai lea o Iuta mona nuu paia,", "Judah was his sanctuary,"], ["o Isaraelu o le na ia pule i ai.", "and Israel his dominion."]]},
  {num:3,words:[["Ua iloa atu e le sami,", "The sea saw it,"], ["ona sola ai lea;", "and fled:"], ["ua liliu i tua Ioritana.", "Jordan was driven back."]]},
  {num:4,words:[["Ua feosofai mauga faapei o mamoe poa,", "The mountains skipped like rams,"], ["ma mauga iti pei o tamai mamoe.", "and the little hills like lambs."]]},
  {num:5,words:[["Le sami e,", "What ailed thee,"], ["se a ea le mea na e sola ai? O oe Ioritana e,", "O thou sea, that thou fleddest? thou Jordan,"], ["se a le mea na e liliu ai i tua?", "that thou wast driven back?"]]},
  {num:6,words:[["O outou mauga na outou feosofai faapei o mamoe poa i se a? Ma outou mauga iti pei o tamai mamoe i se a?", "Ye mountains, that ye skipped like rams; and ye little hills, like lambs?"]]},
  {num:7,words:[["Le eleele e,", "Tremble,"], ["ina gatete ia oe i luma o le Alii,", "thou earth, at the presence of the Lord,"], ["i luma o le Atua o Iakopo;", "at the presence of the God of Jacob;"]]},
  {num:8,words:[["o le na te liua le papa e fai ma vailepa;", "Which turned the rock into a standing water,"], ["o le papa alā e fai ma vaipuna.", "the flint into a fountain of waters."]]},
];
renderVerseSet(psa_ch_114_Verses, 'psa-ch114-verses');

var psa_ch_115_Verses = [
  {num:1,words:[["Aua ne'i ia te i matou,", "Not unto us,"], ["Ieova e,", "O LORD,"], ["aua ne'i ia te i matou,", "not unto us, but unto thy name give glory,"], ["a ia tuuina atu le viiga i lou suafa,", "for thy mercy,"], ["ona o lou alofa ma lou faamaoni.", "and for thy truth's sake."]]},
  {num:2,words:[["Se a le mea e fai mai ai nuu ese,", "Wherefore should the heathen say,"], ["O ifea o i ai lo latou Atua?", "Where is now their God?"]]},
  {num:3,words:[["A o lo matou Atua, o i le lagi lava ia;", "But our God is in the heavens:"], ["ua faia e ia o mea uma ua ia finagalo i ai.", "he hath done whatsoever he hath pleased."]]},
  {num:4,words:[["O latou tupua, o ario ma auro ia,", "Their idols are silver and gold,"], ["o le galuega a lima o tagata.", "the work of men's hands."]]},
  {num:5,words:[["E fai o latou gutu,", "They have mouths,"], ["a e le feganavai i latou;", "but they speak not:"], ["e fai o latou mata,", "eyes have they,"], ["a e le vaai i latou;", "but they see not:"]]},
  {num:6,words:[["e fai o latou taliga,", "They have ears,"], ["a e le faalogo i latou;", "but they hear not:"], ["e fai o latou isu,", "noses have they,"], ["a e le sogisogi i latou;", "but they smell not:"]]},
  {num:7,words:[["e fai o latou lima,", "They have hands,"], ["a e le fetagofi i latou;", "but they handle not:"], ["e fai o latou vae,", "feet have they,"], ["a e le savavali i latou;", "but they walk not:"], ["e leai se leo i o latou faaī.", "neither speak they through their throat."]]},
  {num:8,words:[["O e faia ia mea ua tutusa lava ma i latou;", "They that make them are like unto them;"], ["o i latou uma o e faatuatua i ai.", "so is every one that trusteth in them."]]},
  {num:9,words:[["Isaraelu e,", "O Israel,"], ["ia e faatuatua ia Ieova;", "trust thou in the LORD:"], ["o ia lava lo latou fesoasoani ma lo latou talita.", "he is their help and their shield."]]},
  {num:10,words:[["Le aiga o Arona e,", "O house of Aaron,"], ["faatuatua ia outou ia Ieova;", "trust in the LORD:"], ["o ia lava lo latou fesoasoani ma lo latou talita.", "he is their help and their shield."]]},
  {num:11,words:[["Outou na,", "Ye that fear the LORD,"], ["o e matatau ia Ieova, ina faatuatua ia ia Ieova;", "trust in the LORD:"], ["o ia lava lo latou fesoasoani ma lo latou talita.", "he is their help and their shield."]]},
  {num:12,words:[["Ua manatu mai Ieova ia i tatou;", "The LORD hath been mindful of us:"], ["e faamanuina mai e ia;", "he will bless us;"], ["e faamanuia e ia le aiga o Isaraelu;", "he will bless the house of Israel;"], ["e faamanuia e ia le aiga o Arona.", "he will bless the house of Aaron."]]},
  {num:13,words:[["E faamanuia mai e ia i e matatau ia Ieova,", "He will bless them that fear the LORD,"], ["o tagatānuu atoa ma alii.", "both small and great."]]},
  {num:14,words:[["E faaopoopoina ia te outou e Ieova,", "The LORD shall increase you more and more,"], ["o outou atoa ma la outou fanau.", "you and your children."]]},
  {num:15,words:[["O loo faamanuia mai outou e Ieova, o le na faia le lagi atoa ma le lalolagi.", "Ye are blessed of the LORD which made heaven and earth."]]},
  {num:16,words:[["O le lagi,", "The heaven,"], ["o le lagi lava,", "even the heavens,"], ["e ia Ieova lea;", "are the LORD'S:"], ["a ua tuuina mai e ia le lalolagi mo le fanau a tagata.", "but the earth hath he given to the children of men."]]},
  {num:17,words:[["E le vivii atu ia Ioa e ua oti,", "The dead praise not the LORD,"], ["ma i latou uma o e ō ifo i le mea taaligoligoa.", "neither any that go down into silence."]]},
  {num:18,words:[["A o i tatou nei, tatou te faamanū atu ia Ioa, e afua mai nei lava, a e oo i le faavavau.", "But we will bless the LORD from this time forth and for evermore."], ["Ia outou vivii atu ia Ioa.", "Praise the LORD."]]},
];
renderVerseSet(psa_ch_115_Verses, 'psa-ch115-verses');

var psa_ch_116_Verses = [
  {num:1,words:[["Ou te alofa,", "I love the LORD,"], ["auā ua faafofoga mai Ieova i lo'u leo ma a'u aioi.", "because he hath heard my voice and my supplications."]]},
  {num:2,words:[["Auā na liliu mai ona fofoga ia te au,", "Because he hath inclined his ear unto me,"], ["o lea ou te valaau ai ia te ia i lo'u olaga.", "therefore will I call upon him as long as I live."]]},
  {num:3,words:[["Na siomia a'u i mailei e oti ai;", "The sorrows of death compassed me,"], ["na maua a'u e puapuaga o le tuugamau;", "and the pains of hell gat hold upon me:"], ["na maua a'u e le puapuaga ma le faanoanoa.", "I found trouble and sorrow."]]},
  {num:4,words:[["Ona ou valaau atu lea i le suafa o Ieova,", "Then called I upon the name of the LORD;"], ["Ieova e,", "O LORD, I beseech thee,"], ["ou te aioi atu ia e laveai mai ia te au.", "deliver my soul."]]},
  {num:5,words:[["O Ieova o lē alofa fua ma lē amiotonu ia;", "Gracious is the LORD,"], ["o lo tatou Atua,", "and righteous; yea,"], ["e alofa mutimuti vale ia.", "our God is merciful."]]},
  {num:6,words:[["E tausi e Ieova i e faigofie;", "The LORD preserveth the simple:"], ["sa vaivai a'u,", "I was brought low,"], ["ona faaola mai lea o ia ia te au.", "and he helped me."]]},
  {num:7,words:[["Lo'u agaga e,", "Return unto thy rest,"], ["ia e foi atu i lou mapusaga;", "O my soul;"], ["auā ua agalelei mai Ieova ia te oe.", "for the LORD hath dealt bountifully with thee."]]},
  {num:8,words:[["Auā ua e laveai mai ia te au nai le oti,", "For thou hast delivered my soul from death,"], ["o o'u mata ne'i tagi,", "mine eyes from tears,"], ["ma o'u vae ne'i paū.", "and my feet from falling."]]},
  {num:9,words:[["Ou te savali i luma o Ieova i nuu o tagata ola.", "I will walk before the LORD in the land of the living."]]},
  {num:10,words:[["Na ou faatuatua,", "I believed,"], ["o le mea lea na ou tautala atu ai;", "therefore have I spoken:"], ["o a'u nei sa matuā tigaina a'u.", "I was greatly afflicted:"]]},
  {num:11,words:[["O a'u nei sa ou faapea atu i lo'u popole,", "I said in my haste,"], ["Ua pepelo tagata uma lava.", "All men are liars."]]},
  {num:12,words:[["Se a se mea ou te taui a'i atu ia Ieova ona o lona agalelei mai uma lava ia te au?", "What shall I render unto the LORD for all his benefits toward me?"]]},
  {num:13,words:[["Ou te avae le ipu o le olataga,", "I will take the cup of salvation,"], ["ma ou valaau atu i le suafa o Ieova.", "and call upon the name of the LORD."]]},
  {num:14,words:[["Ou te avatua ia Ieova i luma o lona nuu uma lava o Ieova na ou tauto ai.", "I will pay my vows unto the LORD now in the presence of all his people."]]},
  {num:15,words:[["E silisili i le manatu o Ieova le oti o ona tagata amio Atua.", "Precious in the sight of the LORD is the death of his saints."]]},
  {num:16,words:[["Ou te aioi atu,", "O LORD,"], ["Ieova e,", "truly I am thy servant;"], ["o lau auauna lava a'u,", "I am thy servant,"], ["o lau auauna a'u nei,", "and the son of thine handmaid:"], ["o le tama a lau auauna fafine.", "thou hast loosed my bonds."]]},
  {num:17,words:[["Ua e tatala mai i o'u noanoaga. Ou te fai le taulaga o le viiga ia te oe,", "I will offer to thee the sacrifice of thanksgiving,"], ["ou te valaau atu foi i le suafa o Ieova.", "and will call upon the name of the LORD."]]},
  {num:18,words:[["Ou te avatua ia Ieova i luma o lona nuu uma lava o mea na ou tauto ai, i lotoā o le fale o Ieova,", "I will pay my vows unto the LORD now in the presence of all his people,"]]},
  {num:19,words:[["i totonu lava ia te oe,", "In the courts of the LORD'S house, in the midst of thee,"], ["Ierusalema e.", "O Jerusalem."], ["Ia outou vivii atu ia Ioa.", "Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_116_Verses, 'psa-ch116-verses');

var psa_ch_117_Verses = [
  {num:1,words:[["Vivii atu ia Ieova outou o nuu ese uma lava;", "O praise the LORD, all ye nations:"], ["faaneenee atu ia te ia outou tagata uma lava.", "praise him, all ye people."]]},
  {num:2,words:[["Auā ua tele lava lona alofa mai ia te i tatou;", "For his merciful kindness is great toward us:"], ["o le faamaoni foi o Ieova e faavavau lava lea. Ia outou vivii atu ia Ioa.", "and the truth of the LORD endureth for ever. Praise ye the LORD."]]},
];
renderVerseSet(psa_ch_117_Verses, 'psa-ch117-verses');

var psa_ch_118_Verses = [
  {num:1,words:[["Vivii atu ia outou ia Ieova,", "O give thanks unto the LORD;"], ["auā e lelei o ia;", "for he is good:"], ["auā e faavavau lava lona alofa.", "because his mercy endureth for ever."]]},
  {num:2,words:[["Ia faapea atu lava Isaraelu,", "Let Israel now say,"], ["e faavavau lava lona alofa.", "that his mercy endureth for ever."]]},
  {num:3,words:[["Ia faapea atu lava le aiga o Arona,", "Let the house of Aaron now say,"], ["e faavavau lava lona alofa.", "that his mercy endureth for ever."]]},
  {num:4,words:[["Ia faapea atu lava i latou o e matatau ia Ieova,", "Let them now that fear the LORD say,"], ["e faavavau lava lona alofa.", "that his mercy endureth for ever."]]},
  {num:5,words:[["Na ou valaau atu ia Ioa i lo'u puapuaga;", "I called upon the LORD in distress:"], ["na tali mai Ioa ia te au,", "the LORD answered me,"], ["ma na aumaia a'u i le mea lautele.", "and set me in a large place."]]},
  {num:6,words:[["O loo ia te au Ieova;", "The LORD is on my side;"], ["ou te le fefe;", "I will not fear:"], ["se a se mea e faia e tagata ia te au?", "what can man do unto me?"]]},
  {num:7,words:[["O loo ia te au Ieova e faatasi ma i latou ua fesoasoani mai ia te au; a o a'u nei,", "The LORD taketh my part with them that help me:"], ["ou te iloa atu le taui o e ua 'ino'ino mai ia te au.", "therefore shall I see my desire upon them that hate me."]]},
  {num:8,words:[["O le faatuatua ia Ieova, e sili lea i le faalagolago i tagata.", "It is better to trust in the LORD than to put confidence in man."]]},
  {num:9,words:[["O le faatuatua ia Ieova, e sili lea i le faalagolago i alii.", "It is better to trust in the LORD than to put confidence in princes."]]},
  {num:10,words:[["Ua siosio mai nuu ese uma ia te au;", "All nations compassed me about:"], ["o le suafa o Ieova ou te faaumatia ai i latou.", "but in the name of the LORD will I destroy them."]]},
  {num:11,words:[["Ua latou siosio mai ia te au,", "They compassed me about;"], ["ua siosio mai lava ia te au;", "yea, they compassed me about:"], ["o le suafa o Ieova ou te faaumatia ai i latou.", "but in the name of the LORD I will destroy them."]]},
  {num:12,words:[["Na latou siosio mai ia te au faapei o lagomeli;", "They compassed me about like bees;"], ["e tineia i latou pei o le afi laau talatala;", "they are quenched as the fire of thorns:"], ["o le suafa o Ieova ou te faaumatia ai i latou.", "for in the name of the LORD I will destroy them."]]},
  {num:13,words:[["Na e tulei tele mai ia te au, ina ia ou paū;", "Thou hast thrust sore at me that I might fall:"], ["a ua fesoasoani mai Ieova ia te au.", "but the LORD helped me."]]},
  {num:14,words:[["O Ioa, o lo'u malosi o ia ma la'u pese,", "The LORD is my strength and song,"], ["ua avea foi o ia mo'u faaolataga.", "and is become my salvation."]]},
  {num:15,words:[["O leo o le alaga fiafia ma le olataga,", "The voice of rejoicing and salvation is in the tabernacles of the righteous:"], ["o i ai ia i fale ie o e amiotonu. Ua se toa le aao taumatau o Ieova.", "the right hand of the LORD doeth valiantly."]]},
  {num:16,words:[["Ua maualuga le aao taumatau o Ieova;", "The right hand of the LORD is exalted:"], ["ua se toa le aao taumatau o Ieova.", "the right hand of the LORD doeth valiantly."]]},
  {num:17,words:[["Ou te le oti,", "I shall not die,"], ["ou te ola lava,", "but live,"], ["ma ou ta'uta'u atu mea na faia e Ioa.", "and declare the works of the LORD."]]},
  {num:18,words:[["Na matuā aoai mai Ioa ia te au;", "The LORD hath chastened me sore:"], ["a ua na le tuuina a'u i le oti.", "but he hath not given me over unto death."]]},
  {num:19,words:[["To mai ia ia te au o faitotoa o le amiotonu;", "Open to me the gates of righteousness:"], ["ou te ulufale atu i ai,", "I will go into them,"], ["ma ou vivii atu ia Ioa.", "and I will praise the LORD:"]]},
  {num:20,words:[["O le faitotoa lenei o Ieova,", "This gate of the LORD,"], ["e ulu atu ai e ua amiotonu.", "into which the righteous shall enter."]]},
  {num:21,words:[["Ou te vivii atu ia te oe;", "I will praise thee:"], ["auā na e tali mai ia te au,", "for thou hast heard me,"], ["ua avea foi oe mo'u faaolataga.", "and art become my salvation."]]},
  {num:22,words:[["O le maa na lafoaiina e tufuga fai fale, ua fai lea ma maa tulimanu aupitoaluga.", "The stone which the builders refused is become the head stone of the corner."]]},
  {num:23,words:[["O le mea lea ua faia e Ieova;", "This is the LORD'S doing;"], ["o le mea tatou te ofo ai pe a vaai i ai.", "it is marvellous in our eyes."]]},
  {num:24,words:[["O le aso lenei ua faia e Ieova;", "This is the day which the LORD hath made;"], ["ia tatou olioli ma fiafia i ai.", "we will rejoice and be glad in it."]]},
  {num:25,words:[["Ieova e,", "Save now,"], ["ou te aioi atu ia e faaola mai lava;", "I beseech thee,"], ["ou te aioi atu,", "O LORD: O LORD,"], ["Ieova e,", "I beseech thee,"], ["ia e faamanuia mai lava.", "send now prosperity."]]},
  {num:26,words:[["Ia manuia le o maliu mai i le suafa o Ieova;", "Blessed be he that cometh in the name of the LORD:"], ["matou te faamanuia atu ia te outou ai le fale o Ieova.", "we have blessed you out of the house of the LORD."]]},
  {num:27,words:[["O le Atua o Ieova lea,", "God is the LORD,"], ["ua na faamalamalama mai ia te i tatou;", "which hath shewed us light:"], ["ina noanoa ia i maea le taulaga,", "bind the sacrifice with cords,"], ["ia oo i nifo o le fata faitaulaga.", "even unto the horns of the altar."]]},
  {num:28,words:[["O oe lava lo'u Atua,", "Thou art my God,"], ["ou te vivii atu ia te oe;", "and I will praise thee:"], ["o oe lava lo'u Atua,", "thou art my God,"], ["ou te faaneenee atu ia te oe.", "I will exalt thee."]]},
  {num:29,words:[["Vivii atu ia outou ia Ieova,", "O give thanks unto the LORD;"], ["auā e lelei o ia;", "for he is good:"], ["auā e faavavau lava lona alofa.", "for his mercy endureth for ever."]]},
];
renderVerseSet(psa_ch_118_Verses, 'psa-ch118-verses');

var psa_ch_119_Verses = [
  {num:1,words:[["Amuia e ua sao l o latou ala,", "Blessed are the undefiled in the way,"], ["o e savavali i le tulafono a Ieova.", "who walk in the law of the LORD."]]},
  {num:2,words:[["Amuia i latou o e tausi i ana tulafono,", "Blessed are they that keep his testimonies,"], ["o e sailiili ia te ia ma le loto atoa;", "and that seek him with the whole heart."]]},
  {num:3,words:[["e le faia foi e i latou se mea leaga;", "They also do no iniquity:"], ["e savavali i latou i ona ala.", "they walk in his ways."]]},
  {num:4,words:[["O oe lava na e poloai mai ia matuā tausiusi i au feau.", "Thou hast commanded us to keep thy precepts diligently."]]},
  {num:5,words:[["E! Fia faatatauina o'u ala, ina ia ou tausi i au tulafono.", "O that my ways were directed to keep thy statutes!"]]},
  {num:6,words:[["Ona ou le mā lava lea,", "Then shall I not be ashamed,"], ["pe a a'u manatu i au poloaiga uma.", "when I have respect unto all thy commandments."]]},
  {num:7,words:[["Ou te vivii atu ia te oe ma le loto faamaoni,", "I will praise thee with uprightness of heart,"], ["pe a a'a'oina a'u i au faamasinoga tonu.", "when I shall have learned thy righteous judgments."]]},
  {num:8,words:[["Ou te tausi i au tulafono;", "I will keep thy statutes:"], ["aua lava e te matuā lafoai mai ia te au.", "O forsake me not utterly."]]},
  {num:9,words:[["E faapefea ea ona faamamāina e le taulealea o lona ala? Ona ua tausi i ai e tusa ma lau afioga.", "Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word."]]},
  {num:10,words:[["Ua ou saili ia te oe ma lo'u loto atoa;", "With my whole heart have I sought thee:"], ["aua ne'i ou sese i au poloaiga.", "O let me not wander from thy commandments."]]},
  {num:11,words:[["Ua ou teu i lo'u loto lau afioga,", "Thy word have I hid in mine heart,"], ["ina ne'i ou agasala ia te oe.", "that I might not sin against thee."]]},
  {num:12,words:[["Ia faafetaia oe,", "Blessed art thou,"], ["Ieova e;", "O LORD:"], ["ia e a'oa'o mai ia te au i au tulafono.", "teach me thy statutes."]]},
  {num:13,words:[["Ua ou ta'u atu i o'u laugutu o faamasinoga uma o lou fofoga.", "With my lips have I declared all the judgments of thy mouth."]]},
  {num:14,words:[["Ua ou fiafia lava i le ala o au tulafono,", "I have rejoiced in the way of thy testimonies,"], ["e sili i le oloa uma lava.", "as much as in all riches."]]},
  {num:15,words:[["Ou te mafaufau lava i au feau,", "I will meditate in thy precepts,"], ["ma ou manatua lava ou ala.", "and have respect unto thy ways."]]},
  {num:16,words:[["Ou te fiafia lava a'u i au tulafono;", "I will delight myself in thy statutes:"], ["e le galo ia te au o lau afioga.", "I will not forget thy word."]]},
  {num:17,words:[["Ia e agalelei mai i lau auauna,", "Deal bountifully with thy servant, that I may live,"], ["ia ola ai a'u ma tausi i lau afioga.", "and keep thy word."]]},
  {num:18,words:[["Ia e faapupula mai o'u mata,", "Open thou mine eyes,"], ["ia ou vaai lava i mea e ofo ai i lau tulafono.", "that I may behold wondrous things out of thy law."]]},
  {num:19,words:[["O le tagata ese a'u nei i le lalolagi;", "I am a stranger in the earth:"], ["aua le nanā ia te au o au poloaiga.", "hide not thy commandments from me."]]},
  {num:20,words:[["Ua nutimomoia lo'u loto i le manao tele i au faamasinoga i aso uma.", "My soul breaketh for the longing that it hath unto thy judgments at all times."]]},
  {num:21,words:[["Ua e aoai atu i e faamaualuga, o e ua faafanoina,", "Thou hast rebuked the proud that are cursed,"], ["o e sese i au poloaiga.", "which do err from thy commandments."]]},
  {num:22,words:[["Ia e ave ese ia te au le luma ma le inosia;", "Remove from me reproach and contempt;"], ["auā ua ou anaana i au tulafono.", "for I have kept thy testimonies."]]},
  {num:23,words:[["Sa nonofo lava alii ma fai upu ia te au;", "Princes also did sit and speak against me:"], ["a ua mafaufau lau auauna i au tulafono.", "but thy servant did meditate in thy statutes."]]},
  {num:24,words:[["O au tulafono o lo'u lava fiafia ia, o a'u faipule lava ia.", "Thy testimonies also are my delight and my counsellors."]]},
  {num:25,words:[["Ua pipii atu lo'u ola i le efuefu;", "My soul cleaveth unto the dust:"], ["ia e faaolaola mai ia te au e tusa ma lau afioga.", "quicken thou me according to thy word."]]},
  {num:26,words:[["Ua ou ta'u atu o'u ala;", "I have declared my ways,"], ["na e tali mai foi ia te au;", "and thou heardest me:"], ["ia e a'oa'o mai ia te au i au tulafono.", "teach me thy statutes."]]},
  {num:27,words:[["Ia e faailoa mai ia te au le ala o au feau;", "Make me to understand the way of thy precepts:"], ["ona ou mafaufau lea i ou vavega.", "so shall I talk of thy wondrous works."]]},
  {num:28,words:[["Ua sisina ifo o'u loimata ona o le faanoanoa;", "My soul melteth for heaviness:"], ["ia e faamalosia a'u e tusa ma lau afioga.", "strengthen thou me according unto thy word."]]},
  {num:29,words:[["Ia e faatea ese ia te au le ala o le pepelo;", "Remove from me the way of lying:"], ["ma ia e foai mai lau tulafono ia te au i le alofa.", "and grant me thy law graciously."]]},
  {num:30,words:[["Ua ou filifili i le ala o le faamaoni;", "I have chosen the way of truth:"], ["ua ou tuuina au faamasinoga i o'u luma .", "thy judgments have I laid before me."]]},
  {num:31,words:[["Ua ou pipii atu i au tulafono;", "I have stuck unto thy testimonies:"], ["Ieova e,", "O LORD,"], ["aua e te faamaina a'u.", "put me not to shame."]]},
  {num:32,words:[["Ou te momo'e i le ala o au poloaiga,", "I will run the way of thy commandments,"], ["pe a e foaiina mai ia te au le loto matala.", "when thou shalt enlarge my heart."]]},
  {num:33,words:[["Ieova e,", "Teach me,"], ["ia e a'oa'o mai ia te au i le ala o au tulafono,", "O LORD, the way of thy statutes;"], ["ona ou anaana lava lea i ai seia oo i le gataaga.", "and I shall keep it unto the end."]]},
  {num:34,words:[["Ia e a'oa'o mai ia te au,", "Give me understanding,"], ["ona ou anaana lea i lau tulafono,", "and I shall keep thy law; yea,"], ["ma ou tausia ma lo'u loto atoa.", "I shall observe it with my whole heart."]]},
  {num:35,words:[["Ia e ta'ita'iina atu a'u i le ala o au poloaiga;", "Make me to go in the path of thy commandments;"], ["auā ou te fiafia lava i ai.", "for therein do I delight."]]},
  {num:36,words:[["Ia e faauai atu lo'u loto i au tulafono,", "Incline my heart unto thy testimonies,"], ["a e aua ne'i i le matapeapea.", "and not to covetousness."]]},
  {num:37,words:[["Ia e liliueseina o'u mata ne'i ou vaai i mea le aoga;", "Turn away mine eyes from beholding vanity;"], ["ia e faaolaolaina a'u i lou ala.", "and quicken thou me in thy way."]]},
  {num:38,words:[["Ia e faatumauina lau afioga i lau auauna,", "Stablish thy word unto thy servant,"], ["o le ua mata'u ia te oe.", "who is devoted to thy fear."]]},
  {num:39,words:[["Ia e liliueseina lo'u luma ou te fefe ai;", "Turn away my reproach which I fear:"], ["auā e lelei au faamasinoga.", "for thy judgments are good."]]},
  {num:40,words:[["Faauta,", "Behold,"], ["ua ou naunau lava i au feau;", "I have longed after thy precepts:"], ["ia e faaolaola mai ia te au i lau amiotonu.", "quicken me in thy righteousness."]]},
  {num:41,words:[["Ia oo mai foi ia te au lou alofa,", "Let thy mercies come also unto me,"], ["Ieova e,", "O LORD,"], ["o lau olataga,", "even thy salvation,"], ["e tusa ma lau afioga.", "according to thy word."]]},
  {num:42,words:[["Ona ou tali atu lea se upu i lē faalumaina a'u;", "So shall I have wherewith to answer him that reproacheth me:"], ["auā ou te faatuatua i lau afioga.", "for I trust in thy word."]]},
  {num:43,words:[["Aua foi e te matuā aveesea le upu moni i lo'u gutu;", "And take not the word of truth utterly out of my mouth;"], ["auā ua ou faamoemoe i au faamasinoga.", "for I have hoped in thy judgments."]]},
  {num:44,words:[["Ona ou tausi lea e le aunoa lau tulafono e faavavau faavavau lava.", "So shall I keep thy law continually for ever and ever."]]},
  {num:45,words:[["Ou te savali foi i le mea lautele;", "And I will walk at liberty:"], ["auā ua ou saili i au feau.", "for I seek thy precepts."]]},
  {num:46,words:[["Ou te tautala foi i au tulafono i luma o tupu;", "I will speak of thy testimonies also before kings,"], ["ou te le mā ai lava.", "and will not be ashamed."]]},
  {num:47,words:[["Ou te fiafia lava a'u i au poloaiga,", "And I will delight myself in thy commandments,"], ["ua ou naunau i ai.", "which I have loved."]]},
  {num:48,words:[["Ou te sii foi i luga o'u lima i au poloaiga ua ou naunau i ai;", "My hands also will I lift up unto thy commandments, which I have loved;"], ["ou te mafaufau lava i au tulafono.", "and I will meditate in thy statutes."]]},
  {num:49,words:[["Ia e manatua lau afioga i lau auauna,", "Remember the word unto thy servant,"], ["auā ua e faatupuina lo'u faamoemoe.", "upon which thou hast caused me to hope."]]},
  {num:50,words:[["O le faamatalaloto lea ia te au i lo'u puapuaga;", "This is my comfort in my affliction:"], ["auā o lau afioga ua faaolaolaina ai a'u.", "for thy word hath quickened me."]]},
  {num:51,words:[["Ua matuā tauemu mai ia te au o e faamaualuga;", "The proud have had me greatly in derision:"], ["ou te lei liliu ese i lau tulafono.", "yet have I not declined from thy law."]]},
  {num:52,words:[["Ieova e,", "I remembered thy judgments of old,"], ["ua ou manatu i au faamasinoga talu anamua,", "O LORD;"], ["ona faamafanafanaina ai lea o a'u.", "and have comforted myself."]]},
  {num:53,words:[["Ua maua a'u e le tiga tele ona o e amio leaga, e ua lafoaiina lau tulafono.", "Horror hath taken hold upon me because of the wicked that forsake thy law."]]},
  {num:54,words:[["O au tulafono ua fai ia ma'u pese i le fale ou te āumau ai.", "Thy statutes have been my songs in the house of my pilgrimage."]]},
  {num:55,words:[["Ieova e,", "I have remembered thy name,"], ["ua ou manatu i lou suafa i le po,", "O LORD, in the night,"], ["ma ou tausi i lau tulafono.", "and have kept thy law."]]},
  {num:56,words:[["Ua ia te au lena mea,", "This I had,"], ["auā ua ou anaana i au feau.", "because I kept thy precepts."]]},
  {num:57,words:[["Ieova e,", "Thou art my portion,"], ["o lo'u tofi lava oe , ua ou fai atu,", "O LORD:"], ["Ou te tausi i au afioga.", "I have said that I would keep thy words."]]},
  {num:58,words:[["Ua ou faatoga atu i ou luma ma lo'u loto atoa;", "I intreated thy favour with my whole heart:"], ["ia e alofa mai ia te au e tusa ma lau afioga.", "be merciful unto me according to thy word."]]},
  {num:59,words:[["Na ou manatunatu i o'u ala,", "I thought on my ways,"], ["ona liliu atu lava lea o'u vae i au tulafono.", "and turned my feet unto thy testimonies."]]},
  {num:60,words:[["Ua ou faatelevave,", "I made haste,"], ["ou te lei faatelegese ona tausi i au poloaiga.", "and delayed not to keep thy commandments."]]},
  {num:61,words:[["Ua siomia a'u i mailei a e amio leaga;", "The bands of the wicked have robbed me:"], ["ua le galo ia te au o lau tolafono.", "but I have not forgotten thy law."]]},
  {num:62,words:[["Ou te ala i le tulua o po e vivii atu ai ia te oe, ona o au faamasinoga tonu.", "At midnight I will rise to give thanks unto thee because of thy righteous judgments."]]},
  {num:63,words:[["Ua matou uo ma i latou uma o e matatau ia te oe,", "I am a companion of all them that fear thee,"], ["ma e ua tausi i au feau.", "and of them that keep thy precepts."]]},
  {num:64,words:[["Ieova e,", "The earth,"], ["ua tumu le lalolagi i lou alofa;", "O LORD, is full of thy mercy:"], ["ia e a'oa'o mai ia te au i au tulafono.", "teach me thy statutes."]]},
  {num:65,words:[["Ieova e,", "Thou hast dealt well with thy servant,"], ["ua e agalelei mai i lau auauna,", "O LORD,"], ["e tusa ma lau afioga.", "according unto thy word."]]},
  {num:66,words:[["Ia e a'oa'o mai ia te au i le faautauta lelei ma le poto;", "Teach me good judgment and knowledge:"], ["auā ua ou faamaoni i au poloaiga.", "for I have believed thy commandments."]]},
  {num:67,words:[["A o lei puapuagatia a'u na ou sese; a o lenei,", "Before I was afflicted I went astray:"], ["ua ou tausi i lau afioga.", "but now have I kept thy word."]]},
  {num:68,words:[["E lelei oe,", "Thou art good,"], ["ua e agalelei foi;", "and doest good;"], ["ia e a'oa'o mai ia te au i au tulafono.", "teach me thy statutes."]]},
  {num:69,words:[["Ua fatu fua e e ua faamaualuga le tala pepelo ia te au; o a'u,", "The proud have forged a lie against me:"], ["ou te anaana i au feau ma lo'u loto atoa.", "but I will keep thy precepts with my whole heart."]]},
  {num:70,words:[["Ua lololo o latou loto e pei o le ga'o; o a'u,", "Their heart is as fat as grease;"], ["ou te olioli lava i lau tulafono.", "but I delight in thy law."]]},
  {num:71,words:[["O le mea e lelei ai a'u ina ua puapuagatia a'u,", "It is good for me that I have been afflicted;"], ["ina ia a'oa'oina ai a'u i au tulafono.", "that I might learn thy statutes."]]},
  {num:72,words:[["E sili ona lelei ia te au o le tulafono a lou fofoga i afe o auro ma ario.", "The law of thy mouth is better unto me than thousands of gold and silver."]]},
  {num:73,words:[["Na faia a'u e ou aao,", "Thy hands have made me and fashioned me:"], ["ua saunia ai foi a'u; ia e faalotomatala mai ia te au,", "give me understanding,"], ["ina ia a'oa'oina lava a'u i au poloaiga.", "that I may learn thy commandments."]]},
  {num:74,words:[["O e matatau ia te oe latou te iloa mai a'u, ona fiafia lea o i latou;", "They that fear thee will be glad when they see me;"], ["auā ua ou faamoemoe i lau afioga.", "because I have hoped in thy word."]]},
  {num:75,words:[["Ieova e,", "I know,"], ["ua ou iloa e tonu lava au faamasinoga,", "O LORD, that thy judgments are right,"], ["na e faapuapuagatia foi a'u i le faamaoni.", "and that thou in faithfulness hast afflicted me."]]},
  {num:76,words:[["Ia fai lou alofa ma faamatalaloto ia te au,", "Let, I pray thee,"], ["e tusa ma lau afioga i lau auauna.", "thy merciful kindness be for my comfort, according to thy word unto thy servant."]]},
  {num:77,words:[["Ia oo mai ia te au ou alofa mutimuti vale,", "Let thy tender mercies come unto me,"], ["ia ou ola ai; auā o lau tulafono,", "that I may live:"], ["o lo'u fiafia lea.", "for thy law is my delight."]]},
  {num:78,words:[["Ia masiasi o e faamaualuga,", "Let the proud be ashamed;"], ["auā ua latou faapiopio fua mai ia te au; o a'u,", "for they dealt perversely with me without a cause:"], ["ou te mafaufau i au feau.", "but I will meditate in thy precepts."]]},
  {num:79,words:[["Ia faasaga mai ia te au o e matatau ia te oe,", "Let those that fear thee turn unto me,"], ["atoa ma e ua iloa au tulafono.", "and those that have known thy testimonies."]]},
  {num:80,words:[["Ia sao lava lo'u loto i au tulafono,", "Let my heart be sound in thy statutes;"], ["ina ia ou le mā lava.", "that I be not ashamed."]]},
  {num:81,words:[["Ua lailoa lava a'u i le manao i le olataga mai ia te oe;", "My soul fainteth for thy salvation:"], ["ou te faamoemoe foi i lau afioga.", "but I hope in thy word."]]},
  {num:82,words:[["O le a avea o'u mata i le vaai atu i lau afioga,", "Mine eyes fail for thy word,"], ["o loo ou faapea atu,", "saying,"], ["E te faamafanafana ai ea afea ia te au?", "When wilt thou comfort me?"]]},
  {num:83,words:[["E ui ina avea a'u pei o se fagupa'u i le asu,", "For I am become like a bottle in the smoke;"], ["ua le galo ia te au au tulafono.", "yet do I not forget thy statutes."]]},
  {num:84,words:[["E fia ea aso o lau auauna? E te faia ea afea le faamasinoga i e saua mai ia te au?", "How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?"]]},
  {num:85,words:[["O e faamaualuga, ua latou elia lua mo a'u,", "The proud have digged pits for me,"], ["ua le tusa lea ma lau tulafono.", "which are not after thy law."]]},
  {num:86,words:[["O au poloaiga uma e faamaoni lava ia;", "All thy commandments are faithful:"], ["e saua fua mai i latou ia te au;", "they persecute me wrongfully;"], ["ia e fesoasoani mai ia te au.", "help thou me."]]},
  {num:87,words:[["Ua toe ina latou faaumatia a'u i le nuu; a o a'u,", "They had almost consumed me upon earth;"], ["ou te le lafoaiina au feau.", "but I forsook not thy precepts."]]},
  {num:88,words:[["Ia e faaolaola mai ia te au e tusa ma lou alofa,", "Quicken me after thy lovingkindness;"], ["ona ou tausi lava lea i le tulafono a lou fofoga.", "so shall I keep the testimony of thy mouth."]]},
  {num:89,words:[["Ieova e,", "For ever, O LORD,"], ["ua mausali lau afioga i le lagi e faavavau lava.", "thy word is settled in heaven."]]},
  {num:90,words:[["E au tupulaga lou faamaoni;", "Thy faithfulness is unto all generations:"], ["na e faatumauina le lalolagi,", "thou hast established the earth,"], ["ona tumau lea.", "and it abideth."]]},
  {num:91,words:[["O lau pule o loo tumau ai ia mea i le aso nei;", "They continue this day according to thine ordinances:"], ["auā o au auauna ia mea uma lava.", "for all are thy servants."]]},
  {num:92,words:[["Ana le avea lau tulafono mo'u fiafia,", "Unless thy law had been my delights,"], ["po ua ou fano i lo'u puapuaga.", "I should then have perished in mine affliction."]]},
  {num:93,words:[["E le galo ia te au au feau e faavavau;", "I will never forget thy precepts:"], ["auā o mea ia na e faaolaola mai ai ia te au.", "for with them thou hast quickened me."]]},
  {num:94,words:[["O ia te oe a'u nei,", "I am thine,"], ["ia e faaola mai ia te au;", "save me;"], ["auā ua ou saili i au feau.", "for I have sought thy precepts."]]},
  {num:95,words:[["Ua lamalama o e amio leaga latou te fasioti ia te au;", "The wicked have waited for me to destroy me:"], ["ua ou mafaufau i au tulafono.", "but I will consider thy testimonies."]]},
  {num:96,words:[["Ua ou vaaia le iuga o mea uma ua atoatoa ona lelei;", "I have seen an end of all perfection:"], ["o lau poloaiga e matuā lautele lea.", "but thy commandment is exceeding broad."]]},
  {num:97,words:[["Ua tele lava lo'u naunau i lau tulafono; ou te mafaufau i ai i le aso atoa.", "O how love I thy law! it is my meditation all the day."]]},
  {num:98,words:[["O au poloaiga e sili ai ona poto o a'u i e ita mai ia te au;", "Thou through thy commandments hast made me wiser than mine enemies:"], ["auā e ia te au lava ia e faavavau.", "for they are ever with me."]]},
  {num:99,words:[["Ua sili ona atamai o a'u i e a'oa'o mai ia te au uma lava;", "I have more understanding than all my teachers:"], ["auā o au tulafono ou te mafaufau i ai.", "for thy testimonies are my meditation."]]},
  {num:100,words:[["O lo'u lotomatala ua sili i e toeaina,", "I understand more than the ancients,"], ["auā ua ou anaana i au feau.", "because I keep thy precepts."]]},
  {num:101,words:[["Ua 'alo ese o'u vae i ala leaga uma lava,", "I have refrained my feet from every evil way,"], ["ina ia ou tausi i lau afioga.", "that I might keep thy word."]]},
  {num:102,words:[["Ou te lei alu ese i au faamasinoga,", "I have not departed from thy judgments:"], ["auā ua e a'oa'o mai oe ia te au.", "for thou hast taught me."]]},
  {num:103,words:[["Ua matuā suamalie au afioga i lo'u gutu;", "How sweet are thy words unto my taste! yea,"], ["ua sili i lo le meli i lo'u gutu.", "sweeter than honey to my mouth!"]]},
  {num:104,words:[["O au feau ou te maua ai le lotomatala;", "Through thy precepts I get understanding:"], ["o le mea lea ou te 'ino'ino ai i ala pepelo uma lava.", "therefore I hate every false way."]]},
  {num:105,words:[["O lau afioga o le sulu lea i o'u vae,", "Thy word is a lamp unto my feet,"], ["ma le malamalama i lo'u ala.", "and a light unto my path."]]},
  {num:106,words:[["Na ou tauto,", "I have sworn,"], ["ou te faamaoni foi,", "and I will perform it,"], ["ou te tausi i au faamasinoga tonu.", "that I will keep thy righteous judgments."]]},
  {num:107,words:[["Ua matuā puapuagaina a'u;", "I am afflicted very much:"], ["Ieova e,", "quicken me, O LORD,"], ["ia e faaolaola mai ia te au e tusa ma lau afioga.", "according unto thy word."]]},
  {num:108,words:[["Ieova e,", "Accept, I beseech thee,"], ["ia e talia mai lava o taulaga e faia ma le loto na fai atu ai lo'u gutu;", "the freewill offerings of my mouth,"], ["ma a'oa'o mai ia te au i au faamasinoga.", "O LORD, and teach me thy judgments."]]},
  {num:109,words:[["O i lo'u lima lo'u nei ola e le aunoa;", "My soul is continually in my hand:"], ["a e le galo ia te au lau tulafono.", "yet do I not forget thy law."]]},
  {num:110,words:[["O e amio leaga ua latou faia le mailei mo a'u;", "The wicked have laid a snare for me:"], ["a e lei sese a'u i au feau.", "yet I erred not from thy precepts."]]},
  {num:111,words:[["Ua fai mo'u tofi o au tulafono e faavavau;", "Thy testimonies have I taken as an heritage for ever:"], ["auā o mea ia e faafiafia a'i lo'u loto.", "for they are the rejoicing of my heart."]]},
  {num:112,words:[["Ua uai atu lo'u loto e fai au tulafono e faavavau faavavau lava.", "I have inclined mine heart to perform thy statutes alway, even unto the end."]]},
  {num:113,words:[["Ou te 'ino'ino i e loto fetoa'i,", "I hate vain thoughts:"], ["a ou te naunau i lau tulafono.", "but thy law do I love."]]},
  {num:114,words:[["O lo'u lafitaga oe ma lo'u talita;", "Thou art my hiding place and my shield:"], ["ou te faamoemoe i lau afioga.", "I hope in thy word."]]},
  {num:115,words:[["O ese ia ia te au,", "Depart from me,"], ["outou o e amio leaga;", "ye evildoers:"], ["auā ou te anaana lava i poloaiga a lo'u Atua.", "for I will keep the commandments of my God."]]},
  {num:116,words:[["Ia e lagolagoina mai a'u e tusa ma lau afioga,", "Uphold me according unto thy word,"], ["ina ia ou ola;", "that I may live:"], ["aua foi ne'i ou mā i lo'u faamoemoega.", "and let me not be ashamed of my hope."]]},
  {num:117,words:[["Ia e lagolagoina o a'u,", "Hold thou me up,"], ["ona faaolaina lea o a'u;", "and I shall be safe:"], ["ona ou faasaga lea e le aunoa i au tulafono.", "and I will have respect unto thy statutes continually."]]},
  {num:118,words:[["Ua e faaleaogaina i latou uma o e sese i au tulafono;", "Thou hast trodden down all them that err from thy statutes:"], ["auā o le pepelo lo latou faa'ole'ole.", "for their deceit is falsehood."]]},
  {num:119,words:[["Ua e aveeseina o e amio leaga uma o i le nuu pei o le otaota o ario;", "Thou puttest away all the wicked of the earth like dross:"], ["o le mea lea ou te naunau ai i au tulafono.", "therefore I love thy testimonies."]]},
  {num:120,words:[["Ua mogea lo'u tino i le mata'u ia te oe;", "My flesh trembleth for fear of thee;"], ["ma ou fefe i au faamasinoga.", "and I am afraid of thy judgments."]]},
  {num:121,words:[["Ua ou faia le faamasinoga ma le amiotonu;", "I have done judgment and justice:"], ["aua e te tuuina atu a'u i e saua mai ia te au.", "leave me not to mine oppressors."]]},
  {num:122,words:[["Ia fai oe ma fesoasoani i lau auauna, ou te lelei ai;", "Be surety for thy servant for good:"], ["aua ne'i saua mai ia te au o e faamaualuga.", "let not the proud oppress me."]]},
  {num:123,words:[["Ua avea o'u mata i le manao i lau olataga,", "Mine eyes fail for thy salvation,"], ["ma lau afioga tonu.", "and for the word of thy righteousness."]]},
  {num:124,words:[["Ia e faia i lau auauna e tusa ma lou alofa;", "Deal with thy servant according unto thy mercy,"], ["ma a'oa'o mai ia te au i au tulafono.", "and teach me thy statutes."]]},
  {num:125,words:[["O lau auauna a'u nei,", "I am thy servant;"], ["ia e faalotomatala mai ia te au,", "give me understanding,"], ["ina ia ou iloa au tulafono.", "that I may know thy testimonies."]]},
  {num:126,words:[["Ua oo mai ona po e galue ai Ieova;", "It is time for thee, LORD,"], ["ua solia e i latou lau tulafono.", "to work: for they have made void thy law."]]},
  {num:127,words:[["O le mea lea ua sili ai lo'u manao i au poloaiga i le auro,", "Therefore I love thy commandments above gold; yea,"], ["o le auro lelei lava.", "above fine gold."]]},
  {num:128,words:[["O le mea lea ou te manatu ai ua tonu au feau atoa uma lava;", "Therefore I esteem all thy precepts concerning all things to be right;"], ["ou te 'ino'ino i ala pepelo uma lava.", "and I hate every false way."]]},
  {num:129,words:[["O mea e ofo ai au tulafono,", "Thy testimonies are wonderful:"], ["o le mea lea e anaana i ai lo'u loto.", "therefore doth my soul keep them."]]},
  {num:130,words:[["O le faaalia mai o au afioga e faamalamalamaina ai;", "The entrance of thy words giveth light;"], ["e faalotomatalaina ai e ua faigofie.", "it giveth understanding unto the simple."]]},
  {num:131,words:[["Ua faamaga lo'u gutu,", "I opened my mouth,"], ["ma ou ga'ega'e;", "and panted:"], ["auā ua ou naunau atu i au poloaiga.", "for I longed for thy commandments."]]},
  {num:132,words:[["Ia e liuliualo mai ia te au,", "Look thou upon me,"], ["ma alofa fua mai ia te au,", "and be merciful unto me,"], ["e pei ona e masani ai i e alolofa i lou suafa.", "as thou usest to do unto those that love thy name."]]},
  {num:133,words:[["Ia e faamautuina lo'u savali i lau afioga;", "Order my steps in thy word:"], ["aua foi ne'i manumalo mai se amio leaga e tasi ia te au.", "and let not any iniquity have dominion over me."]]},
  {num:134,words:[["Laveai mai ia te au i le sauaga a tagata;", "Deliver me from the oppression of man:"], ["ona ou tausi lea i au feau.", "so will I keep thy precepts."]]},
  {num:135,words:[["Ia faamalamalama mai ou fofoga i lau auauna;", "Make thy face to shine upon thy servant;"], ["ma a'oa'o mai ia te au i au tulafono.", "and teach me thy statutes."]]},
  {num:136,words:[["O loo tafe ifo o vaitafe i o'u mata,", "Rivers of waters run down mine eyes,"], ["auā e le tausi e i latou lau tulafono.", "because they keep not thy law."]]},
  {num:137,words:[["E amiotonu lava oe,", "Righteous art thou,"], ["Ieova e,", "O LORD,"], ["ua tonu foi au faamasinoga.", "and upright are thy judgments."]]},
  {num:138,words:[["Ua e poloai mai i au tulafono ua tonu, ma le faamaoni lava.", "Thy testimonies that thou hast commanded are righteous and very faithful."]]},
  {num:139,words:[["Ua faaumatia a'u i lo'u maelega,", "My zeal hath consumed me,"], ["ina ua galo i e saua mai ia te au au afioga.", "because mine enemies have forgotten thy words."]]},
  {num:140,words:[["Ua se ario ua te'a ma le otaota lau afioga;", "Thy word is very pure:"], ["e naunau foi i ai lau auauna.", "therefore thy servant loveth it."]]},
  {num:141,words:[["E faatauvaa lava a'u, ma inosia;", "I am small and despised:"], ["a e le galo ia te au au feau.", "yet do not I forget thy precepts."]]},
  {num:142,words:[["O lau amiotonu o le amiotonu e faavavau lea;", "Thy righteousness is an everlasting righteousness,"], ["o le mea moni foi lau tulafono.", "and thy law is the truth."]]},
  {num:143,words:[["Ua maua a'u e le puapuaga ma le tiga;", "Trouble and anguish have taken hold on me:"], ["o au poloaiga ou te fiafia i ai.", "yet thy commandments are my delights."]]},
  {num:144,words:[["O au tulafono o mea tonu ia e faavavau;", "The righteousness of thy testimonies is everlasting:"], ["ia e faalotomatala mai ia te au,", "give me understanding,"], ["ou te ola ai.", "and I shall live."]]},
  {num:145,words:[["Ua ou valaau ia te oe ma le loto atoa;", "I cried with my whole heart;"], ["Ieova e,", "hear me,"], ["ia e tali mai ia te au;", "O LORD:"], ["ou te anaana lava i au tulafono.", "I will keep thy statutes."]]},
  {num:146,words:[["Ua ou valaau ia te oe;", "I cried unto thee;"], ["ia e faaola mai ia te au,", "save me,"], ["ona ou tausi lea i au tulafono.", "and I shall keep thy testimonies."]]},
  {num:147,words:[["Ua muamua i le tafa o ata ona ou alaga atu;", "I prevented the dawning of the morning, and cried:"], ["ua ou faamoemoe i lau afioga.", "I hoped in thy word."]]},
  {num:148,words:[["Ua muamua ona pupula o'u mata i leoleoga i itupo,", "Mine eyes prevent the night watches,"], ["ina ia ou mafaufau i lau afioga.", "that I might meditate in thy word."]]},
  {num:149,words:[["Ia e faafofoga mai i lo'u leo e tusa ma lou alofa;", "Hear my voice according unto thy lovingkindness:"], ["Ieova e,", "O LORD,"], ["ia e faaolaola mai ia te au e tusa ma lau faamasinoga.", "quicken me according to thy judgment."]]},
  {num:150,words:[["O loo faalatalata mai e ua tausisi i amio leaga;", "They draw nigh that follow after mischief:"], ["e vava mamao i latou ma lau tulafono.", "they are far from thy law."]]},
  {num:151,words:[["Ua latalata mai oe Ieova e;", "Thou art near, O LORD;"], ["o au poloaiga uma foi e moni lava ia.", "and all thy commandments are truth."]]},
  {num:152,words:[["Talu anamuā ua ou iloa ai au tulafono,", "Concerning thy testimonies,"], ["ua e faavaeina ia e faavavau.", "I have known of old that thou hast founded them for ever."]]},
  {num:153,words:[["Silasila mai ia i lo'u tiga,", "Consider mine affliction,"], ["ma ia e laveai mai ia te au;", "and deliver me:"], ["auā e le galo ia te au lau tulafono.", "for I do not forget thy law."]]},
  {num:154,words:[["Ia e faia la'u finauga,", "Plead my cause,"], ["ma laveai mai ia te au;", "and deliver me:"], ["ia e faaolaola mai ia te au e tusa ma lau afioga.", "quicken me according to thy word."]]},
  {num:155,words:[["E vava mamao le faaolataga ma i latou o e amio leaga;", "Salvation is far from the wicked:"], ["auā e le saili i latou i au tulafono.", "for they seek not thy statutes."]]},
  {num:156,words:[["Ieova e,", "Great are thy tender mercies,"], ["ua tele lou alofa mutimuti vale;", "O LORD:"], ["ia e faaolaola mai ia te au e tusa ma au faamasinoga.", "quicken me according to thy judgments."]]},
  {num:157,words:[["E toatele o e saua mai ma ita mai ia te au;", "Many are my persecutors and mine enemies;"], ["ou te le liliu ese lava i au tulafono.", "yet do I not decline from thy testimonies."]]},
  {num:158,words:[["Na ou iloa atu i e ua faa'ole'ole,", "I beheld the transgressors,"], ["ma ou 'ino'ino i ai,", "and was grieved;"], ["o i latou o e le tausi i lau afioga.", "because they kept not thy word."]]},
  {num:159,words:[["Ia e silasila mai ua ou naunau i au feau;", "Consider how I love thy precepts:"], ["Ieova e,", "quicken me, O LORD,"], ["ia e faaolaola mai ia te au e tusa ma lou alofa.", "according to thy lovingkindness."]]},
  {num:160,words:[["E moni lava lau afioga talu le amataga;", "Thy word is true from the beginning:"], ["e faavavau foi au faamasinoga tonu uma lava.", "and every one of thy righteous judgments endureth for ever."]]},
  {num:161,words:[["Ua saua fua mai alii ia te au;", "Princes have persecuted me without a cause:"], ["a ua fefe lo'u loto i au afioga.", "but my heart standeth in awe of thy word."]]},
  {num:162,words:[["Ou te fiafia a'u i lau afioga,", "I rejoice at thy word,"], ["faapei o le ua maua le vete tele.", "as one that findeth great spoil."]]},
  {num:163,words:[["Ou te 'ino'ino i le tala pepelo, ou te matuā 'ino'ino i ai;", "I hate and abhor lying:"], ["a ou te naunau i lau tulafono.", "but thy law do I love."]]},
  {num:164,words:[["E ta'i foi faafitu i aso ona ou vivii atu ia te oe, ona o au faamasinoga tonu.", "Seven times a day do I praise thee because of thy righteous judgments."]]},
  {num:165,words:[["Ua tele le filemu o e naunau i lau tulafono;", "Great peace have they which love thy law:"], ["e leai foi se mea e tausuai ai i latou.", "and nothing shall offend them."]]},
  {num:166,words:[["Ieova e,", "LORD,"], ["ua ou faamoemoe i lau olataga,", "I have hoped for thy salvation,"], ["ma a'u faia au poloaiga.", "and done thy commandments."]]},
  {num:167,words:[["Ua tausi au tulafono i lo'u loto;", "My soul hath kept thy testimonies;"], ["ma ou matuā naunau i ai.", "and I love them exceedingly."]]},
  {num:168,words:[["Ua ou tausi i au feau, atoa ma au tulafono;", "I have kept thy precepts and thy testimonies:"], ["auā o i ou luma o'u ala uma lava.", "for all my ways are before thee."]]},
  {num:169,words:[["Ieova e,", "Let my cry come near before thee,"], ["ia oo atu la'u alaga i ou luma; ia e faalotomatala mai ia te au,", "O LORD:"], ["e tusa ma lau afioga.", "give me understanding according to thy word."]]},
  {num:170,words:[["Ia oo atu i ou luma la'u aioi atu; ia e laveai mai ia te au,", "Let my supplication come before thee:"], ["e tusa ma lau afioga.", "deliver me according to thy word."]]},
  {num:171,words:[["E ta'u atu le viiga i o'u laugutu,", "My lips shall utter praise,"], ["pe a e a'oa'o mai ia te au i au tulafono.", "when thou hast taught me thy statutes."]]},
  {num:172,words:[["E tautala lo'u laulaufaiva i lau afioga,", "My tongue shall speak of thy word:"], ["auā ua tonu au poloaiga uma lava.", "for all thy commandments are righteousness."]]},
  {num:173,words:[["Ia fesoasoani mai lou aao ia te au;", "Let thine hand help me;"], ["auā ua ou filifilia au feau.", "for I have chosen thy precepts."]]},
  {num:174,words:[["Ieova e,", "I have longed for thy salvation,"], ["ou te naunau i lau faaolataga; o lau tulafono foi,", "O LORD;"], ["o lo'u lea fiafia.", "and thy law is my delight."]]},
  {num:175,words:[["Ia ola lava a'u,", "Let my soul live,"], ["ina ia ou vivii atu ia te oe;", "and it shall praise thee;"], ["ia fesoasoani mai foi au faamasinoga ia te au.", "and let thy judgments help me."]]},
  {num:176,words:[["Ua ou alu ese faapei o le mamoe ua sē;", "I have gone astray like a lost sheep;"], ["ia e saili mai i lau auauna;", "seek thy servant;"], ["auā ua le galo ia te au au poloaiga.", "for I do not forget thy commandments."]]},
];
renderVerseSet(psa_ch_119_Verses, 'psa-ch119-verses');

var psa_ch_120_Verses = [
  {num:1,words:[["Na ou valaau atu ia Ieova i lo'u puapuaga,", "In my distress I cried unto the LORD,"], ["na ia tali mai foi ia te au.", "and he heard me."]]},
  {num:2,words:[["Ieova e,", "Deliver my soul,"], ["ia e laveai mai ia te au i laugutu pepelo,", "O LORD, from lying lips,"], ["ma le laulaufaiva e faa'ole'ole.", "and from a deceitful tongue."]]},
  {num:3,words:[["Le laulaufaiva faa'ole'ole e,", "What shall be given unto thee? or what shall be done unto thee,"], ["se a se mea e tuuina atu ia te oe? Se a foi se mea e faaopoopoina ia te oe?", "thou false tongue?"]]},
  {num:4,words:[["O u maamaai a le tagata malosi,", "Sharp arrows of the mighty,"], ["atoa ma malala ola o le ratami.", "with coals of juniper."]]},
  {num:5,words:[["Aue a'u nei! Auā ou te āumau i Meseko,", "Woe is me, that I sojourn in Mesech,"], ["ma ou nofo i faleie o Kitara.", "that I dwell in the tents of Kedar!"]]},
  {num:6,words:[["Ua leva ona ou nofo faatasi ma le ua 'ino'ino i le filemu.", "My soul hath long dwelt with him that hateth peace."]]},
  {num:7,words:[["O a'u nei e filemu lava a'u;", "I am for peace:"], ["a o i latou, a a'u tautala atu,", "but when I speak,"], ["e fia tau i latou.", "they are for war."]]},
];
renderVerseSet(psa_ch_120_Verses, 'psa-ch120-verses');

var psa_ch_121_Verses = [
  {num:1,words:[["E faasaga ae o'u mata i mauga,", "I will lift up mine eyes unto the hills,"], ["e oo mai ai lo'u fesoasoani.", "from whence cometh my help."]]},
  {num:2,words:[["O lo'u fesoasoani mai ia Ieova lea,", "My help cometh from the LORD,"], ["o le na faia le lagi atoa ma le lalolagi.", "which made heaven and earth."]]},
  {num:3,words:[["E le tuuina mai e ia ia mapeva lou vae;", "He will not suffer thy foot to be moved:"], ["o lou leoleo e le tulemoe lava ia.", "he that keepeth thee will not slumber."]]},
  {num:4,words:[["Faauta, o lē leoleo ia Isaraelu,", "Behold,"], ["e le tulemoe ia, e le moe lava.", "he that keepeth Israel shall neither slumber nor sleep."]]},
  {num:5,words:[["O Ieova, o lou leoleo ia;", "The LORD is thy keeper:"], ["o Ieova, o lou paolo lea i lou itu taumatau.", "the LORD is thy shade upon thy right hand."]]},
  {num:6,words:[["E le taia oe e le la i le ao,", "The sun shall not smite thee by day,"], ["po o le masina i le po.", "nor the moon by night."]]},
  {num:7,words:[["E leoleo e Ieova ia te oe i mea leaga uma lava;", "The LORD shall preserve thee from all evil:"], ["e leoleo mai o ia i lou agaga.", "he shall preserve thy soul."]]},
  {num:8,words:[["E leoleo Ieova i lou ulufafo ma lou ulufale, e amata mai nei lava,", "The LORD shall preserve thy going out and thy coming in from this time forth,"], ["a e oo i le faavavau.", "and even for evermore."]]},
];
renderVerseSet(psa_ch_121_Verses, 'psa-ch121-verses');

var psa_ch_122_Verses = [
  {num:1,words:[["Na ou fiafia ina ua latou fai mai ia te au,", "I was glad when they said unto me,"], ["Tatou te o i le fale o Ieova.", "Let us go into the house of the LORD."]]},
  {num:2,words:[["Ierusalema e,", "Our feet shall stand within thy gates,"], ["e tutū o matou vae i ou faitotoa.", "O Jerusalem."]]},
  {num:3,words:[["Ua atiina ae Ierusalema pei o le aai ua fesootai faatasi.", "Jerusalem is builded as a city that is compact together:"]]},
  {num:4,words:[["E o ae ai o itu aiga,", "Whither the tribes go up,"], ["o itu aiga lava o Ioa,", "the tribes of the LORD,"], ["o le tulafono lea ia Isaraelu,", "unto the testimony of Israel,"], ["ina ia vivii atu ai i le suafa o Ieova.", "to give thanks unto the name of the LORD."]]},
  {num:5,words:[["Auā ua tu ai nofoālii e faamasino ai,", "For there are set thrones of judgment,"], ["o nofoālii o le aiga o Tavita.", "the thrones of the house of David."]]},
  {num:6,words:[["Aioi atu outou ina ia manuia Ierusalema;", "Pray for the peace of Jerusalem:"], ["e manuia i latou o e alolofa ia te oe.", "they shall prosper that love thee."]]},
  {num:7,words:[["Ia i ai le manuia i totonu o ou pa,", "Peace be within thy walls,"], ["o le manuia i totonu o ou maota.", "and prosperity within thy palaces."]]},
  {num:8,words:[["Ona o o'u uso ma a'u aumea mamae,", "For my brethren and companions' sakes,"], ["ou te faapea atu ai lava,", "I will now say,"], ["Ia ia te oe le manuia.", "Peace be within thee."]]},
  {num:9,words:[["Ona o le fale o Ieova lo tatou Atua, ou te saili ai le manuia mo oe.", "Because of the house of the LORD our God I will seek thy good."]]},
];
renderVerseSet(psa_ch_122_Verses, 'psa-ch122-verses');

var psa_ch_123_Verses = [
  {num:1,words:[["Ua faasaga ae o'u mata ia te oe,", "Unto thee lift I up mine eyes,"], ["o lē afio i le lagi.", "O thou that dwellest in the heavens."]]},
  {num:2,words:[["Faauta,", "Behold,"], ["faapei o mata o auauna tane ua vaai atu i le lima o latou matai;", "as the eyes of servants look unto the hand of their masters,"], ["e pei o mata o le auauna fafine ua vaai atu i lima o lona matai tamaitai;", "and as the eyes of a maiden unto the hand of her mistress;"], ["e faapea o tatou mata ua vaai ae i lo tatou Atua o Ieova,", "so our eyes wait upon the LORD our God,"], ["seia alofa mai o ia ia te i tatou.", "until that he have mercy upon us."]]},
  {num:3,words:[["Ia e alofa mai,", "Have mercy upon us,"], ["Ieova e,", "O LORD,"], ["alofa mai ia te i matou;", "have mercy upon us:"], ["auā ua matuā inosia lava i matou.", "for we are exceedingly filled with contempt."]]},
  {num:4,words:[["Ua matuā tutumu o matou loto i le tauemu mai o e faasiasia,", "Our soul is exceedingly filled with the scorning of those that are at ease,"], ["ma le 'ino'ino mai o e faamaualuga.", "and with the contempt of the proud."]]},
];
renderVerseSet(psa_ch_123_Verses, 'psa-ch123-verses');

var psa_ch_124_Verses = [
  {num:1,words:[["Ana le seanoa Ieova na ia te i tatou,", "If it had not been the LORD who was on our side,"], ["ia faapea atu lava Isaraelu;", "now may Israel say;"]]},
  {num:2,words:[["ana le seanoa Ieova na ia te i tatou,", "If it had not been the LORD who was on our side,"], ["ina ua laga mai tagata ia te i tatou;", "when men rose up against us:"]]},
  {num:3,words:[["po ua latou foloolaina i tatou,", "Then they had swallowed us up quick,"], ["ina ua tupu tele lo latou ita mai ia te i tatou;", "when their wrath was kindled against us:"]]},
  {num:4,words:[["po ua tatou malelemo i le vai;", "Then the waters had overwhelmed us,"], ["po ua lofia i tatou i le alia;", "the stream had gone over our soul:"]]},
  {num:5,words:[["po ua tafe mai le vai faamaualuga i o tatou luga.", "Then the proud waters had gone over our soul."]]},
  {num:6,words:[["Ia faafetaia Ieova,", "Blessed be the LORD,"], ["o le na le tuuina atu i tatou ina ia saeia i o latou nifo.", "who hath not given us as a prey to their teeth."]]},
  {num:7,words:[["Ua sosola i tatou e pei o le manu nai le matāsele a e fāi manu;", "Our soul is escaped as a bird out of the snare of the fowlers:"], ["ua motu le matāsele,", "the snare is broken,"], ["i le ua sosola i tatou.", "and we are escaped."]]},
  {num:8,words:[["O lo tatou fesoasoani o i le suafa o Ieova lea,", "Our help is in the name of the LORD,"], ["o le na faia le lagi atoa ma le lalolagi.", "who made heaven and earth."]]},
];
renderVerseSet(psa_ch_124_Verses, 'psa-ch124-verses');

var psa_ch_125_Verses = [
  {num:1,words:[["O e faalagolago ia Ieova e faapei o le mauga o Siona i latou,", "They that trust in the LORD shall be as mount Zion,"], ["e le faagaeetia,", "which cannot be removed,"], ["a e tumau e faavavau.", "but abideth for ever."]]},
  {num:2,words:[["O Ierusalema ua siosioina i mauga; o Ieova foi na te siomia lona nuu,", "As the mountains are round about Jerusalem,"], ["e amata mai nei lava, a e oo i le faavavau.", "so the LORD is round about his people from henceforth even for ever."]]},
  {num:3,words:[["Auā o le tootoo o e amio leaga e le tumau lea i le tofi o e amiotonu;", "For the rod of the wicked shall not rest upon the lot of the righteous;"], ["ina ne'i tago atu lima o e amiotonu i se amio leaga.", "lest the righteous put forth their hands unto iniquity."]]},
  {num:4,words:[["Ieova e,", "Do good,"], ["ia e agalelei mai i e ua agalelei,", "O LORD, unto those that be good,"], ["ma e ua tonu o latou loto.", "and to them that are upright in their hearts."]]},
  {num:5,words:[["A o e liliu ane i le agapiopio,", "As for such as turn aside unto their crooked ways,"], ["o Ieova na te ta'ita'iina i latou faatasi ma e o fai amio leaga;", "the LORD shall lead them forth with the workers of iniquity:"], ["e ia Isaraelu le manuia.", "but peace shall be upon Israel."]]},
];
renderVerseSet(psa_ch_125_Verses, 'psa-ch125-verses');

var psa_ch_126_Verses = [
  {num:1,words:[["Na faafoisia mai e Ieova o Siona nai le tafeaga,", "When the LORD turned again the captivity of Zion,"], ["ona tusa ai lea o i tatou ma tagata ua fai a latou miti.", "we were like them that dream."]]},
  {num:2,words:[["Ona tumu ai lea o o tatou gutu i le featani,", "Then was our mouth filled with laughter,"], ["ma o tatou laulaufaiva i le leo fiafia;", "and our tongue with singing:"], ["ona latou faapea ane lea i nuu ese,", "then said they among the heathen,"], ["Ua faia e Ieova mea tetele mo i latou.", "The LORD hath done great things for them."]]},
  {num:3,words:[["Ua faia e Ieova mea tetele mo i tatou;", "The LORD hath done great things for us;"], ["ua tatou fiafia ai.", "whereof we are glad."]]},
  {num:4,words:[["Ieova e,", "Turn again our captivity,"], ["ia e faafoisia mai la matou tafeaga,", "O LORD,"], ["faapei o vaitafe i le itu i toga.", "as the streams in the south."]]},
  {num:5,words:[["O e lulu saito ma loimata, latou te seleseleina ma le alaga fiafia.", "They that sow in tears shall reap in joy."]]},
  {num:6,words:[["O le ua alu atu ma tagi fano,", "He that goeth forth and weepeth,"], ["o loo ave le saito e lulu,", "bearing precious seed,"], ["e foi mai lava ia ma le alaga fiafia,", "shall doubtless come again with rejoicing,"], ["o loo au mai ana fusi saito.", "bringing his sheaves with him."]]},
];
renderVerseSet(psa_ch_126_Verses, 'psa-ch126-verses');

var psa_ch_127_Verses = [
  {num:1,words:[["Afai e le atiina ae e Ieova le fale,", "Except the LORD build the house,"], ["e galulue fua i latou o e atiina ae;", "they labour in vain that build it:"], ["afai e le leoleo e Ieova le aai,", "except the LORD keep the city,"], ["e mataala fua o le na te leoleoina.", "the watchman waketh but in vain."]]},
  {num:2,words:[["E le aoga ia te outou ona tulai i le taeao lava,", "It is vain for you to rise up early,"], ["ma faatuai ona mānava,", "to sit up late,"], ["ma aai le mea e 'ai o le tiga,", "to eat the bread of sorrows:"], ["e faapea ona avatu e ia le moe i lana pele.", "for so he giveth his beloved sleep."]]},
  {num:3,words:[["Faauta, o le fanau,", "Lo,"], ["o le tofi lea mai ia Ieova;", "children are an heritage of the LORD:"], ["o e ua fanau mai, o le taui lea mai ia te ia .", "and the fruit of the womb is his reward."]]},
  {num:4,words:[["E pei o u fanafana i le lima o le toa,", "As arrows are in the hand of a mighty man;"], ["e faapea lava atalii o taulelea.", "so are children of the youth."]]},
  {num:5,words:[["Amuia le tagata ua tumu ai lana utu;", "Happy is the man that hath his quiver full of them: they shall not be ashamed,"], ["e le mamā i latou pe a latou tautala i le faitotoa ma e ita mai.", "but they shall speak with the enemies in the gate."]]},
];
renderVerseSet(psa_ch_127_Verses, 'psa-ch127-verses');

var psa_ch_128_Verses = [
  {num:1,words:[["Amuia i latou uma o e matatau ia Ieova,", "Blessed is every one that feareth the LORD;"], ["o e savavali i ona ala.", "that walketh in his ways."]]},
  {num:2,words:[["Auā e te 'ai i mea e galue ai ou lima;", "For thou shalt eat the labour of thine hands:"], ["e ia te oe le manuia,", "happy shalt thou be,"], ["e ia te oe foi le lelei.", "and it shall be well with thee."]]},
  {num:3,words:[["E avea lau avā pei o le vine fua tele mai i totonu o lou fale;", "Thy wife shall be as a fruitful vine by the sides of thine house:"], ["o lau fanau e pei o tamai olive e vagavagai lau laoai.", "thy children like olive plants round about thy table."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["e faapea ona manuia o le tagata e mata'u ia Ieova.", "that thus shall the man be blessed that feareth the LORD."]]},
  {num:5,words:[["E faamanuia mai Ieova ia te oe mai Siona;", "The LORD shall bless thee out of Zion:"], ["ona e iloa atu lea le manuia o Ierusalema i aso uma o lou olaga.", "and thou shalt see the good of Jerusalem all the days of thy life."]]},
  {num:6,words:[["E te iloa atu foi le fanau a lau fanau;", "Yea, thou shalt see thy children's children,"], ["e ia Isaraelu le manuia.", "and peace upon Israel."]]},
];
renderVerseSet(psa_ch_128_Verses, 'psa-ch128-verses');

var psa_ch_129_Verses = [
  {num:1,words:[["Ua tele lo latou faasaua mai ia te au talu lo'u taulealea,", "Many a time have they afflicted me from my youth,"], ["ia faapea ane lava Isaraelu;", "may Israel now say:"]]},
  {num:2,words:[["ua tele lo latou faasaua mai ia te au talu lo'u taulealea;", "Many a time have they afflicted me from my youth:"], ["a ua latou le manumalo mai ia te a'u.", "yet they have not prevailed against me."]]},
  {num:3,words:[["O e suatia le eleele ua latou suatia lo'u tua,", "The plowers plowed upon my back:"], ["ua latou faauumi i a latou suataga.", "they made long their furrows."]]},
  {num:4,words:[["E amiotonu Ieova,", "The LORD is righteous:"], ["ua na sala i maea a e amio leaga.", "he hath cut asunder the cords of the wicked."]]},
  {num:5,words:[["E mamā ma liutuaina i latou uma lava o e 'ino'ino i Siona.", "Let them all be confounded and turned back that hate Zion."]]},
  {num:6,words:[["E avea i latou pei o le mutia i luga o fale,", "Let them be as the grass upon the housetops,"], ["e magumagu a o le velea.", "which withereth afore it groweth up:"]]},
  {num:7,words:[["E le tumu ai le lima o lē selesele,", "Wherewith the mower filleth not his hand;"], ["po o le fatafata o le na te fusi saito.", "nor he that bindeth sheaves his bosom."]]},
  {num:8,words:[["E le fai atu foi o e ui ane ai,", "Neither do they which go by say,"], ["Ia manuia outou mai ia Ieova;", "The blessing of the LORD be upon you:"], ["matou te faamanuia ia te outou i le suafa o Ieova.", "we bless you in the name of the LORD."]]},
];
renderVerseSet(psa_ch_129_Verses, 'psa-ch129-verses');

var psa_ch_130_Verses = [
  {num:1,words:[["Ieova e,", "Out of the depths have I cried unto thee,"], ["ua ou valaau atu ia te oe ai mea loloto.", "O LORD."]]},
  {num:2,words:[["Le Alii e,", "Lord,"], ["ia e faafofoga mai i lo'u leo;", "hear my voice:"], ["ia liliu mai ou fofoga i le leo o la'u aioi atu.", "let thine ears be attentive to the voice of my supplications."]]},
  {num:3,words:[["Ioa e,", "If thou,"], ["afai e te mataulia le amio leaga,", "LORD,"], ["le Alii e,", "shouldest mark iniquities, O Lord,"], ["o ai se na te mafaia ona tulai?", "who shall stand?"]]},
  {num:4,words:[["A o ia te oe le faamagaloina o sala,", "But there is forgiveness with thee,"], ["ina ia matautia oe.", "that thou mayest be feared."]]},
  {num:5,words:[["Ou te faatali atu ia Ieova,", "I wait for the LORD,"], ["o loo faatali atu lava lo'u agaga;", "my soul doth wait,"], ["ou te faamoemoe foi i lana afioga.", "and in his word do I hope."]]},
  {num:6,words:[["O loo faatalitali atu lo'u agaga i le Alii e sili i e o leoleo ona faatalitali i le taeao;", "My soul waiteth for the Lord more than they that watch for the morning: I say,"], ["e sili lava i e o leoleo ona faatalitali i le taeao.", "more than they that watch for the morning."]]},
  {num:7,words:[["Ia faamoemoe Isaraelu ia Ieova;", "Let Israel hope in the LORD:"], ["auā o ia Ieova le alofa,", "for with the LORD there is mercy,"], ["o ia te ia foi le faaolataga tele.", "and with him is plenteous redemption."]]},
  {num:8,words:[["O ia lava na te faaolaina Isaraelu ai a latou amio leaga uma lava.", "And he shall redeem Israel from all his iniquities."]]},
];
renderVerseSet(psa_ch_130_Verses, 'psa-ch130-verses');

var psa_ch_131_Verses = [
  {num:1,words:[["Ieova e,", "LORD,"], ["ua ou le loto faamaualuga,", "my heart is not haughty,"], ["ua le faasiasia o'u mata,", "nor mine eyes lofty: neither do I exercise myself in great matters,"], ["ou te le masani ma mea faasilisili ma mea ua sili ona faigata ia te au.", "or in things too high for me."]]},
  {num:2,words:[["E moni,", "Surely I have behaved and quieted myself,"], ["na ou fifilemu ma ou faalologo faapei o le tama ua te'a ma le susu o lona tinā,", "as a child that is weaned of his mother:"], ["ua tusa a'u ma le tama ua te'a ma le susu.", "my soul is even as a weaned child."]]},
  {num:3,words:[["Ia faamoemoe Isaraelu ia Ieova, e amata mai nei lava, a e oo i le faavavau.", "Let Israel hope in the LORD from henceforth and for ever."]]},
];
renderVerseSet(psa_ch_131_Verses, 'psa-ch131-verses');

var psa_ch_132_Verses = [
  {num:1,words:[["Ieova e,", "LORD, remember David,"], ["ia e manatu ia Tavita i ona puapuaga uma lava;", "and all his afflictions:"]]},
  {num:2,words:[["o le na tauto ia Ieova,", "How he sware unto the LORD,"], ["na tuuautapu i lē Malosi o Iakopo;", "and vowed unto the mighty God of Jacob;"]]},
  {num:3,words:[["sa faapea , E moni,", "Surely I will not come into the tabernacle of my house,"], ["ou te le alu i le fale ie o lo'u fale, pe alu ae i lo'u moega, o le mea e moe ai;", "nor go up into my bed;"]]},
  {num:4,words:[["ou te le mafai ona mou o'u mata,", "I will not give sleep to mine eyes,"], ["pe matămoe o'u laumata,", "or slumber to mine eyelids,"]]},
  {num:5,words:[["seia ou maua se mea e afio ai Ieova,", "Until I find out a place for the LORD,"], ["o le afioaga mo lē Malosi o Iakopo.", "an habitation for the mighty God of Jacob."]]},
  {num:6,words:[["Faauta,", "Lo,"], ["na tatou faalogo i ai i Efarata;", "we heard of it at Ephratah:"], ["na tatou maua i fanua o i le vao.", "we found it in the fields of the wood."]]},
  {num:7,words:[["Tatou te o lava i ona afioaga;", "We will go into his tabernacles:"], ["tatou te ifo atu i luma o le mea e tu ai ona aao.", "we will worship at his footstool."]]},
  {num:8,words:[["Ieova e,", "Arise, O LORD,"], ["ia e tulai atu i lou malologa,", "into thy rest;"], ["o oe ma le atolaau o lou malosi.", "thou, and the ark of thy strength."]]},
  {num:9,words:[["Ia oofu au ositaulaga i le amiotonu,", "Let thy priests be clothed with righteousness;"], ["ma ia alaga fiafia ou tagata amio Atua.", "and let thy saints shout for joy."]]},
  {num:10,words:[["Aua le 'alo ou fofoga i le ua e faauuina, ona o lau auauna o Tavita.", "For thy servant David's sake turn not away the face of thine anointed."]]},
  {num:11,words:[["Na tauto Ieova ia Tavita i le faamaoni,", "The LORD hath sworn in truth unto David;"], ["e le 'alo ese ai o ia,", "he will not turn from it;"], ["Ou te faanofoina i lou nofoālii so le fanau a lou tino.", "Of the fruit of thy body will I set upon thy throne."]]},
  {num:12,words:[["Afai e tausi au fanau i la'u feagaiga ma a'u tulafono ou te a'oa'oina ai i latou,", "If thy children will keep my covenant and my testimony that I shall teach them,"], ["ona nonofo lea o la latou fanau i lou nofoālii e faavavau lava.", "their children shall also sit upon thy throne for evermore."]]},
  {num:13,words:[["Auā ua filifilia Siona e Ieova;", "For the LORD hath chosen Zion;"], ["ua finagalo lava i ai e fai mona afioaga.", "he hath desired it for his habitation."]]},
  {num:14,words:[["O lo'u malologa lenei e faavavau;", "This is my rest for ever:"], ["o le mea nei ou te nofo ai,", "here will I dwell;"], ["auā ua ou manao ai.", "for I have desired it."]]},
  {num:15,words:[["Ou te matuā faamanuia ana mea e 'ai;", "I will abundantly bless her provision:"], ["ou te faamaoona ona tagata matitiva i le areto.", "I will satisfy her poor with bread."]]},
  {num:16,words:[["Ou te faaofuina ana ositaulaga i le olataga;", "I will also clothe her priests with salvation:"], ["e alalaga foi ma le olioli ona tagata amio Atua.", "and her saints shall shout aloud for joy."]]},
  {num:17,words:[["Ou te faatupuina ai le nifo mo Tavita;", "There will I make the horn of David to bud:"], ["ua ou saunia le lamepa mo le ua ou faauuina.", "I have ordained a lamp for mine anointed."]]},
  {num:18,words:[["Ou te faaofuina o e ita ia te ia i le ma;", "His enemies will I clothe with shame:"], ["a e pupula mai lona palealii i luga ia te ia.", "but upon himself shall his crown flourish."]]},
];
renderVerseSet(psa_ch_132_Verses, 'psa-ch132-verses');

var psa_ch_133_Verses = [
  {num:1,words:[["Faauta, o le mea e matuā lelei ma le matagofie lava,", "Behold,"], ["pe a nonofo faatasi lava o uso.", "how good and how pleasant it is for brethren to dwell together in unity!"]]},
  {num:2,words:[["Ua tusa ma le suāuu lelei i luga o le ulu,", "It is like the precious ointment upon the head,"], ["na tafe ifo i le 'ava,", "that ran down upon the beard,"], ["o le 'ava lava a Arona,", "even Aaron's beard:"], ["na tafe ifo i le ua o ona ofu.", "that went down to the skirts of his garments;"]]},
  {num:3,words:[["E tusa ma le sau i Heremoni,", "As the dew of Hermon,"], ["ua totō ifo i luga o mauga o Siona;", "and as the dew that descended upon the mountains of Zion:"], ["auā na poloai Ieova ia oo i ai lana faamanuia,", "for there the LORD commanded the blessing,"], ["o le ola lava lea e faavavau.", "even life for evermore."]]},
];
renderVerseSet(psa_ch_133_Verses, 'psa-ch133-verses');

var psa_ch_134_Verses = [
  {num:1,words:[["Faauta mai,", "Behold,"], ["o outou o auauna uma lava a Ieova,", "bless ye the LORD,"], ["faamanū atu ia outou ia Ieova;", "all ye servants of the LORD,"], ["outou o e tutū i le fale o Ieova i le po.", "which by night stand in the house of the LORD."]]},
  {num:2,words:[["Ia outou sisii i luga o outou lima i le malumalu,", "Lift up your hands in the sanctuary,"], ["ma ia outou faamanū atu ia Ieova.", "and bless the LORD."]]},
  {num:3,words:[["E faamanuia mai e Ieova ia te oe mai Siona, o ia na faia le lagi atoa ma le lalolagi.", "The LORD that made heaven and earth bless thee out of Zion."]]},
];
renderVerseSet(psa_ch_134_Verses, 'psa-ch134-verses');

var psa_ch_135_Verses = [
  {num:1,words:[["Ia outou vivii atu ia Ioa. Vivii atu ia outou i le suafa o Ieova;", "Praise ye the LORD. Praise ye the name of the LORD;"], ["o outou auauna a Ieova,", "praise him,"], ["vivii atu ia outou ia te ia .", "O ye servants of the LORD."]]},
  {num:2,words:[["Outou o e tutū i le fale o Ieova,", "Ye that stand in the house of the LORD,"], ["i lotoā o le fale o lo tatou Atua,", "in the courts of the house of our God,"]]},
  {num:3,words:[["ia outou vivii atu ia Ioa;", "Praise the LORD;"], ["auā e lelei Ieova,", "for the LORD is good:"], ["ia fai pesega i lona suafa;", "sing praises unto his name;"], ["auā e matagofie lea.", "for it is pleasant."]]},
  {num:4,words:[["Auā ua filifilia Iakopo e Ioa mona,", "For the LORD hath chosen Jacob unto himself,"], ["o Isaraelu e fai mana oloa tāua.", "and Israel for his peculiar treasure."]]},
  {num:5,words:[["Auā o a'u nei, ua ou iloa e sili lava Ieova,", "For I know that the LORD is great,"], ["e sili foi lo tatou Alii i atua uma lava.", "and that our Lord is above all gods."]]},
  {num:6,words:[["O mea uma lava e finagalo i ai Ieova,", "Whatsoever the LORD pleased, that did he in heaven,"], ["e faia lava e ia i le lagi atoa ma le lalolagi,", "and in earth,"], ["o le sami ma mea loloto uma lava.", "in the seas, and all deep places."]]},
  {num:7,words:[["E avae e ia o ausa mai tulu'iga o le lalolagi;", "He causeth the vapours to ascend from the ends of the earth;"], ["na te faia le uila atoa ma le ua;", "he maketh lightnings for the rain;"], ["na te aumaia le matagi mai mea e teu ai ana oloa.", "he bringeth the wind out of his treasuries."]]},
  {num:8,words:[["O le na fasia ulumatua a Aikupito,", "Who smote the firstborn of Egypt,"], ["o tagata atoa ma manu.", "both of man and beast."]]},
  {num:9,words:[["O le na auina atu o faailoga ma vavega ia te oe,", "Who sent tokens and wonders into the midst of thee,"], ["Aikupito e,", "O Egypt, upon Pharaoh,"], ["ia Farao ma ana auauna uma lava.", "and upon all his servants."]]},
  {num:10,words:[["O le na fasia nuu tetele,", "Who smote great nations,"], ["ma na fasiotia o tupu malolosi;", "and slew mighty kings;"]]},
  {num:11,words:[["o Sekono le tupu o sa Amorī,", "Sihon king of the Amorites,"], ["ma Oko le tupu o Vasana,", "and Og king of Bashan,"], ["atoa ma tupu uma o Kanana.", "and all the kingdoms of Canaan:"]]},
  {num:12,words:[["Ua na avatu foi lo latou laueleele ma tofi,", "And gave their land for an heritage,"], ["o le tofi lava o lona nuu o Isaraelu.", "an heritage unto Israel his people."]]},
  {num:13,words:[["Ieova e,", "Thy name,"], ["e faavavau lava Iou suafa;", "O LORD,"], ["o le faamanatuga ia te oe,", "endureth for ever; and thy memorial,"], ["Ieova e,", "O LORD,"], ["e āu tupulaga lea.", "throughout all generations."]]},
  {num:14,words:[["Auā e faamasino e Ieova lona nuu;", "For the LORD will judge his people,"], ["e salamo foi ia ona o ana auauna.", "and he will repent himself concerning his servants."]]},
  {num:15,words:[["O tupua o nuu ese, o ario ma auro ia,", "The idols of the heathen are silver and gold,"], ["o galuega a lima o tagata.", "the work of men's hands."]]},
  {num:16,words:[["E fai o latou gutu,", "They have mouths,"], ["a e le feganavai;", "but they speak not;"], ["e fai o latou mata,", "eyes have they,"], ["a e le vaai;", "but they see not;"]]},
  {num:17,words:[["e fai o latou taliga,", "They have ears,"], ["a e le faalogo;", "but they hear not;"], ["e leai foi se mānava i o latou gutu.", "neither is there any breath in their mouths."]]},
  {num:18,words:[["O e faia ia mea ua tutusa lava ma i latou,", "They that make them are like unto them:"], ["o i latou uma o e faatuatua i ai.", "so is every one that trusteth in them."]]},
  {num:19,words:[["Le aiga o Isaraelu e,", "Bless the LORD,"], ["ia outou faamanū atu ia Ieova;", "O house of Israel:"], ["le aiga o Arona e, ia outou faamanū atu ia Ieova;", "bless the LORD,"], ["le aiga o Levi e,", "O house of Aaron:"]]},
  {num:20,words:[["ia outou faamanū atu ia Ieova;", "Bless the LORD,"], ["outou o e matatau ia Ieova,", "O house of Levi: ye that fear the LORD,"], ["ina faamanū atu ia ia Ieova.", "bless the LORD."]]},
  {num:21,words:[["Ia faamanū atu ia Ieova mai Siona,", "Blessed be the LORD out of Zion,"], ["o le o afio i Ierusalema. Ia outou vivii atu ia Ioa.", "which dwelleth at Jerusalem. Praise ye the LORD."]]},
];
