var psa_ch_137_Verses = [
  {num:1,words:[["Na matou nonofo i auvai o vaitafe i Papelonia,", "By the rivers of Babylon, there we sat down,"], ["na fetagisi ai lava i matou,", "yea,"], ["ina ua matou manatua Siona.", "we wept, when we remembered Zion."]]},
  {num:2,words:[["Ua matou tautauina a matou kitara i luga o garava ua i ai.", "We hanged our harps upon the willows in the midst thereof."]]},
  {num:3,words:[["Auā na inoino mai ia te i matou i lea mea o e na ta'ita'i ia i matou i le tafeaga, ia matou pepese i upu o le pese;", "For there they that carried us away captive required of us a song;"], ["o i latou foi na faatiga mai ia i matou,", "and they that wasted us required of us mirth,"], ["ua inoino mai ia olioli,", "saying,"], ["ua faapea mai , Ia outou pepese mai ia i matou ni pese a Siona.", "Sing us one of the songs of Zion."]]},
  {num:4,words:[["Pe faapefea ona matou pepese le pese ia Ieova i le nuu ese?", "How shall we sing the LORD'S song in a strange land?"]]},
  {num:5,words:[["Ierusalema e,", "If I forget thee,"], ["afai e galo oe ia te au,", "O Jerusalem,"], ["ia galo lava i lo'u lima taumatau;", "let my right hand forget her cunning."]]},
  {num:6,words:[["afai ou te le manatua oe,", "If I do not remember thee,"], ["ia pipii ae lo'u laulaufaiva i lo'u gutu,", "let my tongue cleave to the roof of my mouth;"], ["pe a le faasili Ierusalema i mea uma ou te fiafia i ai.", "if I prefer not Jerusalem above my chief joy."]]},
  {num:7,words:[["Ieova e,", "Remember,"], ["ia e manatu i le fanauga a Etoma i le aso o Ierusalema;", "O LORD,"], ["na latou faapea ane ai,", "the children of Edom in the day of Jerusalem; who said,"], ["ia faataatitiaina,", "Rase it,"], ["ia faataatitiaina,", "rase it,"], ["ia oo i ona faavae.", "even to the foundation thereof."]]},
  {num:8,words:[["Le tama fafine a Papelonia e,", "O daughter of Babylon,"], ["e faatafunaina oe;", "who art to be destroyed; happy shall he be,"], ["amuia o lē faatatau ia te oe le taui na e taui mai ai ia te i matou.", "that rewardeth thee as thou hast served us."]]},
  {num:9,words:[["Amuia le tago i au tama meamea,", "Happy shall he be,"], ["ma palasi ia te i latou i le papa.", "that taketh and dasheth thy little ones against the stones."]]},
];
